{
  "name": "SeteCordas Pro",
  "description": "An advanced practice companion for Brazilian 7-string guitarists, featuring a precision tuner with alternate tunings and a rhythm-aware metronome backed by AI coaching.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum SeventhStringTuning {
  B = 'B (Standard)',
  C = 'C (Samba/Choro)',
  A = 'A (Low)',
}

export enum RhythmStyle {
  SAMBA = 'Samba',
  CHORO = 'Choro',
  BOSSA_NOVA = 'Bossa Nova',
  BAIAO = 'Baião',
}

export interface GuitarString {
  note: string;
  octave: number;
  frequency: number;
  description?: string;
}

export interface RhythmPreset {
  name: RhythmStyle;
  description: string;
  countPattern: string;
  bpmRanges: {
    beginner: number;
    intermediate: number;
    advanced: number;
  };
  accentBeat: number[]; // 1-based index of beats to accent
  subdivision: number; // 2 for 8th notes, 4 for 16th notes
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

import { GuitarString, RhythmPreset, RhythmStyle, SeventhStringTuning } from './types';

export const STANDARD_STRINGS: GuitarString[] = [
  { note: 'E', octave: 4, frequency: 329.63 },
  { note: 'B', octave: 3, frequency: 246.94 },
  { note: 'G', octave: 3, frequency: 196.00 },
  { note: 'D', octave: 3, frequency: 146.83 },
  { note: 'A', octave: 2, frequency: 110.00 },
  { note: 'E', octave: 2, frequency: 82.41 },
];

export const SEVENTH_STRING_OPTIONS: Record<SeventhStringTuning, GuitarString> = {
  [SeventhStringTuning.B]: { note: 'B', octave: 1, frequency: 61.74, description: 'Standard 7-string tuning' },
  [SeventhStringTuning.C]: { note: 'C', octave: 2, frequency: 65.41, description: 'Common for Samba & Choro (Baixaria)' },
  [SeventhStringTuning.A]: { note: 'A', octave: 1, frequency: 55.00, description: 'Extended low range' },
};

export const RHYTHM_PRESETS: RhythmPreset[] = [
  {
    name: RhythmStyle.SAMBA,
    description: 'The heartbeat of Brazil. Focus on the strong "surdo" accent on beat 2.',
    countPattern: '1 (and) 2 (and) - "tum-TA-tum-tum"',
    bpmRanges: { beginner: 80, intermediate: 100, advanced: 120 },
    accentBeat: [2, 4], 
    subdivision: 2,
  },
  {
    name: RhythmStyle.CHORO,
    description: 'Fast, melodic, and technical. The 7th string drives the counterpoint.',
    countPattern: '1 e & a 2 e & a - Continuous 16ths',
    bpmRanges: { beginner: 60, intermediate: 90, advanced: 130 },
    accentBeat: [1, 3], // Choro often feels 2/4
    subdivision: 4,
  },
  {
    name: RhythmStyle.BOSSA_NOVA,
    description: 'Syncopated and smooth. Jazz influenced harmony.',
    countPattern: 'Syncopated claves',
    bpmRanges: { beginner: 100, intermediate: 130, advanced: 160 }, // Bossa is often counted in cut time, but here we treat quarter notes
    accentBeat: [1], 
    subdivision: 2,
  },
  {
    name: RhythmStyle.BAIAO,
    description: 'Northeastern rhythm. Syncopated bass drum pattern.',
    countPattern: 'Baião beat: Root - 5th - Octave',
    bpmRanges: { beginner: 85, intermediate: 105, advanced: 130 },
    accentBeat: [1, 4], // Simplified feeling
    subdivision: 2,
  },
];

// Simple audio context singleton to avoid recreating it
let audioCtx: AudioContext | null = null;

const getAudioContext = (): AudioContext => {
  if (!audioCtx) {
    audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
  }
  return audioCtx;
};

export const playTone = (frequency: number, type: OscillatorType = 'triangle', duration = 2.0) => {
  const ctx = getAudioContext();
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  osc.type = type;
  osc.frequency.setValueAtTime(frequency, ctx.currentTime);

  // Envelope
  gain.gain.setValueAtTime(0, ctx.currentTime);
  gain.gain.linearRampToValueAtTime(0.3, ctx.currentTime + 0.05); // Attack
  gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + duration); // Decay

  osc.connect(gain);
  gain.connect(ctx.destination);

  osc.start();
  osc.stop(ctx.currentTime + duration);
};

export const playClick = (accent: boolean) => {
  const ctx = getAudioContext();
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  // Woody click sound
  osc.type = accent ? 'square' : 'triangle';
  // Higher pitch for accent (downbeat or specialized accent), lower for weak
  osc.frequency.setValueAtTime(accent ? 1200 : 800, ctx.currentTime); 

  if (accent) {
     // A bit more "bite" for the accent
     osc.frequency.exponentialRampToValueAtTime(600, ctx.currentTime + 0.1);
  } else {
     osc.frequency.exponentialRampToValueAtTime(400, ctx.currentTime + 0.1);
  }

  gain.gain.setValueAtTime(0, ctx.currentTime);
  gain.gain.linearRampToValueAtTime(accent ? 0.5 : 0.3, ctx.currentTime + 0.005);
  gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.1);

  osc.connect(gain);
  gain.connect(ctx.destination);

  osc.start();
  osc.stop(ctx.currentTime + 0.1);
};

import { GoogleGenAI } from "@google/genai";
import { RhythmStyle, SeventhStringTuning } from '../types';

export const generatePracticeTip = async (
  tuning: SeventhStringTuning,
  rhythm: RhythmStyle
): Promise<string> => {
  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    return "Please set your API Key to generate a personalized practice tip.";
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    const prompt = `
      Act as a world-class Brazilian 7-string guitar teacher (violão de 7 cordas).

      The student has configured their guitar with the 7th string tuned to: ${tuning}.
      They want to practice the rhythm: ${rhythm}.

      Please provide a SHORT, specific, and musical "Warm-up Exercise" that combines this specific tuning and rhythm. 

      1. Mention a specific chord progression or scale pattern that benefits from this 7th string tuning (e.g., using the low C for C major/minor runs if tuned to C).
      2. Give a rhythmic instruction relevant to ${rhythm}.
      3. Keep it under 100 words. Be encouraging but technical.
      4. Use formatting like bullet points or bold text for clarity.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "Could not generate a tip at this time.";
  } catch (error) {
    console.error("Error calling Gemini:", error);
    return "Sorry, I couldn't connect to the teaching assistant. Please check your connection or API key.";
  }
};

import React, { useState } from 'react';
import { Volume2 } from 'lucide-react';
import { STANDARD_STRINGS, SEVENTH_STRING_OPTIONS } from '../constants';
import { SeventhStringTuning } from '../types';
import { playTone } from '../utils/audio';

interface TunerProps {
  currentTuning: SeventhStringTuning;
  onTuningChange: (tuning: SeventhStringTuning) => void;
}

export const Tuner: React.FC<TunerProps> = ({ currentTuning, onTuningChange }) => {
  const [playingIndex, setPlayingIndex] = useState<number | null>(null);

  // Combine standard 6 strings (reversed for display E to E) with the selected 7th
  // Actually, standard list is top down E4 -> E2.
  // 7-string guitar usually listed 1st (high E) to 7th (low).
  const strings = [...STANDARD_STRINGS, SEVENTH_STRING_OPTIONS[currentTuning]];

  const handlePlay = (freq: number, index: number) => {
    playTone(freq);
    setPlayingIndex(index);
    setTimeout(() => setPlayingIndex(null), 2000); // Visual feedback duration
  };

  return (
    <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-yellow-500 flex items-center gap-2">
          <span>🎸</span> 7-String Tuner
        </h2>
        <div className="flex flex-col items-end">
          <label className="text-xs text-slate-400 mb-1 uppercase tracking-wider font-semibold">7th String Tuning</label>
          <select 
            value={currentTuning}
            onChange={(e) => onTuningChange(e.target.value as SeventhStringTuning)}
            className="bg-slate-900 text-slate-200 border border-slate-600 rounded px-3 py-1 text-sm focus:outline-none focus:border-yellow-500"
          >
            {Object.values(SeventhStringTuning).map((t) => (
              <option key={t} value={t}>{t}</option>
            ))}
          </select>
        </div>
      </div>

      <div className="space-y-3">
        {strings.map((str, idx) => {
          const stringNumber = idx + 1;
          const isPlaying = playingIndex === idx;

          return (
            <div 
              key={idx}
              onClick={() => handlePlay(str.frequency, idx)}
              className={`
                group relative flex items-center justify-between p-4 rounded-xl cursor-pointer transition-all duration-300
                ${isPlaying ? 'bg-yellow-500/20 border-yellow-500/50' : 'bg-slate-900/50 border-slate-700 hover:bg-slate-700/50'}
                border
              `}
            >
              <div className="flex items-center gap-4">
                <div className={`
                  w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm
                  ${isPlaying ? 'bg-yellow-500 text-slate-900' : 'bg-slate-700 text-slate-400 group-hover:bg-slate-600'}
                `}>
                  {stringNumber}
                </div>
                <div>
                  <div className="flex items-baseline gap-2">
                    <span className={`text-2xl font-bold ${isPlaying ? 'text-yellow-400' : 'text-white'}`}>
                      {str.note}
                    </span>
                    <span className="text-xs text-slate-500">{str.octave}</span>
                  </div>
                  {str.description && (
                    <p className="text-xs text-slate-400">{str.description}</p>
                  )}
                </div>
              </div>

              <div className="flex items-center gap-4">
                <span className="font-mono text-slate-400 text-sm">{str.frequency.toFixed(2)} Hz</span>
                <Volume2 size={20} className={`${isPlaying ? 'text-yellow-400 animate-pulse' : 'text-slate-600'}`} />
              </div>

              {/* Visual String representation */}
              <div className="absolute bottom-0 left-0 w-full h-1 overflow-hidden rounded-b-xl">
                 <div className={`h-full bg-yellow-500 transition-all duration-1000 ${isPlaying ? 'w-full opacity-50' : 'w-0 opacity-0'}`} />
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Play, Square, Activity } from 'lucide-react';
import { RHYTHM_PRESETS } from '../constants';
import { RhythmStyle } from '../types';
import { playClick } from '../utils/audio';

interface MetronomeProps {
  selectedRhythm: RhythmStyle;
  onRhythmChange: (rhythm: RhythmStyle) => void;
}

export const Metronome: React.FC<MetronomeProps> = ({ selectedRhythm, onRhythmChange }) => {
  const [bpm, setBpm] = useState(100);
  const [isPlaying, setIsPlaying] = useState(false);
  const [beatCount, setBeatCount] = useState(1);

  const preset = RHYTHM_PRESETS.find(r => r.name === selectedRhythm) || RHYTHM_PRESETS[0];

  // Timer Refs
  const timerRef = useRef<NodeJS.Timeout | null>(null);
  const expectedRef = useRef<number>(0);
  const beatCounterRef = useRef<number>(0);

  // Update BPM when preset changes to intermediate default if not playing
  useEffect(() => {
    if (!isPlaying) {
      setBpm(preset.bpmRanges.intermediate);
    }
  }, [preset, isPlaying]);

  const tick = useCallback(() => {
    const timePerBeat = 60000 / bpm;
    // Drift correction logic
    const dt = Date.now() - expectedRef.current;

    if (dt > timePerBeat) {
        // If we drifted too far (e.g. tab inactive), reset
        expectedRef.current = Date.now();
    }

    // Audio
    // Determine accent based on rhythm preset
    const currentBeatInMeasure = (beatCounterRef.current % 4) + 1; // Assuming 4/4 mostly for simplicity
    const isAccent = preset.accentBeat.includes(currentBeatInMeasure);

    playClick(isAccent);

    // Visual update
    setBeatCount(currentBeatInMeasure);

    // Schedule next
    expectedRef.current += timePerBeat;
    beatCounterRef.current += 1;

    timerRef.current = setTimeout(tick, Math.max(0, timePerBeat - dt));
  }, [bpm, preset.accentBeat]);

  const togglePlay = () => {
    if (isPlaying) {
      if (timerRef.current) clearTimeout(timerRef.current);
      setIsPlaying(false);
      setBeatCount(1);
    } else {
      setIsPlaying(true);
      beatCounterRef.current = 0;
      expectedRef.current = Date.now();
      tick();
    }
  };

  useEffect(() => {
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, []);

  return (
    <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 flex flex-col h-full">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-green-400 flex items-center gap-2">
          <span>🥁</span> Metronome
        </h2>
        <div className="flex items-center gap-2">
           <Activity className={isPlaying ? "text-green-400 animate-pulse" : "text-slate-600"} />
        </div>
      </div>

      {/* Rhythm Selector */}
      <div className="mb-6">
        <label className="text-xs text-slate-400 uppercase tracking-wider font-semibold mb-2 block">Rhythm Style</label>
        <div className="grid grid-cols-2 gap-2">
          {RHYTHM_PRESETS.map((r) => (
            <button
              key={r.name}
              onClick={() => onRhythmChange(r.name)}
              className={`
                px-3 py-2 rounded-lg text-sm font-medium transition-colors
                ${selectedRhythm === r.name 
                  ? 'bg-green-600 text-white shadow-lg shadow-green-900/50' 
                  : 'bg-slate-900 text-slate-400 hover:bg-slate-700 hover:text-white'}
              `}
            >
              {r.name}
            </button>
          ))}
        </div>
        <p className="mt-3 text-sm text-slate-300 italic">"{preset.countPattern}"</p>
      </div>

      {/* BPM Controls */}
      <div className="mb-8">
        <div className="flex justify-between items-end mb-2">
           <span className="text-4xl font-mono font-bold text-white">{bpm} <span className="text-lg text-slate-500 font-normal">BPM</span></span>
           <div className="flex gap-2 text-xs">
             <button onClick={() => setBpm(preset.bpmRanges.beginner)} className="text-slate-400 hover:text-green-400">Beg</button>
             <button onClick={() => setBpm(preset.bpmRanges.intermediate)} className="text-slate-400 hover:text-green-400">Int</button>
             <button onClick={() => setBpm(preset.bpmRanges.advanced)} className="text-slate-400 hover:text-green-400">Adv</button>
           </div>
        </div>
        <input 
          type="range" 
          min="40" 
          max="220" 
          value={bpm} 
          onChange={(e) => setBpm(Number(e.target.value))}
          className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-green-500"
        />
      </div>

      {/* Play/Stop & Visualizer */}
      <div className="mt-auto flex flex-col gap-6">
        {/* Beat Dots */}
        <div className="flex justify-center gap-4">
          {[1, 2, 3, 4].map((beat) => (
            <div 
              key={beat}
              className={`
                w-4 h-4 rounded-full transition-all duration-100
                ${beatCount === beat && isPlaying ? 'bg-green-400 scale-125 shadow-[0_0_10px_rgba(74,222,128,0.8)]' : 'bg-slate-700'}
                ${preset.accentBeat.includes(beat) ? 'border-2 border-slate-500' : ''}
              `}
            />
          ))}
        </div>

        <button
          onClick={togglePlay}
          className={`
            w-full py-4 rounded-xl flex items-center justify-center gap-3 font-bold text-lg transition-all
            ${isPlaying 
              ? 'bg-red-500/10 text-red-500 border border-red-500/50 hover:bg-red-500/20' 
              : 'bg-green-500 text-slate-900 hover:bg-green-400 shadow-lg shadow-green-900/50'}
          `}
        >
          {isPlaying ? <><Square fill="currentColor" size={20} /> Stop</> : <><Play fill="currentColor" size={20} /> Start</>}
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Sparkles, RefreshCw } from 'lucide-react';
import { RhythmStyle, SeventhStringTuning } from '../types';
import { generatePracticeTip } from '../services/geminiService';
import ReactMarkdown from 'react-markdown';

interface PracticeCoachProps {
  tuning: SeventhStringTuning;
  rhythm: RhythmStyle;
}

export const PracticeCoach: React.FC<PracticeCoachProps> = ({ tuning, rhythm }) => {
  const [tip, setTip] = useState<string>("");
  const [loading, setLoading] = useState(false);

  const handleGenerate = async () => {
    setLoading(true);
    const result = await generatePracticeTip(tuning, rhythm);
    setTip(result);
    setLoading(false);
  };

  return (
    <div className="bg-gradient-to-br from-indigo-900 to-slate-900 rounded-2xl p-1 shadow-xl border border-indigo-500/30">
      <div className="bg-slate-900/80 backdrop-blur-sm rounded-xl p-6 h-full">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-xl font-bold text-indigo-400 flex items-center gap-2">
            <Sparkles size={20} /> AI Practice Coach
          </h2>
        </div>

        <p className="text-slate-400 text-sm mb-6">
            Get a specialized warm-up exercise combining 
            <span className="text-yellow-400 font-semibold mx-1">{tuning.split('(')[0]} tuning</span> 
            and 
            <span className="text-green-400 font-semibold mx-1">{rhythm}</span>.
        </p>

        {!tip && !loading && (
          <div className="text-center py-8">
            <button 
              onClick={handleGenerate}
              className="px-6 py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg font-semibold transition-all shadow-lg hover:shadow-indigo-500/20 flex items-center gap-2 mx-auto"
            >
              <Sparkles size={18} /> Generate Exercise
            </button>
          </div>
        )}

        {loading && (
          <div className="flex flex-col items-center justify-center py-12 text-indigo-400 animate-pulse">
            <RefreshCw className="animate-spin mb-2" size={32} />
            <span className="text-sm">Consulting the Maestro...</span>
          </div>
        )}

        {tip && !loading && (
          <div className="animate-fadeIn">
            <div className="prose prose-invert prose-sm max-w-none bg-slate-800/50 p-4 rounded-lg border border-slate-700">
               <ReactMarkdown>{tip}</ReactMarkdown>
            </div>
            <div className="mt-4 flex justify-end">
              <button 
                onClick={handleGenerate}
                className="text-xs text-slate-500 hover:text-indigo-400 flex items-center gap-1"
              >
                <RefreshCw size={12} /> New Tip
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Tuner } from './components/Tuner';
import { Metronome } from './components/Metronome';
import { PracticeCoach } from './components/PracticeCoach';
import { SeventhStringTuning, RhythmStyle } from './types';
import { Music } from 'lucide-react';

const App: React.FC = () => {
  const [tuning, setTuning] = useState<SeventhStringTuning>(SeventhStringTuning.C); // Default to C for Brazilian style
  const [rhythm, setRhythm] = useState<RhythmStyle>(RhythmStyle.SAMBA);

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 p-4 md:p-8 selection:bg-yellow-500/30">

      {/* Header */}
      <header className="max-w-6xl mx-auto mb-8 md:mb-12 flex flex-col md:flex-row items-center justify-between gap-4 border-b border-slate-800 pb-6">
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 bg-gradient-to-br from-green-600 to-yellow-500 rounded-xl flex items-center justify-center shadow-lg transform rotate-3">
             <Music className="text-slate-900" size={28} strokeWidth={2.5} />
          </div>
          <div>
            <h1 className="text-3xl font-extrabold tracking-tight text-transparent bg-clip-text bg-gradient-to-r from-green-400 via-yellow-400 to-green-400">
              SeteCordas Pro
            </h1>
            <p className="text-slate-400 text-sm">Digital Assistant for the Brazilian 7-String Guitar</p>
          </div>
        </div>
        <div className="text-xs text-slate-500 text-center md:text-right">
           <p>Powered by Gemini 2.5 Flash</p>
        </div>
      </header>

      {/* Main Grid */}
      <main className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-6">

        {/* Left Column: Tuner (Takes up 7 cols on large screens) */}
        <section className="lg:col-span-7 space-y-6">
          <Tuner 
            currentTuning={tuning} 
            onTuningChange={setTuning} 
          />
          {/* Mobile/Tablet layout: Coach might appear below tuner, but for desktop we want it nicely integrated */}
           <div className="hidden lg:block">
              <PracticeCoach tuning={tuning} rhythm={rhythm} />
           </div>
        </section>

        {/* Right Column: Metronome (Takes up 5 cols) */}
        <section className="lg:col-span-5 flex flex-col gap-6">
          <Metronome 
            selectedRhythm={rhythm} 
            onRhythmChange={setRhythm} 
          />
           <div className="lg:hidden">
              <PracticeCoach tuning={tuning} rhythm={rhythm} />
           </div>
        </section>

      </main>

      {/* Footer */}
      <footer className="max-w-6xl mx-auto mt-12 pt-8 border-t border-slate-800 text-center text-slate-600 text-sm">
        <p>&copy; {new Date().getFullYear()} SeteCordas Pro. Designed for musicians.</p>
      </footer>
    </div>
  );
};

export default App;

