import { RHYTHM_PRESETS } from '../constants';
import { RhythmStyle } from '../types';
import { playClick } from '../utils/audio';

interface MetronomeProps {
  selectedRhythm: RhythmStyle;
  onRhythmChange: (rhythm: RhythmStyle) => void;
}

export const Metronome: React.FC<MetronomeProps> = ({ selectedRhythm, onRhythmChange }) => {
  const [bpm, setBpm] = useState(100);
  const [isPlaying, setIsPlaying] = useState(false);
  const [beatCount, setBeatCount] = useState(1);

  const preset = RHYTHM_PRESETS.find(r => r.name === selectedRhythm) || RHYTHM_PRESETS[0];

  // Timer Refs
  // Changed from NodeJS.Timeout to number as setTimeout returns a number in browser environments
  const timerRef = useRef<number | null>(null);
  const expectedRef = useRef<number>(0);
  const beatCounterRef = useRef<number>(0);

  // Update BPM when preset changes to intermediate default if not playing
  useEffect(() => {
    if (!isPlaying) {
      setBpm(preset.bpmRanges.intermediate);
    }
  }, [preset, isPlaying]);

  const tick = useCallback(() => {
    const timePerBeat = 60000 / bpm;
    // Drift correction logic
    const dt = Date.now() - expectedRef.current;

    if (dt > timePerBeat) {
        // If we drifted too far (e.g. tab inactive), reset
        expectedRef.current = Date.now();
    }

    // Audio
    // Determine accent based on rhythm preset
    const currentBeatInMeasure = (beatCounterRef.current % 4) + 1; // Assuming 4/4 mostly for simplicity
    const isAccent = preset.accentBeat.includes(currentBeatInMeasure);

    playClick(isAccent);

    // Visual update
    setBeatCount(currentBeatInMeasure);

    // Schedule next
    expectedRef.current += timePerBeat;
    beatCounterRef.current += 1;

    timerRef.current = window.setTimeout(tick, Math.max(0, timePerBeat - dt));
  }, [bpm, preset.accentBeat]);

  const togglePlay = () => {
    if (isPlaying) {
      if (timerRef.current) clearTimeout(timerRef.current);
      setIsPlaying(false);
      setBeatCount(1);
    } else {
      setIsPlaying(true);
      beatCounterRef.current = 0;
      expectedRef.current = Date.now();
      tick();
    }
  };

  useEffect(() => {
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, []);

  return (
    <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 flex flex-col h-full">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-green-400 flex items-center gap-2">
          <span>🥁</span> Metronome
        </h2>
        <div className="flex items-center gap-2">
           <Activity className={isPlaying ? "text-green-400 animate-pulse" : "text-slate-600"} />
        </div>
      </div>

      {/* Rhythm Selector */}
      <div className="mb-6">
        <label className="text-xs text-slate-400 uppercase tracking-wider font-semibold mb-2 block">Rhythm Style</label>
        <div className="grid grid-cols-2 gap-2">
          {RHYTHM_PRESETS.map((r) => (
            <button
              key={r.name}
              onClick={() => onRhythmChange(r.name)}
              className={`
                px-3 py-2 rounded-lg text-sm font-medium transition-colors
                ${selectedRhythm === r.name 
                  ? 'bg-green-600 text-white shadow-lg shadow-green-900/50' 
                  : 'bg-slate-900 text-slate-400 hover:bg-slate-700 hover:text-white'}
              `}
            >
              {r.name}
            </button>
          ))}
        </div>
        <p className="mt-3 text-sm text-slate-300 italic">"{preset.countPattern}"</p>
      </div>

      {/* BPM Controls */}
      <div className="mb-8">
        <div className="flex justify-between items-end mb-2">
           <span className="text-4xl font-mono font-bold text-white">{bpm} <span className="text-lg text-slate-500 font-normal">BPM</span></span>
           <div className="flex gap-2 text-xs">
             <button onClick={() => setBpm(preset.bpmRanges.beginner)} className="text-slate-400 hover:text-green-400">Beg</button>
             <button onClick={() => setBpm(preset.bpmRanges.intermediate)} className="text-slate-400 hover:text-green-400">Int</button>
             <button onClick={() => setBpm(preset.bpmRanges.advanced)} className="text-slate-400 hover:text-green-400">Adv</button>
           </div>
        </div>
        <input 
          type="range" 
          min="40" 
          max="220" 
          value={bpm} 
          onChange={(e) => setBpm(Number(e.target.value))}
          className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-green-500"
        />
      </div>

      {/* Play/Stop & Visualizer */}
      <div className="mt-auto flex flex-col gap-6">
        {/* Beat Dots */}
        <div className="flex justify-center gap-4">
          {[1, 2, 3, 4].map((beat) => (
            <div 
              key={beat}
              className={`
                w-4 h-4 rounded-full transition-all duration-100
                ${beatCount === beat && isPlaying ? 'bg-green-400 scale-125 shadow-[0_0_10px_rgba(74,222,128,0.8)]' : 'bg-slate-700'}
                ${preset.accentBeat.includes(beat) ? 'border-2 border-slate-500' : ''}
              `}
            />
          ))}
        </div>

        <button
          onClick={togglePlay}
          className={`
            w-full py-4 rounded-xl flex items-center justify-center gap-3 font-bold text-lg transition-all
            ${isPlaying 
              ? 'bg-red-500/10 text-red-500 border border-red-500/50 hover:bg-red-500/20' 
              : 'bg-green-500 text-slate-900 hover:bg-green-400 shadow-lg shadow-green-900/50'}
          `}
        >
          {isPlaying ? <><Square fill="currentColor" size={20} /> Stop</> : <><Play fill="currentColor" size={20} /> Start</>}
        </button>
      </div>
    </div>
  );
};

