import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Play, Square, Activity, Music2 } from 'lucide-react';
import { RHYTHM_PRESETS } from '../constants';
import { RhythmStyle } from '../types';
import { playClick } from '../utils/audio';

interface MetronomeProps {
  selectedRhythm: RhythmStyle;
  onRhythmChange: (rhythm: RhythmStyle) => void;
}

export const Metronome: React.FC<MetronomeProps> = ({ selectedRhythm, onRhythmChange }) => {
  const [bpm, setBpm] = useState(100);
  const [isPlaying, setIsPlaying] = useState(false);
  const [beatCount, setBeatCount] = useState(1);

  const preset = RHYTHM_PRESETS.find(r => r.name === selectedRhythm) || RHYTHM_PRESETS[0];

  const timerRef = useRef<number | null>(null);
  const expectedRef = useRef<number>(0);
  const beatCounterRef = useRef<number>(0);

  // When preset changes, if stopped, update default BPM
  useEffect(() => {
    if (!isPlaying) {
      setBpm(preset.bpmRanges.intermediate);
    }
  }, [preset, isPlaying]);

  // Tick function that handles the audio and scheduling
  const tick = useCallback(() => {
    const timePerBeat = 60000 / bpm;
    // Drift correction
    const now = Date.now();
    const dt = now - expectedRef.current;

    // If drift is huge (tab inactive), hard reset schedule
    if (dt > timePerBeat) {
        expectedRef.current = now;
    }

    // Audio Logic
    const currentBeatInMeasure = (beatCounterRef.current % 4) + 1; 
    const isAccent = preset.accentBeat.includes(currentBeatInMeasure);

    playClick(isAccent);
    setBeatCount(currentBeatInMeasure);

    // Schedule next
    expectedRef.current += timePerBeat;
    beatCounterRef.current += 1;

    // Calculate next delay, compensating for drift
    const nextDelay = Math.max(0, timePerBeat - dt);

    timerRef.current = window.setTimeout(tick, nextDelay);
  }, [bpm, preset.accentBeat]); 
  // IMPORTANT: bpm is in dependency array. 
  // When bpm changes, `tick` is recreated. 
  // However, the *currently running* timeout references the *old* tick closure.

  // Effect to handle live BPM updates
  useEffect(() => {
    if (isPlaying) {
      // If BPM changes while playing, we don't necessarily need to restart the whole loop immediately
      // but the *next* recursive call to `tick` needs to use the new BPM.
      // Since `tick` is a dependency of this effect (via useCallback dependency),
      // this effect runs whenever BPM changes.

      // We clear the pending timeout and restart immediately to make it feel responsive
      if (timerRef.current) clearTimeout(timerRef.current);

      // Reset expected time to now to prevent a "catch up" burst of clicks
      expectedRef.current = Date.now();

      // Resume
      const timePerBeat = 60000 / bpm;
      timerRef.current = window.setTimeout(tick, timePerBeat);
    }
  }, [bpm, isPlaying, tick]);

  const togglePlay = () => {
    if (isPlaying) {
      if (timerRef.current) clearTimeout(timerRef.current);
      setIsPlaying(false);
      setBeatCount(1);
    } else {
      setIsPlaying(true);
      beatCounterRef.current = 0;
      expectedRef.current = Date.now();
      tick();
    }
  };

  useEffect(() => {
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, []);

  return (
    <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 flex flex-col h-full">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-green-400 flex items-center gap-2">
          <span>🥁</span> Metronome
        </h2>
        <div className="flex items-center gap-2">
           <Activity className={isPlaying ? "text-green-400 animate-pulse" : "text-slate-600"} />
        </div>
      </div>

      {/* Rhythm Selector */}
      <div className="mb-6">
        <label className="text-xs text-slate-400 uppercase tracking-wider font-semibold mb-2 block">Rhythm Style</label>
        <div className="grid grid-cols-2 gap-2">
          {RHYTHM_PRESETS.map((r) => (
            <button
              key={r.name}
              onClick={() => onRhythmChange(r.name)}
              className={`
                px-3 py-2 rounded-lg text-sm font-medium transition-colors
                ${selectedRhythm === r.name 
                  ? 'bg-green-600 text-white shadow-lg shadow-green-900/50' 
                  : 'bg-slate-900 text-slate-400 hover:bg-slate-700 hover:text-white'}
              `}
            >
              {r.name}
            </button>
          ))}
        </div>
        <p className="mt-3 text-sm text-slate-300 italic h-6">"{preset.countPattern}"</p>
      </div>

      {/* BPM Controls */}
      <div className="mb-8">
        <div className="flex justify-between items-end mb-4">
           <span className="text-5xl font-mono font-bold text-white tracking-tighter">{bpm} <span className="text-lg text-slate-500 font-normal tracking-normal">BPM</span></span>
           <div className="flex gap-1 text-xs bg-slate-900 p-1 rounded-lg">
             <button onClick={() => setBpm(preset.bpmRanges.beginner)} className="px-2 py-1 rounded hover:bg-slate-700 text-slate-400 hover:text-green-400 transition">Beg</button>
             <button onClick={() => setBpm(preset.bpmRanges.intermediate)} className="px-2 py-1 rounded hover:bg-slate-700 text-slate-400 hover:text-green-400 transition">Int</button>
             <button onClick={() => setBpm(preset.bpmRanges.advanced)} className="px-2 py-1 rounded hover:bg-slate-700 text-slate-400 hover:text-green-400 transition">Adv</button>
           </div>
        </div>

        <div className="relative h-12 flex items-center">
            <input 
            type="range" 
            min="40" 
            max="220" 
            value={bpm} 
            onChange={(e) => setBpm(Number(e.target.value))}
            className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-green-500 hover:accent-green-400 transition-all z-10 relative"
            />
            {/* Tick marks could go here */}
        </div>
        <div className="flex justify-between text-xs text-slate-500 font-mono px-1">
            <span>40</span>
            <span>220</span>
        </div>
      </div>

      {/* Play/Stop & Visualizer */}
      <div className="mt-auto flex flex-col gap-8">
        {/* Beat Dots */}
        <div className="flex justify-center gap-6">
          {[1, 2, 3, 4].map((beat) => (
            <div 
              key={beat}
              className={`
                w-5 h-5 rounded-full transition-all duration-75
                ${beatCount === beat && isPlaying 
                    ? 'bg-green-400 scale-150 shadow-[0_0_15px_rgba(74,222,128,0.6)]' 
                    : preset.accentBeat.includes(beat) ? 'bg-slate-600 border border-slate-500' : 'bg-slate-800 border border-slate-700'}
              `}
            />
          ))}
        </div>

        <button
          onClick={togglePlay}
          className={`
            w-full py-5 rounded-2xl flex items-center justify-center gap-3 font-bold text-xl transition-all shadow-xl
            ${isPlaying 
              ? 'bg-red-500/10 text-red-500 border border-red-500/50 hover:bg-red-500/20' 
              : 'bg-gradient-to-r from-green-600 to-green-500 text-white hover:from-green-500 hover:to-green-400 shadow-green-900/50 hover:scale-[1.02] active:scale-[0.98]'}
          `}
        >
          {isPlaying ? <><Square fill="currentColor" size={24} /> Stop</> : <><Play fill="currentColor" size={24} /> Start</>}
        </button>
      </div>
    </div>
  );
};

