export const generatePracticeTip = async (
  tuning: SeventhStringTuning,
  rhythm: RhythmStyle
): Promise<string> => {
  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    return "Por favor, configure sua chave de API para gerar dicas personalizadas.";
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    const prompt = `
      Atue como um professor de violão de 7 cordas de classe mundial.

      O aluno configurou a 7ª corda em: ${tuning}.
      Ele deseja praticar o ritmo: ${rhythm}.

      Por favor, forneça um "Exercício de Aquecimento" CURTO, específico e musical que combine essa afinação e ritmo.

      1. Mencione uma progressão de acordes específica ou padrão de escala que se beneficie dessa afinação da 7ª corda (ex: usar o Dó grave para escalas de Dó maior/menor se afinado em Dó).
      2. Dê uma instrução rítmica relevante para ${rhythm}.
      3. Mantenha em menos de 100 palavras. Seja encorajador, mas técnico.
      4. Use formatação como tópicos ou negrito para clareza.

      IMPORTANTE: Responda em Português do Brasil.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "Não foi possível gerar uma dica no momento.";
  } catch (error) {
    console.error("Error calling Gemini:", error);
    return "Desculpe, não consegui conectar ao assistente. Verifique sua conexão ou chave de API.";
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Volume2, Mic, MicOff, CheckCircle } from 'lucide-react';
import { STANDARD_STRINGS, SEVENTH_STRING_OPTIONS } from '../constants';
import { SeventhStringTuning } from '../types';
import { playTone, getAudioContext } from '../utils/audio';
import { autoCorrelate, centsOffFromPitch, noteFromPitch } from '../utils/pitchDetection';

interface TunerProps {
  currentTuning: SeventhStringTuning;
  onTuningChange: (tuning: SeventhStringTuning) => void;
}

export const Tuner: React.FC<TunerProps> = ({ currentTuning, onTuningChange }) => {
  const [mode, setMode] = useState<'manual' | 'auto'>('manual');
  const [playingIndex, setPlayingIndex] = useState<number | null>(null);

  // Auto Mode State
  const [listening, setListening] = useState(false);
  const [detectedPitch, setDetectedPitch] = useState<number | null>(null);
  const [detectedNote, setDetectedNote] = useState<string>("--");
  const [centsOff, setCentsOff] = useState<number>(0);
  const [closestStringIndex, setClosestStringIndex] = useState<number | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const rafIdRef = useRef<number | null>(null);

  const strings = [...STANDARD_STRINGS, SEVENTH_STRING_OPTIONS[currentTuning]];

  // Cleanup on unmount or mode switch
  useEffect(() => {
    return () => stopListening();
  }, [mode]);

  const startListening = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      audioContextRef.current = getAudioContext();
      if (audioContextRef.current.state === 'suspended') {
        await audioContextRef.current.resume();
      }

      analyserRef.current = audioContextRef.current.createAnalyser();
      analyserRef.current.fftSize = 2048;

      sourceRef.current = audioContextRef.current.createMediaStreamSource(stream);
      sourceRef.current.connect(analyserRef.current);

      setListening(true);
      detectPitch();
    } catch (err) {
      console.error("Error accessing microphone", err);
      alert("Acesso ao microfone negado ou não disponível.");
      setMode('manual');
    }
  };

  const stopListening = () => {
    if (rafIdRef.current) cancelAnimationFrame(rafIdRef.current);
    if (sourceRef.current) {
        // Disconnect but don't close the shared context
        sourceRef.current.disconnect(); 
    }
    setListening(false);
    setDetectedPitch(null);
    setClosestStringIndex(null);
  };

  const detectPitch = () => {
    if (!analyserRef.current || !audioContextRef.current) return;

    const buffer = new Float32Array(analyserRef.current.fftSize);
    analyserRef.current.getFloatTimeDomainData(buffer);

    const pitch = autoCorrelate(buffer, audioContextRef.current.sampleRate);

    if (pitch > -1) {
      setDetectedPitch(pitch);

      // Find closest string
      let minDiff = Infinity;
      let closestIdx = -1;

      strings.forEach((str, idx) => {
        const diff = Math.abs(pitch - str.frequency);
        if (diff < minDiff) {
          minDiff = diff;
          closestIdx = idx;
        }
      });

      if (closestIdx !== -1) {
        setClosestStringIndex(closestIdx);
        const targetString = strings[closestIdx];

        // Calculate Cents
        // We calculate cents relative to the TARGET string, not just the nearest semitone
        // This ensures the gauge works specifically for the guitar strings
        const targetNoteNum = noteFromPitch(targetString.frequency); // This is approximate for the string
        const cents = 1200 * Math.log(pitch / targetString.frequency) / Math.log(2);

        setCentsOff(Math.round(cents));
        setDetectedNote(targetString.note);
      }
    } else {
       // Hold the previous value for a split second or clear? 
       // For UI stability, we often don't clear immediately, but here we will for simplicity
    }

    rafIdRef.current = requestAnimationFrame(detectPitch);
  };

  const toggleMode = () => {
    if (mode === 'manual') {
      setMode('auto');
      startListening();
    } else {
      stopListening();
      setMode('manual');
    }
  };

  const handleManualPlay = (freq: number, index: number) => {
    if (mode === 'auto') return;
    playTone(freq);
    setPlayingIndex(index);
    setTimeout(() => setPlayingIndex(null), 2000);
  };

  // Render Meter
  const renderMeter = () => {
    if (mode === 'manual') return null;

    const isTune = Math.abs(centsOff) < 5;
    const color = isTune ? 'text-green-500' : Math.abs(centsOff) < 20 ? 'text-yellow-500' : 'text-red-500';
    const needleRotation = Math.max(-45, Math.min(45, centsOff)); // Clamp rotation

    return (
      <div className="bg-slate-900 rounded-xl p-6 mb-6 flex flex-col items-center justify-center relative overflow-hidden border border-slate-700">
        <div className="text-sm text-slate-500 mb-2 uppercase tracking-widest">Frequência Detectada</div>
        <div className={`text-5xl font-bold mb-4 ${listening && detectedPitch ? color : 'text-slate-700'}`}>
          {listening && detectedPitch && closestStringIndex !== null ? strings[closestStringIndex].note : '--'}
        </div>

        {/* Gauge */}
        <div className="relative w-64 h-32 flex justify-center overflow-hidden">
          {/* Arc */}
          <div className="absolute bottom-0 w-full h-full border-t-[20px] border-slate-700 rounded-t-full"></div>

          {/* Center Marker */}
          <div className="absolute bottom-0 w-1 h-4 bg-green-500/50 z-10"></div>

          {/* Needle */}
          <div 
            className={`absolute bottom-0 left-1/2 w-1 h-full bg-slate-200 origin-bottom transition-transform duration-100 ease-linear ${!detectedPitch ? 'opacity-20' : ''}`}
            style={{ transform: `translateX(-50%) rotate(${needleRotation}deg)` }}
          >
             <div className={`w-4 h-4 rounded-full -ml-1.5 mt-2 ${color}`}></div>
          </div>
        </div>

        <div className="flex justify-between w-full max-w-xs mt-2 text-xs font-mono text-slate-500">
          <span>Grave</span>
          <span className={isTune ? "text-green-500 font-bold" : ""}>{isTune ? "PERFEITO" : ""}</span>
          <span>Agudo</span>
        </div>
      </div>
    );
  };

  return (
    <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 h-full flex flex-col">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-yellow-500 flex items-center gap-2">
          <span>🎸</span> Afinador
        </h2>

        {/* Tuning Selector & Mode Toggle */}
        <div className="flex items-center gap-4">
            <button 
                onClick={toggleMode}
                className={`flex items-center gap-2 px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider transition-all ${mode === 'auto' ? 'bg-red-500/20 text-red-400 border border-red-500/50' : 'bg-slate-700 text-slate-400 hover:bg-slate-600'}`}
            >
                {mode === 'auto' ? <Mic size={14}/> : <MicOff size={14}/>}
                {mode === 'auto' ? 'Auto' : 'Manual'}
            </button>

            <select 
                value={currentTuning}
                onChange={(e) => onTuningChange(e.target.value as SeventhStringTuning)}
                className="bg-slate-900 text-slate-200 border border-slate-600 rounded px-3 py-1 text-sm focus:outline-none focus:border-yellow-500 max-w-[120px]"
            >
                {Object.values(SeventhStringTuning).map((t) => (
                <option key={t} value={t}>{t}</option>
                ))}
            </select>
        </div>
      </div>

      {renderMeter()}

      <div className="space-y-2 flex-1 overflow-y-auto">
        {strings.map((str, idx) => {
          const stringNumber = idx + 1;
          const isPlaying = playingIndex === idx;
          const isDetected = mode === 'auto' && closestStringIndex === idx;

          return (
            <div 
              key={idx}
              onClick={() => handleManualPlay(str.frequency, idx)}
              className={`
                group relative flex items-center justify-between p-3 rounded-xl cursor-pointer transition-all duration-200
                ${isDetected ? 'bg-green-500/20 border-green-500 scale-[1.02]' : ''}
                ${isPlaying ? 'bg-yellow-500/20 border-yellow-500/50' : 'bg-slate-900/50 border-slate-700 hover:bg-slate-700/50'}
                border
              `}
            >
              <div className="flex items-center gap-4">
                <div className={`
                  w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm
                  ${isDetected ? 'bg-green-500 text-white' : isPlaying ? 'bg-yellow-500 text-slate-900' : 'bg-slate-700 text-slate-400 group-hover:bg-slate-600'}
                `}>
                  {stringNumber}
                </div>
                <div>
                  <div className="flex items-baseline gap-2">
                    <span className={`text-xl font-bold ${isDetected ? 'text-green-400' : isPlaying ? 'text-yellow-400' : 'text-white'}`}>
                      {str.note}
                    </span>
                    <span className="text-xs text-slate-500">{str.octave}</span>
                  </div>
                </div>
              </div>

              <div className="flex items-center gap-4">
                <span className="font-mono text-slate-400 text-sm hidden sm:block">{str.frequency.toFixed(2)} Hz</span>
                {mode === 'manual' && (
                    <Volume2 size={18} className={`${isPlaying ? 'text-yellow-400 animate-pulse' : 'text-slate-600'}`} />
                )}
                {mode === 'auto' && isDetected && (
                    <CheckCircle size={18} className="text-green-500" />
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Play, Square, Activity, Music2 } from 'lucide-react';
import { RHYTHM_PRESETS } from '../constants';
import { RhythmStyle } from '../types';
import { playClick } from '../utils/audio';

interface MetronomeProps {
  selectedRhythm: RhythmStyle;
  onRhythmChange: (rhythm: RhythmStyle) => void;
}

export const Metronome: React.FC<MetronomeProps> = ({ selectedRhythm, onRhythmChange }) => {
  const [bpm, setBpm] = useState(100);
  const [isPlaying, setIsPlaying] = useState(false);
  const [beatCount, setBeatCount] = useState(1);

  const preset = RHYTHM_PRESETS.find(r => r.name === selectedRhythm) || RHYTHM_PRESETS[0];

  const timerRef = useRef<number | null>(null);
  const expectedRef = useRef<number>(0);
  const beatCounterRef = useRef<number>(0);

  // When preset changes, if stopped, update default BPM
  useEffect(() => {
    if (!isPlaying) {
      setBpm(preset.bpmRanges.intermediate);
    }
  }, [preset, isPlaying]);

  // Tick function that handles the audio and scheduling
  const tick = useCallback(() => {
    const timePerBeat = 60000 / bpm;
    // Drift correction
    const now = Date.now();
    const dt = now - expectedRef.current;

    // If drift is huge (tab inactive), hard reset schedule
    if (dt > timePerBeat) {
        expectedRef.current = now;
    }

    // Audio Logic
    const currentBeatInMeasure = (beatCounterRef.current % 4) + 1; 
    const isAccent = preset.accentBeat.includes(currentBeatInMeasure);

    playClick(isAccent);
    setBeatCount(currentBeatInMeasure);

    // Schedule next
    expectedRef.current += timePerBeat;
    beatCounterRef.current += 1;

    // Calculate next delay, compensating for drift
    const nextDelay = Math.max(0, timePerBeat - dt);

    timerRef.current = window.setTimeout(tick, nextDelay);
  }, [bpm, preset.accentBeat]); 
  // IMPORTANT: bpm is in dependency array. 
  // When bpm changes, `tick` is recreated. 
  // However, the *currently running* timeout references the *old* tick closure.

  // Effect to handle live BPM updates
  useEffect(() => {
    if (isPlaying) {
      // If BPM changes while playing, we don't necessarily need to restart the whole loop immediately
      // but the *next* recursive call to `tick` needs to use the new BPM.
      // Since `tick` is a dependency of this effect (via useCallback dependency),
      // this effect runs whenever BPM changes.

      // We clear the pending timeout and restart immediately to make it feel responsive
      if (timerRef.current) clearTimeout(timerRef.current);

      // Reset expected time to now to prevent a "catch up" burst of clicks
      expectedRef.current = Date.now();

      // Resume
      const timePerBeat = 60000 / bpm;
      timerRef.current = window.setTimeout(tick, timePerBeat);
    }
  }, [bpm, isPlaying, tick]);

  const togglePlay = () => {
    if (isPlaying) {
      if (timerRef.current) clearTimeout(timerRef.current);
      setIsPlaying(false);
      setBeatCount(1);
    } else {
      setIsPlaying(true);
      beatCounterRef.current = 0;
      expectedRef.current = Date.now();
      tick();
    }
  };

  useEffect(() => {
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, []);

  return (
    <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 flex flex-col h-full">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-green-400 flex items-center gap-2">
          <span>🥁</span> Metrônomo
        </h2>
        <div className="flex items-center gap-2">
           <Activity className={isPlaying ? "text-green-400 animate-pulse" : "text-slate-600"} />
        </div>
      </div>

      {/* Rhythm Selector */}
      <div className="mb-6">
        <label className="text-xs text-slate-400 uppercase tracking-wider font-semibold mb-2 block">Estilo Rítmico</label>
        <div className="grid grid-cols-2 gap-2">
          {RHYTHM_PRESETS.map((r) => (
            <button
              key={r.name}
              onClick={() => onRhythmChange(r.name)}
              className={`
                px-3 py-2 rounded-lg text-sm font-medium transition-colors
                ${selectedRhythm === r.name 
                  ? 'bg-green-600 text-white shadow-lg shadow-green-900/50' 
                  : 'bg-slate-900 text-slate-400 hover:bg-slate-700 hover:text-white'}
              `}
            >
              {r.name}
            </button>
          ))}
        </div>
        <p className="mt-3 text-sm text-slate-300 italic h-6">"{preset.countPattern}"</p>
      </div>

      {/* BPM Controls */}
      <div className="mb-8">
        <div className="flex justify-between items-end mb-4">
           <span className="text-5xl font-mono font-bold text-white tracking-tighter">{bpm} <span className="text-lg text-slate-500 font-normal tracking-normal">BPM</span></span>
           <div className="flex gap-1 text-xs bg-slate-900 p-1 rounded-lg">
             <button onClick={() => setBpm(preset.bpmRanges.beginner)} className="px-2 py-1 rounded hover:bg-slate-700 text-slate-400 hover:text-green-400 transition">Ini</button>
             <button onClick={() => setBpm(preset.bpmRanges.intermediate)} className="px-2 py-1 rounded hover:bg-slate-700 text-slate-400 hover:text-green-400 transition">Int</button>
             <button onClick={() => setBpm(preset.bpmRanges.advanced)} className="px-2 py-1 rounded hover:bg-slate-700 text-slate-400 hover:text-green-400 transition">Ava</button>
           </div>
        </div>

        <div className="relative h-12 flex items-center">
            <input 
            type="range" 
            min="40" 
            max="220" 
            value={bpm} 
            onChange={(e) => setBpm(Number(e.target.value))}
            className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-green-500 hover:accent-green-400 transition-all z-10 relative"
            />
            {/* Tick marks could go here */}
        </div>
        <div className="flex justify-between text-xs text-slate-500 font-mono px-1">
            <span>40</span>
            <span>220</span>
        </div>
      </div>

      {/* Play/Stop & Visualizer */}
      <div className="mt-auto flex flex-col gap-8">
        {/* Beat Dots */}
        <div className="flex justify-center gap-6">
          {[1, 2, 3, 4].map((beat) => (
            <div 
              key={beat}
              className={`
                w-5 h-5 rounded-full transition-all duration-75
                ${beatCount === beat && isPlaying 
                    ? 'bg-green-400 scale-150 shadow-[0_0_15px_rgba(74,222,128,0.6)]' 
                    : preset.accentBeat.includes(beat) ? 'bg-slate-600 border border-slate-500' : 'bg-slate-800 border border-slate-700'}
              `}
            />
          ))}
        </div>

        <button
          onClick={togglePlay}
          className={`
            w-full py-5 rounded-2xl flex items-center justify-center gap-3 font-bold text-xl transition-all shadow-xl
            ${isPlaying 
              ? 'bg-red-500/10 text-red-500 border border-red-500/50 hover:bg-red-500/20' 
              : 'bg-gradient-to-r from-green-600 to-green-500 text-white hover:from-green-500 hover:to-green-400 shadow-green-900/50 hover:scale-[1.02] active:scale-[0.98]'}
          `}
        >
          {isPlaying ? <><Square fill="currentColor" size={24} /> Parar</> : <><Play fill="currentColor" size={24} /> Iniciar</>}
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
