      {/* Mobile Bottom Navigation */}
      <div className="md:hidden fixed bottom-0 left-0 w-full bg-slate-900 border-t border-slate-800 z-50">
          <div className="grid grid-cols-3 h-16">
            <button 
                onClick={() => setActiveTab('tuner')}
                className={`flex flex-col items-center justify-center gap-1 ${activeTab === 'tuner' ? 'text-yellow-500' : 'text-slate-500'}`}
            >
                <Mic2 size={24} />
                <span className="text-[10px] font-bold uppercase">Afinador</span>
            </button>
            <button 
                onClick={() => setActiveTab('metronome')}
                className={`flex flex-col items-center justify-center gap-1 ${activeTab === 'metronome' ? 'text-green-500' : 'text-slate-500'}`}
            >
                <Disc size={24} />
                <span className="text-[10px] font-bold uppercase">Metrônomo</span>
            </button>
            <button 
                onClick={() => setActiveTab('coach')}
                className={`flex flex-col items-center justify-center gap-1 ${activeTab === 'coach' ? 'text-indigo-400' : 'text-slate-500'}`}
            >
                <Sparkles size={24} />
                <span className="text-[10px] font-bold uppercase">Treinador</span>
            </button>
          </div>
      </div>

    </div>
  );
};

export default App;

