                    <Volume2 size={18} className={`${isPlaying ? 'text-yellow-400 animate-pulse' : 'text-slate-600'}`} />
                )}
                {mode === 'auto' && isDetected && (
                    <CheckCircle size={18} className={`transition-colors duration-200 ${isLocked ? 'text-green-400 fill-green-400/20' : 'text-green-500'}`} />
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export interface PitchResult {
  pitch: number;
  clarity: number; // 0 to 1 confidence score
}

export const autoCorrelate = (buffer: Float32Array, sampleRate: number): PitchResult => {
  const size = buffer.length;
  let rms = 0;

  for (let i = 0; i < size; i++) {
    const val = buffer[i];
    rms += val * val;
  }
  rms = Math.sqrt(rms / size);

  // 1. Noise Gate: Increased threshold to ignore background hum/wind
  if (rms < 0.02) return { pitch: -1, clarity: 0 };

  // 2. Normalized Autocorrelation (find periodicity)
  // We only search for lags corresponding to our frequency range (approx 50Hz to 400Hz)
  // 50Hz at 44100/48000 sample rate = approx 960 samples max lag
  const maxLag = Math.floor(sampleRate / 45); 
  const minLag = Math.floor(sampleRate / 450);

  let bestLag = -1;
  let maxCorrelation = 0;

  // We optimize by calculating correlation only within the relevant lag range
  for (let lag = minLag; lag < maxLag; lag++) {
    let sum = 0;
    // Normalize to get clarity (0.0 - 1.0)
    // Using a simplified normalization approach (Pearson-like)
    // Correlation = sum(x[i] * x[i+lag])

    // We limit the summation window to avoid running off the buffer
    const n = size - lag;

    for (let i = 0; i < n; i++) {
      sum += buffer[i] * buffer[i + lag];
    }

    // Normalization factor (Energy at lag 0 vs Energy at lag t)
    // Simplified approximation for speed
    const clarity = sum / n; 

    // Find the first major peak that is a peak (greater than neighbors)
    if (clarity > maxCorrelation) {
      maxCorrelation = clarity;
      bestLag = lag;
    }
  }

  // Refined Normalization: Calculate true correlation coefficient for the best lag
  // This is crucial to distinguish a guitar string (pure tone) from voice/noise.
  let sumProduct = 0;
  let sumSq1 = 0;
  let sumSq2 = 0;
  const n = size - bestLag;

  for (let i = 0; i < n; i++) {
    const s1 = buffer[i];
    const s2 = buffer[i + bestLag];
    sumProduct += s1 * s2;
    sumSq1 += s1 * s1;
    sumSq2 += s2 * s2;
  }

  // Normalized Cross-Correlation Coefficient (-1 to 1)
  const clarity = sumProduct / (Math.sqrt(sumSq1 * sumSq2) + 0.0000001);

  // If clarity is low, it's noise/wind/voice. Guitar strings are usually > 0.95
  if (clarity < 0.9) { 
      return { pitch: -1, clarity: clarity };
  }

  // 3. Parabolic Interpolation for precision
  // Only if we have a valid peak
  let pitch = sampleRate / bestLag;

  // We don't have the neighbor values from the optimized loop above easily accessible 
  // without re-running, but for this level of precision, the lag index is often "good enough" 
  // combined with the tuner's stability buffer. 
  // However, let's do a tiny local search to interpolate.

  // (Simplified interpolation not strictly necessary if buffer is stable, 
  // but let's keep it simple: return raw pitch from lag)

  return { pitch, clarity };
};

export const noteFromPitch = (frequency: number) => {
  const noteNum = 12 * (Math.log(frequency / 440) / Math.log(2));
  return Math.round(noteNum) + 69;
};

export const frequencyFromNoteNumber = (note: number) => {
  return 440 * Math.pow(2, (note - 69) / 12);
};

export const centsOffFromPitch = (frequency: number, note: number) => {
  return Math.floor(1200 * Math.log(frequency / frequencyFromNoteNumber(note)) / Math.log(2));
};

import React, { useState, useEffect, useRef } from 'react';
import { Volume2, Mic, MicOff, CheckCircle, Wind } from 'lucide-react';
import { STANDARD_STRINGS, SEVENTH_STRING_OPTIONS } from '../constants';
import { SeventhStringTuning } from '../types';
import { playTone, playSuccessSound, getAudioContext } from '../utils/audio';
import { autoCorrelate } from '../utils/pitchDetection';

interface TunerProps {
  currentTuning: SeventhStringTuning;
  onTuningChange: (tuning: SeventhStringTuning) => void;
}

export const Tuner: React.FC<TunerProps> = ({ currentTuning, onTuningChange }) => {
  const [mode, setMode] = useState<'manual' | 'auto'>('manual');
  const [playingIndex, setPlayingIndex] = useState<number | null>(null);

  // Auto Mode State
  const [listening, setListening] = useState(false);
  const [detectedPitch, setDetectedPitch] = useState<number | null>(null);
  const [centsOff, setCentsOff] = useState<number>(0);
  const [closestStringIndex, setClosestStringIndex] = useState<number | null>(null);
  const [isLocked, setIsLocked] = useState(false);
  const [signalQuality, setSignalQuality] = useState<number>(0); // Visual feedback for noise

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const rafIdRef = useRef<number | null>(null);

  // References for filtering logic
  const pitchBufferRef = useRef<number[]>([]); // Stores last N valid pitches
  const inTuneStartTimeRef = useRef<number | null>(null);
  const hasPlayedSuccessRef = useRef<boolean>(false);

  const strings = [...STANDARD_STRINGS, SEVENTH_STRING_OPTIONS[currentTuning]];

  // Cleanup on unmount or mode switch
  useEffect(() => {
    return () => stopListening();
  }, [mode]);

  const startListening = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        audio: {
            echoCancellation: false, // Important for music
            autoGainControl: false,  // Important for dynamics
            noiseSuppression: false  // We do our own filtering
        } 
      });

      audioContextRef.current = getAudioContext();
      if (audioContextRef.current.state === 'suspended') {
        await audioContextRef.current.resume();
      }

      analyserRef.current = audioContextRef.current.createAnalyser();
      analyserRef.current.fftSize = 2048; // Optimized for balance between bass accuracy and speed
      analyserRef.current.smoothingTimeConstant = 0.8;

      sourceRef.current = audioContextRef.current.createMediaStreamSource(stream);
      sourceRef.current.connect(analyserRef.current);

      setListening(true);
      detectPitch();
    } catch (err) {
      console.error("Error accessing microphone", err);
      alert("Acesso ao microfone negado ou não disponível. Verifique as permissões.");
      setMode('manual');
    }
  };

  const stopListening = () => {
    if (rafIdRef.current) cancelAnimationFrame(rafIdRef.current);
    if (sourceRef.current) {
        sourceRef.current.disconnect(); 
    }
    setListening(false);
    setDetectedPitch(null);
    setClosestStringIndex(null);
    setIsLocked(false);
    setSignalQuality(0);
    hasPlayedSuccessRef.current = false;
    inTuneStartTimeRef.current = null;
    pitchBufferRef.current = [];
  };

  const detectPitch = () => {
    if (!analyserRef.current || !audioContextRef.current) return;

    const buffer = new Float32Array(analyserRef.current.fftSize);
    analyserRef.current.getFloatTimeDomainData(buffer);

    // Get Pitch AND Clarity
    const result = autoCorrelate(buffer, audioContextRef.current.sampleRate);
    const { pitch: rawPitch, clarity } = result;

    setSignalQuality(clarity); // Update visual debugger

    // STRICT FILTERING LOGIC
    // 1. Clarity Check: Guitar strings are very periodic (>0.93). Voice/Wind are lower.
    // 2. Range Check: 50Hz to 450Hz
    let validPitch = null;

    if (rawPitch !== -1 && rawPitch > 50 && rawPitch < 450 && clarity > 0.93) {

        // 3. Stability Buffer (Debounce)
        // We push to a buffer. We only accept the pitch if the buffer 
        // has enough samples and they are all roughly the same.
        const buffer = pitchBufferRef.current;
        buffer.push(rawPitch);
        if (buffer.length > 5) buffer.shift(); // Keep last 5 frames

        // Check variance in buffer
        if (buffer.length === 5) {
            const sorted = [...buffer].sort((a, b) => a - b);
            const range = sorted[sorted.length - 1] - sorted[0];

            // If the pitch varies by less than 1.5Hz over 5 frames, it's a stable tone (not voice modulation)
            if (range < 1.5) {
                // Use the average for smoothness
                const avgPitch = buffer.reduce((a, b) => a + b) / buffer.length;

                // Double check it matches a known guitar string to avoid harmonic errors
                const isGuitarSound = strings.some(str => {
                    const ratio = avgPitch / str.frequency;
                    return ratio > 0.90 && ratio < 1.12; // Broad window to catch the string
                });

                if (isGuitarSound) {
                    validPitch = avgPitch;
                }
            }
        }
    } else {
        // If signal drops (silence or noise), reduce buffer slowly or clear if clarity is terrible
        if (clarity < 0.5) pitchBufferRef.current = [];
    }

    if (validPitch) {
      setDetectedPitch(validPitch);

      // Find closest string
      let minDiff = Infinity;
      let closestIdx = -1;

      strings.forEach((str, idx) => {
        const diff = Math.abs(validPitch! - str.frequency);
        if (diff < minDiff) {
          minDiff = diff;
          closestIdx = idx;
        }
      });

      if (closestIdx !== -1) {
        setClosestStringIndex(closestIdx);
        const targetString = strings[closestIdx];

        // Calculate Cents
        const cents = 1200 * Math.log(validPitch / targetString.frequency) / Math.log(2);
        const roundedCents = Math.round(cents);
        setCentsOff(roundedCents);

        // SUCCESS SOUND LOGIC
        // Strict threshold: +/- 3 cents for "perfect"
        if (Math.abs(roundedCents) <= 3) {
            if (inTuneStartTimeRef.current === null) {
                inTuneStartTimeRef.current = Date.now();
            } else {
                const duration = Date.now() - inTuneStartTimeRef.current;
                // Require 400ms of PERFECT stability to confirm
                if (duration > 400 && !hasPlayedSuccessRef.current) {
                    playSuccessSound(targetString.frequency);
                    hasPlayedSuccessRef.current = true;
                    setIsLocked(true);
                }
            }
        } else {
            // Reset if we drift out
            inTuneStartTimeRef.current = null;
            hasPlayedSuccessRef.current = false;
            setIsLocked(false);
        }
      }
    } else {
        // Only clear the display if we haven't had a valid pitch for a while
        // This prevents flickering when the string oscillates
        // If buffer is empty, clear it
        if (pitchBufferRef.current.length === 0) {
             setClosestStringIndex(null);
             setDetectedPitch(null);
             setIsLocked(false);
             inTuneStartTimeRef.current = null;
             hasPlayedSuccessRef.current = false;
        }
    }

    rafIdRef.current = requestAnimationFrame(detectPitch);
  };

  const toggleMode = () => {
    if (mode === 'manual') {
      setMode('auto');
      startListening();
    } else {
      stopListening();
      setMode('manual');
    }
  };

  const handleManualPlay = (freq: number, index: number) => {
    if (mode === 'auto') return;
    playTone(freq);
    setPlayingIndex(index);
    setTimeout(() => setPlayingIndex(null), 2000);
  };

  // Render Meter
  const renderMeter = () => {
    if (mode === 'manual') return null;

    const isTune = Math.abs(centsOff) < 5;
    const color = isLocked ? 'text-green-400 drop-shadow-[0_0_10px_rgba(74,222,128,0.5)]' : isTune ? 'text-green-500' : Math.abs(centsOff) < 20 ? 'text-yellow-500' : 'text-red-500';

    // Clamp rotation
    const needleRotation = Math.max(-45, Math.min(45, centsOff)); 

    return (
      <div className={`
        bg-slate-900 rounded-xl p-6 mb-6 flex flex-col items-center justify-center relative overflow-hidden border transition-colors duration-300
        ${isLocked ? 'border-green-500 shadow-[0_0_20px_rgba(74,222,128,0.2)]' : 'border-slate-700'}
      `}>
        {/* Noise Indicator (Debug/UX) */}
        {listening && signalQuality > 0.1 && signalQuality < 0.9 && !detectedPitch && (
            <div className="absolute top-2 right-2 flex items-center gap-1 text-slate-500 text-xs animate-pulse">
                <Wind size={12} />
                <span>Ruído detectado</span>
            </div>
        )}

        <div className="text-sm text-slate-500 mb-2 uppercase tracking-widest">Frequência Detectada</div>
        <div className={`text-5xl font-bold mb-4 transition-all duration-200 ${listening && detectedPitch ? color : 'text-slate-700'}`}>
          {listening && detectedPitch && closestStringIndex !== null ? strings[closestStringIndex].note : '--'}
        </div>

        {/* Gauge */}
        <div className="relative w-64 h-32 flex justify-center overflow-hidden">
          {/* Arc */}
          <div className="absolute bottom-0 w-full h-full border-t-[20px] border-slate-700 rounded-t-full"></div>

          {/* Center Marker */}
          <div className={`absolute bottom-0 w-1 h-4 z-10 ${isLocked ? 'bg-green-400 box-shadow-glow' : 'bg-green-500/50'}`}></div>

          {/* Needle */}
          <div 
            className={`absolute bottom-0 left-1/2 w-1 h-full bg-slate-200 origin-bottom transition-transform duration-100 ease-linear ${!detectedPitch ? 'opacity-20' : ''}`}
            style={{ transform: `translateX(-50%) rotate(${needleRotation}deg)` }}
          >
             <div className={`w-4 h-4 rounded-full -ml-1.5 mt-2 ${color} transition-colors duration-200`}></div>
          </div>
        </div>

        <div className="flex justify-between w-full max-w-xs mt-2 text-xs font-mono text-slate-500">
          <span>Grave</span>
          <span className={`font-bold transition-all duration-300 ${isLocked ? "text-green-400 scale-125" : isTune ? "text-green-500" : "opacity-0"}`}>
            {isLocked ? "AFINADO!" : "PERFEITO"}
          </span>
          <span>Agudo</span>
        </div>
      </div>
    );
  };

  return (
    <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 h-full flex flex-col">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-yellow-500 flex items-center gap-2">
          <span>🎸</span> Afinador
        </h2>

        {/* Tuning Selector & Mode Toggle */}
        <div className="flex items-center gap-4">
            <button 
                onClick={toggleMode}
                className={`flex items-center gap-2 px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider transition-all ${mode === 'auto' ? 'bg-red-500/20 text-red-400 border border-red-500/50' : 'bg-slate-700 text-slate-400 hover:bg-slate-600'}`}
            >
                {mode === 'auto' ? <Mic size={14}/> : <MicOff size={14}/>}
                {mode === 'auto' ? 'Auto' : 'Manual'}
            </button>

            <select 
                value={currentTuning}
                onChange={(e) => onTuningChange(e.target.value as SeventhStringTuning)}
                className="bg-slate-900 text-slate-200 border border-slate-600 rounded px-3 py-1 text-sm focus:outline-none focus:border-yellow-500 max-w-[120px]"
            >
                {Object.values(SeventhStringTuning).map((t) => (
                <option key={t} value={t}>{t}</option>
                ))}
            </select>
        </div>
      </div>

      {renderMeter()}

      <div className="space-y-2 flex-1 overflow-y-auto">
        {strings.map((str, idx) => {
          const stringNumber = idx + 1;
          const isPlaying = playingIndex === idx;
          const isDetected = mode === 'auto' && closestStringIndex === idx;

          return (
            <div 
              key={idx}
              onClick={() => handleManualPlay(str.frequency, idx)}
              className={`
                group relative flex items-center justify-between p-3 rounded-xl cursor-pointer transition-all duration-200
                ${isDetected ? (isLocked ? 'bg-green-500/30 border-green-400' : 'bg-green-500/20 border-green-500') : ''}
                ${isDetected ? 'scale-[1.02]' : ''}
                ${isPlaying ? 'bg-yellow-500/20 border-yellow-500/50' : !isDetected ? 'bg-slate-900/50 border-slate-700 hover:bg-slate-700/50' : 'border-slate-700'}
                border
              `}
            >
              <div className="flex items-center gap-4">
                <div className={`
                  w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm transition-colors duration-200
                  ${isDetected ? (isLocked ? 'bg-green-400 text-slate-900' : 'bg-green-500 text-white') : isPlaying ? 'bg-yellow-500 text-slate-900' : 'bg-slate-700 text-slate-400 group-hover:bg-slate-600'}
                `}>
                  {stringNumber}
                </div>
                <div>
                  <div className="flex items-baseline gap-2">
                    <span className={`text-xl font-bold transition-colors duration-200 ${isDetected ? (isLocked ? 'text-green-300' : 'text-green-400') : isPlaying ? 'text-yellow-400' : 'text-white'}`}>
                      {str.note}
                    </span>
                    <span className="text-xs text-slate-500">{str.octave}</span>
                  </div>
                </div>
              </div>

              <div className="flex items-center gap-4">
                <span className="font-mono text-slate-400 text-sm hidden sm:block">{str.frequency.toFixed(2)} Hz</span>
                {mode === 'manual' && (
                    <Volume2 size={18} className={`${isPlaying ? 'text-yellow-400 animate-pulse' : 'text-slate-600'}`} />
                )}
                {mode === 'auto' && isDetected && (
                    <CheckCircle size={18} className={`transition-colors duration-200 ${isLocked ? 'text-green-400 fill-green-400/20' : 'text-green-500'}`} />
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

