  text: string;
}

export type TimeSignature = '2/4' | '3/4' | '4/4' | '6/8';
export type Subdivision = '1' | '2' | '3' | '4'; // Quarter, 8th, Triplet, 16th

export interface MetronomeState {
  bpm: number;
  isPlaying: boolean;
  timeSignature: TimeSignature;
  subdivision: Subdivision;
  volume: number;
  isGrooveMode: boolean; // 2 & 4 only
  isGhostMode: boolean; // Random drops
}

// Simple audio context singleton to avoid recreating it
let audioCtx: AudioContext | null = null;
let masterGain: GainNode | null = null;

export const getAudioContext = (): AudioContext => {
  if (!audioCtx) {
    audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    masterGain = audioCtx.createGain();
    masterGain.connect(audioCtx.destination);
    masterGain.gain.value = 0.8; // Default volume
  }
  return audioCtx;
};

export const setMasterVolume = (val: number) => {
  if (masterGain) {
    // Smooth transition to avoid clicks
    masterGain.gain.setTargetAtTime(val, getAudioContext().currentTime, 0.02);
  }
};

export const playTone = (frequency: number, type: OscillatorType = 'triangle', duration = 2.0) => {
  const ctx = getAudioContext();
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  osc.type = type;
  osc.frequency.setValueAtTime(frequency, ctx.currentTime);

  // Envelope
  gain.gain.setValueAtTime(0, ctx.currentTime);
  gain.gain.linearRampToValueAtTime(0.3, ctx.currentTime + 0.05); // Attack
  gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + duration); // Decay

  osc.connect(gain);
  // Bypass master gain for tuner tones if desired, or connect to masterGain logic
  gain.connect(ctx.destination); 

  osc.start();
  osc.stop(ctx.currentTime + duration);
};

// Precise scheduled click for Metronome
export const scheduleClick = (time: number, type: 'accent' | 'sub' | 'normal') => {
  const ctx = getAudioContext();
  if (!masterGain) getAudioContext(); // Ensure init

  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  // GUITAR OPTIMIZED FREQUENCIES
  // Guitar fundamentals: ~82Hz to ~1000Hz.
  // We choose frequencies that cut through without masking the guitar tone.
  // Accent: 2000Hz (High presence, distinct)
  // Normal: 1200Hz (Mid-high, distinct but softer)
  // Sub: 800Hz (Woodblock-ish feel for subdivisions)

  let freq = 1200;
  let vol = 1.0;

  if (type === 'accent') {
    freq = 2000;
    vol = 1.0;
  } else if (type === 'sub') {
    freq = 800;
    vol = 0.4; // Softer subdivisions
  } else {
    freq = 1200;
    vol = 0.7;
  }

  osc.type = 'triangle'; // Cleaner than square, sharper than sine
  osc.frequency.setValueAtTime(freq, time);

  // ADSR ENVELOPE - OPTIMIZED FOR TRANSIENT
  // Short attack (1ms) to define the start time precisely
  // Short decay (50ms) to leave space for the music
  gain.gain.setValueAtTime(0, time);
  gain.gain.linearRampToValueAtTime(vol, time + 0.001); 
  gain.gain.exponentialRampToValueAtTime(0.001, time + 0.05);

  osc.connect(gain);
  if (masterGain) {
      gain.connect(masterGain);
  } else {
      gain.connect(ctx.destination);
  }

  osc.start(time);
  osc.stop(time + 0.06);
};

export const playClick = (accent: boolean) => {
    // Legacy support for simple play
    scheduleClick(getAudioContext().currentTime, accent ? 'accent' : 'normal');
};

export const playSuccessSound = (frequency: number) => {
  const ctx = getAudioContext();
  if (ctx.state === 'suspended') {
    ctx.resume();
  }

  const t = ctx.currentTime;

  // "Nylon Guitar" Synthesis
  const oscBright = ctx.createOscillator();
  oscBright.type = 'sawtooth';
  oscBright.frequency.setValueAtTime(frequency, t);

  const filter = ctx.createBiquadFilter();
  filter.type = 'lowpass';
  filter.Q.value = 0; 
  filter.frequency.setValueAtTime(frequency * 4, t); 
  filter.frequency.setTargetAtTime(frequency, t + 0.05, 0.1); 

  const gainBright = ctx.createGain();
  gainBright.gain.setValueAtTime(0, t);
  gainBright.gain.linearRampToValueAtTime(0.3, t + 0.02); 
  gainBright.gain.setTargetAtTime(0, t + 0.05, 0.3); 

  oscBright.connect(filter);
  filter.connect(gainBright);
  gainBright.connect(ctx.destination);

  const oscBody = ctx.createOscillator();
  oscBody.type = 'triangle';
  oscBody.frequency.setValueAtTime(frequency, t);

  const gainBody = ctx.createGain();
  gainBody.gain.setValueAtTime(0, t);
  gainBody.gain.linearRampToValueAtTime(0.4, t + 0.02);
  gainBody.gain.setTargetAtTime(0, t + 0.05, 0.8); 

  oscBody.connect(gainBody);
  gainBody.connect(ctx.destination);

  oscBright.start(t);
  oscBright.stop(t + 3.0);

  oscBody.start(t);
  oscBody.stop(t + 3.0);
};

export const preloadGuitarSounds = (notes: {note: string, octave: number}[]) => {
  // No-op for synthesis
};

export const playGuitarSample = (frequency: number) => {
  playSuccessSound(frequency);
};

import React, { useState, useEffect, useRef } from 'react';
import { Play, Square, Volume2, Settings2, Zap, Ghost } from 'lucide-react';
import { RHYTHM_PRESETS } from '../constants';
import { RhythmStyle, TimeSignature, Subdivision } from '../types';
import { scheduleClick, getAudioContext, setMasterVolume } from '../utils/audio';

interface MetronomeProps {
  selectedRhythm: RhythmStyle;
  onRhythmChange: (rhythm: RhythmStyle) => void;
}

export const Metronome: React.FC<MetronomeProps> = ({ selectedRhythm, onRhythmChange }) => {
  // --- State ---
  const [bpm, setBpm] = useState(100);
  const [isPlaying, setIsPlaying] = useState(false);
  const [volume, setVolume] = useState(0.8);
  const [timeSig, setTimeSig] = useState<TimeSignature>('4/4');
  const [subdivision, setSubdivision] = useState<Subdivision>('1');

  // Modes
  const [isGrooveMode, setIsGrooveMode] = useState(false); // Beats 2 & 4 only
  const [isGhostMode, setIsGhostMode] = useState(false); // Randomly drops bars

  // Visuals
  const [currentBeat, setCurrentBeat] = useState(1);
  const [flash, setFlash] = useState(false);

  // --- Scheduler Refs (Audio Engine) ---
  const nextNoteTimeRef = useRef<number>(0);
  const timerIDRef = useRef<number | null>(null);
  const beatCounterRef = useRef<number>(0); // Global counter
  const ghostBarRef = useRef<boolean>(false); // Is current bar muted?

  // Sync state with Rhythm Preset changes
  useEffect(() => {
    const preset = RHYTHM_PRESETS.find(r => r.name === selectedRhythm);
    if (preset && !isPlaying) {
      setBpm(preset.bpmRanges.intermediate);
      // Auto-set time sig based on rhythm feel? Keeping it manual for pro control is better usually,
      // but let's hint it.
      if (selectedRhythm === RhythmStyle.CHORO || selectedRhythm === RhythmStyle.SAMBA) setTimeSig('2/4');
      else setTimeSig('4/4');
    }
  }, [selectedRhythm, isPlaying]);

  // Volume Effect
  useEffect(() => {
    setMasterVolume(volume);
  }, [volume]);

  // --- Scheduler Logic ---
  const LOOKAHEAD = 25.0; // How frequently to call scheduling function (in milliseconds)
  const SCHEDULE_AHEAD_TIME = 0.1; // How far ahead to schedule audio (in seconds)

  const nextNote = () => {
    const secondsPerBeat = 60.0 / bpm;
    // Calculate 16th note duration for subdivisions
    const sixteenthTime = secondsPerBeat / 4;

    // Advance time
    if (subdivision === '1') nextNoteTimeRef.current += secondsPerBeat;
    else if (subdivision === '2') nextNoteTimeRef.current += secondsPerBeat / 2;
    else if (subdivision === '3') nextNoteTimeRef.current += secondsPerBeat / 3;
    else if (subdivision === '4') nextNoteTimeRef.current += secondsPerBeat / 4;

    beatCounterRef.current++;
  };

  const scheduleNotes = (beatNumber: number, time: number) => {
    // Determine Time Signature Math
    let beatsPerBar = 4;
    if (timeSig === '2/4') beatsPerBar = 2;
    if (timeSig === '3/4') beatsPerBar = 3;
    if (timeSig === '6/8') beatsPerBar = 6;

    // Subdivisions per beat logic
    let subDivs = 1;
    if (subdivision === '2') subDivs = 2;
    if (subdivision === '3') subDivs = 3;
    if (subdivision === '4') subDivs = 4;

    const totalSubBeatsPerBar = beatsPerBar * subDivs;
    const currentSubBeatInBar = beatNumber % totalSubBeatsPerBar;

    // Convert to musical beat (1-based)
    const currentMainBeat = Math.floor(currentSubBeatInBar / subDivs) + 1;
    const isDownbeat = currentSubBeatInBar === 0; // The '1' of the bar
    const isMainBeatStart = currentSubBeatInBar % subDivs === 0;

    // --- GHOST MODE LOGIC ---
    // If it's the start of a bar, decide if we mute this bar
    if (isDownbeat) {
        if (isGhostMode) {
            // 25% chance to mute bar
            ghostBarRef.current = Math.random() < 0.25;
        } else {
            ghostBarRef.current = false;
        }
    }

    // --- SOUND LOGIC ---
    // Don't play if Ghost bar
    if (!ghostBarRef.current) {
        let playType: 'accent' | 'normal' | 'sub' | 'mute' = 'sub';

        if (isMainBeatStart) {
            // It is a main beat (1, 2, 3...)
            if (isDownbeat) {
                playType = 'accent'; // The '1'
            } else {
                playType = 'normal';
            }

            // --- GROOVE MODE LOGIC ---
            // "2 & 4" feel usually means accenting 2 and 4, and playing soft or muting 1 and 3.
            // For this implementation: We only play clicks on 2 and 4.
            if (isGrooveMode && beatsPerBar === 4) {
                if (currentMainBeat === 1 || currentMainBeat === 3) {
                    playType = 'mute';
                } else {
                    playType = 'accent'; // Make 2 and 4 pop
                }
            } else if (isGrooveMode && beatsPerBar === 2) {
                 // Samba feel: Accent 2
                 if (currentMainBeat === 1) playType = 'mute';
                 else playType = 'accent';
            }
        }

        // Send to Audio Engine
        if (playType !== 'mute') {
            scheduleClick(time, playType);
        }
    }

    // --- VISUAL SCHEDULING ---
    // We draw the UI update slightly later or essentially now
    // Since React state updates are async, we use a timeout to sync visual with audio roughly
    const visualDelay = (time - getAudioContext().currentTime) * 1000;
    setTimeout(() => {
        if (isMainBeatStart) {
            setCurrentBeat(currentMainBeat);
            setFlash(true);
            setTimeout(() => setFlash(false), 100);
        }
    }, Math.max(0, visualDelay));
  };

  const scheduler = () => {
    // while there are notes that will need to play before the next interval, 
    // schedule them and advance the pointer.
    while (nextNoteTimeRef.current < getAudioContext().currentTime + SCHEDULE_AHEAD_TIME) {
      scheduleNotes(beatCounterRef.current, nextNoteTimeRef.current);
      nextNote();
    }
    timerIDRef.current = window.setTimeout(scheduler, LOOKAHEAD);
  };

  const togglePlay = () => {
    if (isPlaying) {
      if (timerIDRef.current) clearTimeout(timerIDRef.current);
      setIsPlaying(false);
      setCurrentBeat(1);
    } else {
      const ctx = getAudioContext();
      if (ctx.state === 'suspended') ctx.resume();

      beatCounterRef.current = 0;
      nextNoteTimeRef.current = ctx.currentTime + 0.05; // Start very slightly in future
      ghostBarRef.current = false;

      setIsPlaying(true);
      scheduler();
    }
  };

  // Cleanup
  useEffect(() => {
    return () => {
      if (timerIDRef.current) clearTimeout(timerIDRef.current);
    };
  }, []);

  // --- Render Helpers ---
  const quickBpms = [50, 70, 90, 110, 130];

  // Render Beaters
  const renderVisualizer = () => {
      let beats = 4;
      if (timeSig === '2/4') beats = 2;
      if (timeSig === '3/4') beats = 3;
      if (timeSig === '6/8') beats = 2; // Usually felt in 2 dotted quarters

      return (
        <div className="flex justify-center gap-4 mb-8 h-8 items-center">
            {Array.from({ length: beats }).map((_, i) => {
                const beatNum = i + 1;
                const isActive = currentBeat === beatNum && isPlaying;
                const isAccent = beatNum === 1;

                return (
                    <div 
                        key={i}
                        className={`
                            rounded-full transition-all duration-75
                            ${isActive 
                                ? (isAccent ? 'w-6 h-6 bg-red-500 shadow-[0_0_15px_rgba(239,68,68,0.8)]' : 'w-5 h-5 bg-green-400 shadow-[0_0_10px_rgba(74,222,128,0.6)]') 
                                : 'w-3 h-3 bg-slate-700'}
                        `}
                    />
                )
            })}
        </div>
      );
  };

  return (
