import React, { useState } from 'react';
import { SeventhStringTuning, NoteName } from '../types';
import { playTone, frequencyFromNoteNumber, noteFromPitch } from '../utils/pitchDetection'; // Reusing utils roughly
import { playSuccessSound } from '../utils/audio';

interface FretboardProps {
  tuning: SeventhStringTuning;
}

const NOTES: NoteName[] = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'];

const getNoteAtFret = (openNote: NoteName, fret: number): NoteName => {
  const openIndex = NOTES.indexOf(openNote);
  return NOTES[(openIndex + fret) % 12];
};

// Helper to get frequency roughly (simplified for visualization clicks)
const getFrequency = (stringIndex: number, fret: number, tuning: SeventhStringTuning): number => {
    // Base frequencies for open strings (High E to Low 7th)
    // E4, B3, G3, D3, A2, E2... 7th varies
    const standardOpen = [329.63, 246.94, 196.00, 146.83, 110.00, 82.41];
    let seventhFreq = 61.74; // B1
    if (tuning.includes('C')) seventhFreq = 65.41; // C2
    if (tuning.includes('A')) seventhFreq = 55.00; // A1

    const baseFreq = stringIndex === 6 ? seventhFreq : standardOpen[stringIndex];
    return baseFreq * Math.pow(2, fret / 12);
};

export const Fretboard: React.FC<FretboardProps> = ({ tuning }) => {
  const [highlightKey, setHighlightKey] = useState<NoteName | null>('C');
  const [showIntervals, setShowIntervals] = useState(false);

  // Define string open notes based on tuning
  // Index 0 = High E, Index 6 = Low 7th
  const stringNotes: NoteName[] = ['E', 'B', 'G', 'D', 'A', 'E', tuning.includes('C') ? 'C' : tuning.includes('A') ? 'A' : 'B'];

  // Scale Logic (Major Scale default)
  const getInterval = (root: NoteName, note: NoteName): string | null => {
      if (!root) return null;
      const rootIdx = NOTES.indexOf(root);
      const noteIdx = NOTES.indexOf(note);
      let semi = (noteIdx - rootIdx + 12) % 12;

      const intervals = {
          0: 'R', 2: '2M', 4: '3M', 5: '4J', 7: '5J', 9: '6M', 11: '7M'
      };
      return (intervals as any)[semi] || null;
  };

  const handleNoteClick = (strIndex: number, fret: number) => {
      const freq = getFrequency(strIndex, fret, tuning);
      playSuccessSound(freq); // Use the nice guitar-ish synth
  };

  const renderFret = (strIndex: number, fret: number) => {
    const openNote = stringNotes[strIndex];
    const note = getNoteAtFret(openNote, fret);
    const interval = highlightKey ? getInterval(highlightKey, note) : null;
    const isRoot = interval === 'R';
    const isVisible = !!interval;

    return (
      <div 
        key={fret} 
        className="flex-1 relative flex items-center justify-center border-r border-slate-600 h-full"
        onClick={() => handleNoteClick(strIndex, fret)}
      >
        {/* String Line */}
        <div className={`absolute w-full h-[1px] ${strIndex > 4 ? 'bg-yellow-600/50 h-[2px]' : 'bg-slate-400/50'} z-0`}></div>

        {/* Fret Marker Dots */}
        {(fret === 3 || fret === 5 || fret === 7 || fret === 9 || fret === 15 || fret === 17) && strIndex === 3 && (
            <div className="absolute w-3 h-3 rounded-full bg-slate-700/50 z-0"></div>
        )}
        {(fret === 12) && (strIndex === 2 || strIndex === 4) && (
             <div className="absolute w-3 h-3 rounded-full bg-slate-700/50 z-0"></div>
        )}

        {/* Note Circle */}
        <div className={`
            relative z-10 w-7 h-7 rounded-full flex items-center justify-center text-[10px] font-bold shadow-sm cursor-pointer transition-all hover:scale-110
            ${isVisible 
                ? (isRoot ? 'bg-red-500 text-white shadow-red-500/50' : 'bg-indigo-500 text-white shadow-indigo-500/50') 
                : 'bg-slate-800 text-slate-500 hover:bg-slate-700 opacity-0 hover:opacity-100'}
        `}>
            {showIntervals && isVisible ? interval : note}
        </div>
      </div>
    );
  };

  return (
    <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 h-full flex flex-col overflow-hidden">
        <div className="flex justify-between items-center mb-4">
            <h2 className="text-xl font-bold text-indigo-400">Mapa do Braço (7 Cordas)</h2>
            <div className="flex gap-2">
                 <select 
                    value={highlightKey || ''} 
                    onChange={(e) => setHighlightKey(e.target.value as NoteName)}
                    className="bg-slate-900 border border-slate-600 text-xs rounded px-2 py-1"
                >
                    <option value="">Cromático</option>
                    {NOTES.map(n => <option key={n} value={n}>Tom: {n}</option>)}
                 </select>
                 <button 
                    onClick={() => setShowIntervals(!showIntervals)}
                    className="text-xs bg-slate-700 px-3 py-1 rounded hover:bg-slate-600"
                 >
                    {showIntervals ? 'Ver Notas' : 'Ver Graus'}
                 </button>
            </div>
        </div>

        {/* Neck Container */}
        <div className="flex-1 overflow-x-auto overflow-y-hidden bg-slate-900 rounded-xl border border-slate-700 relative select-none">
            <div className="min-w-[800px] h-full flex flex-col py-4 pr-4">
                {stringNotes.map((note, strIndex) => (
                    <div key={strIndex} className="flex-1 flex items-center">
                        {/* Open String */}
                        <div 
                            className="w-12 flex items-center justify-center border-r-4 border-slate-500 bg-slate-800 z-20 h-full shadow-xl"
                            onClick={() => handleNoteClick(strIndex, 0)}
                        >
                             <span className={`text-xs font-bold ${strIndex === 6 ? 'text-yellow-500' : 'text-slate-400'}`}>{note}</span>
                        </div>
                        {/* Frets 1-15 */}
                        {Array.from({length: 15}).map((_, i) => renderFret(strIndex, i + 1))}
                    </div>
                ))}
            </div>
        </div>
        <p className="text-center text-xs text-slate-500 mt-2">Toque nas notas para ouvir. A 7ª corda está destacada.</p>
    </div>
  );
};

