// Helper to calc frequency
const getFreq = (str: number, fret: number, tuningStr: string) => {
     // Simplified standard tuning base frequencies 
     // E4, B3, G3, D3, A2, E2, B1/C2
     const bases = [329.63, 246.94, 196.00, 146.83, 110.00, 82.41];
     let seventh = 61.74; // B
     if(tuningStr.includes('C')) seventh = 65.41;

     const base = str === 7 ? seventh : bases[str-1];
     return base * Math.pow(2, fret/12);
};

export const BassTrainer: React.FC = () => {
    const [selectedLick, setSelectedLick] = useState<BassLick>(BAIXARIAS[0]);
    const [isPlaying, setIsPlaying] = useState(false);
    const [currentNoteIndex, setCurrentNoteIndex] = useState(-1);
    const [tempo, setTempo] = useState(90);

    const timeoutsRef = useRef<number[]>([]);

    const stop = () => {
        timeoutsRef.current.forEach(t => clearTimeout(t));
        timeoutsRef.current = [];
        setIsPlaying(false);
        setCurrentNoteIndex(-1);
    };

    const play = () => {
        if (isPlaying) { stop(); return; }

        setIsPlaying(true);
        setCurrentNoteIndex(-1);

        let currentTime = 0;
        const beatDuration = 60000 / tempo;

        selectedLick.notes.forEach((n, idx) => {
            const t = setTimeout(() => {
                setCurrentNoteIndex(idx);
                // Calculate freq roughly
                // Mapping string 1=HighE to 7=Low
                // Our data uses guitar string numbers (1-7)
                // getFreq expects 1-based index
                const freq = getFreq(n.string, n.fret, selectedLick.tuningRequired);
                playSuccessSound(freq);

                if (idx === selectedLick.notes.length - 1) {
                    setTimeout(() => stop(), beatDuration * n.duration);
                }
            }, currentTime);

            timeoutsRef.current.push(t);
            currentTime += beatDuration * n.duration;
        });
    };

    useEffect(() => {
        return () => stop();
    }, []);

    return (
        <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 h-full flex flex-col">
            <div className="flex items-center gap-3 mb-6">
                 <div className="w-10 h-10 bg-yellow-500 rounded-lg flex items-center justify-center text-slate-900 font-bold">
                    <Music size={20} />
                 </div>
                 <div>
                    <h2 className="text-xl font-bold text-white">Treinador de Baixarias</h2>
                    <p className="text-xs text-slate-400">Frases essenciais para 7 cordas</p>
                 </div>
            </div>

            {/* Selector */}
            <div className="flex gap-2 mb-6 overflow-x-auto pb-2">
                {BAIXARIAS.map(lick => (
                    <button
                        key={lick.id}
                        onClick={() => { stop(); setSelectedLick(lick); }}
                        className={`
                            whitespace-nowrap px-4 py-2 rounded-lg text-sm font-medium border transition-all
                            ${selectedLick.id === lick.id 
                                ? 'bg-yellow-500/10 border-yellow-500 text-yellow-500' 
                                : 'bg-slate-900 border-slate-700 text-slate-400 hover:bg-slate-700'}
                        `}
                    >
                        {lick.title}
                    </button>
                ))}
