// Helper to calc frequency
const getFreq = (str: number, fret: number, tuningStr: string) => {
     // Simplified standard tuning base frequencies 
     // E4, B3, G3, D3, A2, E2, B1/C2
     const bases = [329.63, 246.94, 196.00, 146.83, 110.00, 82.41];
     let seventh = 61.74; // B
     if(tuningStr.includes('C')) seventh = 65.41; // C2
     if(tuningStr.includes('A')) seventh = 55.00; // A1

     const base = str === 7 ? seventh : bases[str-1];
     return base * Math.pow(2, fret/12);
};

export const BassTrainer: React.FC = () => {
    // Mode: 'play' or 'create'
    const [viewMode, setViewMode] = useState<'play' | 'create'>('play');

    // Data
    const [userLicks, setUserLicks] = useState<BassLick[]>([]);
    const [selectedLick, setSelectedLick] = useState<BassLick>(SYSTEM_BAIXARIAS[0]);

    // Player State
    const [isPlaying, setIsPlaying] = useState(false);
    const [currentNoteIndex, setCurrentNoteIndex] = useState(-1);
    const [tempo, setTempo] = useState(90);
    const timeoutsRef = useRef<number[]>([]);

    // Creator State
    const [draftTitle, setDraftTitle] = useState('');
    const [draftNotes, setDraftNotes] = useState<BassLick['notes']>([]);
    const [draftString, setDraftString] = useState(7);
    const [draftFret, setDraftFret] = useState(0);
    const [draftDuration, setDraftDuration] = useState(1); // 1 beat
    const [draftTuning, setDraftTuning] = useState<SeventhStringTuning>(SeventhStringTuning.C);

    // --- PLAYER LOGIC ---
    const stop = () => {
        timeoutsRef.current.forEach(t => clearTimeout(t));
        timeoutsRef.current = [];
        setIsPlaying(false);
        setCurrentNoteIndex(-1);
    };

    const playSequence = (notesToPlay: BassLick['notes'], tuning: string) => {
        if (isPlaying) { stop(); return; }

        setIsPlaying(true);
        setCurrentNoteIndex(-1);

        let currentTime = 0;
        const beatDuration = 60000 / tempo;

        notesToPlay.forEach((n, idx) => {
            const t = setTimeout(() => {
                setCurrentNoteIndex(idx);
                const freq = getFreq(n.string, n.fret, tuning);
                playSuccessSound(freq);

                if (idx === notesToPlay.length - 1) {
                    setTimeout(() => stop(), beatDuration * n.duration);
                }
            }, currentTime);

            timeoutsRef.current.push(t);
            currentTime += beatDuration * n.duration;
        });
    };

    const handlePlayCurrent = () => playSequence(selectedLick.notes, selectedLick.tuningRequired);
    const handlePlayDraft = () => playSequence(draftNotes, draftTuning);

    useEffect(() => {
        return () => stop();
    }, []);

    // --- CREATOR LOGIC ---
    const addNoteToDraft = () => {
        const newNote = {
            note: '?', // Visual label isn't critical for audio, simpler to leave generic for user custom input
            duration: draftDuration,
            string: draftString,
            fret: draftFret
        };
        setDraftNotes([...draftNotes, newNote]);
    };

    const removeLastNote = () => {
        setDraftNotes(draftNotes.slice(0, -1));
    };

    const saveDraft = () => {
        if (!draftTitle.trim() || draftNotes.length === 0) return;

        const newLick: BassLick = {
            id: `user-${Date.now()}`,
            title: draftTitle,
            style: RhythmStyle.SAMBA, // Default
            difficulty: 'Intermediário', // Default
            description: 'Exercício personalizado',
            tuningRequired: draftTuning,
            notes: draftNotes
        };

        setUserLicks([...userLicks, newLick]);
        setSelectedLick(newLick);
        setViewMode('play');

        // Reset Draft
        setDraftTitle('');
        setDraftNotes([]);
    };

    const deleteUserLick = (id: string) => {
        const filtered = userLicks.filter(l => l.id !== id);
        setUserLicks(filtered);
        if (selectedLick.id === id) {
            setSelectedLick(SYSTEM_BAIXARIAS[0]);
        }
    };

    // --- RENDER ---

    if (viewMode === 'create') {
        return (
            <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 h-full flex flex-col overflow-y-auto">
                <div className="flex items-center gap-3 mb-6 border-b border-slate-700 pb-4">
                    <button 
                        onClick={() => { stop(); setViewMode('play'); }}
                        className="p-2 rounded-full hover:bg-slate-700 text-slate-400"
                    >
                        <ArrowLeft size={20} />
                    </button>
                    <h2 className="text-xl font-bold text-white">Criar Escala / Baixaria</h2>
                </div>

                <div className="space-y-6">
                    {/* Settings */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="text-xs text-slate-500 uppercase font-bold mb-1 block">Nome do Exercício</label>
                            <input 
                                type="text" 
                                value={draftTitle}
                                onChange={(e) => setDraftTitle(e.target.value)}
                                placeholder="Ex: Escala de Sol Menor"
                                className="w-full bg-slate-900 border border-slate-600 rounded-lg px-3 py-2 text-white focus:border-yellow-500 outline-none"
                            />
                        </div>
                        <div>
                            <label className="text-xs text-slate-500 uppercase font-bold mb-1 block">Afinação da 7ª</label>
                            <select 
                                value={draftTuning}
                                onChange={(e) => setDraftTuning(e.target.value as SeventhStringTuning)}
                                className="w-full bg-slate-900 border border-slate-600 rounded-lg px-3 py-2 text-white"
                            >
                                {Object.values(SeventhStringTuning).map(t => (
                                    <option key={t} value={t}>{t}</option>
                                ))}
                            </select>
                        </div>
                    </div>

                    {/* Input Controls */}
                    <div className="bg-slate-900/50 p-4 rounded-xl border border-slate-700">
                        <div className="flex flex-wrap items-end gap-4">
                            <div className="flex-1 min-w-[100px]">
                                <label className="text-xs text-slate-400 block mb-1">Corda (1=E agudo)</label>
                                <div className="flex gap-1">
                                    {[7, 6, 5, 4, 3, 2, 1].map(s => (
                                        <button 
                                            key={s}
                                            onClick={() => setDraftString(s)}
                                            className={`w-8 h-8 rounded text-sm font-bold ${draftString === s ? 'bg-yellow-500 text-slate-900' : 'bg-slate-700 text-slate-400'}`}
