import { NoteName, Chord, ChordQuality, SeventhStringTuning } from '../types';

export const NOTES: NoteName[] = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'];

// Map chords to their intervals (semitones from root)
export const CHORD_INTERVALS: Record<ChordQuality, number[]> = {
  'maj7': [0, 4, 7, 11],
  '7': [0, 4, 7, 10],
  'm7': [0, 3, 7, 10],
  'm7b5': [0, 3, 6, 10],
  'dim7': [0, 3, 6, 9],
  '6': [0, 4, 7, 9],
  'm6': [0, 3, 7, 9],
};

export const getNoteIndex = (note: NoteName): number => NOTES.indexOf(note);

export const getNoteFromInterval = (root: NoteName, semitones: number): NoteName => {
  const rootIdx = getNoteIndex(root);
  return NOTES[(rootIdx + semitones) % 12];
};

export const getChordTones = (chord: Chord): NoteName[] => {
  const intervals = CHORD_INTERVALS[chord.quality];
  return intervals.map(i => getNoteFromInterval(chord.root, i));
};

// --- Fretboard Mapping for 7-String ---

interface FretPosition {
  string: number; // 1-7
  fret: number;
  note: NoteName;
  octave: number;
}

// Base frequencies for string calculation
// Standard 7 String: E4, B3, G3, D3, A2, E2, B1
const STRING_OPEN_NOTES: { note: NoteName, octave: number }[] = [
  { note: 'E', octave: 4 }, // 1
  { note: 'B', octave: 3 }, // 2
  { note: 'G', octave: 3 }, // 3
  { note: 'D', octave: 3 }, // 4
  { note: 'A', octave: 2 }, // 5
  { note: 'E', octave: 2 }, // 6
  { note: 'B', octave: 1 }, // 7 (Default)
];

export const findFretPosition = (
  targetNote: NoteName, 
  targetOctave: number, 
  tuning: SeventhStringTuning, 
  preferredString?: number
): FretPosition | null => {

  // Adjust 7th string based on tuning
  const currentStringNotes = [...STRING_OPEN_NOTES];
  if (tuning.includes('C')) {
    currentStringNotes[6] = { note: 'C', octave: 2 };
  } else if (tuning.includes('A')) {
    currentStringNotes[6] = { note: 'A', octave: 1 };
  } else {
    currentStringNotes[6] = { note: 'B', octave: 1 };
  }

  // Search logic: prioritize lower strings (higher string index) for bass lines
  // We want "Baixaria" sound, so strings 5, 6, 7 are preferred.

  const possiblePositions: FretPosition[] = [];

  for (let s = 0; s < 7; s++) { // 0 to 6 (representing strings 1 to 7)
    const open = currentStringNotes[s];
    const openNoteIdx = getNoteIndex(open.note);
    // Base MIDI number approx calculation for comparison
    const openMidi = openNoteIdx + (open.octave + 1) * 12;

    const targetNoteIdx = getNoteIndex(targetNote);
    const targetMidi = targetNoteIdx + (targetOctave + 1) * 12;

    const diff = targetMidi - openMidi;

    if (diff >= 0 && diff <= 19) { // Available frets
      possiblePositions.push({
        string: s + 1, // 1-based index
        fret: diff,
        note: targetNote,
        octave: targetOctave
      });
    }
  }

  if (possiblePositions.length === 0) return null;

  // Prefer lower strings (higher index) for bass sound
  // Or prefer specifically requested string
  if (preferredString) {
      const match = possiblePositions.find(p => p.string === preferredString);
      if (match) return match;
  }

  // Default Sort: Prefer String 7, then 6, then 5...
  possiblePositions.sort((a, b) => b.string - a.string);

  return possiblePositions[0];
};

export const getFrequency = (note: NoteName, octave: number): number => {
    const noteIdx = getNoteIndex(note);
    // A4 = 440Hz (Index 9, Octave 4)
    // MIDI number calculation: (Octave + 1) * 12 + Index
    const midi = (octave + 1) * 12 + noteIdx;
    const A4Midi = 69;
    return 440 * Math.pow(2, (midi - A4Midi) / 12);
};

import { BassLick, BassNote, Chord, NoteName, RhythmStyle, SeventhStringTuning, ChordQuality } from '../types';
import { NOTES, getChordTones, findFretPosition, getNoteIndex } from '../utils/musicTheory';

// --- GENERATORS ---

/**
 * Creates a harmonic progression typical of Brazilian music (Choro/Samba)
 */
export const generateProgression = (key: NoteName, level: string): Chord[] => {
  const progression: Chord[] = [];

  // Simplify key index
  const keyIdx = getNoteIndex(key);
  const getRelNote = (semitones: number) => NOTES[(keyIdx + semitones) % 12];

  if (level === 'Iniciante') {
    // Simple V7 - I loop
    progression.push({ root: key, quality: '6', display: `${key}6`, duration: 4 });
    progression.push({ root: getRelNote(7), quality: '7', display: `${getRelNote(7)}7`, duration: 4 });
  } 
  else if (level === 'Intermediário') {
    // II - V - I
    progression.push({ root: getRelNote(2), quality: 'm7', display: `${getRelNote(2)}m7`, duration: 2 });
    progression.push({ root: getRelNote(7), quality: '7', display: `${getRelNote(7)}7`, duration: 2 });
    progression.push({ root: key, quality: '6', display: `${key}6`, duration: 4 });
  } 
  else {
    // Advanced: Cycle with secondary dominants (e.g., E7 -> A7 -> D7 -> G7 -> C)
    // III7 - VI7 - II7 - V7 - I
    progression.push({ root: getRelNote(4), quality: '7', display: `${getRelNote(4)}7`, duration: 2 }); // E7 in C
    progression.push({ root: getRelNote(9), quality: '7', display: `${getRelNote(9)}7`, duration: 2 }); // A7 in C
    progression.push({ root: getRelNote(2), quality: '7', display: `${getRelNote(2)}7`, duration: 2 }); // D7 in C
    progression.push({ root: getRelNote(7), quality: '7', display: `${getRelNote(7)}7`, duration: 2 }); // G7 in C
    progression.push({ root: key, quality: 'maj7', display: `${key}maj7`, duration: 4 });
  }

  return progression;
};

/**
 * THE BRAIN: Generates the bass line notes based on chords and rules
 */
export const generateBassLine = (
  progression: Chord[],
  style: RhythmStyle,
  level: 'Iniciante' | 'Intermediário' | 'Avançado',
  tuning: SeventhStringTuning
): BassNote[] => {
  const notes: BassNote[] = [];
  let currentBeatOffset = 0;

  progression.forEach((chord, index) => {
    const nextChord = progression[(index + 1) % progression.length];

    // 1. Always Root on Beat 1 (or mostly)
    // 2. Aim for Next Root on the last note of this measure (Approach note)

    // Define "Bar" structure based on style
    // Samba 2/4 is typical. Choro 2/4.
    // We treat duration in quarter notes. 2 beats = 1 bar of 2/4.

    const beatsInChord = chord.duration;

    // --- BEAT 1: ROOT ---
    // Try to use 7th string if possible/appropriate
    let rootOctave = 2; // Default E2 range
    if (['A', 'B', 'C'].includes(chord.root)) rootOctave = 2; // Keep it low
    if (tuning.includes('C') && chord.root === 'C') rootOctave = 2; // Low C is C2

    // Special case for Low B/C/A tuning utilization
    // If we have a C chord and C tuning, use the open C (C2) usually mapped to string 7?
    // Note: C2 is 65Hz. E2 is 82Hz.
    // Our util `findFretPosition` handles mapping. We just need to pick the note.

    // Add Root
    const rootPos = findFretPosition(chord.root, 2, tuning) || findFretPosition(chord.root, 3, tuning);
    if (rootPos) {
       notes.push({
           ...rootPos,
           duration: style === RhythmStyle.SAMBA ? 1.5 : 1, // Dotted quarter for Samba feel start? Or simple quarter
           startTime: currentBeatOffset,
           isChordTone: true
       });
    }

    // --- FILLERS based on Level ---

    if (level === 'Iniciante') {
        // Just Root and Fifth
        const fifth = getChordTones(chord)[2]; // 0=R, 1=3, 2=5
        const fifthPos = findFretPosition(fifth, 2, tuning) || findFretPosition(fifth, 3, tuning);

        // Add Fifth on Beat 2 (if duration allows)
        if (beatsInChord >= 2 && fifthPos) {
             notes.push({
                 ...fifthPos,
                 duration: 1,
                 startTime: currentBeatOffset + 1,
                 isChordTone: true
             });
        }
    } 
    else {
        // Intermediate/Advanced: Walking / Baixaria
        // Target: Root of next chord
        const targetNote = nextChord.root;

        // Pattern for Samba (Syncopated):
        // 1 (Root) ... 2 (Fifth or Approach)
        // 1 . & . 2 . & .
        // Beat 1 (Root), Beat 2 (Approach)

        // Pattern for Choro (16ths):
        // 1 e & a 2 e & a
        // Scale run down or up

        if (style === RhythmStyle.CHORO && level === 'Avançado') {
            // 16th note run
            // Generate simple scalar path from Current Root to Next Root
            // This is a simplified "Best Effort" logic
            const scaleNotes = getChordTones(chord); // Use Arpeggio for safety

            // Fill beats
            for (let b = 1; b < beatsInChord * 4; b++) { // 16th notes
                // Simple Arpeggio pattern
                const n = scaleNotes[b % scaleNotes.length];
                const pos = findFretPosition(n, 3, tuning);
                if (pos) {
                     notes.push({
                        ...pos,
                        duration: 0.25,
                        startTime: currentBeatOffset + (b * 0.25),
                        isChordTone: true
                     });
                }
            }
        } else {
            // Standard Walking / Samba Logic
            // Beat 2 Approach

            // Determine Approach Note (Chromatic or Dominant)
            // Chromatic from below: Target Index - 1
            // Chromatic from above: Target Index + 1
            const targetIdx = getNoteIndex(targetNote);
            const approachNote = NOTES[(targetIdx - 1 + 12) % 12]; // Semitone below (leading tone)

            const approachPos = findFretPosition(approachNote, 2, tuning) || findFretPosition(approachNote, 3, tuning);

            if (beatsInChord >= 2 && approachPos) {
                 notes.push({
                     ...approachPos,
                     duration: 1,
                     startTime: currentBeatOffset + (beatsInChord - 1), // Last beat
                     isChromatic: true
                 });
            }
        }
    }

    currentBeatOffset += beatsInChord;
  });

  // Sort notes by time just in case
  return notes.sort((a, b) => a.startTime - b.startTime);
};

import React, { useState, useRef, useEffect } from 'react';
import { Play, Square, Music, Plus, Save, Trash2, Settings2, RefreshCw, Layers, Download, Wand2 } from 'lucide-react';
import { RhythmStyle, SeventhStringTuning, BassLick, Chord, BassNote, NoteName } from '../types';
import { generateProgression, generateBassLine } from '../services/baixariaGenerator';
import { playSuccessSound, scheduleClick, getAudioContext } from '../utils/audio';
import { getFrequency, NOTES } from '../utils/musicTheory';

export const BassTrainer: React.FC = () => {
    // --- State ---
    const [style, setStyle] = useState<RhythmStyle>(RhythmStyle.SAMBA);
    const [tuning, setTuning] = useState<SeventhStringTuning>(SeventhStringTuning.C);
    const [level, setLevel] = useState<'Iniciante' | 'Intermediário' | 'Avançado'>('Intermediário');
    const [key, setKey] = useState<NoteName>('C');
    const [tempo, setTempo] = useState(90);

    const [progression, setProgression] = useState<Chord[]>([]);
    const [bassLine, setBassLine] = useState<BassNote[]>([]);
    const [isPlaying, setIsPlaying] = useState(false);
    const [currentBeat, setCurrentBeat] = useState(0);

    // Audio Refs
    const timerRef = useRef<number | null>(null);
    const startTimeRef = useRef<number>(0);
    const beatRef = useRef<number>(0);

    // --- GENERATOR ---
    const handleGenerate = () => {
        setIsPlaying(false);
        const newProg = generateProgression(key, level);
        const newBass = generateBassLine(newProg, style, level, tuning);
        setProgression(newProg);
        setBassLine(newBass);
        setCurrentBeat(0);
    };

    // Initial Generate
    useEffect(() => {
        handleGenerate();
    }, []);

    // --- SEQUENCER / PLAYBACK ---
    const play = () => {
        if (isPlaying) {
            stop();
            return;
        }

        const ctx = getAudioContext();
        if (ctx.state === 'suspended') ctx.resume();

        setIsPlaying(true);
        beatRef.current = 0;
        startTimeRef.current = ctx.currentTime;

        scheduleNext();
    };

    const stop = () => {
        if (timerRef.current) clearTimeout(timerRef.current);
        setIsPlaying(false);
        setCurrentBeat(0);
    };

    const scheduleNext = () => {
        const ctx = getAudioContext();
        const secondsPerBeat = 60.0 / tempo;
        const lookahead = 0.1; // 100ms

        // Calculate current time in song
        const playTime = ctx.currentTime - startTimeRef.current;
        // Convert to beats
        const currentSeqBeat = playTime / secondsPerBeat;

        setCurrentBeat(currentSeqBeat);

        // Schedule Notes that are within lookahead
        bassLine.forEach(note => {
            // Check if note is in the window [currentSeqBeat, currentSeqBeat + small]
            // We use a "hasPlayed" logic normally, but here simple diff for react render demo
            // Real implementation would use a "nextNoteIndex" pointer for efficiency

            // To simplify for this React component without complex audio scheduling class:
            // We just let the visual loop update state, but actual audio scheduling 
            // happens slightly ahead.

            const noteTime = note.startTime * secondsPerBeat;
            const diff = noteTime - playTime;

            if (diff >= 0 && diff < lookahead) {
                // Schedule audio
                const freq = getFrequency(note.note, note.octave);
                // We add a tiny random offset for "Human Feel"
                const humanize = Math.random() * 0.02;

                // Play Tone
                // Using existing util, but better to implement a synth here
                // We use setTimeout to trigger the existing playSuccessSound which is immediate
                // Ideally we'd use scheduleClick-like precise AudioParam scheduling
                setTimeout(() => {
                    playSuccessSound(freq);
                }, (diff + humanize) * 1000);
            }
        });

        // Loop Logic
        const totalDuration = progression.reduce((acc, c) => acc + c.duration, 0);
        if (currentSeqBeat >= totalDuration) {
             startTimeRef.current = ctx.currentTime; // Reset loop
        }

        timerRef.current = window.setTimeout(scheduleNext, 50); // 20Hz refresh
    };

    useEffect(() => {
        return () => stop();
    }, []);

    // --- EDITOR HELPERS ---
    const exportMidi = () => {
        alert("Simulação: Arquivo 'baixaria_samba.mid' gerado e pronto para download!");
