                     {Array.from({ length: totalBeats }).map((_, i) => (
                         <div key={i} className="absolute top-0 bottom-0 border-r border-slate-700/50" style={{ left: i * beatWidth }}>
                             <span className="text-[10px] text-slate-600 pl-1">{i + 1}</span>
