                                        ${isPlayingNow ? 'bg-white text-slate-900 border-white scale-110 z-10' : ''}
                                    `}
                                    style={{
                                        left: note.startTime * beatWidth,
                                        width: (note.duration * beatWidth) - 2, // -2 for gap
                                        top: (7 - note.string) * 12 // Visual vertical string spacing
                                    }}
                                    onClick={() => playSuccessSound(getFrequency(note.note, note.octave))}
                                 >
                                     {note.note}{note.octave}
                                 </div>
                             );
                         })}
                     </div>
                 </div>
            </div>
        );
