// --- AUDIO ENGINE ---

const playSound = (ctx: AudioContext, dest: GainNode, type: string, time: number, gainVal: number) => {
    const osc = ctx.createOscillator();
    const env = ctx.createGain();

    // Connect
    osc.connect(env);
    env.connect(dest);

    // Synthesis Logic
    if (type === 'kick') {
        osc.frequency.setValueAtTime(120, time);
        osc.frequency.exponentialRampToValueAtTime(40, time + 0.1);
        env.gain.setValueAtTime(gainVal * 1.0, time);
        env.gain.exponentialRampToValueAtTime(0.001, time + 0.3);
        osc.start(time);
        osc.stop(time + 0.3);
    } 
    else if (type === 'shaker') {
        // Use filtered noise ideally, simulating with high tri for simplicity without noise buffer util
        osc.type = 'sawtooth'; // Rougher
        osc.frequency.setValueAtTime(8000, time);
        env.gain.setValueAtTime(gainVal * 0.1, time);
        env.gain.exponentialRampToValueAtTime(0.001, time + 0.05);
        osc.start(time);
        osc.stop(time + 0.05);
    }
    else if (type === 'rim' || type === 'snare') {
        osc.type = 'square';
        osc.frequency.setValueAtTime(800, time);
        env.gain.setValueAtTime(gainVal * 0.3, time);
        env.gain.exponentialRampToValueAtTime(0.001, time + 0.08);
        osc.start(time);
        osc.stop(time + 0.08);
    }
    else if (type === 'agogo') {
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(1000, time);
        env.gain.setValueAtTime(gainVal * 0.4, time);
        env.gain.exponentialRampToValueAtTime(0.001, time + 0.1);
        osc.start(time);
        osc.stop(time + 0.1);
    }
    else if (type === 'bass') {
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(82.4, time); // E2
        env.gain.setValueAtTime(gainVal * 0.8, time);
        env.gain.linearRampToValueAtTime(gainVal * 0.5, time + 0.1);
        env.gain.exponentialRampToValueAtTime(0.001, time + 0.4);
        osc.start(time);
        osc.stop(time + 0.4);
    }
    else if (type === 'chord') {
        // Simulate a strummed chord (Root-5-10)
        const freqs = [261.6, 329.6, 392.0]; // C Major
        const now = time;
        freqs.forEach((f, i) => {
            const o = ctx.createOscillator();
            const g = ctx.createGain();
            o.frequency.value = f;
            o.type = 'triangle';
            o.connect(g);
            g.connect(dest);
            g.gain.setValueAtTime(0, now);
            g.gain.linearRampToValueAtTime(gainVal * 0.1, now + 0.02 + (i*0.01)); // Strum
            g.gain.exponentialRampToValueAtTime(0.001, now + 1.0);
            o.start(now);
            o.stop(now + 1.0);
        });
    }
};

export const RhythmLibrary: React.FC = () => {
  const [activeRhythm, setActiveRhythm] = useState<RhythmDefinition>(RHYTHMS[0]);
  const [bpm, setBpm] = useState(RHYTHMS[0].defaultBpm);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentStep, setCurrentStep] = useState(0);

  // Volumes (0 to 1)
  const [volHarmony, setVolHarmony] = useState(0.5);
  const [volPercussion, setVolPercussion] = useState(0.7);
  const [volBass, setVolBass] = useState(0.8);

  // Audio Refs
  const schedulerRef = useRef<number | null>(null);
  const nextNoteTimeRef = useRef(0);
  const currentStepRef = useRef(0);

  // Mixer Nodes
  const mixerRef = useRef<{
      master: GainNode | null;
      harmony: GainNode | null;
      percussion: GainNode | null;
      bass: GainNode | null;
  }>({ master: null, harmony: null, percussion: null, bass: null });

  // Init Audio
  useEffect(() => {
    const ctx = getAudioContext();
    if (!mixerRef.current.master) {
        mixerRef.current.master = ctx.createGain();
        mixerRef.current.master.connect(ctx.destination);

        mixerRef.current.harmony = ctx.createGain();
        mixerRef.current.harmony.connect(mixerRef.current.master);

        mixerRef.current.percussion = ctx.createGain();
        mixerRef.current.percussion.connect(mixerRef.current.master);

        mixerRef.current.bass = ctx.createGain();
        mixerRef.current.bass.connect(mixerRef.current.master);
    }
  }, []);

  // Update Volumes
  useEffect(() => {
    const ctx = getAudioContext();
    const t = ctx.currentTime;
    if (mixerRef.current.harmony) mixerRef.current.harmony.gain.setTargetAtTime(volHarmony, t, 0.1);
    if (mixerRef.current.percussion) mixerRef.current.percussion.gain.setTargetAtTime(volPercussion, t, 0.1);
    if (mixerRef.current.bass) mixerRef.current.bass.gain.setTargetAtTime(volBass, t, 0.1);
  }, [volHarmony, volPercussion, volBass]);

  // Scheduler Engine
  const schedule = () => {
    const ctx = getAudioContext();
    const lookahead = 25.0; // ms
    const scheduleAheadTime = 0.1; // s

    while (nextNoteTimeRef.current < ctx.currentTime + scheduleAheadTime) {
        // Play Sounds for current step
        const step = currentStepRef.current % 16;
        const time = nextNoteTimeRef.current;

        // Visual update (decoupled slightly)
        // Using a ref or timeout to sync visual to audio
        const visualDelay = (time - ctx.currentTime) * 1000;
        setTimeout(() => setCurrentStep(step), Math.max(0, visualDelay));

        // Trigger Tracks
        // 1. Percussion
        activeRhythm.tracks.percussion.forEach(track => {
            const val = track.steps[step];
            if (val > 0) {
                playSound(ctx, mixerRef.current.percussion!, track.soundType, time, val);
            }
        });

        // 2. Bass
        const bassVal = activeRhythm.tracks.bass.steps[step];
        if (bassVal > 0) {
            playSound(ctx, mixerRef.current.bass!, activeRhythm.tracks.bass.soundType, time, bassVal);
        }

        // 3. Harmony
        const harmVal = activeRhythm.tracks.harmony.steps[step];
        if (harmVal > 0) {
            playSound(ctx, mixerRef.current.harmony!, activeRhythm.tracks.harmony.soundType, time, harmVal);
        }

        // Advance
        const secondsPerStep = (60.0 / bpm) / 4; // 16th notes
        nextNoteTimeRef.current += secondsPerStep;
        currentStepRef.current++;
    }

    schedulerRef.current = window.setTimeout(schedule, lookahead);
  };

  const togglePlay = () => {
      if (isPlaying) {
          if (schedulerRef.current) clearTimeout(schedulerRef.current);
          setIsPlaying(false);
          setCurrentStep(0);
      } else {
          const ctx = getAudioContext();
          if (ctx.state === 'suspended') ctx.resume();

          nextNoteTimeRef.current = ctx.currentTime + 0.05;
          currentStepRef.current = 0;
          setIsPlaying(true);
          schedule();
      }
  };

  const selectRhythm = (r: RhythmDefinition) => {
      if (isPlaying) togglePlay();
      setActiveRhythm(r);
      setBpm(r.defaultBpm);
  };

  useEffect(() => {
      return () => {
          if (schedulerRef.current) clearTimeout(schedulerRef.current);
      };
  }, []);

  return (
    <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 h-full flex flex-col md:flex-row gap-6">

       {/* Sidebar: List */}
       <div className="w-full md:w-1/3 flex flex-col border-r border-slate-700/50 pr-0 md:pr-4">
            <div className="flex items-center gap-3 mb-6">
                <div className="w-10 h-10 bg-pink-500 rounded-lg flex items-center justify-center text-slate-900 font-bold">
                    <Music2 size={20} />
                </div>
                <div>
                    <h2 className="text-xl font-bold text-white">Biblioteca</h2>
                    <p className="text-xs text-slate-400">Playbacks brasileiros</p>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto space-y-2 pr-2">
                {RHYTHMS.map(r => (
                    <button
                        key={r.id}
                        onClick={() => selectRhythm(r)}
                        className={`w-full text-left p-3 rounded-xl border transition-all ${activeRhythm.id === r.id ? 'bg-pink-500/10 border-pink-500 text-white' : 'bg-slate-900/50 border-slate-700 text-slate-400 hover:bg-slate-700'}`}
                    >
                        <div className="font-bold text-sm">{r.id}</div>
                        <div className="text-[10px] opacity-70">{r.defaultBpm} BPM • {r.description}</div>
                    </button>
                ))}
            </div>
       </div>

       {/* Main Area: Mixer & Player */}
       <div className="flex-1 flex flex-col">
            {/* Header / Transport */}
            <div className="bg-slate-900 rounded-xl p-6 border border-slate-700 mb-6 relative overflow-hidden">
                {/* Visualizer Background */}
                <div className="absolute top-0 left-0 h-1 w-full flex">
                     {Array.from({length: 16}).map((_, i) => (
                         <div 
                            key={i} 
                            className={`flex-1 transition-colors duration-75 ${currentStep % 16 === i && isPlaying ? 'bg-pink-500' : 'bg-slate-800'}`} 
                         />
                     ))}
                </div>

                <div className="flex justify-between items-start mb-6 mt-2">
                    <div>
                        <h3 className="text-2xl font-bold text-white mb-1">{activeRhythm.id}</h3>
                        <div className="flex items-center gap-2 text-pink-400 text-sm font-bold bg-pink-900/20 px-2 py-1 rounded inline-block">
                             <span>Compasso: {activeRhythm.timeSignature}/4</span>
                             <span>•</span>
                             <span>16 Steps Loop</span>
                        </div>
                    </div>
                    <div className="text-right">
                        <div className="text-4xl font-mono font-bold text-slate-200">{bpm}</div>
                        <div className="text-[10px] uppercase text-slate-500">BPM</div>
                    </div>
                </div>

                <div className="flex items-center gap-4">
                     <button 
                        onClick={togglePlay}
                        className={`w-16 h-16 rounded-full flex items-center justify-center shadow-lg transition-all hover:scale-105 active:scale-95 ${isPlaying ? 'bg-red-500 text-white' : 'bg-green-500 text-slate-900'}`}
                     >
                        {isPlaying ? <Square size={24} fill="currentColor"/> : <Play size={28} fill="currentColor" className="ml-1"/>}
                     </button>

                     <div className="flex-1 bg-slate-800 rounded-lg p-3 flex items-center gap-3 border border-slate-700">
                        <Rewind size={20} className="text-slate-500 cursor-pointer hover:text-white" onClick={() => setBpm(b => b - 5)}/>
                        <input 
                            type="range" min="40" max="160" value={bpm} 
                            onChange={(e) => setBpm(Number(e.target.value))}
                            className="flex-1 h-2 bg-slate-700 rounded-lg appearance-none accent-pink-500"
                        />
                        <FastForward size={20} className="text-slate-500 cursor-pointer hover:text-white" onClick={() => setBpm(b => b + 5)}/>
                     </div>
                </div>
            </div>

            {/* Mixer */}
            <div className="bg-slate-900/50 rounded-xl p-6 border border-slate-700 flex-1">
                 <div className="flex items-center gap-2 mb-4 text-slate-400">
                     <Sliders size={18} />
                     <span className="text-xs font-bold uppercase tracking-widest">Mixer de Canais</span>
                 </div>

                 <div className="space-y-6">
                     {/* Harmony Channel */}
                     <div className="flex items-center gap-4">
                         <div className="w-24 text-right text-xs font-bold text-indigo-300">HARMONIA</div>
                         <Volume2 size={16} className={volHarmony === 0 ? 'text-slate-600' : 'text-indigo-500'} />
                         <input 
                            type="range" min="0" max="1" step="0.05"
                            value={volHarmony}
                            onChange={(e) => setVolHarmony(Number(e.target.value))}
                            className="flex-1 h-2 bg-slate-700 rounded-lg appearance-none accent-indigo-500"
                         />
                         <div className="w-8 text-xs text-slate-500 font-mono">{(volHarmony * 100).toFixed(0)}%</div>
                     </div>

                     {/* Percussion Channel */}
                     <div className="flex items-center gap-4">
                         <div className="w-24 text-right text-xs font-bold text-pink-300">PERCUSSÃO</div>
                         <Volume2 size={16} className={volPercussion === 0 ? 'text-slate-600' : 'text-pink-500'} />
                         <input 
                            type="range" min="0" max="1" step="0.05"
                            value={volPercussion}
                            onChange={(e) => setVolPercussion(Number(e.target.value))}
                            className="flex-1 h-2 bg-slate-700 rounded-lg appearance-none accent-pink-500"
                         />
                         <div className="w-8 text-xs text-slate-500 font-mono">{(volPercussion * 100).toFixed(0)}%</div>
                     </div>

                     {/* Bass Channel */}
                     <div className="flex items-center gap-4">
                         <div className="w-24 text-right text-xs font-bold text-yellow-300">BAIXO</div>
                         <Volume2 size={16} className={volBass === 0 ? 'text-slate-600' : 'text-yellow-500'} />
                         <input 
                            type="range" min="0" max="1" step="0.05"
                            value={volBass}
                            onChange={(e) => setVolBass(Number(e.target.value))}
                            className="flex-1 h-2 bg-slate-700 rounded-lg appearance-none accent-yellow-500"
                         />
                         <div className="w-8 text-xs text-slate-500 font-mono">{(volBass * 100).toFixed(0)}%</div>
                     </div>
                 </div>

                 <div className="mt-8 pt-6 border-t border-slate-700/50 flex justify-between items-center text-xs text-slate-500">
                    <div>
                        <span className="block font-bold text-slate-400">Dica de Estudo:</span>
                        Zere a Harmonia para treinar o acompanhamento, ou zere o Baixo para criar suas baixarias.
                    </div>
                    <div className="flex gap-1">
                        {Array.from({length: 4}).map((_, i) => (
                             <div key={i} className={`w-2 h-2 rounded-full ${Math.floor(currentStep / 4) === i && isPlaying ? 'bg-pink-500' : 'bg-slate-700'}`} />
                        ))}
                    </div>
                 </div>
            </div>
       </div>
    </div>
  );
};

import { NoteName, Chord, ChordQuality, SeventhStringTuning } from '../types';

export const NOTES: NoteName[] = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'];

// Map chords to their intervals (semitones from root)
export const CHORD_INTERVALS: Record<ChordQuality, number[]> = {
  'maj7': [0, 4, 7, 11],
  '7': [0, 4, 7, 10],
  'm7': [0, 3, 7, 10],
  'm7b5': [0, 3, 6, 10],
  'dim7': [0, 3, 6, 9],
  '6': [0, 4, 7, 9],
  'm6': [0, 3, 7, 9],
};

// --- SCALES & MODES ---
export type ScaleType = 'Major' | 'Minor' | 'Harmonic Minor' | 'Melodic Minor' | 'Dorian' | 'Phrygian' | 'Lydian' | 'Mixolydian' | 'Locrian';

export const SCALES: Record<ScaleType, number[]> = {
    'Major': [0, 2, 4, 5, 7, 9, 11], // Ionian
    'Minor': [0, 2, 3, 5, 7, 8, 10], // Aeolian
    'Harmonic Minor': [0, 2, 3, 5, 7, 8, 11], // Common in Choro
    'Melodic Minor': [0, 2, 3, 5, 7, 9, 11], // Common in Brazilian Jazz
    'Dorian': [0, 2, 3, 5, 7, 9, 10], // Minor 6 feel
    'Phrygian': [0, 1, 3, 5, 7, 8, 10], // Nordeste/Baião feel sometimes
    'Lydian': [0, 2, 4, 6, 7, 9, 11],
    'Mixolydian': [0, 2, 4, 5, 7, 9, 10], // Dominant/Samba
    'Locrian': [0, 1, 3, 5, 6, 8, 10]
};

export const INTERVAL_NAMES: Record<number, string> = {
    0: 'T', 1: 'b2', 2: '2M', 3: '3m', 4: '3M', 5: '4J', 6: '#4/b5', 7: '5J', 8: 'b6', 9: '6M', 10: '7m', 11: '7M'
};

export const getNoteIndex = (note: NoteName): number => NOTES.indexOf(note);

export const getNoteFromInterval = (root: NoteName, semitones: number): NoteName => {
  const rootIdx = getNoteIndex(root);
  return NOTES[(rootIdx + semitones) % 12];
};

export const getChordTones = (chord: Chord): NoteName[] => {
  const intervals = CHORD_INTERVALS[chord.quality];
  return intervals.map(i => getNoteFromInterval(chord.root, i));
};

export const getScaleNotes = (root: NoteName, scaleType: ScaleType): NoteName[] => {
    return SCALES[scaleType].map(interval => getNoteFromInterval(root, interval));
};

// --- Fretboard Mapping for 7-String ---

interface FretPosition {
  string: number; // 1-7
  fret: number;
  note: NoteName;
  octave: number;
}

// Base frequencies for string calculation
// Standard 7 String: E4, B3, G3, D3, A2, E2, B1
const STRING_OPEN_NOTES: { note: NoteName, octave: number }[] = [
  { note: 'E', octave: 4 }, // 1
  { note: 'B', octave: 3 }, // 2
  { note: 'G', octave: 3 }, // 3
  { note: 'D', octave: 3 }, // 4
  { note: 'A', octave: 2 }, // 5
  { note: 'E', octave: 2 }, // 6
  { note: 'B', octave: 1 }, // 7 (Default)
];

export const findFretPosition = (
  targetNote: NoteName, 
  targetOctave: number, 
  tuning: SeventhStringTuning, 
  preferredString?: number
): FretPosition | null => {

  // Adjust 7th string based on tuning
  const currentStringNotes = [...STRING_OPEN_NOTES];
  if (tuning.includes('C')) {
    currentStringNotes[6] = { note: 'C', octave: 2 };
  } else if (tuning.includes('A')) {
    currentStringNotes[6] = { note: 'A', octave: 1 };
  } else {
    currentStringNotes[6] = { note: 'B', octave: 1 };
  }

  // Search logic: prioritize lower strings (higher string index) for bass lines
  // We want "Baixaria" sound, so strings 5, 6, 7 are preferred.

  const possiblePositions: FretPosition[] = [];

  for (let s = 0; s < 7; s++) { // 0 to 6 (representing strings 1 to 7)
    const open = currentStringNotes[s];
    const openNoteIdx = getNoteIndex(open.note);
    // Base MIDI number approx calculation for comparison
    const openMidi = openNoteIdx + (open.octave + 1) * 12;

    const targetNoteIdx = getNoteIndex(targetNote);
    const targetMidi = targetNoteIdx + (targetOctave + 1) * 12;

    const diff = targetMidi - openMidi;

    if (diff >= 0 && diff <= 19) { // Available frets
      possiblePositions.push({
        string: s + 1, // 1-based index
        fret: diff,
        note: targetNote,
        octave: targetOctave
      });
    }
  }

  if (possiblePositions.length === 0) return null;

  // Prefer lower strings (higher index) for bass sound
  // Or prefer specifically requested string
  if (preferredString) {
      const match = possiblePositions.find(p => p.string === preferredString);
      if (match) return match;
  }

  // Default Sort: Prefer String 7, then 6, then 5...
  possiblePositions.sort((a, b) => b.string - a.string);

  return possiblePositions[0];
};

export const getFrequency = (note: NoteName, octave: number): number => {
    const noteIdx = getNoteIndex(note);
    // A4 = 440Hz (Index 9, Octave 4)
    // MIDI number calculation: (Octave + 1) * 12 + Index
    const midi = (octave + 1) * 12 + noteIdx;
    const A4Midi = 69;
    return 440 * Math.pow(2, (midi - A4Midi) / 12);
};

import React, { useState, useEffect } from 'react';
import { SeventhStringTuning, NoteName } from '../types';
import { SCALES, ScaleType, INTERVAL_NAMES, NOTES, getNoteIndex } from '../utils/musicTheory';
import { playSuccessSound } from '../utils/audio';
import { Layers, Eye, Music, GitBranch, ArrowRight } from 'lucide-react';

interface FretboardProps {
  tuning: SeventhStringTuning;
}

// Helper to get frequency roughly (simplified for visualization clicks)
const getFrequency = (stringIndex: number, fret: number, tuning: SeventhStringTuning): number => {
    const standardOpen = [329.63, 246.94, 196.00, 146.83, 110.00, 82.41];
    let seventhFreq = 61.74; // B1
    if (tuning.includes('C')) seventhFreq = 65.41; // C2
    if (tuning.includes('A')) seventhFreq = 55.00; // A1

    const baseFreq = stringIndex === 6 ? seventhFreq : standardOpen[stringIndex];
    return baseFreq * Math.pow(2, fret / 12);
};

const getNoteAtFret = (openNote: NoteName, fret: number): NoteName => {
  const openIndex = NOTES.indexOf(openNote);
  return NOTES[(openIndex + fret) % 12];
};

export const Fretboard: React.FC<FretboardProps> = ({ tuning }) => {
  // State
  const [rootNote, setRootNote] = useState<NoteName>('C');
  const [scaleType, setScaleType] = useState<ScaleType>('Major');
  const [displayMode, setDisplayMode] = useState<'notes' | 'intervals'>('intervals');
  const [viewMode, setViewMode] = useState<'scale' | 'arpeggio'>('scale');
  const [arpeggioFocus, setArpeggioFocus] = useState<number | null>(null); // Index of chord in harmonic field (1-7)

  // Configuration
  const stringNotes: NoteName[] = ['E', 'B', 'G', 'D', 'A', 'E', tuning.includes('C') ? 'C' : tuning.includes('A') ? 'A' : 'B'];

  // Logic
  const rootIndex = getNoteIndex(rootNote);
  const scaleIntervals = SCALES[scaleType];

  // Calculate valid notes in current scale
  // Set of intervals from root that are valid
  const activeIntervals = new Set(scaleIntervals);

  // Harmonic Field Logic (Simplified Diatonic Triads/7ths)
  // We generate the 7 chords of the key
  const harmonicField = scaleIntervals.map((interval, index) => {
      const chordRoot = NOTES[(rootIndex + interval) % 12];

      // Determine quality based on thirds stacking within the scale
      // 3rd = index + 2, 5th = index + 4, 7th = index + 6 (wrapping around scale length)
      const thirdIndex = (index + 2) % 7;
      const fifthIndex = (index + 4) % 7;
      const seventhIndex = (index + 6) % 7;

      // Calculate interval distance from chord root to chord third
      // To do this accurately, we need cumulative semitones
      // This is complex for all modes, so for UI simplicity in this context, 
      // we might hardcode the standard Major/Minor field patterns or calculate dynamically.

      // Dynamic Calculation:
      const getSemi = (idx: number) => scaleIntervals[idx]; 
      const rootSemi = getSemi(index);

      // Wrap logic: if index wraps, add 12 semitones
      let thirdSemi = getSemi(thirdIndex);
      if (thirdIndex < index) thirdSemi += 12;

      let fifthSemi = getSemi(fifthIndex);
      if (fifthIndex < index) fifthSemi += 12;

      let seventhSemi = getSemi(seventhIndex);
      if (seventhIndex < index) seventhSemi += 12;

      const distThird = thirdSemi - rootSemi;
      const distSeventh = seventhSemi - rootSemi;

      let suffix = '';
      if (distThird === 4 && distSeventh === 11) suffix = 'maj7';
      else if (distThird === 4 && distSeventh === 10) suffix = '7';
      else if (distThird === 3 && distSeventh === 10 && (fifthSemi - rootSemi) === 6) suffix = 'm7b5';
      else if (distThird === 3 && distSeventh === 10) suffix = 'm7';
      else if (distThird === 3 && distSeventh === 9) suffix = 'dim7'; // Rough approx
      else suffix = ''; 

      return {
          degree: index + 1,
          roman: ['I', 'II', 'III', 'IV', 'V', 'VI', 'VII'][index],
          root: chordRoot,
          name: `${chordRoot}${suffix}`,
          intervals: [0, thirdSemi - rootSemi, fifthSemi - rootSemi, seventhSemi - rootSemi] // Relative to chord root
      };
  });

  const getIntervalFromRoot = (note: NoteName): number => {
      const noteIdx = getNoteIndex(note);
      return (noteIdx - rootIndex + 12) % 12;
  };

  const handleNoteClick = (strIndex: number, fret: number) => {
      const freq = getFrequency(strIndex, fret, tuning);
      playSuccessSound(freq);
  };

  const selectArpeggio = (degreeIndex: number) => {
      if (viewMode === 'arpeggio' && arpeggioFocus === degreeIndex) {
          setViewMode('scale');
          setArpeggioFocus(null);
      } else {
          setViewMode('arpeggio');
          setArpeggioFocus(degreeIndex);
      }
  };

  const renderFret = (strIndex: number, fret: number) => {
    const openNote = stringNotes[strIndex];
    const note = getNoteAtFret(openNote, fret);
    const intervalFromKeyRoot = getIntervalFromRoot(note);

    // Visibility Logic
    let isVisible = false;
    let isChordTone = false;
    let isRoot = false;
    let label = '';
    let colorClass = 'bg-slate-800 text-slate-500 opacity-0';

    if (viewMode === 'scale') {
        if (activeIntervals.has(intervalFromKeyRoot)) {
            isVisible = true;
            isRoot = intervalFromKeyRoot === 0;
            // Highlight specific intervals
            if (isRoot) colorClass = 'bg-red-500 text-white shadow-red-500/50';
            else if (intervalFromKeyRoot === 7) colorClass = 'bg-indigo-500 text-white'; // 5th
            else if (intervalFromKeyRoot === 4 || intervalFromKeyRoot === 3) colorClass = 'bg-yellow-500 text-slate-900'; // 3rds
            else colorClass = 'bg-slate-600 text-slate-200';
        }
    } else if (viewMode === 'arpeggio' && arpeggioFocus !== null) {
        // Check if note belongs to selected chord
        const chord = harmonicField[arpeggioFocus];
        // chord.intervals are relative to CHORD root.
        // intervalFromKeyRoot is relative to KEY root.

        // We need interval relative to CHORD root
        const chordRootIdx = getNoteIndex(chord.root);
        const noteIdx = getNoteIndex(note);
        const intervalFromChordRoot = (noteIdx - chordRootIdx + 12) % 12;

        if (chord.intervals.includes(intervalFromChordRoot)) {
            isVisible = true;
            isRoot = intervalFromChordRoot === 0;
            isChordTone = true;

            if (isRoot) colorClass = 'bg-pink-500 text-white shadow-pink-500/50'; // Chord Root
            else if (intervalFromChordRoot === 7) colorClass = 'bg-purple-500 text-white';
            else if (intervalFromChordRoot === 3 || intervalFromChordRoot === 4) colorClass = 'bg-yellow-500 text-slate-900';
            else colorClass = 'bg-slate-500 text-white';
        } else if (activeIntervals.has(intervalFromKeyRoot)) {
             // Ghost notes for scale
             isVisible = true;
             colorClass = 'bg-slate-800/50 text-slate-600 border border-slate-700';
        }
    }

    // Label Logic
    if (isVisible) {
        if (displayMode === 'notes') {
            label = note;
        } else {
            // If Arpeggio mode, show interval relative to CHORD
            if (viewMode === 'arpeggio' && arpeggioFocus !== null) {
                const chord = harmonicField[arpeggioFocus];
                const noteIdx = getNoteIndex(note);
                const chordRootIdx = getNoteIndex(chord.root);
                const intVal = (noteIdx - chordRootIdx + 12) % 12;
                label = INTERVAL_NAMES[intVal] || '?';
            } else {
                // Scale mode
                label = INTERVAL_NAMES[intervalFromKeyRoot] || '?';
            }
        }
    }

    return (
      <div 
        key={fret} 
        className="flex-1 relative flex items-center justify-center border-r border-slate-600 h-full group"
        onClick={() => handleNoteClick(strIndex, fret)}
      >
        {/* String Line */}
        <div className={`absolute w-full h-[1px] ${strIndex === 6 ? 'bg-yellow-600 h-[2px] shadow-[0_0_5px_rgba(234,179,8,0.5)]' : 'bg-slate-500/30'} z-0`}></div>

        {/* Fret Markers */}
        {(fret === 3 || fret === 5 || fret === 7 || fret === 9 || fret === 15 || fret === 17) && strIndex === 3 && (
            <div className="absolute w-2 h-2 rounded-full bg-slate-700 z-0"></div>
        )}
        {(fret === 12) && (strIndex === 2 || strIndex === 4) && (
             <div className="absolute w-2 h-2 rounded-full bg-slate-700 z-0"></div>
        )}

        {/* Note Circle */}
        <div className={`
            relative z-10 w-7 h-7 rounded-full flex items-center justify-center text-[10px] font-bold shadow-sm cursor-pointer transition-all duration-200
            ${isVisible ? 'opacity-100 scale-100' : 'opacity-0 scale-50 group-hover:opacity-30 group-hover:scale-75 group-hover:bg-slate-700'}
            ${colorClass}
        `}>
            {label}
        </div>
      </div>
    );
  };

  return (
    <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 h-full flex flex-col overflow-hidden">

        {/* TOP CONTROLS */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">

            {/* 1. Key & Scale */}
            <div className="bg-slate-900/50 p-3 rounded-xl border border-slate-700">
                <div className="flex items-center gap-2 mb-2 text-indigo-400 font-bold text-xs uppercase tracking-wider">
                    <Music size={14} /> Tonalidade & Escala
                </div>
                <div className="flex gap-2">
                    <select 
                        value={rootNote} 
                        onChange={(e) => setRootNote(e.target.value as NoteName)}
                        className="bg-slate-800 border border-slate-600 text-white text-sm rounded px-2 py-1 flex-1 font-bold"
                    >
                        {NOTES.map(n => <option key={n} value={n}>{n}</option>)}
                    </select>
                    <select 
                        value={scaleType} 
                        onChange={(e) => setScaleType(e.target.value as ScaleType)}
                        className="bg-slate-800 border border-slate-600 text-white text-sm rounded px-2 py-1 flex-[2]"
                    >
                        {Object.keys(SCALES).map(s => <option key={s} value={s}>{s}</option>)}
                    </select>
                </div>
            </div>

            {/* 2. Visualization Toggles */}
            <div className="bg-slate-900/50 p-3 rounded-xl border border-slate-700">
                 <div className="flex items-center gap-2 mb-2 text-yellow-500 font-bold text-xs uppercase tracking-wider">
                    <Eye size={14} /> Visualização
                </div>
                <div className="flex gap-2 bg-slate-800 rounded-lg p-1">
                    <button 
                        onClick={() => setDisplayMode('intervals')}
                        className={`flex-1 py-1 text-xs rounded font-medium transition-colors ${displayMode === 'intervals' ? 'bg-slate-600 text-white' : 'text-slate-400 hover:text-white'}`}
                    >
                        Graus (T, 3, 5)
                    </button>
                    <button 
                        onClick={() => setDisplayMode('notes')}
                        className={`flex-1 py-1 text-xs rounded font-medium transition-colors ${displayMode === 'notes' ? 'bg-slate-600 text-white' : 'text-slate-400 hover:text-white'}`}
                    >
                        Notas (C, E, G)
                    </button>
                </div>
            </div>

            {/* 3. 7th String Indicator */}
            <div className="bg-slate-900/50 p-3 rounded-xl border border-slate-700 flex flex-col justify-center">
                 <div className="flex justify-between items-center">
                    <span className="text-xs font-bold text-slate-400 uppercase">7ª Corda Afinada em:</span>
                    <span className="text-xl font-black text-yellow-500">{tuning.split('(')[0]}</span>
                 </div>
                 <div className="text-[10px] text-slate-500 mt-1">
                    Ideal para baixarias em {tuning.includes('C') ? 'Do Maior / Sol' : 'Si / Mi Menor'}.
                 </div>
            </div>
        </div>

        {/* HARMONIC FIELD BAR */}
        <div className="mb-6">
            <div className="flex items-center gap-2 mb-2 text-pink-400 font-bold text-xs uppercase tracking-wider">
                <GitBranch size={14} /> Campo Harmônico (Clique para ver arpejos)
            </div>
            <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                {harmonicField.map((chord, idx) => {
                    const isActive = viewMode === 'arpeggio' && arpeggioFocus === idx;
                    return (
                        <button
                            key={idx}
                            onClick={() => selectArpeggio(idx)}
                            className={`
                                min-w-[70px] flex-1 py-2 px-3 rounded-lg border flex flex-col items-center justify-center transition-all
                                ${isActive 
                                    ? 'bg-pink-500 border-pink-400 text-white shadow-lg shadow-pink-900/50 scale-105' 
                                    : 'bg-slate-900 border-slate-700 text-slate-400 hover:border-pink-500/50 hover:text-pink-200'}
                            `}
                        >
                            <span className="text-[10px] opacity-70 mb-1">{chord.roman}</span>
                            <span className="font-bold text-sm whitespace-nowrap">{chord.name}</span>
                        </button>
                    )
                })}
            </div>
        </div>

        {/* NECK CONTAINER */}
        <div className="flex-1 overflow-x-auto overflow-y-hidden bg-slate-900 rounded-xl border border-slate-700 relative select-none shadow-inner">
            <div className="min-w-[900px] h-full flex flex-col py-6 pr-6 pl-2">
                {stringNotes.map((note, strIndex) => (
                    <div key={strIndex} className="flex-1 flex items-center">
                        {/* String Label (Open Note) */}
                        <div 
                            className={`
                                w-10 flex items-center justify-center border-r-4 z-20 h-full shadow-2xl relative
                                ${strIndex === 6 ? 'border-yellow-600 bg-slate-800' : 'border-slate-600 bg-slate-800'}
                            `}
                            onClick={() => handleNoteClick(strIndex, 0)}
                        >
                             <span className={`text-sm font-black ${strIndex === 6 ? 'text-yellow-500' : 'text-slate-300'}`}>{note}</span>
                             {strIndex === 6 && <div className="absolute -left-2 w-1 h-full bg-yellow-500/20"></div>}
                        </div>

                        {/* Frets 1-19 */}
                        {Array.from({length: 19}).map((_, i) => renderFret(strIndex, i + 1))}
