import { BassNote, Chord, NoteName, RhythmStyle, SeventhStringTuning, ChordQuality } from '../types';
import { NOTES, getChordTones, findFretPosition, getNoteIndex, getScaleNotes, getNoteFromInterval } from '../utils/musicTheory';

// --- HELPERS ---
const getRandomInt = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;
const getRandomElement = <T>(arr: T[]): T => arr[Math.floor(Math.random() * arr.length)];

// --- PROGRESSION GENERATOR ---

const PROGRESSION_POOLS: Record<string, Record<string, string[][]>> = {
  'Iniciante': {
    'Samba': [['I', 'V7'], ['I', 'IV', 'V7', 'I']],
    'Choro': [['Im', 'V7'], ['Im', 'IVm', 'V7', 'Im']],
  },
  'Intermediário': {
    'Samba': [['I', 'VI7', 'II7', 'V7'], ['I', 'III7', 'VI7', 'II7', 'V7']], // Circular
    'Choro': [['Im', 'V7/IV', 'IVm', 'V7'], ['Im', 'bVI7', 'V7', 'Im']],
  },
  'Avançado': {
    'Samba': [['Imaj7', 'dim', 'IIm7', 'V7alt'], ['I', 'VII7', 'III7', 'VI7', 'II7', 'V7']],
    'Choro': [['Im', 'Im/G', 'Im/F#', 'Im/F', 'Im/E'], ['I', 'V7', 'I', 'IV', '#IVdim', 'I/V', 'V7', 'I']],
  }
};

/**
 * Creates a unique harmonic progression based on level
 */
export const generateProgression = (key: NoteName, level: string): Chord[] => {
  const progression: Chord[] = [];
  const keyIdx = getNoteIndex(key);
  const getRelNote = (semitones: number) => NOTES[(keyIdx + semitones) % 12];

  // Logic to translate generic Roman numerals to Chords
  // Simplified for this demo: We create variations manually

  if (level === 'Iniciante') {
    const vars = [
        [{ r: 0, q: '6' }, { r: 7, q: '7' }, { r: 0, q: '6' }, { r: 7, q: '7' }], // I - V loop
        [{ r: 0, q: '6' }, { r: 5, q: 'maj7' }, { r: 7, q: '7' }, { r: 0, q: '6' }] // I - IV - V
    ];
    const choice = getRandomElement(vars);
    choice.forEach(c => progression.push({ root: getRelNote(c.r), quality: c.q as any, display: `${getRelNote(c.r)}${c.q}`, duration: 4 }));
  } 
  else if (level === 'Intermediário') {
    const vars = [
        // Circular de Samba
        [{ r: 0, q: '6' }, { r: 9, q: '7' }, { r: 2, q: 'm7' }, { r: 7, q: '7' }], 
        // Descida de Choro (Am - A7 - Dm - E7)
        [{ r: 0, q: 'm7' }, { r: 9, q: '7' }, { r: 5, q: 'm7' }, { r: 7, q: '7' }]
    ];
    const choice = getRandomElement(vars);
    choice.forEach(c => progression.push({ root: getRelNote(c.r), quality: c.q as any, display: `${getRelNote(c.r)}${c.q}`, duration: 2 }));
  } 
  else {
    // Advanced Variations
    const vars = [
        // "Cadência de Choro Completa"
        [{ r: 0, q: '6' }, { r: 11, q: 'dim7' }, { r: 2, q: 'm7' }, { r: 7, q: '7' }, { r: 4, q: '7' }, { r: 9, q: '7' }],
        // "Chromatics"
        [{ r: 0, q: 'maj7' }, { r: 1, q: 'dim7' }, { r: 2, q: 'm7' }, { r: 3, q: 'dim7' }, { r: 4, q: 'm7' }, { r: 7, q: '7' }]
    ];
    const choice = getRandomElement(vars);
    choice.forEach(c => progression.push({ root: getRelNote(c.r), quality: c.q as any, display: `${getRelNote(c.r)}${c.q}`, duration: 2 }));
  }

  return progression;
};

// --- BASS LINE STRATEGIES ---

type Strategy = 'ROOT_FIFTH' | 'SCALE_RUN' | 'CHROMATIC_APPROACH' | 'ARPEGGIO';

const getNoteBetween = (n1: number, n2: number, steps: number): number[] => {
    // Generate 'steps' midi notes between n1 and n2
    const path: number[] = [];
    const dir = n2 > n1 ? 1 : -1;
    const stepSize = Math.floor(Math.abs(n2 - n1) / steps) || 1;

    for(let i=1; i<=steps; i++) {
        path.push(n1 + (dir * stepSize * i));
    }
    return path;
};

/**
 * THE BRAIN: Generates a stochastic bass line
 */
export const generateBassLine = (
  progression: Chord[],
  style: RhythmStyle,
  level: 'Iniciante' | 'Intermediário' | 'Avançado',
  tuning: SeventhStringTuning
): BassNote[] => {
  const notes: BassNote[] = [];
  let currentBeatOffset = 0;

  // Track previous note to ensure legato flow
  let prevNoteMidi = -1; 

  progression.forEach((chord, index) => {
    const nextChord = progression[(index + 1) % progression.length];
    const beatsInChord = chord.duration;

    // DECISION: Which strategy for this measure?
    let strategy: Strategy = 'ROOT_FIFTH';
    const rand = Math.random();

    if (level === 'Iniciante') {
        strategy = 'ROOT_FIFTH';
    } else if (level === 'Intermediário') {
        strategy = rand > 0.6 ? 'CHROMATIC_APPROACH' : 'ROOT_FIFTH';
    } else {
        // Advanced mixes everything
        if (style === RhythmStyle.CHORO) strategy = rand > 0.3 ? 'SCALE_RUN' : 'ARPEGGIO';
        else strategy = rand > 0.5 ? 'CHROMATIC_APPROACH' : 'ARPEGGIO';
    }

    // --- BEAT 1: THE ANCHOR ---
    // Try to find a low root
    let rootOctave = 2; 
    // If we have a 7th string tuned to C and chord is C, use octave 2 (Low C)
    if (tuning.includes('C') && chord.root === 'C') rootOctave = 2;
    // If tuning is B and chord is B, use octave 1
    if (tuning.includes('B') && chord.root === 'B') rootOctave = 1;

    // Try to vary octave if we just played this note?
    const rootPos = findFretPosition(chord.root, rootOctave, tuning) || findFretPosition(chord.root, 3, tuning);

    if (rootPos) {
        notes.push({
           ...rootPos,
           duration: style === RhythmStyle.CHORO ? 0.25 : 1, // Choro starts running immediately
           startTime: currentBeatOffset,
           isChordTone: true
        });
        prevNoteMidi = getNoteIndex(rootPos.note) + (rootPos.octave + 1) * 12;
    }

    // --- FILLS ---

    // We need to fill (beatsInChord - 1) beats approximately, aiming for nextChord.root
    // Simplified time slots:
    // If Duration 2: Fill beat 1.25, 1.5, 1.75 -> Target 2.0 (Next Chord) is wrong. 
    // Target is Start of Next Chord. We fill UNTIL then.

    const targetNoteName = nextChord.root;
    // Guess target octave (keep it low for bass)
    const targetOctave = 2; 
    const targetMidi = getNoteIndex(targetNoteName) + (targetOctave + 1) * 12;

    if (strategy === 'ROOT_FIFTH') {
        // Simple: Play Root, wait, Play Fifth on beat 2 or offbeat
        const fifth = getChordTones(chord)[2];
        const fifthPos = findFretPosition(fifth, 2, tuning) || findFretPosition(fifth, 3, tuning);

        if (beatsInChord >= 2 && fifthPos) {
            // Samba kick on beat 2
            notes.push({
                ...fifthPos,
                duration: 0.5,
                startTime: currentBeatOffset + 1.5, // The "and" of 2 in 2/4? No, accent on 2.
                // Samba: 1 ... 2.
                startTime: currentBeatOffset + 1.0,
                isChordTone: true
            });
        }
    }
    else if (strategy === 'CHROMATIC_APPROACH') {
        // Classic 7-string: "Tum - (chromatic run) - Target"
        // If we have 2 beats, and next is target.
        // Beat 1: Root. Beat 2: Run.

        // E.g. C to F. Target F. Approach E, Eb, D... no wait.
        // Approach: Gb, G... 
        // 1 Semitone away: E (natural) -> F.

        const direction = Math.random() > 0.5 ? 1 : -1;
        const approachCount = getRandomInt(1, 3);

        // Calculate notes backwards from target
        for(let i = approachCount; i > 0; i--) {
            const semitoneOffset = i * direction * -1; // e.g. -1, -2, -3 from target
            const noteIdx = (getNoteIndex(targetNoteName) + semitoneOffset + 24) % 12; // +24 to handle neg
            const noteName = NOTES[noteIdx];

            // Find pos
            const pos = findFretPosition(noteName, 2, tuning) || findFretPosition(noteName, 3, tuning);

            if (pos) {
                // Place them in the last portion of the measure
                // e.g. beat 1.5, 1.75...
                const timeSlot = currentBeatOffset + beatsInChord - (i * 0.25);
                notes.push({
                    ...pos,
                    duration: 0.25,
                    startTime: timeSlot,
                    isChromatic: true
                });
            }
        }
    }
    else if (strategy === 'SCALE_RUN' || strategy === 'ARPEGGIO') {
        // "Baixaria" style: Continuous 16th notes
        // Start from current beat + 0.25
        const slots = (beatsInChord * 4) - 1; // 16th note slots remaining

        // Use chord tones or scale tones
        const tones = strategy === 'ARPEGGIO' ? getChordTones(chord) : getScaleNotes(chord.root, 'Mixolydian'); // generic scale

        let currentMidi = prevNoteMidi;

        for(let i = 1; i <= slots; i++) {
            // Random walk towards target?
            // Or just random walk in scale?

            // 50% chance to move towards target, 50% random interval
            let nextMidiCandidate = 0;

            if (Math.random() > 0.4) {
                 // Move closer to target
                 const diff = targetMidi - currentMidi;
                 const step = diff > 0 ? 1 : -1;
                 // Try to find a scale note in that direction
                 nextMidiCandidate = currentMidi + step; 
                 // (Simplified: just chromatic step towards target often works in jazz, but let's try to stick to key)
            } else {
                // Random jump
                nextMidiCandidate = currentMidi + getRandomInt(-3, 3);
            }

            // Map back to Note/Octave
            const candidateOctave = Math.floor(nextMidiCandidate / 12) - 1;
            const candidateNoteIdx = nextMidiCandidate % 12;
            const candidateNote = NOTES[candidateNoteIdx];

            // Validate range (Guitar range approx E2(40) to E5)
            // 7 String goes down to B1 (35) or C2 (36)
            if (nextMidiCandidate < 35 || nextMidiCandidate > 65) continue; 

            const pos = findFretPosition(candidateNote, candidateOctave, tuning);

            if (pos) {
                notes.push({
                    ...pos,
                    duration: 0.25,
                    startTime: currentBeatOffset + (i * 0.25),
                    isChordTone: getChordTones(chord).includes(candidateNote)
                });
                currentMidi = nextMidiCandidate;
            }
        }
    }

    currentBeatOffset += beatsInChord;
  });

  return notes.sort((a, b) => a.startTime - b.startTime);
};

