        // "Cadência de Choro Completa"
        [{ r: 0, q: '6' }, { r: 11, q: 'dim7' }, { r: 2, q: 'm7' }, { r: 7, q: '7' }, { r: 4, q: '7' }, { r: 9, q: '7' }],
        // "Chromatics"
        [{ r: 0, q: 'maj7' }, { r: 1, q: 'dim7' }, { r: 2, q: 'm7' }, { r: 3, q: 'dim7' }, { r: 4, q: 'm7' }, { r: 7, q: '7' }]
    ];
    const choice = getRandomElement(vars);
    choice.forEach(c => progression.push({ root: getRelNote(c.r), quality: c.q as any, display: `${getRelNote(c.r)}${c.q}`, duration: 2 }));
  }

  return progression;
};

// --- BASS LINE STRATEGIES ---

type Strategy = 'ROOT_FIFTH' | 'SCALE_RUN' | 'CHROMATIC_APPROACH' | 'ARPEGGIO';

const getNoteBetween = (n1: number, n2: number, steps: number): number[] => {
    // Generate 'steps' midi notes between n1 and n2
    const path: number[] = [];
    const dir = n2 > n1 ? 1 : -1;
    const stepSize = Math.floor(Math.abs(n2 - n1) / steps) || 1;

    for(let i=1; i<=steps; i++) {
        path.push(n1 + (dir * stepSize * i));
    }
    return path;
};

/**
 * THE BRAIN: Generates a stochastic bass line
 */
export const generateBassLine = (
  progression: Chord[],
  style: RhythmStyle,
  level: 'Iniciante' | 'Intermediário' | 'Avançado',
  tuning: SeventhStringTuning
): BassNote[] => {
  const notes: BassNote[] = [];
  let currentBeatOffset = 0;

  // Track previous note to ensure legato flow
  let prevNoteMidi = -1; 

  progression.forEach((chord, index) => {
    const nextChord = progression[(index + 1) % progression.length];
    const beatsInChord = chord.duration;

    // DECISION: Which strategy for this measure?
    let strategy: Strategy = 'ROOT_FIFTH';
    const rand = Math.random();

    if (level === 'Iniciante') {
        strategy = 'ROOT_FIFTH';
    } else if (level === 'Intermediário') {
        strategy = rand > 0.6 ? 'CHROMATIC_APPROACH' : 'ROOT_FIFTH';
    } else {
        // Advanced mixes everything
        if (style === RhythmStyle.CHORO) strategy = rand > 0.3 ? 'SCALE_RUN' : 'ARPEGGIO';
        else strategy = rand > 0.5 ? 'CHROMATIC_APPROACH' : 'ARPEGGIO';
    }

    // --- BEAT 1: THE ANCHOR ---
    // Try to find a low root
    let rootOctave = 2; 
    // If we have a 7th string tuned to C and chord is C, use octave 2 (Low C)
    if (tuning.includes('C') && chord.root === 'C') rootOctave = 2;
    // If tuning is B and chord is B, use octave 1
    if (tuning.includes('B') && chord.root === 'B') rootOctave = 1;

    // Try to vary octave if we just played this note?
    const rootPos = findFretPosition(chord.root, rootOctave, tuning) || findFretPosition(chord.root, 3, tuning);

    if (rootPos) {
        notes.push({
           ...rootPos,
           duration: style === RhythmStyle.CHORO ? 0.25 : 1, // Choro starts running immediately
           startTime: currentBeatOffset,
           isChordTone: true
        });
        prevNoteMidi = getNoteIndex(rootPos.note) + (rootPos.octave + 1) * 12;
    }

    // --- FILLS ---

    // We need to fill (beatsInChord - 1) beats approximately, aiming for nextChord.root
    // Simplified time slots:
    // If Duration 2: Fill beat 1.25, 1.5, 1.75 -> Target 2.0 (Next Chord) is wrong. 
    // Target is Start of Next Chord. We fill UNTIL then.

    const targetNoteName = nextChord.root;
    // Guess target octave (keep it low for bass)
    const targetOctave = 2; 
    const targetMidi = getNoteIndex(targetNoteName) + (targetOctave + 1) * 12;

    if (strategy === 'ROOT_FIFTH') {
        // Simple: Play Root, wait, Play Fifth on beat 2 or offbeat
        const fifth = getChordTones(chord)[2];
        const fifthPos = findFretPosition(fifth, 2, tuning) || findFretPosition(fifth, 3, tuning);

        if (beatsInChord >= 2 && fifthPos) {
            // Samba kick on beat 2
            notes.push({
                ...fifthPos,
                duration: 0.5,
                // Samba: 1 ... 2.
                startTime: currentBeatOffset + 1.0,
                isChordTone: true
            });
        }
    }
    else if (strategy === 'CHROMATIC_APPROACH') {
        // Classic 7-string: "Tum - (chromatic run) - Target"
        // If we have 2 beats, and next is target.
        // Beat 1: Root. Beat 2: Run.

        // E.g. C to F. Target F. Approach E, Eb, D... no wait.
        // Approach: Gb, G... 
        // 1 Semitone away: E (natural) -> F.

        const direction = Math.random() > 0.5 ? 1 : -1;
        const approachCount = getRandomInt(1, 3);

        // Calculate notes backwards from target
        for(let i = approachCount; i > 0; i--) {
            const semitoneOffset = i * direction * -1; // e.g. -1, -2, -3 from target
            const noteIdx = (getNoteIndex(targetNoteName) + semitoneOffset + 24) % 12; // +24 to handle neg
            const noteName = NOTES[noteIdx];

            // Find pos
            const pos = findFretPosition(noteName, 2, tuning) || findFretPosition(noteName, 3, tuning);

            if (pos) {
                // Place them in the last portion of the measure
                // e.g. beat 1.5, 1.75...
                const timeSlot = currentBeatOffset + beatsInChord - (i * 0.25);
                notes.push({
                    ...pos,
                    duration: 0.25,
                    startTime: timeSlot,
                    isChromatic: true
                });
            }
        }
    }
    else if (strategy === 'SCALE_RUN' || strategy === 'ARPEGGIO') {
        // "Baixaria" style: Continuous 16th notes
        // Start from current beat + 0.25
        const slots = (beatsInChord * 4) - 1; // 16th note slots remaining

        // Use chord tones or scale tones
        const tones = strategy === 'ARPEGGIO' ? getChordTones(chord) : getScaleNotes(chord.root, 'Mixolydian'); // generic scale

        let currentMidi = prevNoteMidi;

        for(let i = 1; i <= slots; i++) {
            // Random walk towards target?
            // Or just random walk in scale?

            // 50% chance to move towards target, 50% random interval
            let nextMidiCandidate = 0;

            if (Math.random() > 0.4) {
                 // Move closer to target
                 const diff = targetMidi - currentMidi;
                 const step = diff > 0 ? 1 : -1;
                 // Try to find a scale note in that direction
                 nextMidiCandidate = currentMidi + step; 
                 // (Simplified: just chromatic step towards target often works in jazz, but let's try to stick to key)
            } else {
                // Random jump
                nextMidiCandidate = currentMidi + getRandomInt(-3, 3);
            }

            // Map back to Note/Octave
            const candidateOctave = Math.floor(nextMidiCandidate / 12) - 1;
            const candidateNoteIdx = nextMidiCandidate % 12;
            const candidateNote = NOTES[candidateNoteIdx];

            // Validate range (Guitar range approx E2(40) to E5)
            // 7 String goes down to B1 (35) or C2 (36)
            if (nextMidiCandidate < 35 || nextMidiCandidate > 65) continue; 

            const pos = findFretPosition(candidateNote, candidateOctave, tuning);

            if (pos) {
                notes.push({
                    ...pos,
                    duration: 0.25,
                    startTime: currentBeatOffset + (i * 0.25),
                    isChordTone: getChordTones(chord).includes(candidateNote)
                });
                currentMidi = nextMidiCandidate;
            }
        }
    }

    currentBeatOffset += beatsInChord;
  });

  return notes.sort((a, b) => a.startTime - b.startTime);
};

import React, { useState, useRef, useEffect } from 'react';
import { Play, Square, Music, Plus, Save, Trash2, Settings2, RefreshCw, Layers, Download, Wand2 } from 'lucide-react';
import { RhythmStyle, SeventhStringTuning, BassLick, Chord, BassNote, NoteName } from '../types';
import { generateProgression, generateBassLine } from '../services/baixariaGenerator';
import { playSuccessSound, scheduleClick, getAudioContext } from '../utils/audio';
import { getFrequency, NOTES } from '../utils/musicTheory';

export const BassTrainer: React.FC = () => {
    // --- State ---
    const [style, setStyle] = useState<RhythmStyle>(RhythmStyle.SAMBA);
    const [tuning, setTuning] = useState<SeventhStringTuning>(SeventhStringTuning.C);
    const [level, setLevel] = useState<'Iniciante' | 'Intermediário' | 'Avançado'>('Intermediário');
    const [key, setKey] = useState<NoteName>('C');
    const [tempo, setTempo] = useState(90);

    const [progression, setProgression] = useState<Chord[]>([]);
    const [bassLine, setBassLine] = useState<BassNote[]>([]);
    const [isPlaying, setIsPlaying] = useState(false);
    const [currentBeat, setCurrentBeat] = useState(0);

    // Audio Refs
    const timerRef = useRef<number | null>(null);
    const startTimeRef = useRef<number>(0);
    const beatRef = useRef<number>(0);

    // --- GENERATOR ---
    const handleGenerate = () => {
        setIsPlaying(false);
        const newProg = generateProgression(key, level);
        const newBass = generateBassLine(newProg, style, level, tuning);
        setProgression(newProg);
        setBassLine(newBass);
        setCurrentBeat(0);
    };

    // Initial Generate
    useEffect(() => {
        handleGenerate();
    }, []);

    // --- SEQUENCER / PLAYBACK ---
    const play = () => {
        if (isPlaying) {
            stop();
            return;
        }

        const ctx = getAudioContext();
        if (ctx.state === 'suspended') ctx.resume();

        setIsPlaying(true);
        beatRef.current = 0;
        startTimeRef.current = ctx.currentTime;

        scheduleNext();
    };

    const stop = () => {
        if (timerRef.current) clearTimeout(timerRef.current);
        setIsPlaying(false);
        setCurrentBeat(0);
    };

    const scheduleNext = () => {
        const ctx = getAudioContext();
        const secondsPerBeat = 60.0 / tempo;
        const lookahead = 0.1; // 100ms

        // Calculate current time in song
        const playTime = ctx.currentTime - startTimeRef.current;
        // Convert to beats
        const currentSeqBeat = playTime / secondsPerBeat;

        setCurrentBeat(currentSeqBeat);

        // Schedule Notes that are within lookahead
        bassLine.forEach(note => {
            // Check if note is in the window [currentSeqBeat, currentSeqBeat + small]
            const noteTime = note.startTime * secondsPerBeat;
            const diff = noteTime - playTime;

            if (diff >= 0 && diff < lookahead) {
                // Schedule audio
                const freq = getFrequency(note.note, note.octave);
                // We add a tiny random offset for "Human Feel"
                const humanize = Math.random() * 0.02;

                setTimeout(() => {
                    playSuccessSound(freq);
                }, (diff + humanize) * 1000);
            }
        });

        // Loop Logic
        const totalDuration = progression.reduce((acc, c) => acc + c.duration, 0);
        if (currentSeqBeat >= totalDuration) {
             startTimeRef.current = ctx.currentTime; // Reset loop
        }

        timerRef.current = window.setTimeout(scheduleNext, 50); // 20Hz refresh
    };

    useEffect(() => {
        return () => stop();
    }, []);

    // --- EDITOR HELPERS ---
    const exportMidi = () => {
        alert("Simulação: Arquivo 'baixaria_samba.mid' gerado e pronto para download!");
    };

    // --- RENDERERS ---

    const renderTimeline = () => {
        if (progression.length === 0) return null;

        const totalBeats = progression.reduce((sum, c) => sum + c.duration, 0);
        const beatWidth = 60; // px per beat

        return (
            <div className="relative h-48 bg-slate-900 rounded-xl border border-slate-700 overflow-x-auto overflow-y-hidden mb-6 select-none">
                 <div className="absolute top-0 left-0 h-full bg-slate-800/50" style={{ width: `${totalBeats * beatWidth}px` }}>
                     {/* Grid Lines */}
                     {Array.from({ length: totalBeats }).map((_, i) => (
                         <div key={i} className="absolute top-0 bottom-0 border-r border-slate-700/50" style={{ left: i * beatWidth }}>
                             <span className="text-[10px] text-slate-600 pl-1">{i + 1}</span>
                         </div>
                     ))}

                     {/* Cursor */}
                     {isPlaying && (
                         <div 
                            className="absolute top-0 bottom-0 w-0.5 bg-green-500 z-50 shadow-[0_0_10px_rgba(74,222,128,0.8)] transition-all duration-75 ease-linear"
                            style={{ left: `${(currentBeat % totalBeats) * beatWidth}px` }}
                         />
                     )}

                     {/* Chords Track */}
                     <div className="h-12 flex border-b border-slate-700">
                         {progression.map((chord, i) => (
                             <div 
                                key={i} 
                                className="border-r border-slate-600 bg-slate-800 flex items-center justify-center text-sm font-bold text-yellow-500"
                                style={{ width: chord.duration * beatWidth }}
                             >
                                 {chord.display}
                             </div>
                         ))}
                     </div>

                     {/* Bass Notes Track */}
                     <div className="relative h-36 mt-2">
                         {bassLine.map((note, i) => {
                             const isPlayingNow = Math.abs(currentBeat - note.startTime) < 0.2 && isPlaying;
                             return (
                                 <div
                                    key={i}
                                    className={`
                                        absolute h-8 rounded-md flex items-center justify-center text-[10px] font-bold border shadow-sm transition-transform hover:scale-110 cursor-pointer
                                        ${note.isChromatic ? 'bg-pink-500/20 border-pink-500 text-pink-300' : 'bg-indigo-500/20 border-indigo-500 text-indigo-300'}
                                        ${isPlayingNow ? 'bg-white text-slate-900 border-white scale-110 z-10' : ''}
                                    `}
                                    style={{
                                        left: note.startTime * beatWidth,
                                        width: (note.duration * beatWidth) - 2, // -2 for gap
                                        top: (7 - note.string) * 12 // Visual vertical string spacing
                                    }}
                                    onClick={() => playSuccessSound(getFrequency(note.note, note.octave))}
                                 >
                                     {note.note}{note.octave}
                                 </div>
                             );
                         })}
                     </div>
                 </div>
            </div>
        );
    };

    return (
        <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 h-full flex flex-col">

            {/* --- HEADER --- */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
                 <div>
                    <h2 className="text-xl font-bold text-white flex items-center gap-2">
                        <Wand2 className="text-yellow-500" />
                        Gerador de Baixarias 7 Cordas
                    </h2>
                    <p className="text-xs text-slate-400">Engine harmônica brasileira com IA algorítmica</p>
                 </div>

                 <div className="flex gap-2">
                    <button 
                        onClick={exportMidi}
                        className="flex items-center gap-2 px-3 py-2 bg-slate-700 hover:bg-slate-600 rounded-lg text-xs font-bold text-slate-300 transition-colors"
                    >
                        <Download size={14} /> MIDI
                    </button>
                    <button 
                        onClick={handleGenerate}
                        className="flex items-center gap-2 px-4 py-2 bg-yellow-500 hover:bg-yellow-400 text-slate-900 rounded-lg text-sm font-bold shadow-lg shadow-yellow-500/20 transition-all active:scale-95"
                    >
                        <RefreshCw size={16} /> Gerar Nova
                    </button>
                 </div>
            </div>

            {/* --- CONTROLS --- */}
            <div className="grid grid-cols-2 md:grid-cols-5 gap-3 mb-6 bg-slate-900/50 p-4 rounded-xl border border-slate-700">
                <div>
                    <label className="text-[10px] uppercase font-bold text-slate-500 block mb-1">Tom</label>
                    <select 
                        value={key} 
                        onChange={e => setKey(e.target.value as NoteName)}
                        className="w-full bg-slate-800 border border-slate-600 rounded px-2 py-1 text-sm"
                    >
                        {NOTES.map(n => <option key={n} value={n}>{n}</option>)}
                    </select>
                </div>
                <div>
                    <label className="text-[10px] uppercase font-bold text-slate-500 block mb-1">Estilo</label>
                    <select 
                        value={style} 
                        onChange={e => setStyle(e.target.value as RhythmStyle)}
                        className="w-full bg-slate-800 border border-slate-600 rounded px-2 py-1 text-sm"
                    >
                        {Object.values(RhythmStyle).map(s => <option key={s} value={s}>{s}</option>)}
                    </select>
                </div>
                <div>
                    <label className="text-[10px] uppercase font-bold text-slate-500 block mb-1">Nível</label>
                    <select 
                        value={level} 
                        onChange={e => setLevel(e.target.value as any)}
                        className="w-full bg-slate-800 border border-slate-600 rounded px-2 py-1 text-sm"
                    >
                        <option value="Iniciante">Iniciante</option>
                        <option value="Intermediário">Intermediário</option>
                        <option value="Avançado">Avançado</option>
                    </select>
                </div>
                <div>
                    <label className="text-[10px] uppercase font-bold text-slate-500 block mb-1">7ª Corda</label>
                    <select 
                        value={tuning} 
                        onChange={e => setTuning(e.target.value as any)}
                        className="w-full bg-slate-800 border border-slate-600 rounded px-2 py-1 text-sm"
                    >
                        <option value={SeventhStringTuning.B}>Si (B)</option>
                        <option value={SeventhStringTuning.C}>Dó (C)</option>
                    </select>
                </div>
                <div>
                    <label className="text-[10px] uppercase font-bold text-slate-500 block mb-1">BPM: {tempo}</label>
                    <input 
                        type="range" min="40" max="180" value={tempo} 
                        onChange={e => setTempo(Number(e.target.value))}
                        className="w-full h-2 bg-slate-700 rounded-lg accent-yellow-500"
                    />
                </div>
            </div>

            {/* --- VISUALIZER --- */}
            {renderTimeline()}

            {/* --- PLAYER --- */}
            <div className="mt-auto flex justify-center gap-4">
                 {!isPlaying ? (
                    <button
                        onClick={play}
                        className="flex items-center gap-2 px-8 py-4 rounded-full bg-green-500 text-slate-900 font-bold text-lg shadow-xl shadow-green-900/20 hover:bg-green-400 hover:scale-105 transition-all"
                    >
                        <Play fill="currentColor" size={24} /> Ouvir Baixaria
                    </button>
                 ) : (
                    <button
                        onClick={stop}
                        className="flex items-center gap-2 px-8 py-4 rounded-full bg-red-500 text-white font-bold text-lg shadow-xl shadow-red-900/20 hover:bg-red-400 hover:scale-105 transition-all"
                    >
                        <Square fill="currentColor" size={24} /> PARAR
                    </button>
                 )}
            </div>

            <div className="mt-4 text-center">
                 <p className="text-xs text-slate-500">
                    Dica: Use fones de ouvido. A engine gera frases únicas a cada clique em "Gerar Nova".
                 </p>
            </div>
        </div>
    );
};

