// --- HELPERS ---
const getRandomInt = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;
const getRandomElement = <T>(arr: T[]): T => arr[Math.floor(Math.random() * arr.length)];

// --- PROGRESSION GENERATOR ---

// Progressions represented as relative semitone offset from Root + Chord Quality
// e.g. { r: 2, q: 'm7' } in key of C is Dm7
// { r: 1, q: '7' } in key of C is C#7 (SubV of G7?) No, Db7. 
// Note: Relative calculation handles sharps. 1 semitone up from C is C#. Db is enharmonic.

// Updated Pools with Brazilian Harmonic Logic
const PROGRESSION_POOLS = {
  'Iniciante': {
    'Samba': [
        // I - V7 basic
        [{ r: 0, q: '6' }, { r: 7, q: '7' }, { r: 0, q: '6' }, { r: 7, q: '7' }], 
        // I - IV - V7
        [{ r: 0, q: '6' }, { r: 5, q: 'maj7' }, { r: 7, q: '7' }, { r: 0, q: '6' }] 
    ],
    'Choro': [
        // Im - V7
        [{ r: 0, q: 'm6' }, { r: 7, q: '7' }, { r: 0, q: 'm6' }, { r: 7, q: '7' }], 
        // Im - IVm - V7
        [{ r: 0, q: 'm6' }, { r: 5, q: 'm6' }, { r: 7, q: '7' }, { r: 0, q: 'm6' }]
    ],
  },
  'Intermediário': {
    'Samba': [
        // Circular: I - VI7 - II7 - V7
        [{ r: 0, q: '6' }, { r: 9, q: '7' }, { r: 2, q: 'm7' }, { r: 7, q: '7' }], 
        // "Quadrado": I - III7 - VI7 - II7 - V7
        [{ r: 0, q: 'maj7' }, { r: 4, q: '7' }, { r: 9, q: '7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
    'Choro': [
        // Descida Cromática de Baixo (ex: Am - Am/G - D/F# - Fmaj7 - E7) -> Simulated via chords
        // Im - V7/IV - IV - bVI7 - V7
        [{ r: 0, q: 'm7' }, { r: 0, q: '7' }, { r: 5, q: 'm7' }, { r: 8, q: '7' }, { r: 7, q: '7' }],
        // Empréstimo Modal (Samba/Choro): I - Im - I
        [{ r: 0, q: 'maj7' }, { r: 5, q: 'm6' }, { r: 0, q: 'maj7' }, { r: 7, q: '7' }]
    ],
  },
  'Avançado': {
    'Samba': [
        // SubV7 Replacement (Tritone Subs)
        // Imaj7 - bIIIdim - IIm7 - bII7 (SubV) - I
        [{ r: 0, q: 'maj7' }, { r: 3, q: 'dim7' }, { r: 2, q: 'm7' }, { r: 1, q: '7' }, { r: 0, q: '6' }],
        // Deceptive Cadences
        [{ r: 0, q: '6' }, { r: 11, q: 'm7b5' }, { r: 4, q: '7' }, { r: 9, q: 'm7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
    'Choro': [
        // The "Cristal" cadence type
        // I - #Io - II - #IIo - III - VI7 ...
        [{ r: 0, q: '6' }, { r: 1, q: 'dim7' }, { r: 2, q: 'm7' }, { r: 3, q: 'dim7' }, { r: 4, q: 'm7' }, { r: 7, q: '7' }],
        // Modulating feel
        [{ r: 0, q: 'm6' }, { r: 7, q: '7' }, { r: 4, q: '7' }, { r: 9, q: '7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
  }
};

/**
 * Creates a unique harmonic progression based on level
 */
export const generateProgression = (key: NoteName, level: string): Chord[] => {
  const progression: Chord[] = [];
  const keyIdx = getNoteIndex(key);
  const getRelNote = (semitones: number) => NOTES[(keyIdx + semitones) % 12];

  // Logic to get variants
  // We check style generally, but for simplicity we mix Samba/Choro logic or pick random
  // This function is style-agnostic in args, but we can infer or pick randomly

  const lvlKey = level as keyof typeof PROGRESSION_POOLS;
  const styles = Object.keys(PROGRESSION_POOLS[lvlKey]);
  const randomStyle = getRandomElement(styles);

  // @ts-ignore - Dynamic key access
  const pool = PROGRESSION_POOLS[lvlKey][randomStyle];
  const choice = getRandomElement(pool);

  choice.forEach((c: any) => {
      progression.push({ 
          root: getRelNote(c.r), 
          quality: c.q as any, 
          display: `${getRelNote(c.r)}${c.q}`, 
          duration: level === 'Iniciante' ? 4 : 2 
      });
  });

  return progression;
};

// --- BASS LINE STRATEGIES ---

type Strategy = 'ROOT_FIFTH' | 'SCALE_RUN' | 'CHROMATIC_APPROACH' | 'ARPEGGIO';

/**
 * THE BRAIN: Generates a stochastic bass line
 */
export const generateBassLine = (
  progression: Chord[],
  style: RhythmStyle,
  level: 'Iniciante' | 'Intermediário' | 'Avançado',
  tuning: SeventhStringTuning
): BassNote[] => {
  const notes: BassNote[] = [];
  let currentBeatOffset = 0;
  let prevNoteMidi = -1; 

  progression.forEach((chord, index) => {
    const nextChord = progression[(index + 1) % progression.length];
    const beatsInChord = chord.duration;

    // DECISION: Strategy
    let strategy: Strategy = 'ROOT_FIFTH';
    const rand = Math.random();

    if (level === 'Iniciante') {
        strategy = 'ROOT_FIFTH';
    } else if (level === 'Intermediário') {
        strategy = rand > 0.6 ? 'CHROMATIC_APPROACH' : 'ROOT_FIFTH';
    } else {
        // Advanced mixes everything
        if (style === RhythmStyle.CHORO) strategy = rand > 0.3 ? 'SCALE_RUN' : 'ARPEGGIO';
        else strategy = rand > 0.5 ? 'CHROMATIC_APPROACH' : 'ARPEGGIO';
    }

    // --- BEAT 1: ANCHOR ---
    let rootOctave = 2; 
    if (tuning.includes('C') && chord.root === 'C') rootOctave = 2;
    if (tuning.includes('B') && chord.root === 'B') rootOctave = 1;

    const rootPos = findFretPosition(chord.root, rootOctave, tuning) || findFretPosition(chord.root, 3, tuning);

    if (rootPos) {
        notes.push({
           ...rootPos,
           duration: style === RhythmStyle.CHORO ? 0.25 : 1, 
           startTime: currentBeatOffset,
           isChordTone: true
        });
        prevNoteMidi = getNoteIndex(rootPos.note) + (rootPos.octave + 1) * 12;
    }

    // --- FILLS ---
    const targetNoteName = nextChord.root;
    const targetOctave = 2; 
    const targetMidi = getNoteIndex(targetNoteName) + (targetOctave + 1) * 12;

    if (strategy === 'ROOT_FIFTH') {
        const fifth = getChordTones(chord)[2];
        const fifthPos = findFretPosition(fifth, 2, tuning) || findFretPosition(fifth, 3, tuning);

        if (beatsInChord >= 2 && fifthPos) {
            notes.push({
                ...fifthPos,
                duration: 0.5,
                startTime: currentBeatOffset + 1.0,
                isChordTone: true
            });
        }
    }
    else if (strategy === 'CHROMATIC_APPROACH') {
        const direction = Math.random() > 0.5 ? 1 : -1;
        const approachCount = getRandomInt(1, 3);

        for(let i = approachCount; i > 0; i--) {
            const semitoneOffset = i * direction * -1; 
            const noteIdx = (getNoteIndex(targetNoteName) + semitoneOffset + 24) % 12; 
            const noteName = NOTES[noteIdx];

            const pos = findFretPosition(noteName, 2, tuning) || findFretPosition(noteName, 3, tuning);

            if (pos) {
                const timeSlot = currentBeatOffset + beatsInChord - (i * 0.25);
                notes.push({
                    ...pos,
                    duration: 0.25,
                    startTime: timeSlot,
                    isChromatic: true
                });
            }
        }
    }
    else if (strategy === 'SCALE_RUN' || strategy === 'ARPEGGIO') {
        const slots = (beatsInChord * 4) - 1; 

        let currentMidi = prevNoteMidi;

        for(let i = 1; i <= slots; i++) {
            let nextMidiCandidate = 0;

            if (Math.random() > 0.4) {
                 const diff = targetMidi - currentMidi;
                 const step = diff > 0 ? 1 : -1;
                 nextMidiCandidate = currentMidi + step; 
            } else {
                nextMidiCandidate = currentMidi + getRandomInt(-3, 3);
            }

            const candidateOctave = Math.floor(nextMidiCandidate / 12) - 1;
            const candidateNoteIdx = nextMidiCandidate % 12;
            const candidateNote = NOTES[candidateNoteIdx];

            if (nextMidiCandidate < 35 || nextMidiCandidate > 65) continue; 

            const pos = findFretPosition(candidateNote, candidateOctave, tuning);

            if (pos) {
                notes.push({
                    ...pos,
                    duration: 0.25,
                    startTime: currentBeatOffset + (i * 0.25),
                    isChordTone: getChordTones(chord).includes(candidateNote)
                });
                currentMidi = nextMidiCandidate;
            }
        }
    }

    currentBeatOffset += beatsInChord;
  });

  return notes.sort((a, b) => a.startTime - b.startTime);
};

