// --- HELPERS ---
const getRandomInt = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;
const getRandomElement = <T>(arr: T[]): T => arr[Math.floor(Math.random() * arr.length)];

// --- PROGRESSION GENERATOR ---

// Progressions represented as relative semitone offset from Root + Chord Quality
// e.g. { r: 2, q: 'm7' } in key of C is Dm7
// { r: 1, q: '7' } in key of C is C#7 (SubV of G7?) No, Db7. 
// Note: Relative calculation handles sharps. 1 semitone up from C is C#. Db is enharmonic.

// Updated Pools with Brazilian Harmonic Logic
const PROGRESSION_POOLS = {
  'Iniciante': {
    'Samba': [
        // I - V7 basic
        [{ r: 0, q: '6' }, { r: 7, q: '7' }, { r: 0, q: '6' }, { r: 7, q: '7' }], 
        // I - IV - V7
        [{ r: 0, q: '6' }, { r: 5, q: 'maj7' }, { r: 7, q: '7' }, { r: 0, q: '6' }] 
    ],
    'Choro': [
        // Im - V7
        [{ r: 0, q: 'm6' }, { r: 7, q: '7' }, { r: 0, q: 'm6' }, { r: 7, q: '7' }], 
        // Im - IVm - V7
        [{ r: 0, q: 'm6' }, { r: 5, q: 'm6' }, { r: 7, q: '7' }, { r: 0, q: 'm6' }]
    ],
  },
  'Intermediário': {
    'Samba': [
        // Circular: I - VI7 - II7 - V7
        [{ r: 0, q: '6' }, { r: 9, q: '7' }, { r: 2, q: 'm7' }, { r: 7, q: '7' }], 
        // "Quadrado": I - III7 - VI7 - II7 - V7
        [{ r: 0, q: 'maj7' }, { r: 4, q: '7' }, { r: 9, q: '7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
    'Choro': [
        // Descida Cromática de Baixo (ex: Am - Am/G - D/F# - Fmaj7 - E7) -> Simulated via chords
        // Im - V7/IV - IV - bVI7 - V7
        [{ r: 0, q: 'm7' }, { r: 0, q: '7' }, { r: 5, q: 'm7' }, { r: 8, q: '7' }, { r: 7, q: '7' }],
        // Empréstimo Modal (Samba/Choro): I - Im - I
        [{ r: 0, q: 'maj7' }, { r: 5, q: 'm6' }, { r: 0, q: 'maj7' }, { r: 7, q: '7' }]
    ],
  },
  'Avançado': {
    'Samba': [
        // SubV7 Replacement (Tritone Subs)
        // Imaj7 - bIIIdim - IIm7 - bII7 (SubV) - I
        [{ r: 0, q: 'maj7' }, { r: 3, q: 'dim7' }, { r: 2, q: 'm7' }, { r: 1, q: '7' }, { r: 0, q: '6' }],
        // Deceptive Cadences
        [{ r: 0, q: '6' }, { r: 11, q: 'm7b5' }, { r: 4, q: '7' }, { r: 9, q: 'm7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
    'Choro': [
        // The "Cristal" cadence type
        // I - #Io - II - #IIo - III - VI7 ...
        [{ r: 0, q: '6' }, { r: 1, q: 'dim7' }, { r: 2, q: 'm7' }, { r: 3, q: 'dim7' }, { r: 4, q: 'm7' }, { r: 7, q: '7' }],
        // Modulating feel
        [{ r: 0, q: 'm6' }, { r: 7, q: '7' }, { r: 4, q: '7' }, { r: 9, q: '7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
  }
};

