import { InstrumentType } from '../types';

// Simple audio context singleton to avoid recreating it
let audioCtx: AudioContext | null = null;
let masterGain: GainNode | null = null;

export const getAudioContext = (): AudioContext => {
  if (!audioCtx) {
    audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    masterGain = audioCtx.createGain();
    masterGain.connect(audioCtx.destination);
    masterGain.gain.value = 0.8; // Default volume
  }
  return audioCtx;
};

export const setMasterVolume = (val: number) => {
  if (masterGain) {
    // Smooth transition to avoid clicks
    masterGain.gain.setTargetAtTime(val, getAudioContext().currentTime, 0.02);
  }
};

export const playTone = (frequency: number, type: OscillatorType = 'triangle', duration = 2.0) => {
  const ctx = getAudioContext();
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  osc.type = type;
  osc.frequency.setValueAtTime(frequency, ctx.currentTime);

  // Envelope
  gain.gain.setValueAtTime(0, ctx.currentTime);
  gain.gain.linearRampToValueAtTime(0.3, ctx.currentTime + 0.05); // Attack
  gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + duration); // Decay

  osc.connect(gain);
  // Bypass master gain for tuner tones if desired, or connect to masterGain logic
  gain.connect(ctx.destination); 

  osc.start();
  osc.stop(ctx.currentTime + duration);
};

// Precise scheduled click for Metronome
export const scheduleClick = (time: number, type: 'accent' | 'sub' | 'normal') => {
  const ctx = getAudioContext();
  if (!masterGain) getAudioContext(); // Ensure init

  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  // GUITAR OPTIMIZED FREQUENCIES
  // Guitar fundamentals: ~82Hz to ~1000Hz.
  // We choose frequencies that cut through without masking the guitar tone.
  // Accent: 2000Hz (High presence, distinct)
  // Normal: 1200Hz (Mid-high, distinct but softer)
  // Sub: 800Hz (Woodblock-ish feel for subdivisions)

  let freq = 1200;
  let vol = 1.0;

  if (type === 'accent') {
    freq = 2000;
    vol = 1.0;
  } else if (type === 'sub') {
    freq = 800;
    vol = 0.4; // Softer subdivisions
  } else {
    freq = 1200;
    vol = 0.7;
  }

  osc.type = 'triangle'; // Cleaner than square, sharper than sine
  osc.frequency.setValueAtTime(freq, time);

  // ADSR ENVELOPE - OPTIMIZED FOR TRANSIENT
  // Short attack (1ms) to define the start time precisely
  // Short decay (50ms) to leave space for the music
  gain.gain.setValueAtTime(0, time);
  gain.gain.linearRampToValueAtTime(vol, time + 0.001); 
  gain.gain.exponentialRampToValueAtTime(0.001, time + 0.05);

  osc.connect(gain);
  if (masterGain) {
      gain.connect(masterGain);
  } else {
      gain.connect(ctx.destination);
  }

  osc.start(time);
  osc.stop(time + 0.06);
};

export const playClick = (accent: boolean) => {
    // Legacy support for simple play
    scheduleClick(getAudioContext().currentTime, accent ? 'accent' : 'normal');
};

export const playInstrumentNote = (frequency: number, instrument: InstrumentType = 'nylon', duration = 1.0) => {
    const ctx = getAudioContext();
    if (ctx.state === 'suspended') {
      ctx.resume();
    }

    const t = ctx.currentTime;
    const dest = masterGain || ctx.destination;

    if (instrument === 'nylon') {
        // --- NYLON GUITAR ---
        // Sawtooth (bright) + Triangle (body)
        const oscBright = ctx.createOscillator();
        oscBright.type = 'sawtooth';
        oscBright.frequency.setValueAtTime(frequency, t);

        const filter = ctx.createBiquadFilter();
        filter.type = 'lowpass';
        filter.Q.value = 0; 
        filter.frequency.setValueAtTime(frequency * 4, t); 
        filter.frequency.setTargetAtTime(frequency, t + 0.05, 0.1); 

        const gainBright = ctx.createGain();
        gainBright.gain.setValueAtTime(0, t);
        gainBright.gain.linearRampToValueAtTime(0.3, t + 0.02); 
        gainBright.gain.setTargetAtTime(0, t + 0.05, 0.3); 

        oscBright.connect(filter);
        filter.connect(gainBright);
        gainBright.connect(dest);

        const oscBody = ctx.createOscillator();
        oscBody.type = 'triangle';
        oscBody.frequency.setValueAtTime(frequency, t);

        const gainBody = ctx.createGain();
        gainBody.gain.setValueAtTime(0, t);
        gainBody.gain.linearRampToValueAtTime(0.4, t + 0.02);
        gainBody.gain.setTargetAtTime(0, t + 0.05, 0.8); 

        oscBody.connect(gainBody);
        gainBody.connect(dest);

        oscBright.start(t);
        oscBright.stop(t + duration);
        oscBody.start(t);
        oscBody.stop(t + duration);

    } else if (instrument === 'electric') {
        // --- ELECTRIC BASS ---
        // Punchy Triangle + Sine Sub
        const osc = ctx.createOscillator();
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(frequency, t);

        const oscSub = ctx.createOscillator();
        oscSub.type = 'sine';
        oscSub.frequency.setValueAtTime(frequency / 2, t); // Sub octave

        const filter = ctx.createBiquadFilter();
        filter.type = 'lowpass';
        filter.frequency.setValueAtTime(800, t);

        const gain = ctx.createGain();
        gain.gain.setValueAtTime(0, t);
        gain.gain.linearRampToValueAtTime(0.5, t + 0.01); // Fast attack
        gain.gain.exponentialRampToValueAtTime(0.01, t + duration); // Medium decay

        osc.connect(filter);
        oscSub.connect(filter);
        filter.connect(gain);
        gain.connect(dest);

        osc.start(t);
        osc.stop(t + duration);
        oscSub.start(t);
        oscSub.stop(t + duration);

    } else if (instrument === 'synth') {
        // --- SYNTH BASS ---
        // Sawtooth with envelope filter sweep
        const osc = ctx.createOscillator();
        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(frequency, t);

        const osc2 = ctx.createOscillator();
        osc2.type = 'square';
        osc2.frequency.setValueAtTime(frequency / 2, t);
        osc2.detune.value = 5; // Slight detune

        const filter = ctx.createBiquadFilter();
        filter.type = 'lowpass';
        filter.Q.value = 5;
        filter.frequency.setValueAtTime(200, t);
        filter.frequency.linearRampToValueAtTime(2000, t + 0.05); // Filter envelope
        filter.frequency.exponentialRampToValueAtTime(200, t + 0.3);

        const gain = ctx.createGain();
        gain.gain.setValueAtTime(0, t);
        gain.gain.linearRampToValueAtTime(0.4, t + 0.01);
        gain.gain.exponentialRampToValueAtTime(0.01, t + duration);

        osc.connect(filter);
        osc2.connect(filter);
        filter.connect(gain);
        gain.connect(dest);

        osc.start(t);
        osc.stop(t + duration);
        osc2.start(t);
        osc2.stop(t + duration);

    } else if (instrument === 'cello') {
        // --- CELLO (Bowed) ---
        // Sawtooth + Vibrato + Slow Attack
        const osc = ctx.createOscillator();
        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(frequency, t);

        // Vibrato
        const lfo = ctx.createOscillator();
        lfo.type = 'sine';
        lfo.frequency.value = 5; // 5Hz vibrato
        const lfoGain = ctx.createGain();
        lfoGain.gain.value = 6; // Depth
        lfo.connect(lfoGain);
        lfoGain.connect(osc.frequency);

        const filter = ctx.createBiquadFilter();
        filter.type = 'lowpass';
        filter.frequency.value = 1500;

        const gain = ctx.createGain();
        gain.gain.setValueAtTime(0, t);
        gain.gain.linearRampToValueAtTime(0.4, t + 0.15); // Slow bowing attack
        gain.gain.setValueAtTime(0.4, t + duration - 0.1); // Sustain
        gain.gain.linearRampToValueAtTime(0, t + duration); // Release

        osc.connect(filter);
        filter.connect(gain);
        gain.connect(dest);

        osc.start(t);
        lfo.start(t);
        osc.stop(t + duration);
        lfo.stop(t + duration);
    }
};

