export const BassTrainer: React.FC = () => {
    // --- State ---
    const [style, setStyle] = useState<RhythmStyle>(RhythmStyle.SAMBA);
    const [tuning, setTuning] = useState<SeventhStringTuning>(SeventhStringTuning.C);
    const [level, setLevel] = useState<'Iniciante' | 'Intermediário' | 'Avançado'>('Intermediário');
    const [key, setKey] = useState<NoteName>('C');
    const [tempo, setTempo] = useState(90);
    const [instrument, setInstrument] = useState<InstrumentType>('nylon');

    const [progression, setProgression] = useState<Chord[]>([]);
    const [bassLine, setBassLine] = useState<BassNote[]>([]);
    const [isPlaying, setIsPlaying] = useState(false);
    const [currentBeat, setCurrentBeat] = useState(0);

    // Audio Refs
    const timerRef = useRef<number | null>(null);
    const startTimeRef = useRef<number>(0);
    const beatRef = useRef<number>(0);

    // --- GENERATOR ---
    const handleGenerate = () => {
        setIsPlaying(false);
        const newProg = generateProgression(key, level);
        const newBass = generateBassLine(newProg, style, level, tuning);
        setProgression(newProg);
        setBassLine(newBass);
        setCurrentBeat(0);
    };

    // Initial Generate
    useEffect(() => {
        handleGenerate();
    }, []);

    // --- SEQUENCER / PLAYBACK ---
    const play = () => {
        if (isPlaying) {
            stop();
            return;
        }

        const ctx = getAudioContext();
        if (ctx.state === 'suspended') ctx.resume();

        setIsPlaying(true);
        beatRef.current = 0;
        startTimeRef.current = ctx.currentTime;

        scheduleNext();
    };

    const stop = () => {
        if (timerRef.current) clearTimeout(timerRef.current);
        setIsPlaying(false);
        setCurrentBeat(0);
    };

    const scheduleNext = () => {
        const ctx = getAudioContext();
        const secondsPerBeat = 60.0 / tempo;
        const lookahead = 0.1; // 100ms

        // Calculate current time in song
        const playTime = ctx.currentTime - startTimeRef.current;
        // Convert to beats
        const currentSeqBeat = playTime / secondsPerBeat;

        setCurrentBeat(currentSeqBeat);

        // Schedule Notes that are within lookahead
        bassLine.forEach(note => {
            // Check if note is in the window [currentSeqBeat, currentSeqBeat + small]
            const noteTime = note.startTime * secondsPerBeat;
            const diff = noteTime - playTime;

            if (diff >= 0 && diff < lookahead) {
                // Schedule audio
                const freq = getFrequency(note.note, note.octave);
                // We add a tiny random offset for "Human Feel"
                const humanize = Math.random() * 0.02;

                // Duration for the synth
                const dur = note.duration * secondsPerBeat;

                setTimeout(() => {
                    playInstrumentNote(freq, instrument, dur);
                }, (diff + humanize) * 1000);
            }
        });

        // Loop Logic
        const totalDuration = progression.reduce((acc, c) => acc + c.duration, 0);
        if (currentSeqBeat >= totalDuration) {
             startTimeRef.current = ctx.currentTime; // Reset loop
        }

        timerRef.current = window.setTimeout(scheduleNext, 50); // 20Hz refresh
    };

    useEffect(() => {
        return () => stop();
    }, []);

    // --- EDITOR HELPERS ---
    const exportMidi = () => {
        alert("Simulação: Arquivo 'baixaria.mid' gerado e pronto para download!");
    };

    // --- RENDERERS ---

    const renderTimeline = () => {
        if (progression.length === 0) return null;

        const totalBeats = progression.reduce((sum, c) => sum + c.duration, 0);
        const beatWidth = 60; // px per beat

        return (
            <div className="relative h-48 bg-slate-900 rounded-xl border border-slate-700 overflow-x-auto overflow-y-hidden mb-6 select-none">
                 <div className="absolute top-0 left-0 h-full bg-slate-800/50" style={{ width: `${totalBeats * beatWidth}px` }}>
                     {/* Grid Lines */}
                     {Array.from({ length: totalBeats }).map((_, i) => (
                         <div key={i} className="absolute top-0 bottom-0 border-r border-slate-700/50" style={{ left: i * beatWidth }}>
                             <span className="text-[10px] text-slate-600 pl-1">{i + 1}</span>
                         </div>
                     ))}

                     {/* Cursor */}
                     {isPlaying && (
                         <div 
                            className="absolute top-0 bottom-0 w-0.5 bg-green-500 z-50 shadow-[0_0_10px_rgba(74,222,128,0.8)] transition-all duration-75 ease-linear"
                            style={{ left: `${(currentBeat % totalBeats) * beatWidth}px` }}
                         />
                     )}

                     {/* Chords Track */}
                     <div className="h-12 flex border-b border-slate-700">
                         {progression.map((chord, i) => (
                             <div 
                                key={i} 
                                className="border-r border-slate-600 bg-slate-800 flex items-center justify-center text-sm font-bold text-yellow-500"
                                style={{ width: chord.duration * beatWidth }}
                             >
                                 {chord.display}
                             </div>
                         ))}
                     </div>

                     {/* Bass Notes Track */}
                     <div className="relative h-36 mt-2">
                         {bassLine.map((note, i) => {
                             const isPlayingNow = Math.abs(currentBeat - note.startTime) < 0.2 && isPlaying;
                             return (
                                 <div
                                    key={i}
                                    className={`
                                        absolute h-8 rounded-md flex items-center justify-center text-[10px] font-bold border shadow-sm transition-transform hover:scale-110 cursor-pointer
                                        ${note.isChromatic ? 'bg-pink-500/20 border-pink-500 text-pink-300' : 'bg-indigo-500/20 border-indigo-500 text-indigo-300'}
                                        ${isPlayingNow ? 'bg-white text-slate-900 border-white scale-110 z-10' : ''}
                                    `}
                                    style={{
                                        left: note.startTime * beatWidth,
                                        width: (note.duration * beatWidth) - 2, // -2 for gap
                                        top: (7 - note.string) * 12 // Visual vertical string spacing
                                    }}
                                    onClick={() => playInstrumentNote(getFrequency(note.note, note.octave), instrument, 0.5)}
                                 >
                                     {note.note}{note.octave}
                                 </div>
                             );
                         })}
                     </div>
                 </div>
            </div>
        );
    };

    return (
        <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 h-full flex flex-col">

            {/* --- HEADER --- */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
                 <div>
                    <h2 className="text-xl font-bold text-white flex items-center gap-2">
                        <Wand2 className="text-yellow-500" />
                        Gerador de Progressões
                    </h2>
                    <p className="text-xs text-slate-400">Harmonia brasileira e linhas de baixo automático (IA)</p>
                 </div>

                 <div className="flex gap-2">
                    <button 
                        onClick={exportMidi}
                        className="flex items-center gap-2 px-3 py-2 bg-slate-700 hover:bg-slate-600 rounded-lg text-xs font-bold text-slate-300 transition-colors"
                    >
                        <Download size={14} /> MIDI
                    </button>
                    <button 
                        onClick={handleGenerate}
                        className="flex items-center gap-2 px-4 py-2 bg-yellow-500 hover:bg-yellow-400 text-slate-900 rounded-lg text-sm font-bold shadow-lg shadow-yellow-500/20 transition-all active:scale-95"
                    >
                        <RefreshCw size={16} /> Gerar Nova
                    </button>
                 </div>
            </div>

            {/* --- CONTROLS --- */}
            <div className="grid grid-cols-2 md:grid-cols-6 gap-3 mb-6 bg-slate-900/50 p-4 rounded-xl border border-slate-700">
                <div>
                    <label className="text-[10px] uppercase font-bold text-slate-500 block mb-1">Tom</label>
                    <select 
                        value={key} 
                        onChange={e => setKey(e.target.value as NoteName)}
                        className="w-full bg-slate-800 border border-slate-600 rounded px-2 py-1 text-sm"
                    >
                        {NOTES.map(n => <option key={n} value={n}>{n}</option>)}
                    </select>
                </div>
                <div>
                    <label className="text-[10px] uppercase font-bold text-slate-500 block mb-1">Estilo</label>
                    <select 
                        value={style} 
                        onChange={e => setStyle(e.target.value as RhythmStyle)}
                        className="w-full bg-slate-800 border border-slate-600 rounded px-2 py-1 text-sm"
                    >
                        {Object.values(RhythmStyle).map(s => <option key={s} value={s}>{s}</option>)}
                    </select>
                </div>
                <div className="md:col-span-1">
                    <label className="text-[10px] uppercase font-bold text-slate-500 block mb-1">Nível</label>
                    <select 
                        value={level} 
                        onChange={e => setLevel(e.target.value as any)}
                        className="w-full bg-slate-800 border border-slate-600 rounded px-2 py-1 text-sm"
                    >
                        <option value="Iniciante">Iniciante</option>
