import { NoteName, Chord, ChordQuality, SeventhStringTuning } from '../types';

export const NOTES: NoteName[] = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'];

// Map chords to their intervals (semitones from root)
export const CHORD_INTERVALS: Record<ChordQuality, number[]> = {
  'maj7': [0, 4, 7, 11],
  '7': [0, 4, 7, 10],
  'm7': [0, 3, 7, 10],
  'm7b5': [0, 3, 6, 10],
  'dim7': [0, 3, 6, 9],
  '6': [0, 4, 7, 9],
  'm6': [0, 3, 7, 9],
};

// --- SCALES & MODES ---
export type ScaleType = 'Major' | 'Minor' | 'Harmonic Minor' | 'Melodic Minor' | 'Dorian' | 'Phrygian' | 'Lydian' | 'Mixolydian' | 'Locrian';

export const SCALES: Record<ScaleType, number[]> = {
    'Major': [0, 2, 4, 5, 7, 9, 11], // Ionian
    'Minor': [0, 2, 3, 5, 7, 8, 10], // Aeolian
    'Harmonic Minor': [0, 2, 3, 5, 7, 8, 11], // Common in Choro
    'Melodic Minor': [0, 2, 3, 5, 7, 9, 11], // Common in Brazilian Jazz
    'Dorian': [0, 2, 3, 5, 7, 9, 10], // Minor 6 feel
    'Phrygian': [0, 1, 3, 5, 7, 8, 10], // Nordeste/Baião feel sometimes
    'Lydian': [0, 2, 4, 6, 7, 9, 11],
    'Mixolydian': [0, 2, 4, 5, 7, 9, 10], // Dominant/Samba
    'Locrian': [0, 1, 3, 5, 6, 8, 10]
};

export const INTERVAL_NAMES: Record<number, string> = {
    0: 'T', 1: 'b2', 2: '2M', 3: '3m', 4: '3M', 5: '4J', 6: '#4/b5', 7: '5J', 8: 'b6', 9: '6M', 10: '7m', 11: '7M'
};

export const getNoteIndex = (note: NoteName): number => NOTES.indexOf(note);

export const getNoteFromInterval = (root: NoteName, semitones: number): NoteName => {
  const rootIdx = getNoteIndex(root);
  return NOTES[(rootIdx + semitones) % 12];
};

export const getChordTones = (chord: Chord): NoteName[] => {
  const intervals = CHORD_INTERVALS[chord.quality];
  return intervals.map(i => getNoteFromInterval(chord.root, i));
};

export const getScaleNotes = (root: NoteName, scaleType: ScaleType): NoteName[] => {
    return SCALES[scaleType].map(interval => getNoteFromInterval(root, interval));
};

// --- Fretboard Mapping for 7-String ---

interface FretPosition {
  string: number; // 1-7
  fret: number;
  note: NoteName;
  octave: number;
}

// Base frequencies for string calculation
// Standard 7 String: E4, B3, G3, D3, A2, E2, B1
const STRING_OPEN_NOTES: { note: NoteName, octave: number }[] = [
  { note: 'E', octave: 4 }, // 1
  { note: 'B', octave: 3 }, // 2
  { note: 'G', octave: 3 }, // 3
  { note: 'D', octave: 3 }, // 4
  { note: 'A', octave: 2 }, // 5
  { note: 'E', octave: 2 }, // 6
  { note: 'B', octave: 1 }, // 7 (Default)
];

export const findFretPosition = (
  targetNote: NoteName, 
  targetOctave: number, 
  tuning: SeventhStringTuning, 
  prevFret?: number,
  prevString?: number
): FretPosition | null => {

  // Adjust 7th string based on tuning
  const currentStringNotes = [...STRING_OPEN_NOTES];
  if (tuning.includes('C')) {
    currentStringNotes[6] = { note: 'C', octave: 2 };
  } else if (tuning.includes('A')) {
    currentStringNotes[6] = { note: 'A', octave: 1 };
  } else {
    currentStringNotes[6] = { note: 'B', octave: 1 };
  }

  const possiblePositions: FretPosition[] = [];

  for (let s = 0; s < 7; s++) { // 0 to 6 (representing strings 1 to 7)
    const open = currentStringNotes[s];
    const openNoteIdx = getNoteIndex(open.note);
    // Base MIDI number approx calculation for comparison
    const openMidi = openNoteIdx + (open.octave + 1) * 12;

    const targetNoteIdx = getNoteIndex(targetNote);
    const targetMidi = targetNoteIdx + (targetOctave + 1) * 12;

    const diff = targetMidi - openMidi;

    // Standard guitar range usually goes up to 19th fret
    if (diff >= 0 && diff <= 19) { 
      possiblePositions.push({
        string: s + 1, // 1-based index
        fret: diff,
        note: targetNote,
        octave: targetOctave
      });
    }
  }

  if (possiblePositions.length === 0) return null;

  // LOGIC: Hand Position Optimization
  // If we have a previous position, choose the candidate with the closest fret number.
  // This simulates a real hand moving efficiently across strings rather than jumping wildly up/down the same string.
  if (prevFret !== undefined && prevString !== undefined) {
      possiblePositions.sort((a, b) => {
          // Calculate physical distance cost
          // Cost = abs(fret_diff) + (string_diff * penalty)
          // String changes are cheaper than massive fret jumps
          const costA = Math.abs(a.fret - prevFret) + Math.abs(a.string - prevString) * 0.5;
          const costB = Math.abs(b.fret - prevFret) + Math.abs(b.string - prevString) * 0.5;
          return costA - costB;
      });
  } else {
      // Default behavior (Start of phrase): Prefer lower strings (higher index) for that "Seven String" feel
      possiblePositions.sort((a, b) => b.string - a.string);
  }

  return possiblePositions[0];
};

export const getFrequency = (note: NoteName, octave: number): number => {
    const noteIdx = getNoteIndex(note);
    // A4 = 440Hz (Index 9, Octave 4)
    // MIDI number calculation: (Octave + 1) * 12 + Index
    const midi = (octave + 1) * 12 + noteIdx;
    const A4Midi = 69;
    return 440 * Math.pow(2, (midi - A4Midi) / 12);
};

import { BassNote, Chord, NoteName, RhythmStyle, SeventhStringTuning, ChordQuality } from '../types';
import { NOTES, getChordTones, findFretPosition, getNoteIndex, getScaleNotes, getNoteFromInterval } from '../utils/musicTheory';

// --- HELPERS ---
const getRandomInt = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;
const getRandomElement = <T>(arr: T[]): T => arr[Math.floor(Math.random() * arr.length)];

// --- PROGRESSION GENERATOR ---

// Progressions represented as relative semitone offset from Root + Chord Quality
// e.g. { r: 2, q: 'm7' } in key of C is Dm7
// { r: 1, q: '7' } in key of C is C#7 (SubV of G7?) No, Db7. 
// Note: Relative calculation handles sharps. 1 semitone up from C is C#. Db is enharmonic.

// Updated Pools with Brazilian Harmonic Logic
const PROGRESSION_POOLS = {
  'Iniciante': {
    'Samba': [
        // I - V7 basic
        [{ r: 0, q: '6' }, { r: 7, q: '7' }, { r: 0, q: '6' }, { r: 7, q: '7' }], 
        // I - IV - V7
        [{ r: 0, q: '6' }, { r: 5, q: 'maj7' }, { r: 7, q: '7' }, { r: 0, q: '6' }] 
    ],
    'Choro': [
        // Im - V7
        [{ r: 0, q: 'm6' }, { r: 7, q: '7' }, { r: 0, q: 'm6' }, { r: 7, q: '7' }], 
        // Im - IVm - V7
        [{ r: 0, q: 'm6' }, { r: 5, q: 'm6' }, { r: 7, q: '7' }, { r: 0, q: 'm6' }]
    ],
  },
  'Intermediário': {
    'Samba': [
        // Circular: I - VI7 - II7 - V7
        [{ r: 0, q: '6' }, { r: 9, q: '7' }, { r: 2, q: 'm7' }, { r: 7, q: '7' }], 
        // "Quadrado": I - III7 - VI7 - II7 - V7
        [{ r: 0, q: 'maj7' }, { r: 4, q: '7' }, { r: 9, q: '7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
    'Choro': [
        // Descida Cromática de Baixo (ex: Am - Am/G - D/F# - Fmaj7 - E7) -> Simulated via chords
        // Im - V7/IV - IV - bVI7 - V7
        [{ r: 0, q: 'm7' }, { r: 0, q: '7' }, { r: 5, q: 'm7' }, { r: 8, q: '7' }, { r: 7, q: '7' }],
        // Empréstimo Modal (Samba/Choro): I - Im - I
        [{ r: 0, q: 'maj7' }, { r: 5, q: 'm6' }, { r: 0, q: 'maj7' }, { r: 7, q: '7' }]
    ],
  },
  'Avançado': {
    'Samba': [
        // SubV7 Replacement (Tritone Subs)
        // Imaj7 - bIIIdim - IIm7 - bII7 (SubV) - I
        [{ r: 0, q: 'maj7' }, { r: 3, q: 'dim7' }, { r: 2, q: 'm7' }, { r: 1, q: '7' }, { r: 0, q: '6' }],
        // Deceptive Cadences
        [{ r: 0, q: '6' }, { r: 11, q: 'm7b5' }, { r: 4, q: '7' }, { r: 9, q: 'm7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
    'Choro': [
        // The "Cristal" cadence type
        // I - #Io - II - #IIo - III - VI7 ...
        [{ r: 0, q: '6' }, { r: 1, q: 'dim7' }, { r: 2, q: 'm7' }, { r: 3, q: 'dim7' }, { r: 4, q: 'm7' }, { r: 7, q: '7' }],
        // Modulating feel
        [{ r: 0, q: 'm6' }, { r: 7, q: '7' }, { r: 4, q: '7' }, { r: 9, q: '7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
  }
};

/**
 * Creates a unique harmonic progression based on level
 */
export const generateProgression = (key: NoteName, level: string): Chord[] => {
  const progression: Chord[] = [];
  const keyIdx = getNoteIndex(key);
  const getRelNote = (semitones: number) => NOTES[(keyIdx + semitones) % 12];

  // Logic to get variants
  const lvlKey = level as keyof typeof PROGRESSION_POOLS;
  const styles = Object.keys(PROGRESSION_POOLS[lvlKey]);
  const randomStyle = getRandomElement(styles);

  // @ts-ignore - Dynamic key access
  const pool = PROGRESSION_POOLS[lvlKey][randomStyle] as any[];
  const choice = getRandomElement(pool) as any[];

  choice.forEach((c: any) => {
      progression.push({ 
          root: getRelNote(c.r), 
          quality: c.q as any, 
          display: `${getRelNote(c.r)}${c.q}`, 
          duration: level === 'Iniciante' ? 4 : 2 
      });
  });

  return progression;
};

// --- BASS LINE STRATEGIES ---

type Strategy = 'ROOT_FIFTH' | 'SCALE_RUN' | 'CHROMATIC_APPROACH' | 'ARPEGGIO';

/**
 * THE BRAIN: Generates a stochastic bass line that traverses the fretboard
 */
export const generateBassLine = (
  progression: Chord[],
  style: RhythmStyle,
  level: 'Iniciante' | 'Intermediário' | 'Avançado',
  tuning: SeventhStringTuning
): BassNote[] => {
  const notes: BassNote[] = [];
  let currentBeatOffset = 0;

  // Track the very first note MIDI to ensure perfect loop resolution
  let firstNoteMidi: number | null = null;
  let prevNoteMidi = -1; 

  // Track previous physical position for smooth fretboard traversal
  let lastPos: { fret: number, string: number } | undefined = undefined;

  progression.forEach((chord, index) => {
    const nextChord = progression[(index + 1) % progression.length];
    const beatsInChord = chord.duration;

    // DECISION: Strategy
    let strategy: Strategy = 'ROOT_FIFTH';
    const rand = Math.random();

    if (level === 'Iniciante') {
        strategy = 'ROOT_FIFTH';
    } else if (level === 'Intermediário') {
        strategy = rand > 0.6 ? 'CHROMATIC_APPROACH' : 'ROOT_FIFTH';
    } else {
        // Advanced mixes everything
        if (style === RhythmStyle.CHORO) strategy = rand > 0.3 ? 'SCALE_RUN' : 'ARPEGGIO';
        else strategy = rand > 0.5 ? 'CHROMATIC_APPROACH' : 'ARPEGGIO';
    }

    // --- BEAT 1: ANCHOR ---
    // Start with root, but depending on level, we might start on a higher root position
    let rootOctave = 2; 
    if (tuning.includes('C') && chord.root === 'C') rootOctave = 2;
    if (tuning.includes('B') && chord.root === 'B') rootOctave = 1;

    // Try to find fret position. Pass lastPos to optimize hand movement
    const rootPos = findFretPosition(chord.root, rootOctave, tuning, lastPos?.fret, lastPos?.string) 
                    || findFretPosition(chord.root, 3, tuning, lastPos?.fret, lastPos?.string);

    if (rootPos) {
        notes.push({
           ...rootPos,
           duration: style === RhythmStyle.CHORO ? 0.25 : 1, 
           startTime: currentBeatOffset,
           isChordTone: true
        });

        // Store MIDI for calculations
        const thisMidi = getNoteIndex(rootPos.note) + (rootPos.octave + 1) * 12;

        if (index === 0) firstNoteMidi = thisMidi;
        prevNoteMidi = thisMidi;
        lastPos = { fret: rootPos.fret, string: rootPos.string };
    }

    // --- FILLS ---

    // Determine Target for the fill
    let targetMidi: number;
    let targetNoteName: NoteName;

    if (index === progression.length - 1 && firstNoteMidi !== null) {
        // Loop Resolution: Aim for the EXACT start note of the loop
        targetMidi = firstNoteMidi;
        targetNoteName = NOTES[targetMidi % 12];
    } else {
        // Standard Transition: Aim for next chord root
        targetNoteName = nextChord.root;

        // Intelligent Octave Guessing
        // Allow higher target octaves for runs to force string crossing
        let tOct = 2;
        if ((tuning.includes('B') || tuning.includes('A')) && ['A','B'].includes(targetNoteName)) {
             tOct = 1;
        }
        if (tuning.includes('C') && targetNoteName === 'C') {
             tOct = 2; 
        }

        // If previous note was high, maybe target a higher root for smooth voice leading?
        if (prevNoteMidi > 55 && Math.random() > 0.5) tOct = 3; 

        targetMidi = getNoteIndex(targetNoteName) + (tOct + 1) * 12;
    }

    if (strategy === 'ROOT_FIFTH') {
        const fifth = getChordTones(chord)[2];
        const fifthPos = findFretPosition(fifth, 2, tuning, lastPos?.fret, lastPos?.string) 
                        || findFretPosition(fifth, 3, tuning, lastPos?.fret, lastPos?.string);

        if (beatsInChord >= 2 && fifthPos) {
            notes.push({
                ...fifthPos,
                duration: 0.5,
                startTime: currentBeatOffset + 1.0,
                isChordTone: true
            });
            lastPos = { fret: fifthPos.fret, string: fifthPos.string };
            prevNoteMidi = getNoteIndex(fifthPos.note) + (fifthPos.octave + 1) * 12;
        }
    }
    else if (strategy === 'CHROMATIC_APPROACH') {
        const approachCount = getRandomInt(1, 3);

        for(let i = approachCount; i > 0; i--) {
            // Direction usually opposes the jump. If target is higher, approach from below.
            const diff = targetMidi - prevNoteMidi;
            const direction = diff > 0 ? 1 : -1;

            // Standard approach: if target is G, approach F#, F (from below)
            const semitoneOffset = i * direction * -1; 

            const approachMidi = targetMidi + semitoneOffset;
            const appNoteIdx = approachMidi % 12;
            const appNoteName = NOTES[appNoteIdx];
            const appOctave = Math.floor(approachMidi / 12) - 1;

            const pos = findFretPosition(appNoteName, appOctave, tuning, lastPos?.fret, lastPos?.string);

            if (pos) {
                const timeSlot = currentBeatOffset + beatsInChord - (i * 0.25);
                notes.push({
                    ...pos,
                    duration: 0.25,
                    startTime: timeSlot,
                    isChromatic: true
                });
                lastPos = { fret: pos.fret, string: pos.string };
                prevNoteMidi = approachMidi;
            }
        }
    }
    else if (strategy === 'SCALE_RUN' || strategy === 'ARPEGGIO') {
        const slots = (beatsInChord * 4) - 1; 
        let currentMidi = prevNoteMidi;

        for(let i = 1; i <= slots; i++) {
            let nextMidiCandidate = 0;

            // Bias movement towards the target
            const diff = targetMidi - currentMidi;
            const step = diff > 0 ? 1 : diff < 0 ? -1 : 0;

            // Add randomness to step size
            let leap = 1;
            if (strategy === 'ARPEGGIO') leap = Math.random() > 0.4 ? 3 : 4; // Major/Minor 3rds
            else leap = Math.random() > 0.8 ? 2 : 1; // Seconds usually

            // Stochastic movement
            if (Math.abs(diff) > leap) {
                // Move towards target
                nextMidiCandidate = currentMidi + (step * leap);
            } else {
                 // Close enough? Meander a bit or hit target early
                 nextMidiCandidate = targetMidi + getRandomInt(-1, 1);
            }

            // RANGE EXPANSION:
            // Allow notes up to ~F4/G4 (Midi ~77) to force usage of high strings
            if (nextMidiCandidate < 35 || nextMidiCandidate > 77) {
                // If out of bounds, fold back
                nextMidiCandidate = currentMidi - step * 2;
            }

            const candidateOctave = Math.floor(nextMidiCandidate / 12) - 1;
            const candidateNoteIdx = nextMidiCandidate % 12;
            const candidateNote = NOTES[candidateNoteIdx];

            const pos = findFretPosition(candidateNote, candidateOctave, tuning, lastPos?.fret, lastPos?.string);

            if (pos) {
                notes.push({
                    ...pos,
                    duration: 0.25,
                    startTime: currentBeatOffset + (i * 0.25),
                    isChordTone: getChordTones(chord).includes(candidateNote)
                });
                currentMidi = nextMidiCandidate;
                lastPos = { fret: pos.fret, string: pos.string };
                prevNoteMidi = nextMidiCandidate;
            }
        }
    }

    currentBeatOffset += beatsInChord;
  });

  return notes.sort((a, b) => a.startTime - b.startTime);
};

import { BassNote, Chord, NoteName, RhythmStyle, SeventhStringTuning, ChordQuality } from '../types';
import { NOTES, getChordTones, findFretPosition, getNoteIndex, getScaleNotes, getNoteFromInterval } from '../utils/musicTheory';

// --- HELPERS ---
const getRandomInt = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;
const getRandomElement = <T>(arr: T[]): T => arr[Math.floor(Math.random() * arr.length)];

// --- PROGRESSION GENERATOR ---
// (Mantendo as progressões existentes, mas a lógica de geração de notas muda abaixo)
const PROGRESSION_POOLS = {
  'Iniciante': {
    'Samba': [
        [{ r: 0, q: '6' }, { r: 7, q: '7' }, { r: 0, q: '6' }, { r: 7, q: '7' }], 
        [{ r: 0, q: '6' }, { r: 5, q: 'maj7' }, { r: 7, q: '7' }, { r: 0, q: '6' }] 
    ],
    'Choro': [
        [{ r: 0, q: 'm6' }, { r: 7, q: '7' }, { r: 0, q: 'm6' }, { r: 7, q: '7' }], 
        [{ r: 0, q: 'm6' }, { r: 5, q: 'm6' }, { r: 7, q: '7' }, { r: 0, q: 'm6' }]
    ],
  },
  'Intermediário': {
    'Samba': [
        [{ r: 0, q: '6' }, { r: 9, q: '7' }, { r: 2, q: 'm7' }, { r: 7, q: '7' }], 
        [{ r: 0, q: 'maj7' }, { r: 4, q: '7' }, { r: 9, q: '7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
    'Choro': [
        [{ r: 0, q: 'm7' }, { r: 0, q: '7' }, { r: 5, q: 'm7' }, { r: 8, q: '7' }, { r: 7, q: '7' }],
        [{ r: 0, q: 'maj7' }, { r: 5, q: 'm6' }, { r: 0, q: 'maj7' }, { r: 7, q: '7' }]
    ],
  },
  'Avançado': {
    'Samba': [
        [{ r: 0, q: 'maj7' }, { r: 3, q: 'dim7' }, { r: 2, q: 'm7' }, { r: 1, q: '7' }, { r: 0, q: '6' }],
        [{ r: 0, q: '6' }, { r: 11, q: 'm7b5' }, { r: 4, q: '7' }, { r: 9, q: 'm7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
    'Choro': [
        [{ r: 0, q: '6' }, { r: 1, q: 'dim7' }, { r: 2, q: 'm7' }, { r: 3, q: 'dim7' }, { r: 4, q: 'm7' }, { r: 7, q: '7' }],
        [{ r: 0, q: 'm6' }, { r: 7, q: '7' }, { r: 4, q: '7' }, { r: 9, q: '7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
  }
};

export const generateProgression = (key: NoteName, level: string): Chord[] => {
  const progression: Chord[] = [];
  const keyIdx = getNoteIndex(key);
  const getRelNote = (semitones: number) => NOTES[(keyIdx + semitones) % 12];

  const lvlKey = level as keyof typeof PROGRESSION_POOLS;
  const styles = Object.keys(PROGRESSION_POOLS[lvlKey]);
  const randomStyle = getRandomElement(styles);

  // @ts-ignore
  const pool = PROGRESSION_POOLS[lvlKey][randomStyle] as any[];
  const choice = getRandomElement(pool) as any[];

  choice.forEach((c: any) => {
      progression.push({ 
          root: getRelNote(c.r), 
          quality: c.q as any, 
          display: `${getRelNote(c.r)}${c.q}`, 
          duration: level === 'Iniciante' ? 4 : 2 
      });
  });

  return progression;
};

// --- BASS LINE STRATEGIES ---

type Strategy = 'ROOT_FIFTH' | 'MELODIC_COUNTERPOINT' | 'CHROMATIC_APPROACH' | 'ARPEGGIO_FULL_RANGE';

/**
 * THE BRAIN: Generates a stochastic bass line that traverses the ENTIRE fretboard
 * Implements "Call (Bass) and Response (Treble)" logic typical of 7-string guitar.
 */
export const generateBassLine = (
  progression: Chord[],
  style: RhythmStyle,
  level: 'Iniciante' | 'Intermediário' | 'Avançado',
  tuning: SeventhStringTuning
): BassNote[] => {
  const notes: BassNote[] = [];
  let currentBeatOffset = 0;

  let firstNoteMidi: number | null = null;
  let prevNoteMidi = -1; 
  let lastPos: { fret: number, string: number } | undefined = undefined;

  progression.forEach((chord, index) => {
    const nextChord = progression[(index + 1) % progression.length];
    const beatsInChord = chord.duration;

    // DECISION: Strategy
    let strategy: Strategy = 'ROOT_FIFTH';
    const rand = Math.random();

    if (level === 'Iniciante') {
        strategy = 'ROOT_FIFTH';
    } else if (level === 'Intermediário') {
        // More movement
        strategy = rand > 0.5 ? 'MELODIC_COUNTERPOINT' : 'ROOT_FIFTH';
    } else {
        // Advanced: Use full range arpeggios and counterpoint
        if (style === RhythmStyle.CHORO) strategy = rand > 0.2 ? 'ARPEGGIO_FULL_RANGE' : 'MELODIC_COUNTERPOINT';
        else strategy = rand > 0.4 ? 'MELODIC_COUNTERPOINT' : 'CHROMATIC_APPROACH';
    }

    // --- BEAT 1: THE ANCHOR (ALWAYS DEEP) ---
    // The "Surdo" of the guitar. We want strings 7, 6, 5 here.
    let rootOctave = 2; 
    if (tuning.includes('C') && chord.root === 'C') rootOctave = 2; // Low C on 7th
    if (tuning.includes('B') && chord.root === 'B') rootOctave = 1; // Low B on 7th
    if (['F', 'F#', 'G', 'G#'].includes(chord.root)) rootOctave = 2; // E string area
    if (['A', 'A#'].includes(chord.root) && !tuning.includes('A')) rootOctave = 2; // A string area

    // Find position specifically preferring lower strings (5, 6, 7) for the root
    let rootPos = findFretPosition(chord.root, rootOctave, tuning, undefined, undefined); // No prev context to force reset to bass

    // Fallback if low note not found (rare)
    if (!rootPos) rootPos = findFretPosition(chord.root, 3, tuning);

    if (rootPos) {
        notes.push({
           ...rootPos,
           duration: style === RhythmStyle.CHORO ? 0.25 : 0.75, // Dotted feel for Samba often
           startTime: currentBeatOffset,
           isChordTone: true
        });

        const thisMidi = getNoteIndex(rootPos.note) + (rootPos.octave + 1) * 12;
        if (index === 0) firstNoteMidi = thisMidi;
        prevNoteMidi = thisMidi;
        lastPos = { fret: rootPos.fret, string: rootPos.string };
    }

    // --- FILLS / PHRASING (THE RESPONSE) ---

    // Determine Target for the NEXT chord (Resolution)
    let finalTargetMidi: number;
    if (index === progression.length - 1 && firstNoteMidi !== null) {
        finalTargetMidi = firstNoteMidi;
    } else {
        // Guess next root octave (keep it low for the landing)
        const nextNoteIdx = getNoteIndex(nextChord.root);
        // Default to octave 2 or 1 for landing
        let landOct = 2;
        if (tuning.includes('B') && nextChord.root === 'B') landOct = 1;
        finalTargetMidi = nextNoteIdx + (landOct + 1) * 12;
    }

    if (strategy === 'ROOT_FIFTH') {
        // Simple bass toggle
        const fifth = getChordTones(chord)[2];
        const fifthPos = findFretPosition(fifth, 2, tuning) || findFretPosition(fifth, 3, tuning);

        if (beatsInChord >= 2 && fifthPos) {
            notes.push({
                ...fifthPos,
                duration: 0.5,
                startTime: currentBeatOffset + 1.0,
                isChordTone: true
            });
            lastPos = { fret: fifthPos.fret, string: fifthPos.string };
            prevNoteMidi = getNoteIndex(fifthPos.note) + (fifthPos.octave + 1) * 12;
        }
    }
    else if (strategy === 'CHROMATIC_APPROACH') {
        // Classic approach from below/above
        // Stay relatively low but allow moving to D string
        const approachCount = getRandomInt(2, 4);
        const startBeat = beatsInChord - (approachCount * 0.25);

        for(let i = 0; i < approachCount; i++) {
             const distToEnd = approachCount - i;
             const direction = finalTargetMidi > prevNoteMidi ? 1 : -1;

             // Linear chromatic movement towards target
             // Target - distToEnd
             const noteMidi = finalTargetMidi + (distToEnd * (Math.random() > 0.5 ? -1 : 1)); // Approach from above or below

             // Enforce range?

             const nInfo = midiToNote(noteMidi);
             const pos = findFretPosition(nInfo.note, nInfo.octave, tuning, lastPos?.fret, lastPos?.string);

             if (pos) {
                 notes.push({
                     ...pos,
                     duration: 0.25,
                     startTime: currentBeatOffset + startBeat + (i * 0.25),
                     isChromatic: true
                 });
                 lastPos = { fret: pos.fret, string: pos.string };
                 prevNoteMidi = noteMidi;
             }
        }
    }
    else if (strategy === 'MELODIC_COUNTERPOINT' || strategy === 'ARPEGGIO_FULL_RANGE') {
        // THIS IS THE KEY CHANGE FOR THE USER
        // We want to jump UP to the high strings (G, B, E) and then cascade down

        const numNotes = (beatsInChord * 4) - 1; // 16th notes filling the bar minus root
        const startBeat = 0.25;

        // 1. Determine High Point (Climax of phrase)
        // Let's aim for a high chord tone (3rd, 5th, 7th) in Octave 3 or 4
        // String G3 is Midi 55. High E is Midi 64. 12th fret High E is 76.
        // Let's target range 55 - 75.

        const chordTones = getChordTones(chord);
        let currentMidi = prevNoteMidi;

        // Define a melodic contour: UP -> DOWN
        // or UP -> HOVER -> DOWN

        for(let i = 0; i < numNotes; i++) {
            const timePos = currentBeatOffset + startBeat + (i * 0.25);
            const notesLeft = numNotes - i;

            let nextMidi = currentMidi;

            if (i < numNotes / 2) {
                // ASCENDING PHASE (Go to High Strings!)
                // Jump large intervals (arpeggios)
                const interval = getRandomElement([3, 4, 5, 7]);
                nextMidi = currentMidi + interval;

                // Keep it tonal mostly
                // Snap to scale?
            } else {
                // DESCENDING PHASE (Return to Bass)
                // Aim towards finalTargetMidi
                const diff = finalTargetMidi - currentMidi;
                const step = diff > 0 ? 1 : -1;

                // If far away, leap. If close, step.
                if (Math.abs(diff) > 12) nextMidi = currentMidi + (step * 4); // Fast descent
                else if (Math.abs(diff) > 5) nextMidi = currentMidi + (step * 2);
                else nextMidi = currentMidi + step; // Chromatic landing
            }

            // Cap ranges
            if (nextMidi > 78) nextMidi = 78; // Cap at ~High F#
            if (nextMidi < 35) nextMidi = 35; // Cap at Low B

            // Convert MIDI to Note
            const nInfo = midiToNote(nextMidi);

            // Try to find position. 
            // IMPORTANT: If we are high (Midi > 55), we prefer higher strings. 
            // `findFretPosition` usually handles this via range, but we pass lastPos to smooth it.
            const pos = findFretPosition(nInfo.note, nInfo.octave, tuning, lastPos?.fret, lastPos?.string);

            if (pos) {
                notes.push({
                    ...pos,
                    duration: 0.25,
                    startTime: timePos,
                    isChordTone: chordTones.includes(nInfo.note)
                });
                lastPos = { fret: pos.fret, string: pos.string };
                currentMidi = nextMidi;
            }
        }
    }

    currentBeatOffset += beatsInChord;
  });

  return notes.sort((a, b) => a.startTime - b.startTime);
};

// Helper
const midiToNote = (midi: number): { note: NoteName, octave: number } => {
    const idx = midi % 12;
    const oct = Math.floor(midi / 12) - 1;
    return { note: NOTES[idx], octave: oct };
}

import { NoteName, Chord, ChordQuality, SeventhStringTuning } from '../types';

export const NOTES: NoteName[] = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'];

// Map chords to their intervals (semitones from root)
export const CHORD_INTERVALS: Record<ChordQuality, number[]> = {
  'maj7': [0, 4, 7, 11],
  '7': [0, 4, 7, 10],
  'm7': [0, 3, 7, 10],
  'm7b5': [0, 3, 6, 10],
  'dim7': [0, 3, 6, 9],
  '6': [0, 4, 7, 9],
  'm6': [0, 3, 7, 9],
};

// --- SCALES & MODES ---
export type ScaleType = 'Major' | 'Minor' | 'Harmonic Minor' | 'Melodic Minor' | 'Dorian' | 'Phrygian' | 'Lydian' | 'Mixolydian' | 'Locrian';

export const SCALES: Record<ScaleType, number[]> = {
    'Major': [0, 2, 4, 5, 7, 9, 11], // Ionian
    'Minor': [0, 2, 3, 5, 7, 8, 10], // Aeolian
    'Harmonic Minor': [0, 2, 3, 5, 7, 8, 11], // Common in Choro
    'Melodic Minor': [0, 2, 3, 5, 7, 9, 11], // Common in Brazilian Jazz
    'Dorian': [0, 2, 3, 5, 7, 9, 10], // Minor 6 feel
    'Phrygian': [0, 1, 3, 5, 7, 8, 10], // Nordeste/Baião feel sometimes
    'Lydian': [0, 2, 4, 6, 7, 9, 11],
    'Mixolydian': [0, 2, 4, 5, 7, 9, 10], // Dominant/Samba
    'Locrian': [0, 1, 3, 5, 6, 8, 10]
};

export const INTERVAL_NAMES: Record<number, string> = {
    0: 'T', 1: 'b2', 2: '2M', 3: '3m', 4: '3M', 5: '4J', 6: '#4/b5', 7: '5J', 8: 'b6', 9: '6M', 10: '7m', 11: '7M'
};

export const getNoteIndex = (note: NoteName): number => NOTES.indexOf(note);

export const getNoteFromInterval = (root: NoteName, semitones: number): NoteName => {
  const rootIdx = getNoteIndex(root);
  return NOTES[(rootIdx + semitones) % 12];
};

export const getChordTones = (chord: Chord): NoteName[] => {
  const intervals = CHORD_INTERVALS[chord.quality];
  return intervals.map(i => getNoteFromInterval(chord.root, i));
};

export const getScaleNotes = (root: NoteName, scaleType: ScaleType): NoteName[] => {
    return SCALES[scaleType].map(interval => getNoteFromInterval(root, interval));
};

// --- Fretboard Mapping for 7-String ---

interface FretPosition {
  string: number; // 1-7
  fret: number;
  note: NoteName;
  octave: number;
}

// Base frequencies for string calculation
// Standard 7 String: E4, B3, G3, D3, A2, E2, B1
const STRING_OPEN_NOTES: { note: NoteName, octave: number }[] = [
  { note: 'E', octave: 4 }, // 1 (High E)
  { note: 'B', octave: 3 }, // 2
  { note: 'G', octave: 3 }, // 3
  { note: 'D', octave: 3 }, // 4
  { note: 'A', octave: 2 }, // 5
  { note: 'E', octave: 2 }, // 6
  { note: 'B', octave: 1 }, // 7 (Default)
];

export const findFretPosition = (
  targetNote: NoteName, 
  targetOctave: number, 
  tuning: SeventhStringTuning, 
  prevFret?: number,
  prevString?: number
): FretPosition | null => {

  // Adjust 7th string based on tuning
  const currentStringNotes = [...STRING_OPEN_NOTES];
  if (tuning.includes('C')) {
    currentStringNotes[6] = { note: 'C', octave: 2 };
  } else if (tuning.includes('A')) {
    currentStringNotes[6] = { note: 'A', octave: 1 };
  } else {
    currentStringNotes[6] = { note: 'B', octave: 1 };
  }

  const possiblePositions: FretPosition[] = [];

  for (let s = 0; s < 7; s++) { // 0 to 6 (representing strings 1 to 7)
    const open = currentStringNotes[s];
    const openNoteIdx = getNoteIndex(open.note);
    // Base MIDI number approx calculation for comparison
    const openMidi = openNoteIdx + (open.octave + 1) * 12;

    const targetNoteIdx = getNoteIndex(targetNote);
    const targetMidi = targetNoteIdx + (targetOctave + 1) * 12;

    const diff = targetMidi - openMidi;

    // Allow up to 21 frets
    if (diff >= 0 && diff <= 21) { 
      possiblePositions.push({
        string: s + 1, // 1-based index
        fret: diff,
        note: targetNote,
        octave: targetOctave
      });
    }
  }

  if (possiblePositions.length === 0) return null;

  // LOGIC: Hand Position Optimization
  if (prevFret !== undefined && prevString !== undefined) {
      possiblePositions.sort((a, b) => {
          // Calculate physical distance cost
          // We want to penalize jumping across strings LESS if it gets us the note we need in the octave we need
          // But prioritize staying in a "box" position if possible.

          const fretDistA = Math.abs(a.fret - prevFret);
          const fretDistB = Math.abs(b.fret - prevFret);
          const stringDistA = Math.abs(a.string - prevString);
          const stringDistB = Math.abs(b.string - prevString);

          const costA = fretDistA + (stringDistA * 1.5);
          const costB = fretDistB + (stringDistB * 1.5);

          return costA - costB;
      });
  } else {
      // Default: If looking for low notes (Octave 1 or 2), prefer lower strings (higher index).
      // If looking for high notes (Octave 3 or 4), prefer higher strings (lower index).
      if (targetOctave >= 3) {
           possiblePositions.sort((a, b) => a.string - b.string); // Prefer string 1, 2, 3
      } else {
           possiblePositions.sort((a, b) => b.string - a.string); // Prefer string 7, 6, 5
      }
  }

  return possiblePositions[0];
};

export const getFrequency = (note: NoteName, octave: number): number => {
    const noteIdx = getNoteIndex(note);
    const midi = (octave + 1) * 12 + noteIdx;
    const A4Midi = 69;
    return 440 * Math.pow(2, (midi - A4Midi) / 12);
};

import { NoteName, Chord, ChordQuality, SeventhStringTuning } from '../types';

export const NOTES: NoteName[] = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'];

// Map chords to their intervals (semitones from root)
export const CHORD_INTERVALS: Record<ChordQuality, number[]> = {
  'maj7': [0, 4, 7, 11],
  '7': [0, 4, 7, 10],
  'm7': [0, 3, 7, 10],
  'm7b5': [0, 3, 6, 10],
  'dim7': [0, 3, 6, 9],
  '6': [0, 4, 7, 9],
  'm6': [0, 3, 7, 9],
};

// --- SCALES & MODES ---
export type ScaleType = 'Major' | 'Minor' | 'Harmonic Minor' | 'Melodic Minor' | 'Dorian' | 'Phrygian' | 'Lydian' | 'Mixolydian' | 'Locrian';

export const SCALES: Record<ScaleType, number[]> = {
    'Major': [0, 2, 4, 5, 7, 9, 11], // Ionian
    'Minor': [0, 2, 3, 5, 7, 8, 10], // Aeolian
    'Harmonic Minor': [0, 2, 3, 5, 7, 8, 11], // Common in Choro
    'Melodic Minor': [0, 2, 3, 5, 7, 9, 11], // Common in Brazilian Jazz
    'Dorian': [0, 2, 3, 5, 7, 9, 10], // Minor 6 feel
    'Phrygian': [0, 1, 3, 5, 7, 8, 10], // Nordeste/Baião feel sometimes
    'Lydian': [0, 2, 4, 6, 7, 9, 11],
    'Mixolydian': [0, 2, 4, 5, 7, 9, 10], // Dominant/Samba
    'Locrian': [0, 1, 3, 5, 6, 8, 10]
};

export const INTERVAL_NAMES: Record<number, string> = {
    0: 'T', 1: 'b2', 2: '2M', 3: '3m', 4: '3M', 5: '4J', 6: '#4/b5', 7: '5J', 8: 'b6', 9: '6M', 10: '7m', 11: '7M'
};

export const getNoteIndex = (note: NoteName): number => NOTES.indexOf(note);

export const getNoteFromInterval = (root: NoteName, semitones: number): NoteName => {
  const rootIdx = getNoteIndex(root);
  return NOTES[(rootIdx + semitones) % 12];
};

export const getChordTones = (chord: Chord): NoteName[] => {
  const intervals = CHORD_INTERVALS[chord.quality];
  return intervals.map(i => getNoteFromInterval(chord.root, i));
};

export const getScaleNotes = (root: NoteName, scaleType: ScaleType): NoteName[] => {
    return SCALES[scaleType].map(interval => getNoteFromInterval(root, interval));
};

// --- Fretboard Mapping for 7-String ---

interface FretPosition {
  string: number; // 1-7
  fret: number;
  note: NoteName;
  octave: number;
}

// Base frequencies for string calculation
// Standard 7 String: E4, B3, G3, D3, A2, E2, B1
const STRING_OPEN_NOTES: { note: NoteName, octave: number }[] = [
  { note: 'E', octave: 4 }, // 1 (High E)
  { note: 'B', octave: 3 }, // 2
  { note: 'G', octave: 3 }, // 3
  { note: 'D', octave: 3 }, // 4
  { note: 'A', octave: 2 }, // 5
  { note: 'E', octave: 2 }, // 6
  { note: 'B', octave: 1 }, // 7 (Default)
];

export const findFretPosition = (
  targetNote: NoteName, 
  targetOctave: number, 
  tuning: SeventhStringTuning, 
  prevFret?: number,
  prevString?: number
): FretPosition | null => {

  // Adjust 7th string based on tuning
  const currentStringNotes = [...STRING_OPEN_NOTES];
  if (tuning.includes('C')) {
    currentStringNotes[6] = { note: 'C', octave: 2 };
  } else if (tuning.includes('A')) {
    currentStringNotes[6] = { note: 'A', octave: 1 };
  } else {
    currentStringNotes[6] = { note: 'B', octave: 1 };
  }

  const possiblePositions: FretPosition[] = [];

  for (let s = 0; s < 7; s++) { // 0 to 6 (representing strings 1 to 7)
    const open = currentStringNotes[s];
    const openNoteIdx = getNoteIndex(open.note);
    // Base MIDI number approx calculation for comparison
    const openMidi = openNoteIdx + (open.octave + 1) * 12;

    const targetNoteIdx = getNoteIndex(targetNote);
    const targetMidi = targetNoteIdx + (targetOctave + 1) * 12;

    const diff = targetMidi - openMidi;

    // STRICT CONSTRAINT: Prefer first 5 frets, allow up to 12 if absolutely necessary
    if (diff >= 0 && diff <= 19) { 
      possiblePositions.push({
        string: s + 1, // 1-based index
        fret: diff,
        note: targetNote,
        octave: targetOctave
      });
    }
  }

  if (possiblePositions.length === 0) return null;

  // LOGIC: Hand Position Optimization (First 5 Frets Priority)

  // 1. Filter: If we have options in frets 0-5, discard everything else.
  const openPositionOptions = possiblePositions.filter(p => p.fret <= 5);
  const candidates = openPositionOptions.length > 0 ? openPositionOptions : possiblePositions;

  if (prevFret !== undefined && prevString !== undefined) {
      candidates.sort((a, b) => {
          // Calculate physical distance cost
          const fretDistA = Math.abs(a.fret - prevFret);
          const fretDistB = Math.abs(b.fret - prevFret);
          const stringDistA = Math.abs(a.string - prevString);
          const stringDistB = Math.abs(b.string - prevString);

          // Heavily penalize frets > 5 if we are in strict mode (already filtered above mostly)
          // Also prioritize string efficiency
          const costA = fretDistA + (stringDistA * 0.8);
          const costB = fretDistB + (stringDistB * 0.8);

          return costA - costB;
      });
  } else {
      // Default: Prefer lower frets first, then prefer strings that make sense for the octave
      candidates.sort((a, b) => {
          if (a.fret !== b.fret) return a.fret - b.fret; // Lowest fret wins
          return b.string - a.string; // Then prefer thicker strings for tone? Or thinner? Let's prefer thicker for jazz/choro warmth
      });
  }

  return candidates[0];
};

export const getFrequency = (note: NoteName, octave: number): number => {
    const noteIdx = getNoteIndex(note);
    const midi = (octave + 1) * 12 + noteIdx;
    const A4Midi = 69;
    return 440 * Math.pow(2, (midi - A4Midi) / 12);
};

import { BassNote, Chord, NoteName, RhythmStyle, SeventhStringTuning, ChordQuality } from '../types';
import { NOTES, getChordTones, findFretPosition, getNoteIndex, getScaleNotes, getNoteFromInterval } from '../utils/musicTheory';

// --- HELPERS ---
const getRandomInt = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;
const getRandomElement = <T>(arr: T[]): T => arr[Math.floor(Math.random() * arr.length)];

// --- PROGRESSION GENERATOR ---
const PROGRESSION_POOLS = {
  'Iniciante': {
    'Samba': [
        [{ r: 0, q: '6' }, { r: 7, q: '7' }, { r: 0, q: '6' }, { r: 7, q: '7' }], 
        [{ r: 0, q: '6' }, { r: 5, q: 'maj7' }, { r: 7, q: '7' }, { r: 0, q: '6' }] 
    ],
    'Choro': [
        [{ r: 0, q: 'm6' }, { r: 7, q: '7' }, { r: 0, q: 'm6' }, { r: 7, q: '7' }], 
        [{ r: 0, q: 'm6' }, { r: 5, q: 'm6' }, { r: 7, q: '7' }, { r: 0, q: 'm6' }]
    ],
  },
  'Intermediário': {
    'Samba': [
        [{ r: 0, q: '6' }, { r: 9, q: '7' }, { r: 2, q: 'm7' }, { r: 7, q: '7' }], 
        [{ r: 0, q: 'maj7' }, { r: 4, q: '7' }, { r: 9, q: '7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
    'Choro': [
        [{ r: 0, q: 'm7' }, { r: 0, q: '7' }, { r: 5, q: 'm7' }, { r: 8, q: '7' }, { r: 7, q: '7' }],
        [{ r: 0, q: 'maj7' }, { r: 5, q: 'm6' }, { r: 0, q: 'maj7' }, { r: 7, q: '7' }]
    ],
  },
  'Avançado': {
    'Samba': [
        [{ r: 0, q: 'maj7' }, { r: 3, q: 'dim7' }, { r: 2, q: 'm7' }, { r: 1, q: '7' }, { r: 0, q: '6' }],
        [{ r: 0, q: '6' }, { r: 11, q: 'm7b5' }, { r: 4, q: '7' }, { r: 9, q: 'm7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
    'Choro': [
        [{ r: 0, q: '6' }, { r: 1, q: 'dim7' }, { r: 2, q: 'm7' }, { r: 3, q: 'dim7' }, { r: 4, q: 'm7' }, { r: 7, q: '7' }],
        [{ r: 0, q: 'm6' }, { r: 7, q: '7' }, { r: 4, q: '7' }, { r: 9, q: '7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
  }
};

export const generateProgression = (key: NoteName, level: string): Chord[] => {
  const progression: Chord[] = [];
  const keyIdx = getNoteIndex(key);
  const getRelNote = (semitones: number) => NOTES[(keyIdx + semitones) % 12];

  const lvlKey = level as keyof typeof PROGRESSION_POOLS;
  const styles = Object.keys(PROGRESSION_POOLS[lvlKey]);
  const randomStyle = getRandomElement(styles);

  // @ts-ignore
  const pool = PROGRESSION_POOLS[lvlKey][randomStyle] as any[];
  const choice = getRandomElement(pool) as any[];

  choice.forEach((c: any) => {
      progression.push({ 
          root: getRelNote(c.r), 
          quality: c.q as any, 
          display: `${getRelNote(c.r)}${c.q}`, 
          duration: level === 'Iniciante' ? 4 : 2 
      });
  });

  return progression;
};

// --- BASS LINE STRATEGIES ---

type Strategy = 'ROOT_FIFTH' | 'MELODIC_COUNTERPOINT' | 'CHROMATIC_APPROACH' | 'ARPEGGIO_FULL_RANGE';

/**
 * THE BRAIN: Generates a stochastic bass line that traverses the ENTIRE fretboard
 * Implements "Call (Bass) and Response (Treble)" logic typical of 7-string guitar.
 */
export const generateBassLine = (
  progression: Chord[],
  style: RhythmStyle,
  level: 'Iniciante' | 'Intermediário' | 'Avançado',
  tuning: SeventhStringTuning
): BassNote[] => {
  const notes: BassNote[] = [];
  let currentBeatOffset = 0;

  let firstNoteMidi: number | null = null;
  let prevNoteMidi = -1; 
  let lastPos: { fret: number, string: number } | undefined = undefined;

  progression.forEach((chord, index) => {
    const nextChord = progression[(index + 1) % progression.length];
    const beatsInChord = chord.duration;

    // DECISION: Strategy
    let strategy: Strategy = 'ROOT_FIFTH';
    const rand = Math.random();

    if (level === 'Iniciante') {
        strategy = 'ROOT_FIFTH';
    } else if (level === 'Intermediário') {
        // More movement
        strategy = rand > 0.5 ? 'MELODIC_COUNTERPOINT' : 'ROOT_FIFTH';
    } else {
        // Advanced: Use full range arpeggios and counterpoint
        if (style === RhythmStyle.CHORO) strategy = rand > 0.2 ? 'ARPEGGIO_FULL_RANGE' : 'MELODIC_COUNTERPOINT';
        else strategy = rand > 0.4 ? 'MELODIC_COUNTERPOINT' : 'CHROMATIC_APPROACH';
    }

    // --- BEAT 1: THE ANCHOR (ALWAYS DEEP) ---
    // The "Surdo" of the guitar. We want strings 7, 6, 5 here.
    let rootOctave = 2; 
    if (tuning.includes('C') && chord.root === 'C') rootOctave = 2; // Low C on 7th
    if (tuning.includes('B') && chord.root === 'B') rootOctave = 1; // Low B on 7th
    if (['F', 'F#', 'G', 'G#'].includes(chord.root)) rootOctave = 2; // E string area
    if (['A', 'A#'].includes(chord.root) && !tuning.includes('A')) rootOctave = 2; // A string area

    // Find position specifically preferring lower strings (5, 6, 7) for the root
    let rootPos = findFretPosition(chord.root, rootOctave, tuning, undefined, undefined); // No prev context to force reset to bass

    // Fallback if low note not found (rare)
    if (!rootPos) rootPos = findFretPosition(chord.root, 3, tuning);

    if (rootPos) {
        notes.push({
           ...rootPos,
           duration: style === RhythmStyle.CHORO ? 0.25 : 0.75, // Dotted feel for Samba often
           startTime: currentBeatOffset,
           isChordTone: true
        });

        const thisMidi = getNoteIndex(rootPos.note) + (rootPos.octave + 1) * 12;
        if (index === 0) firstNoteMidi = thisMidi;
        prevNoteMidi = thisMidi;
        lastPos = { fret: rootPos.fret, string: rootPos.string };
    }

    // --- FILLS / PHRASING (THE RESPONSE) ---

    // Determine Target for the NEXT chord (Resolution)
    let finalTargetMidi: number;
    if (index === progression.length - 1 && firstNoteMidi !== null) {
        finalTargetMidi = firstNoteMidi;
    } else {
        // Guess next root octave (keep it low for the landing)
        const nextNoteIdx = getNoteIndex(nextChord.root);
        // Default to octave 2 or 1 for landing
        let landOct = 2;
        if (tuning.includes('B') && nextChord.root === 'B') landOct = 1;
        finalTargetMidi = nextNoteIdx + (landOct + 1) * 12;
    }

    if (strategy === 'ROOT_FIFTH') {
        // Simple bass toggle
        const fifth = getChordTones(chord)[2];
        const fifthPos = findFretPosition(fifth, 2, tuning) || findFretPosition(fifth, 3, tuning);

        if (beatsInChord >= 2 && fifthPos) {
            notes.push({
                ...fifthPos,
                duration: 0.5,
                startTime: currentBeatOffset + 1.0,
                isChordTone: true
            });
            lastPos = { fret: fifthPos.fret, string: fifthPos.string };
            prevNoteMidi = getNoteIndex(fifthPos.note) + (fifthPos.octave + 1) * 12;
        }
    }
    else if (strategy === 'CHROMATIC_APPROACH') {
        // Classic approach from below/above
        const approachCount = getRandomInt(2, 4);
        const startBeat = beatsInChord - (approachCount * 0.25);

        for(let i = 0; i < approachCount; i++) {
             const distToEnd = approachCount - i;

             // Linear chromatic movement towards target
             const noteMidi = finalTargetMidi + (distToEnd * (Math.random() > 0.5 ? -1 : 1)); // Approach from above or below

             // Enforce range?

             const nInfo = midiToNote(noteMidi);
             const pos = findFretPosition(nInfo.note, nInfo.octave, tuning, lastPos?.fret, lastPos?.string);

             if (pos) {
                 notes.push({
                     ...pos,
                     duration: 0.25,
                     startTime: currentBeatOffset + startBeat + (i * 0.25),
                     isChromatic: true
                 });
                 lastPos = { fret: pos.fret, string: pos.string };
                 prevNoteMidi = noteMidi;
             }
        }
    }
    else if (strategy === 'MELODIC_COUNTERPOINT' || strategy === 'ARPEGGIO_FULL_RANGE') {
        // Counterpoint logic

        const numNotes = (beatsInChord * 4) - 1; // 16th notes filling the bar minus root
        const startBeat = 0.25;

        // HIGH LIMIT: A4 (MIDI 69) - This is 5th fret on High E string. 
        // We ensure we never ask for a note higher than this to respect the "First 5 Frets" rule.
        const MAX_MIDI_LIMIT = 69; 
        const MIN_MIDI_LIMIT = 35; // Low B

        const chordTones = getChordTones(chord);
        let currentMidi = prevNoteMidi;

        for(let i = 0; i < numNotes; i++) {
            const timePos = currentBeatOffset + startBeat + (i * 0.25);

            let nextMidi = currentMidi;

            if (i < numNotes / 2) {
                // ASCENDING PHASE
                const interval = getRandomElement([3, 4, 5, 7]);
                nextMidi = currentMidi + interval;
            } else {
                // DESCENDING PHASE
                const diff = finalTargetMidi - currentMidi;
                const step = diff > 0 ? 1 : -1;

                if (Math.abs(diff) > 12) nextMidi = currentMidi + (step * 4);
                else if (Math.abs(diff) > 5) nextMidi = currentMidi + (step * 2);
                else nextMidi = currentMidi + step;
            }

            // Cap ranges STRICTLY
            if (nextMidi > MAX_MIDI_LIMIT) nextMidi = MAX_MIDI_LIMIT; 
            if (nextMidi < MIN_MIDI_LIMIT) nextMidi = MIN_MIDI_LIMIT;

            // Convert MIDI to Note
            const nInfo = midiToNote(nextMidi);

            // Try to find position. 
            const pos = findFretPosition(nInfo.note, nInfo.octave, tuning, lastPos?.fret, lastPos?.string);

            if (pos) {
                notes.push({
                    ...pos,
                    duration: 0.25,
                    startTime: timePos,
                    isChordTone: chordTones.includes(nInfo.note)
                });
                lastPos = { fret: pos.fret, string: pos.string };
                currentMidi = nextMidi;
            }
        }
    }

    currentBeatOffset += beatsInChord;
  });

  return notes.sort((a, b) => a.startTime - b.startTime);
};

// Helper
const midiToNote = (midi: number): { note: NoteName, octave: number } => {
    const idx = midi % 12;
    const oct = Math.floor(midi / 12) - 1;
    return { note: NOTES[idx], octave: oct };
}

import React, { useState, useRef, useEffect } from 'react';
import { Play, Square, Music, Plus, Save, Trash2, Settings2, RefreshCw, Layers, Download, Wand2, Speaker } from 'lucide-react';
import { RhythmStyle, SeventhStringTuning, BassLick, Chord, BassNote, NoteName, InstrumentType } from '../types';
import { generateProgression, generateBassLine } from '../services/baixariaGenerator';
import { playInstrumentNote, scheduleClick, getAudioContext } from '../utils/audio';
import { getFrequency, NOTES } from '../utils/musicTheory';

export const BassTrainer: React.FC = () => {
    // --- State ---
    const [style, setStyle] = useState<RhythmStyle>(RhythmStyle.SAMBA);
    const [tuning, setTuning] = useState<SeventhStringTuning>(SeventhStringTuning.C);
    const [level, setLevel] = useState<'Iniciante' | 'Intermediário' | 'Avançado'>('Intermediário');
    const [key, setKey] = useState<NoteName>('C');
    const [tempo, setTempo] = useState(90);
    const [instrument, setInstrument] = useState<InstrumentType>('nylon');

    const [progression, setProgression] = useState<Chord[]>([]);
    const [bassLine, setBassLine] = useState<BassNote[]>([]);
    const [isPlaying, setIsPlaying] = useState(false);
    const [currentBeat, setCurrentBeat] = useState(0);

    // Audio Refs
    const timerRef = useRef<number | null>(null);
    const startTimeRef = useRef<number>(0);
    const beatRef = useRef<number>(0);

    // --- GENERATOR ---
    const handleGenerate = () => {
        setIsPlaying(false);
        const newProg = generateProgression(key, level);
        // Pass 'key' to allow Modal Logic calculations
        const newBass = generateBassLine(newProg, style, level, tuning, key);
        setProgression(newProg);
        setBassLine(newBass);
        setCurrentBeat(0);
    };

    // Initial Generate
    useEffect(() => {
        handleGenerate();
    }, []);

    // --- SEQUENCER / PLAYBACK ---
    const play = () => {
        if (isPlaying) {
            stop();
            return;
        }

        const ctx = getAudioContext();
        if (ctx.state === 'suspended') ctx.resume();

        setIsPlaying(true);
        beatRef.current = 0;
        startTimeRef.current = ctx.currentTime;

        scheduleNext();
    };

    const stop = () => {
        if (timerRef.current) clearTimeout(timerRef.current);
        setIsPlaying(false);
        setCurrentBeat(0);
    };

    const scheduleNext = () => {
        const ctx = getAudioContext();
        const secondsPerBeat = 60.0 / tempo;
        const lookahead = 0.1; // 100ms

        // Calculate current time in song
        const playTime = ctx.currentTime - startTimeRef.current;
        // Convert to beats
        const currentSeqBeat = playTime / secondsPerBeat;

        setCurrentBeat(currentSeqBeat);

        // Schedule Notes that are within lookahead
        bassLine.forEach(note => {
            // Check if note is in the window [currentSeqBeat, currentSeqBeat + small]
            const noteTime = note.startTime * secondsPerBeat;
            const diff = noteTime - playTime;

            if (diff >= 0 && diff < lookahead) {
                // Schedule audio
                const freq = getFrequency(note.note, note.octave);
                // We add a tiny random offset for "Human Feel"
                const humanize = Math.random() * 0.02;

                // Duration for the synth
                const dur = note.duration * secondsPerBeat;

                setTimeout(() => {
                    playInstrumentNote(freq, instrument, dur);
                }, (diff + humanize) * 1000);
            }
        });

        // Loop Logic
        const totalDuration = progression.reduce((acc, c) => acc + c.duration, 0);
        if (currentSeqBeat >= totalDuration) {
             startTimeRef.current = ctx.currentTime; // Reset loop
        }

        timerRef.current = window.setTimeout(scheduleNext, 50); // 20Hz refresh
    };

    useEffect(() => {
        return () => stop();
    }, []);

    // --- EDITOR HELPERS ---
    const exportMidi = () => {
        alert("Simulação: Arquivo 'baixaria.mid' gerado e pronto para download!");
    };

    // --- RENDERERS ---

    const renderTimeline = () => {
        if (progression.length === 0) return null;

        const totalBeats = progression.reduce((sum, c) => sum + c.duration, 0);
        const beatWidth = 60; // px per beat
        const stringSpacing = 24; // px between strings
        const tabTopPadding = 30;

        return (
            <div className="relative bg-[#fafafa] rounded-xl border-4 border-slate-800 overflow-x-auto overflow-y-hidden mb-6 select-none shadow-2xl">
                 <div className="relative" style={{ width: `${Math.max(totalBeats * beatWidth, 600)}px`, minHeight: '300px' }}>

                     {/* 1. PROGRESSION HEADER (CHORDS) */}
                     <div className="h-20 flex bg-white border-b-2 border-slate-800">
                         {progression.map((chord, i) => (
                             <div 
                                key={i} 
                                className="border-r border-slate-200 flex flex-col items-center justify-center relative"
                                style={{ width: chord.duration * beatWidth }}
                             >
                                 <span className="text-xl font-black text-slate-900">{chord.display}</span>
                                 <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest absolute bottom-2">{chord.quality}</span>
                             </div>
                         ))}
                     </div>

                     {/* 2. TIMELINE GRID & CURSOR */}
                     <div className="absolute top-20 bottom-0 left-0 right-0 pointer-events-none z-0">
                         {Array.from({ length: totalBeats + 1 }).map((_, i) => (
                             <div key={i} className="absolute top-0 bottom-0 border-r border-slate-300/50" style={{ left: i * beatWidth }}>
                                 <span className="text-[9px] text-slate-400 pl-1 pt-1 font-mono">{i + 1}</span>
                             </div>
                         ))}
                     </div>

                     {isPlaying && (
