    ],
    'Choro': [
        [{ r: 0, q: 'm7' }, { r: 0, q: '7' }, { r: 5, q: 'm7' }, { r: 8, q: '7' }, { r: 7, q: '7' }],
        [{ r: 0, q: 'maj7' }, { r: 5, q: 'm6' }, { r: 0, q: 'maj7' }, { r: 7, q: '7' }]
    ],
  },
  'Avançado': {
    'Samba': [
        [{ r: 0, q: 'maj7' }, { r: 3, q: 'dim7' }, { r: 2, q: 'm7' }, { r: 1, q: '7' }, { r: 0, q: '6' }],
        [{ r: 0, q: '6' }, { r: 11, q: 'm7b5' }, { r: 4, q: '7' }, { r: 9, q: 'm7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
    'Choro': [
        [{ r: 0, q: '6' }, { r: 1, q: 'dim7' }, { r: 2, q: 'm7' }, { r: 3, q: 'dim7' }, { r: 4, q: 'm7' }, { r: 7, q: '7' }],
        [{ r: 0, q: 'm6' }, { r: 7, q: '7' }, { r: 4, q: '7' }, { r: 9, q: '7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
  }
};

export const generateProgression = (key: NoteName, level: string): Chord[] => {
  const progression: Chord[] = [];
  const keyIdx = getNoteIndex(key);
  const getRelNote = (semitones: number) => NOTES[(keyIdx + semitones) % 12];

  const lvlKey = level as keyof typeof PROGRESSION_POOLS;
  const styles = Object.keys(PROGRESSION_POOLS[lvlKey]);
  const randomStyle = getRandomElement(styles);

  // @ts-ignore
  const pool = PROGRESSION_POOLS[lvlKey][randomStyle] as any[];
  const choice = getRandomElement(pool) as any[];

  choice.forEach((c: any) => {
      progression.push({ 
          root: getRelNote(c.r), 
          quality: c.q as any, 
          display: `${getRelNote(c.r)}${c.q}`, 
          duration: level === 'Iniciante' ? 4 : 2 
      });
  });

  return progression;
};

// --- BASS LINE STRATEGIES ---

type Strategy = 'ROOT_FIFTH' | 'SCALE_RUN_MODAL' | 'CHROMATIC_ENCIRCLEMENT' | 'ARPEGGIO_EXTENDED';

/**
 * THE BRAIN: Generates a stochastic bass line that traverses the ENTIRE fretboard
 * Enforces strict looping resolution to the start note.
 */
export const generateBassLine = (
  progression: Chord[],
  style: RhythmStyle,
  level: 'Iniciante' | 'Intermediário' | 'Avançado',
  tuning: SeventhStringTuning,
  key: NoteName
): BassNote[] => {
  const notes: BassNote[] = [];
  let currentBeatOffset = 0;

  let firstNoteMidi: number | null = null;
  let prevNoteMidi = -1; 
  let lastPos: { fret: number, string: number } | undefined = undefined;

  // Strict Limits (Fret 0-5)
  // Low Limit: Open 7th String (B1=35, C2=36, A1=33)
  // High Limit: 5th Fret High E (A4 = 69)
  const MAX_MIDI_LIMIT = 69; 
  let MIN_MIDI_LIMIT = 35; // Default B1
  if (tuning.includes('A')) MIN_MIDI_LIMIT = 33;

  progression.forEach((chord, index) => {
    const isLastChord = index === progression.length - 1;
    const nextChord = progression[(index + 1) % progression.length];
    const beatsInChord = chord.duration;

    // --- STRATEGY SELECTION ---
    let strategy: Strategy = 'ROOT_FIFTH';
    const rand = Math.random();

    if (level === 'Iniciante') {
        strategy = 'ROOT_FIFTH';
    } else {
        // Force variety
        if (style === RhythmStyle.CHORO) strategy = rand > 0.3 ? 'SCALE_RUN_MODAL' : 'ARPEGGIO_EXTENDED';
        else strategy = rand > 0.4 ? 'CHROMATIC_ENCIRCLEMENT' : 'ARPEGGIO_EXTENDED';
    }

    // --- BEAT 1: ANCHOR (ROOT) ---
    // Start on Strings 5, 6, 7 (Graves)
    let rootOctave = 2; 
    if (tuning.includes('C') && chord.root === 'C') rootOctave = 2;
    if (tuning.includes('B') && chord.root === 'B') rootOctave = 1;
    if (['F', 'F#', 'G', 'G#'].includes(chord.root)) rootOctave = 2; 
    if (['A', 'A#'].includes(chord.root) && !tuning.includes('A')) rootOctave = 2;

    // Force lower if possible for bass feel
    let rootPos = findFretPosition(chord.root, rootOctave, tuning);
    if (!rootPos) rootPos = findFretPosition(chord.root, 3, tuning); // Fallback

    if (rootPos) {
        notes.push({
           ...rootPos,
           duration: style === RhythmStyle.CHORO ? 0.25 : 0.75, 
           startTime: currentBeatOffset,
           isChordTone: true
        });

        const thisMidi = getNoteIndex(rootPos.note) + (rootPos.octave + 1) * 12;
        if (index === 0) firstNoteMidi = thisMidi;
        prevNoteMidi = thisMidi;
        lastPos = { fret: rootPos.fret, string: rootPos.string };
    }

    // --- TARGET DETERMINATION (RESOLUTION) ---
    // Where do we land on the *next* downbeat?
    let finalTargetMidi: number;
    if (isLastChord && firstNoteMidi !== null) {
        // CRITICAL: Force loop resolution
        finalTargetMidi = firstNoteMidi;
    } else {
        const nextNoteIdx = getNoteIndex(nextChord.root);
        let landOct = 2;
        if (tuning.includes('B') && nextChord.root === 'B') landOct = 1;
        finalTargetMidi = nextNoteIdx + (landOct + 1) * 12;
    }

    // --- FILL GENERATION ---
    const numSubdivisions = (beatsInChord * 4); // 16th notes total
    const fillStartIndex = 1; // Skip root at 0

    // HELPER: Map chord quality to Scale Type
    let scaleType: ScaleType = 'Major';
    if (chord.quality === 'maj7') scaleType = 'Major';
    else if (chord.quality === 'm7') scaleType = 'Dorian';
    else if (chord.quality === '7') scaleType = 'Mixolydian';
    else if (chord.quality === 'm7b5') scaleType = 'Locrian';
    else if (chord.quality === 'dim7') scaleType = 'Harmonic Minor';

    const scaleNotes = getScaleNotes(chord.root, scaleType);

    // --- APEX LOGIC (High Strings Targeting) ---
    // Select a "peak" note for this phrase to ensure we use Strings 1, 2, 3
    // Range: ~55 (G3) to 69 (A4)
    let apexMidi = -1;
    let apexIndex = -1;

    // Only attempt full arc if we have enough time (>= 2 beats)
    if (beatsInChord >= 2) {
        const potentialApexes = [];
        for (let m = 55; m <= MAX_MIDI_LIMIT; m++) {
            const n = midiToNote(m);
            // Must be in scale
            if (scaleNotes.includes(n.note)) {
                // Prefer Chord Tones for the peak
                const isChordTone = getChordTones(chord).includes(n.note);
                if (isChordTone) potentialApexes.push(m);
                // Also add non-chord tones with lower probability? No, stick to strong peaks.
            }
        }
        if (potentialApexes.length > 0) {
            apexMidi = getRandomElement(potentialApexes);
            // Apex happens roughly in the middle of the bar
            apexIndex = Math.floor(numSubdivisions / 2);
        }
    }

    if (strategy === 'ROOT_FIFTH') {
        const fifth = getChordTones(chord)[2];
        const fifthPos = findFretPosition(fifth, 2, tuning) || findFretPosition(fifth, 3, tuning);
        if (beatsInChord >= 2 && fifthPos) {
            notes.push({
                ...fifthPos,
                duration: 0.5,
                startTime: currentBeatOffset + 1.0,
                isChordTone: true
            });
            prevNoteMidi = getNoteIndex(fifthPos.note) + (fifthPos.octave + 1) * 12;
            lastPos = { fret: fifthPos.fret, string: fifthPos.string };
        }
    }
    else {
        // Unified Logic for Strategies that move (Scale/Arpeggio)
        let currentMidi = prevNoteMidi;

        for (let i = fillStartIndex; i < numSubdivisions; i++) {
             let nextMidi = currentMidi;

             // Define local target for this step
             let localTarget = finalTargetMidi;

             // If we have an Apex and we haven't reached it yet
             if (apexMidi !== -1 && i < apexIndex) {
                 localTarget = apexMidi;
             } 
             // If we passed Apex, target is final resolution

             // Calculate Direction
             const diff = localTarget - currentMidi;
             const direction = diff > 0 ? 1 : -1;
             const dist = Math.abs(diff);

             // STRATEGY EXECUTION
             if (strategy === 'SCALE_RUN_MODAL') {
                 // Close distance: Stepwise
                 if (dist <= 2) {
                     nextMidi = localTarget;
                 } else {
                     // Find next scale note in direction
                     let attempt = currentMidi + direction;
                     while(!scaleNotes.includes(midiToNote(attempt).note)) {
                         attempt += direction;
                     }
                     nextMidi = attempt;
                 }
             }
             else if (strategy === 'ARPEGGIO_EXTENDED') {
                 // Leap logic
                 if (dist > 4) {
                     // Try to find a chord tone in direction
                     let found = false;
                     // Look ahead up to 7 semitones
                     for(let k=2; k<=7; k++) {
                         let attempt = currentMidi + (k * direction);
                         const n = midiToNote(attempt);
                         // Check chord tones
                         if (getChordTones(chord).includes(n.note)) {
                             nextMidi = attempt;
                             found = true;
                             break;
                         }
                     }
                     if (!found) nextMidi += (direction * 2); // Fallback scale step approx
                 } else {
                     nextMidi += direction; // Close gap
                 }
             }
             else if (strategy === 'CHROMATIC_ENCIRCLEMENT') {
                 // Chromatic approach near targets (Apex or Final)
                 const distToApex = Math.abs(apexMidi - currentMidi);

                 // If near Apex or Near Final, use chromatic
                 if ((apexMidi !== -1 && i >= apexIndex - 2 && i <= apexIndex) || (i >= numSubdivisions - 3)) {
                     nextMidi = currentMidi + direction; // Chromatic step
                 } else {
                     // Otherwise jumpy
                     if (Math.random() > 0.5) nextMidi += (direction * 3);
                     else nextMidi += (direction * 2);
                 }
             }

             // --- CRITICAL: RANGE ENFORCEMENT ---
             if (nextMidi > MAX_MIDI_LIMIT) nextMidi = MAX_MIDI_LIMIT;
             if (nextMidi < MIN_MIDI_LIMIT) nextMidi = MIN_MIDI_LIMIT;

             const nInfo = midiToNote(nextMidi);
             // findFretPosition filters for first 5 frets.
             const pos = findFretPosition(nInfo.note, nInfo.octave, tuning, lastPos?.fret, lastPos?.string);

             if (pos) {
                 notes.push({
                     ...pos, 
                     duration: 0.25, 
                     startTime: currentBeatOffset + (i * 0.25),
                     isChordTone: getChordTones(chord).includes(nInfo.note),
                     isChromatic: !scaleNotes.includes(nInfo.note)
                 });
                 currentMidi = nextMidi;
                 lastPos = { fret: pos.fret, string: pos.string };
             }
        }
    }

    currentBeatOffset += beatsInChord;
  });

  return notes.sort((a, b) => a.startTime - b.startTime);
};

// Helper
const midiToNote = (midi: number): { note: NoteName, octave: number } => {
    const idx = midi % 12;
    const oct = Math.floor(midi / 12) - 1;
    return { note: NOTES[idx], octave: oct };
}

export enum SeventhStringTuning {
  B = 'B (Si - Padrão)',
  C = 'C (Dó - Samba/Choro)',
  A = 'A (Lá - Grave)',
}

export enum RhythmStyle {
  SAMBA = 'Samba',
  CHORO = 'Choro',
  BOSSA_NOVA = 'Bossa Nova',
  BAIAO = 'Baião',
  SAMBA_CANCAO = 'Samba-canção',
  PARTIDO_ALTO = 'Partido Alto',
  MAXIXE = 'Maxixe',
}

export interface GuitarString {
  note: string;
  octave: number;
  frequency: number;
  description?: string;
}

export interface RhythmPreset {
  name: RhythmStyle;
  description: string;
  countPattern: string;
  bpmRanges: {
    beginner: number;
    intermediate: number;
    advanced: number;
  };
  accentBeat: number[]; // 1-based index of beats to accent
  subdivision: number; // 2 for 8th notes, 4 for 16th notes
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

export type TimeSignature = '2/4' | '3/4' | '4/4' | '6/8';
export type Subdivision = '1' | '2' | '3' | '4'; // Quarter, 8th, Triplet, 16th

export interface MetronomeState {
  bpm: number;
  isPlaying: boolean;
  timeSignature: TimeSignature;
  subdivision: Subdivision;
  volume: number;
  isGrooveMode: boolean; // 2 & 4 only
  isGhostMode: boolean; // Randomly drops bars
}

