export type AppTab = 'tuner' | 'metronome' | 'fretboard' | 'bass-trainer' | 'rhythms' | 'coach' | 'separator';

import React, { useState, useRef, useEffect } from 'react';
import { Upload, Play, Pause, Repeat, FastForward, Rewind, Layers, Volume2, Info, Loader2 } from 'lucide-react';
import { getAudioContext } from '../utils/audio';

// --- TYPES ---

interface EqBands {
  low: GainNode | null;
  mid: GainNode | null;
  high: GainNode | null;
}

export const AudioSeparator: React.FC = () => {
  // State
  const [file, setFile] = useState<File | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [duration, setDuration] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isLooping, setIsLooping] = useState(false);
  const [loopStart, setLoopStart] = useState<number>(0);
  const [loopEnd, setLoopEnd] = useState<number>(0);
  const [isLoading, setIsLoading] = useState(false);

  // Mixer Volumes (0.0 - 2.0 to allow boost)
  const [volLow, setVolLow] = useState(1.0);
  const [volMid, setVolMid] = useState(1.0);
  const [volHigh, setVolHigh] = useState(1.0);

  // Refs
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<MediaElementAudioSourceNode | null>(null);
  const eqGainsRef = useRef<EqBands>({ low: null, mid: null, high: null });
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const animationFrameRef = useRef<number | null>(null);
  const waveformBufferRef = useRef<AudioBuffer | null>(null);

  // --- AUDIO SETUP ---

  const setupAudioGraph = () => {
    if (!audioRef.current) return;

    // 1. Init Context
    const ctx = getAudioContext();
    audioContextRef.current = ctx;

    // 2. Create Source (if not exists)
    if (!sourceNodeRef.current) {
        sourceNodeRef.current = ctx.createMediaElementSource(audioRef.current);
    }

    // 3. Create Crossover Filters (Multi-band Separation Simulation)
    // LowPass for Bass (< 250Hz)
    const lowFilter = ctx.createBiquadFilter();
    lowFilter.type = 'lowpass';
    lowFilter.frequency.value = 250;

    // BandPass for Mids (250Hz - 4000Hz) - Creating via HighPass + LowPass combo
    const midLowCut = ctx.createBiquadFilter();
    midLowCut.type = 'highpass';
    midLowCut.frequency.value = 250;
    const midHighCut = ctx.createBiquadFilter();
    midHighCut.type = 'lowpass';
    midHighCut.frequency.value = 4000;

    // HighPass for Treble (> 4000Hz)
    const highFilter = ctx.createBiquadFilter();
    highFilter.type = 'highpass';
    highFilter.frequency.value = 4000;

    // 4. Create Gain Nodes (Volume Controls)
    const lowGain = ctx.createGain();
    const midGain = ctx.createGain();
    const highGain = ctx.createGain();

    eqGainsRef.current = { low: lowGain, mid: midGain, high: highGain };

    // 5. Connect Graph
    // Path 1: Source -> LowFilter -> LowGain -> Dest
    sourceNodeRef.current.connect(lowFilter);
    lowFilter.connect(lowGain);
    lowGain.connect(ctx.destination);

    // Path 2: Source -> MidLowCut -> MidHighCut -> MidGain -> Dest
    sourceNodeRef.current.connect(midLowCut);
    midLowCut.connect(midHighCut);
    midHighCut.connect(midGain);
    midGain.connect(ctx.destination);

    // Path 3: Source -> HighFilter -> HighGain -> Dest
    sourceNodeRef.current.connect(highFilter);
    highFilter.connect(highGain);
    highGain.connect(ctx.destination);
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      setFile(selectedFile);
      setIsLoading(true);
      setIsPlaying(false);

      const objectUrl = URL.createObjectURL(selectedFile);

      if (audioRef.current) {
          audioRef.current.src = objectUrl;
          audioRef.current.load();
      }

      // Decode for visualizer
      try {
          const arrayBuffer = await selectedFile.arrayBuffer();
          const ctx = getAudioContext();
          const audioBuffer = await ctx.decodeAudioData(arrayBuffer);
          waveformBufferRef.current = audioBuffer;
          setDuration(audioBuffer.duration);
          setLoopEnd(audioBuffer.duration);
          drawWaveform();
      } catch (err) {
          console.error("Error decoding audio for visualizer", err);
      } finally {
          setIsLoading(false);
      }
    }
  };

  // --- PLAYBACK CONTROLS ---

  const togglePlay = async () => {
    if (!audioRef.current) return;
    const ctx = getAudioContext();

    if (ctx.state === 'suspended') await ctx.resume();

    // Ensure graph is set up (one time)
    if (!eqGainsRef.current.low) {
        setupAudioGraph();
    }

    if (isPlaying) {
      audioRef.current.pause();
      setIsPlaying(false);
    } else {
      try {
        await audioRef.current.play();
        setIsPlaying(true);
      } catch (err) {
          console.error("Play error:", err);
      }
    }
  };

  // Update Volumes
  useEffect(() => {
    const ctx = getAudioContext();
    const t = ctx.currentTime;
    if (eqGainsRef.current.low) eqGainsRef.current.low.gain.setTargetAtTime(volLow, t, 0.1);
    if (eqGainsRef.current.mid) eqGainsRef.current.mid.gain.setTargetAtTime(volMid, t, 0.1);
    if (eqGainsRef.current.high) eqGainsRef.current.high.gain.setTargetAtTime(volHigh, t, 0.1);
  }, [volLow, volMid, volHigh]);

  // Update Playback Rate
  useEffect(() => {
      if (audioRef.current) {
          audioRef.current.playbackRate = playbackRate;
          // Preserve pitch is default true in modern browsers, but explicitly setting ensures
          audioRef.current.preservesPitch = true;
      }
  }, [playbackRate]);

  // Looping Logic & Time Update
  useEffect(() => {
    const loopCheck = () => {
        if (!audioRef.current) return;

        const curr = audioRef.current.currentTime;
        setCurrentTime(curr);

        if (isLooping && loopEnd > loopStart) {
            if (curr >= loopEnd || curr < loopStart) {
                audioRef.current.currentTime = loopStart;
            }
        }
        animationFrameRef.current = requestAnimationFrame(loopCheck);
    };

    if (isPlaying) {
        animationFrameRef.current = requestAnimationFrame(loopCheck);
    } else {
        if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    }

    return () => {
        if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [isPlaying, isLooping, loopStart, loopEnd]);


  // --- VISUALIZER ---

  const drawWaveform = () => {
      if (!canvasRef.current || !waveformBufferRef.current) return;

      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      const width = canvas.width;
      const height = canvas.height;
      const data = waveformBufferRef.current.getChannelData(0); // Left channel
      const step = Math.ceil(data.length / width);
      const amp = height / 2;

      ctx.clearRect(0, 0, width, height);
      ctx.fillStyle = '#1e293b'; // Slate 800 background
      ctx.fillRect(0, 0, width, height);

      ctx.beginPath();
      ctx.moveTo(0, amp);
      ctx.strokeStyle = '#475569'; // Slate 600
      ctx.lineWidth = 1;

      for (let i = 0; i < width; i++) {
          let min = 1.0;
          let max = -1.0;
          for (let j = 0; j < step; j++) {
              const datum = data[(i * step) + j];
              if (datum < min) min = datum;
              if (datum > max) max = datum;
          }
          ctx.lineTo(i, (1 + min) * amp);
          ctx.lineTo(i, (1 + max) * amp);
      }
      ctx.stroke();
  };

  // Draw Overlay (Progress + Loop)
  useEffect(() => {
      if (!canvasRef.current) return;
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      // Redraw base (inefficient but simple for loop overlay updates)
      drawWaveform(); 

      const width = canvas.width;
      const height = canvas.height;

      // Draw Loop Region
      if (duration > 0) {
          const xStart = (loopStart / duration) * width;
          const xEnd = (loopEnd / duration) * width;

          ctx.fillStyle = 'rgba(20, 184, 166, 0.15)'; // Teal tint
          ctx.fillRect(xStart, 0, xEnd - xStart, height);

          // Loop markers
          ctx.strokeStyle = '#14b8a6';
          ctx.beginPath();
          ctx.moveTo(xStart, 0);
          ctx.lineTo(xStart, height);
          ctx.moveTo(xEnd, 0);
          ctx.lineTo(xEnd, height);
          ctx.stroke();

          // Labels
          ctx.fillStyle = '#14b8a6';
          ctx.font = '10px monospace';
          ctx.fillText('A', xStart + 2, 12);
          ctx.fillText('B', xEnd - 8, 12);
      }

      // Draw Playhead
      if (duration > 0) {
          const xPos = (currentTime / duration) * width;
          ctx.strokeStyle = '#ef4444'; // Red
          ctx.lineWidth = 2;
          ctx.beginPath();
          ctx.moveTo(xPos, 0);
          ctx.lineTo(xPos, height);
          ctx.stroke();
      }
  }, [currentTime, loopStart, loopEnd, duration]);


  // --- HANDLERS ---
  const handleSeek = (e: React.MouseEvent<HTMLCanvasElement>) => {
      if (!duration) return;
      const rect = canvasRef.current!.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const perc = x / rect.width;
      const newTime = perc * duration;

      if (audioRef.current) {
          audioRef.current.currentTime = newTime;
          setCurrentTime(newTime);
      }
  };

  const setLoopPoint = (type: 'start' | 'end') => {
      if (type === 'start') setLoopStart(currentTime);
      else setLoopEnd(currentTime);
      setIsLooping(true);
  };

  const formatTime = (t: number) => {
      const min = Math.floor(t / 60);
      const sec = Math.floor(t % 60);
      return `${min}:${sec.toString().padStart(2, '0')}`;
  };

  return (
    <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 h-full flex flex-col">
      <audio 
        ref={audioRef} 
        onEnded={() => setIsPlaying(false)}
        crossOrigin="anonymous"
      />

      {/* HEADER */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
          <div>
            <h2 className="text-xl font-bold text-white flex items-center gap-2">
                <Layers className="text-teal-400" />
                Estúdio de Separação
            </h2>
            <p className="text-xs text-slate-400">Isole frequências, altere velocidade e crie loops.</p>
          </div>

          <label className="cursor-pointer bg-slate-700 hover:bg-slate-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors border border-slate-600">
             {isLoading ? <Loader2 className="animate-spin" size={16} /> : <Upload size={16} />}
             <span className="text-sm font-bold">Carregar Áudio</span>
             <input type="file" accept="audio/*" onChange={handleFileUpload} className="hidden" />
          </label>
      </div>

      {!file ? (
          <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-slate-700 rounded-xl bg-slate-900/30 text-slate-500 gap-4">
              <Upload size={48} className="opacity-50" />
