                              {isPlaying ? <Pause fill="currentColor" /> : <Play fill="currentColor" className="ml-1" />}
                          </button>
                          <div className="text-xs font-mono text-teal-400 bg-slate-800 px-2 py-1 rounded border border-slate-700">
                              {formatTime(currentTime)} / {formatTime(duration)}
                          </div>
                      </div>

                      <div className="flex items-center gap-2 bg-slate-800 p-1.5 rounded-lg border border-slate-700">
                          <button onClick={() => setLoopPoint('start')} className="px-3 py-1 text-xs font-bold hover:bg-slate-700 rounded text-teal-200">Definir A</button>
                          <button onClick={() => setLoopPoint('end')} className="px-3 py-1 text-xs font-bold hover:bg-slate-700 rounded text-teal-200">Definir B</button>
                          <button 
                            onClick={() => setIsLooping(!isLooping)} 
                            className={`p-1.5 rounded transition-colors ${isLooping ? 'bg-teal-500/20 text-teal-400' : 'text-slate-500 hover:text-white'}`}
                          >
                              <Repeat size={16} />
                          </button>
                      </div>

                      <div className="flex items-center gap-3 bg-slate-800 p-2 rounded-lg border border-slate-700 min-w-[200px]">
                          <span className="text-[10px] uppercase font-bold text-slate-500">Velocidade</span>
                          <Rewind size={14} className="text-slate-500 cursor-pointer" onClick={() => setPlaybackRate(Math.max(0.5, playbackRate - 0.1))} />
                          <input 
                            type="range" min="0.5" max="1.5" step="0.05" 
                            value={playbackRate} 
                            onChange={(e) => setPlaybackRate(Number(e.target.value))}
                            className="flex-1 h-1 bg-slate-600 rounded-lg appearance-none accent-teal-500"
                          />
                          <FastForward size={14} className="text-slate-500 cursor-pointer" onClick={() => setPlaybackRate(Math.min(1.5, playbackRate + 0.1))} />
                          <span className="text-xs font-mono w-8 text-right">{playbackRate.toFixed(2)}x</span>
                      </div>
                  </div>
              </div>

              {/* MIXER (STEM SIMULATION) */}
              <div className="flex-1 bg-slate-900/50 rounded-xl p-6 border border-slate-700">
                   <div className="flex items-center gap-2 mb-6">
                       <Layers size={20} className="text-slate-400" />
                       <h3 className="font-bold text-slate-200">Mixer de Frequências (Simulação de Stems)</h3>
                       <div className="ml-auto group relative">
                           <Info size={16} className="text-slate-500 cursor-help" />
                           <div className="absolute right-0 bottom-full mb-2 w-64 p-2 bg-black text-xs text-slate-300 rounded border border-slate-700 hidden group-hover:block z-50">
                               Isola bandas de frequência. Use "Baixo" para ouvir a 7ª corda, ou remova-o para tocar junto (playback).
                           </div>
                       </div>
                   </div>

                   <div className="grid grid-cols-3 gap-8 h-48">

                       {/* LOW / BASS */}
                       <div className="flex flex-col items-center gap-2">
                           <div className="flex-1 bg-slate-800 w-12 rounded-full relative border border-slate-700 flex justify-center p-2">
                               <input 
                                    type="range" min="0" max="2" step="0.1" 
                                    value={volLow}
                                    onChange={(e) => setVolLow(Number(e.target.value))}
                                    className="absolute h-full w-full opacity-0 cursor-pointer z-10"
                                    style={{ transform: 'rotate(-90deg)' }} // visual hack, better to use vertical slider lib or custom div height
                               />
                               {/* Custom Visual Slider Bar */}
                               <div className="absolute bottom-2 w-2 bg-yellow-500 rounded-full transition-all duration-75" style={{ height: `${(volLow / 2) * 85}%` }}></div>
                           </div>
                           <div className="text-center">
                               <div className="font-bold text-yellow-500 text-sm">BAIXO</div>
                               <div className="text-[10px] text-slate-500">Grave / 7 Cordas</div>
                           </div>
                           <Volume2 size={16} className={volLow === 0 ? 'text-slate-600' : 'text-yellow-500'} />
                       </div>

                       {/* MID / HARMONY */}
                       <div className="flex flex-col items-center gap-2">
                           <div className="flex-1 bg-slate-800 w-12 rounded-full relative border border-slate-700 flex justify-center p-2">
                               <input 
                                    type="range" min="0" max="2" step="0.1" 
                                    value={volMid}
                                    onChange={(e) => setVolMid(Number(e.target.value))}
                                    className="absolute h-full w-full opacity-0 cursor-pointer z-10"
                               />
                               <div className="absolute bottom-2 w-2 bg-indigo-500 rounded-full transition-all duration-75" style={{ height: `${(volMid / 2) * 85}%` }}></div>
                           </div>
                           <div className="text-center">
                               <div className="font-bold text-indigo-500 text-sm">HARMONIA</div>
                               <div className="text-[10px] text-slate-500">Voz / Violão</div>
                           </div>
                           <Volume2 size={16} className={volMid === 0 ? 'text-slate-600' : 'text-indigo-500'} />
                       </div>

                       {/* HIGH / PERCUSSION */}
                       <div className="flex flex-col items-center gap-2">
                           <div className="flex-1 bg-slate-800 w-12 rounded-full relative border border-slate-700 flex justify-center p-2">
                               <input 
                                    type="range" min="0" max="2" step="0.1" 
                                    value={volHigh}
                                    onChange={(e) => setVolHigh(Number(e.target.value))}
                                    className="absolute h-full w-full opacity-0 cursor-pointer z-10"
                               />
                               <div className="absolute bottom-2 w-2 bg-pink-500 rounded-full transition-all duration-75" style={{ height: `${(volHigh / 2) * 85}%` }}></div>
                           </div>
                           <div className="text-center">
                               <div className="font-bold text-pink-500 text-sm">PERCUSSÃO</div>
                               <div className="text-[10px] text-slate-500">Agudos / Pratos</div>
                           </div>
                           <Volume2 size={16} className={volHigh === 0 ? 'text-slate-600' : 'text-pink-500'} />
                       </div>

                   </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Upload, Play, Pause, Square, Repeat, FastForward, Rewind, Layers, Volume2, Info, Loader2, VolumeX } from 'lucide-react';
import { getAudioContext } from '../utils/audio';

// --- TYPES ---

interface EqBands {
  low: GainNode | null;
  mid: GainNode | null;
  high: GainNode | null;
}

export const AudioSeparator: React.FC = () => {
  // State
  const [file, setFile] = useState<File | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [duration, setDuration] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isLooping, setIsLooping] = useState(false);
  const [loopStart, setLoopStart] = useState<number>(0);
  const [loopEnd, setLoopEnd] = useState<number>(0);
  const [isLoading, setIsLoading] = useState(false);

  // Mixer Volumes (0.0 - 2.0 to allow boost)
  const [volLow, setVolLow] = useState(1.0);
  const [volMid, setVolMid] = useState(1.0);
  const [volHigh, setVolHigh] = useState(1.0);

  // Refs
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<MediaElementAudioSourceNode | null>(null);
  const eqGainsRef = useRef<EqBands>({ low: null, mid: null, high: null });
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const animationFrameRef = useRef<number | null>(null);
  const waveformBufferRef = useRef<AudioBuffer | null>(null);

  // --- AUDIO SETUP ---

  const setupAudioGraph = () => {
    if (!audioRef.current) return;

    // 1. Init Context
    const ctx = getAudioContext();
    audioContextRef.current = ctx;

    // 2. Create Source (if not exists)
    if (!sourceNodeRef.current) {
        sourceNodeRef.current = ctx.createMediaElementSource(audioRef.current);
    }

    // --- FREQUENCY CROSSOVERS (STEEPER SLOPES) ---
    // We cascade 2 filters to get 24dB/octave slope for better isolation

    const BASS_CROSSOVER = 200; // Hz
    const TREBLE_CROSSOVER = 4000; // Hz

    // --- PATH 1: LOW (Bass/7 String) ---
    // Source -> LowPass1 -> LowPass2 -> Gain
    const lowFilter1 = ctx.createBiquadFilter();
    lowFilter1.type = 'lowpass';
    lowFilter1.frequency.value = BASS_CROSSOVER;

    const lowFilter2 = ctx.createBiquadFilter();
    lowFilter2.type = 'lowpass';
    lowFilter2.frequency.value = BASS_CROSSOVER;

    // --- PATH 2: MID (Voice/Harmony) ---
    // Source -> HighPass1 -> HighPass2 -> LowPass1 -> LowPass2 -> Gain
    const midHighPass1 = ctx.createBiquadFilter();
    midHighPass1.type = 'highpass';
    midHighPass1.frequency.value = BASS_CROSSOVER;

    const midHighPass2 = ctx.createBiquadFilter();
    midHighPass2.type = 'highpass';
    midHighPass2.frequency.value = BASS_CROSSOVER;

    const midLowPass1 = ctx.createBiquadFilter();
    midLowPass1.type = 'lowpass';
    midLowPass1.frequency.value = TREBLE_CROSSOVER;

    const midLowPass2 = ctx.createBiquadFilter();
    midLowPass2.type = 'lowpass';
    midLowPass2.frequency.value = TREBLE_CROSSOVER;

    // --- PATH 3: HIGH (Percussion) ---
    // Source -> HighPass1 -> HighPass2 -> Gain
    const highFilter1 = ctx.createBiquadFilter();
    highFilter1.type = 'highpass';
    highFilter1.frequency.value = TREBLE_CROSSOVER;

    const highFilter2 = ctx.createBiquadFilter();
    highFilter2.type = 'highpass';
    highFilter2.frequency.value = TREBLE_CROSSOVER;

    // 4. Create Gain Nodes (Volume Controls)
    const lowGain = ctx.createGain();
    const midGain = ctx.createGain();
    const highGain = ctx.createGain();

    eqGainsRef.current = { low: lowGain, mid: midGain, high: highGain };

    // 5. Connect Graph

    // Low Path
    sourceNodeRef.current.connect(lowFilter1);
    lowFilter1.connect(lowFilter2);
    lowFilter2.connect(lowGain);
    lowGain.connect(ctx.destination);

    // Mid Path
    sourceNodeRef.current.connect(midHighPass1);
    midHighPass1.connect(midHighPass2);
    midHighPass2.connect(midLowPass1);
    midLowPass1.connect(midLowPass2);
    midLowPass2.connect(midGain);
    midGain.connect(ctx.destination);

    // High Path
    sourceNodeRef.current.connect(highFilter1);
    highFilter1.connect(highFilter2);
    highFilter2.connect(highGain);
    highGain.connect(ctx.destination);
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      setFile(selectedFile);
      setIsLoading(true);
      setIsPlaying(false);

      const objectUrl = URL.createObjectURL(selectedFile);

      if (audioRef.current) {
          audioRef.current.src = objectUrl;
          audioRef.current.load();
      }

      // Decode for visualizer
      try {
          const arrayBuffer = await selectedFile.arrayBuffer();
          const ctx = getAudioContext();
          const audioBuffer = await ctx.decodeAudioData(arrayBuffer);
          waveformBufferRef.current = audioBuffer;
          setDuration(audioBuffer.duration);
          setLoopEnd(audioBuffer.duration);
          drawWaveform();
      } catch (err) {
          console.error("Error decoding audio for visualizer", err);
      } finally {
          setIsLoading(false);
      }
    }
  };

  // --- PLAYBACK CONTROLS ---

  const togglePlay = async () => {
    if (!audioRef.current) return;
    const ctx = getAudioContext();

    if (ctx.state === 'suspended') await ctx.resume();

    // Ensure graph is set up (one time)
    if (!eqGainsRef.current.low) {
        setupAudioGraph();
    }

    if (isPlaying) {
      audioRef.current.pause();
      setIsPlaying(false);
    } else {
      try {
        await audioRef.current.play();
        setIsPlaying(true);
      } catch (err) {
          console.error("Play error:", err);
      }
    }
  };

  const stopAudio = () => {
      if (!audioRef.current) return;
      audioRef.current.pause();
      audioRef.current.currentTime = isLooping ? loopStart : 0;
      setCurrentTime(audioRef.current.currentTime);
      setIsPlaying(false);
  };

  // Update Volumes with improved Zero Logic
  useEffect(() => {
    const ctx = getAudioContext();
    const t = ctx.currentTime;

    const updateGain = (node: GainNode | null, val: number) => {
        if (!node) return;
        if (val === 0) {
            // Hard mute using cancelScheduledValues to act immediately
            node.gain.cancelScheduledValues(t);
            node.gain.setValueAtTime(0, t);
        } else {
            // Smooth transition
            node.gain.setTargetAtTime(val, t, 0.05);
        }
    };

    updateGain(eqGainsRef.current.low, volLow);
    updateGain(eqGainsRef.current.mid, volMid);
    updateGain(eqGainsRef.current.high, volHigh);

  }, [volLow, volMid, volHigh]);

  // Update Playback Rate
  useEffect(() => {
      if (audioRef.current) {
          audioRef.current.playbackRate = playbackRate;
          audioRef.current.preservesPitch = true;
      }
  }, [playbackRate]);

  // Looping Logic & Time Update
  useEffect(() => {
    const loopCheck = () => {
        if (!audioRef.current) return;

        const curr = audioRef.current.currentTime;
        setCurrentTime(curr);

        if (isLooping && loopEnd > loopStart) {
            if (curr >= loopEnd || curr < loopStart) {
                audioRef.current.currentTime = loopStart;
            }
        }
        animationFrameRef.current = requestAnimationFrame(loopCheck);
    };

    if (isPlaying) {
        animationFrameRef.current = requestAnimationFrame(loopCheck);
    } else {
        if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    }

    return () => {
        if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [isPlaying, isLooping, loopStart, loopEnd]);


  // --- VISUALIZER ---

  const drawWaveform = () => {
      if (!canvasRef.current || !waveformBufferRef.current) return;

      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      const width = canvas.width;
      const height = canvas.height;
      const data = waveformBufferRef.current.getChannelData(0); // Left channel
      const step = Math.ceil(data.length / width);
      const amp = height / 2;

      ctx.clearRect(0, 0, width, height);
      ctx.fillStyle = '#1e293b'; // Slate 800 background
      ctx.fillRect(0, 0, width, height);

      ctx.beginPath();
      ctx.moveTo(0, amp);
      ctx.strokeStyle = '#475569'; // Slate 600
      ctx.lineWidth = 1;

      for (let i = 0; i < width; i++) {
          let min = 1.0;
          let max = -1.0;
          for (let j = 0; j < step; j++) {
              const datum = data[(i * step) + j];
              if (datum < min) min = datum;
              if (datum > max) max = datum;
          }
          ctx.lineTo(i, (1 + min) * amp);
          ctx.lineTo(i, (1 + max) * amp);
      }
      ctx.stroke();
  };

  // Draw Overlay (Progress + Loop)
  useEffect(() => {
      if (!canvasRef.current) return;
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      // Redraw base (inefficient but simple for loop overlay updates)
      drawWaveform(); 

      const width = canvas.width;
      const height = canvas.height;

      // Draw Loop Region
      if (duration > 0) {
          const xStart = (loopStart / duration) * width;
          const xEnd = (loopEnd / duration) * width;

          ctx.fillStyle = 'rgba(20, 184, 166, 0.15)'; // Teal tint
          ctx.fillRect(xStart, 0, xEnd - xStart, height);

          // Loop markers
          ctx.strokeStyle = '#14b8a6';
          ctx.beginPath();
          ctx.moveTo(xStart, 0);
          ctx.lineTo(xStart, height);
          ctx.moveTo(xEnd, 0);
          ctx.lineTo(xEnd, height);
          ctx.stroke();

          // Labels
          ctx.fillStyle = '#14b8a6';
          ctx.font = '10px monospace';
          ctx.fillText('A', xStart + 2, 12);
          ctx.fillText('B', xEnd - 8, 12);
      }

      // Draw Playhead
      if (duration > 0) {
          const xPos = (currentTime / duration) * width;
          ctx.strokeStyle = '#ef4444'; // Red
          ctx.lineWidth = 2;
          ctx.beginPath();
          ctx.moveTo(xPos, 0);
          ctx.lineTo(xPos, height);
          ctx.stroke();
      }
  }, [currentTime, loopStart, loopEnd, duration]);


  // --- HANDLERS ---
  const handleSeek = (e: React.MouseEvent<HTMLCanvasElement>) => {
      if (!duration) return;
      const rect = canvasRef.current!.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const perc = x / rect.width;
      const newTime = perc * duration;

      if (audioRef.current) {
          audioRef.current.currentTime = newTime;
          setCurrentTime(newTime);
      }
  };

  const setLoopPoint = (type: 'start' | 'end') => {
      if (type === 'start') setLoopStart(currentTime);
      else setLoopEnd(currentTime);
      setIsLooping(true);
  };

  const formatTime = (t: number) => {
      const min = Math.floor(t / 60);
      const sec = Math.floor(t % 60);
      return `${min}:${sec.toString().padStart(2, '0')}`;
  };

  return (
    <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 h-full flex flex-col">
      <audio 
        ref={audioRef} 
        onEnded={() => setIsPlaying(false)}
        crossOrigin="anonymous"
      />

      {/* HEADER */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
          <div>
            <h2 className="text-xl font-bold text-white flex items-center gap-2">
                <Layers className="text-teal-400" />
                Estúdio de Separação
            </h2>
            <p className="text-xs text-slate-400">Isole frequências, altere velocidade e crie loops.</p>
          </div>

          <label className="cursor-pointer bg-slate-700 hover:bg-slate-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors border border-slate-600">
             {isLoading ? <Loader2 className="animate-spin" size={16} /> : <Upload size={16} />}
             <span className="text-sm font-bold">Carregar Áudio</span>
             <input type="file" accept="audio/*" onChange={handleFileUpload} className="hidden" />
          </label>
      </div>

      {!file ? (
          <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-slate-700 rounded-xl bg-slate-900/30 text-slate-500 gap-4">
              <Upload size={48} className="opacity-50" />
              <p>Carregue um arquivo MP3 ou WAV para começar</p>
          </div>
      ) : (
          <div className="flex-1 flex flex-col gap-6">

              {/* VISUALIZER & TRANSPORT */}
              <div className="bg-slate-900 rounded-xl p-4 border border-slate-700">
                  <div className="relative h-32 w-full bg-slate-800 rounded-lg overflow-hidden cursor-crosshair mb-4 border border-slate-700">
                      <canvas 
                        ref={canvasRef} 
                        width={800} 
                        height={128} 
                        className="w-full h-full"
                        onClick={handleSeek}
                      />
                  </div>

                  <div className="flex flex-wrap items-center justify-between gap-4">
                      <div className="flex items-center gap-2">
                          <button onClick={togglePlay} className="w-12 h-12 rounded-full bg-teal-500 hover:bg-teal-400 text-slate-900 flex items-center justify-center transition-all shadow-lg shadow-teal-900/20">
                              {isPlaying ? <Pause fill="currentColor" /> : <Play fill="currentColor" className="ml-1" />}
                          </button>
                          <button onClick={stopAudio} className="w-12 h-12 rounded-full bg-slate-700 hover:bg-slate-600 text-white flex items-center justify-center transition-all shadow-md">
                              <Square size={20} fill="currentColor" />
                          </button>
                          <div className="text-xs font-mono text-teal-400 bg-slate-800 px-2 py-1 rounded border border-slate-700">
                              {formatTime(currentTime)} / {formatTime(duration)}
                          </div>
                      </div>

                      <div className="flex items-center gap-2 bg-slate-800 p-1.5 rounded-lg border border-slate-700">
                          <button onClick={() => setLoopPoint('start')} className="px-3 py-1 text-xs font-bold hover:bg-slate-700 rounded text-teal-200">Definir A</button>
                          <button onClick={() => setLoopPoint('end')} className="px-3 py-1 text-xs font-bold hover:bg-slate-700 rounded text-teal-200">Definir B</button>
                          <button 
                            onClick={() => setIsLooping(!isLooping)} 
                            className={`p-1.5 rounded transition-colors ${isLooping ? 'bg-teal-500/20 text-teal-400' : 'text-slate-500 hover:text-white'}`}
                          >
                              <Repeat size={16} />
                          </button>
                      </div>

                      <div className="flex items-center gap-3 bg-slate-800 p-2 rounded-lg border border-slate-700 min-w-[200px]">
                          <span className="text-[10px] uppercase font-bold text-slate-500">Velocidade</span>
                          <Rewind size={14} className="text-slate-500 cursor-pointer" onClick={() => setPlaybackRate(Math.max(0.5, playbackRate - 0.1))} />
                          <input 
                            type="range" min="0.5" max="1.5" step="0.05" 
                            value={playbackRate} 
                            onChange={(e) => setPlaybackRate(Number(e.target.value))}
                            className="flex-1 h-1 bg-slate-600 rounded-lg appearance-none accent-teal-500"
                          />
                          <FastForward size={14} className="text-slate-500 cursor-pointer" onClick={() => setPlaybackRate(Math.min(1.5, playbackRate + 0.1))} />
                          <span className="text-xs font-mono w-8 text-right">{playbackRate.toFixed(2)}x</span>
                      </div>
                  </div>
              </div>

              {/* MIXER (STEM SIMULATION) */}
              <div className="flex-1 bg-slate-900/50 rounded-xl p-6 border border-slate-700">
                   <div className="flex items-center gap-2 mb-6">
                       <Layers size={20} className="text-slate-400" />
                       <h3 className="font-bold text-slate-200">Mixer de Frequências (Simulação de Stems)</h3>
                       <div className="ml-auto group relative">
                           <Info size={16} className="text-slate-500 cursor-help" />
                           <div className="absolute right-0 bottom-full mb-2 w-64 p-2 bg-black text-xs text-slate-300 rounded border border-slate-700 hidden group-hover:block z-50">
                               Isola bandas de frequência. Use "Baixo" para ouvir a 7ª corda, ou "Mute Voz" para zerar a harmonia.
                           </div>
                       </div>
                   </div>

                   <div className="grid grid-cols-3 gap-8 h-48">

                       {/* LOW / BASS */}
                       <div className="flex flex-col items-center gap-2 group">
                           <div className="flex-1 bg-slate-800 w-12 rounded-full relative border border-slate-700 flex justify-center p-2 group-hover:border-yellow-500/50 transition-colors">
                               <input 
                                    type="range" min="0" max="2" step="0.1" 
                                    value={volLow}
                                    onChange={(e) => setVolLow(Number(e.target.value))}
                                    className="absolute h-full w-full opacity-0 cursor-pointer z-10"
                               />
                               {/* Custom Visual Slider Bar */}
                               <div className="absolute bottom-2 w-2 bg-yellow-500 rounded-full transition-all duration-75" style={{ height: `${(volLow / 2) * 85}%` }}></div>
                           </div>
                           <div className="text-center">
                               <div className="font-bold text-yellow-500 text-sm">BAIXO</div>
                               <div className="text-[10px] text-slate-500">7 Cordas</div>
                           </div>
                           <button onClick={() => setVolLow(prev => prev === 0 ? 1 : 0)} className="hover:text-yellow-400">
                                {volLow === 0 ? <VolumeX size={16} className="text-red-500" /> : <Volume2 size={16} className="text-yellow-500" />}
                           </button>
                       </div>

                       {/* MID / HARMONY */}
                       <div className="flex flex-col items-center gap-2 group">
                           <div className="flex-1 bg-slate-800 w-12 rounded-full relative border border-slate-700 flex justify-center p-2 group-hover:border-indigo-500/50 transition-colors">
                               <input 
                                    type="range" min="0" max="2" step="0.1" 
                                    value={volMid}
                                    onChange={(e) => setVolMid(Number(e.target.value))}
                                    className="absolute h-full w-full opacity-0 cursor-pointer z-10"
                               />
                               <div className="absolute bottom-2 w-2 bg-indigo-500 rounded-full transition-all duration-75" style={{ height: `${(volMid / 2) * 85}%` }}></div>
                           </div>
                           <div className="text-center">
                               <div className="font-bold text-indigo-500 text-sm">VOZ/HARMONIA</div>
                               <div className="text-[10px] text-slate-500">Mute Voz</div>
                           </div>
                           <button onClick={() => setVolMid(prev => prev === 0 ? 1 : 0)} className="hover:text-indigo-400">
                               {volMid === 0 ? <VolumeX size={16} className="text-red-500" /> : <Volume2 size={16} className="text-indigo-500" />}
                           </button>
                       </div>

                       {/* HIGH / PERCUSSION */}
                       <div className="flex flex-col items-center gap-2 group">
                           <div className="flex-1 bg-slate-800 w-12 rounded-full relative border border-slate-700 flex justify-center p-2 group-hover:border-pink-500/50 transition-colors">
                               <input 
                                    type="range" min="0" max="2" step="0.1" 
                                    value={volHigh}
                                    onChange={(e) => setVolHigh(Number(e.target.value))}
                                    className="absolute h-full w-full opacity-0 cursor-pointer z-10"
                               />
                               <div className="absolute bottom-2 w-2 bg-pink-500 rounded-full transition-all duration-75" style={{ height: `${(volHigh / 2) * 85}%` }}></div>
                           </div>
                           <div className="text-center">
                               <div className="font-bold text-pink-500 text-sm">PERCUSSÃO</div>
                               <div className="text-[10px] text-slate-500">Agudos</div>
                           </div>
                           <button onClick={() => setVolHigh(prev => prev === 0 ? 1 : 0)} className="hover:text-pink-400">
                               {volHigh === 0 ? <VolumeX size={16} className="text-red-500" /> : <Volume2 size={16} className="text-pink-500" />}
                           </button>
                       </div>

                   </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Upload, Play, Pause, Square, Repeat, FastForward, Rewind, Layers, Volume2, Info, Loader2, VolumeX } from 'lucide-react';
import { getAudioContext } from '../utils/audio';

// --- TYPES ---

interface EqBands {
  low: GainNode | null;
  mid: GainNode | null;
  high: GainNode | null;
}

export const AudioSeparator: React.FC = () => {
  // State
  const [file, setFile] = useState<File | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [duration, setDuration] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isLooping, setIsLooping] = useState(false);
  const [loopStart, setLoopStart] = useState<number>(0);
  const [loopEnd, setLoopEnd] = useState<number>(0);
  const [isLoading, setIsLoading] = useState(false);

  // Mixer Volumes (0.0 - 2.0 to allow boost)
  const [volLow, setVolLow] = useState(1.0);
  const [volMid, setVolMid] = useState(1.0);
  const [volHigh, setVolHigh] = useState(1.0);

  // Refs
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<MediaElementAudioSourceNode | null>(null);
  const eqGainsRef = useRef<EqBands>({ low: null, mid: null, high: null });
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const animationFrameRef = useRef<number | null>(null);
  const waveformBufferRef = useRef<AudioBuffer | null>(null);

  // --- AUDIO SETUP ---

  const setupAudioGraph = () => {
    if (!audioRef.current) return;

    // 1. Init Context
    const ctx = getAudioContext();
    audioContextRef.current = ctx;

    // 2. Create Source (if not exists)
    if (!sourceNodeRef.current) {
        sourceNodeRef.current = ctx.createMediaElementSource(audioRef.current);
    }

    // --- FREQUENCY CROSSOVERS (STEEPER SLOPES - 48dB/octave) ---
    // Cascading 4 BiquadFilters to create a "brick wall" effect for better isolation

    const BASS_CROSSOVER = 150; // Hz - Lowered to exclude vocal fundamentals
    const TREBLE_CROSSOVER = 5000; // Hz - Raised to exclude high harmony

    // Create Gain Nodes (Volume Controls)
    const lowGain = ctx.createGain();
    const midGain = ctx.createGain();
    const highGain = ctx.createGain();

    // IMPORTANT: Initialize with current state values to avoid "full volume" bug before first interaction
    lowGain.gain.value = volLow;
    midGain.gain.value = volMid;
    highGain.gain.value = volHigh;

    eqGainsRef.current = { low: lowGain, mid: midGain, high: highGain };

    // Helper to chain filters
    const chainFilters = (source: AudioNode, filters: BiquadFilterNode[], dest: AudioNode) => {
        let curr = source;
        filters.forEach(f => {
            curr.connect(f);
            curr = f;
        });
        curr.connect(dest);
    };

    const createFilters = (type: BiquadFilterType, freq: number, count: number) => {
        return Array(count).fill(0).map(() => {
            const f = ctx.createBiquadFilter();
            f.type = type;
            f.frequency.value = freq;
            return f;
        });
    };

    // --- PATH 1: LOW (Bass/7 String) ---
    // Source -> 4x LowPass -> Gain
    const lowFilters = createFilters('lowpass', BASS_CROSSOVER, 4);
    chainFilters(sourceNodeRef.current, lowFilters, lowGain);
    lowGain.connect(ctx.destination);

    // --- PATH 2: MID (Voice/Harmony) ---
    // Source -> 4x HighPass (Bass Cut) -> 4x LowPass (Treble Cut) -> Gain
    // Note: To save resources, we could branch, but for clarity/isolation we create distinct chains.
    const midHighPasses = createFilters('highpass', BASS_CROSSOVER, 4);
    const midLowPasses = createFilters('lowpass', TREBLE_CROSSOVER, 4);

    // Chain manually: Source -> [HighPasses] -> [LowPasses] -> Gain
    let curr: AudioNode = sourceNodeRef.current;
    midHighPasses.forEach(f => { curr.connect(f); curr = f; });
    midLowPasses.forEach(f => { curr.connect(f); curr = f; });
    curr.connect(midGain);
    midGain.connect(ctx.destination);

    // --- PATH 3: HIGH (Percussion) ---
    // Source -> 4x HighPass -> Gain
    const highFilters = createFilters('highpass', TREBLE_CROSSOVER, 4);
    chainFilters(sourceNodeRef.current, highFilters, highGain);
    highGain.connect(ctx.destination);
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      setFile(selectedFile);
      setIsLoading(true);
      setIsPlaying(false);

      const objectUrl = URL.createObjectURL(selectedFile);

      if (audioRef.current) {
          audioRef.current.src = objectUrl;
          audioRef.current.load();
      }

      // Decode for visualizer
      try {
          const arrayBuffer = await selectedFile.arrayBuffer();
          const ctx = getAudioContext();
          const audioBuffer = await ctx.decodeAudioData(arrayBuffer);
          waveformBufferRef.current = audioBuffer;
          setDuration(audioBuffer.duration);
          setLoopEnd(audioBuffer.duration);
          drawWaveform();
      } catch (err) {
          console.error("Error decoding audio for visualizer", err);
      } finally {
          setIsLoading(false);
      }
    }
  };

  // --- PLAYBACK CONTROLS ---

  const togglePlay = async () => {
    if (!audioRef.current) return;
    const ctx = getAudioContext();

    if (ctx.state === 'suspended') await ctx.resume();

    // Ensure graph is set up (one time)
    if (!eqGainsRef.current.low) {
        setupAudioGraph();
    }

    if (isPlaying) {
      audioRef.current.pause();
      setIsPlaying(false);
    } else {
      try {
        await audioRef.current.play();
        setIsPlaying(true);
      } catch (err) {
          console.error("Play error:", err);
      }
    }
  };

  const stopAudio = () => {
      if (!audioRef.current) return;
      audioRef.current.pause();
      audioRef.current.currentTime = isLooping ? loopStart : 0;
      setCurrentTime(audioRef.current.currentTime);
      setIsPlaying(false);
  };

  // Update Volumes with improved Zero Logic (Real-time)
  useEffect(() => {
    const ctx = getAudioContext();
    const t = ctx.currentTime;

    const updateGain = (node: GainNode | null, val: number) => {
        if (!node) return;
        // Immediate response for better UX
        node.gain.cancelScheduledValues(t); 

        if (val === 0) {
            node.gain.setValueAtTime(0, t);
        } else {
            // Very fast ramp to avoid clicking but feel instant
            node.gain.setTargetAtTime(val, t, 0.015);
        }
    };

    updateGain(eqGainsRef.current.low, volLow);
    updateGain(eqGainsRef.current.mid, volMid);
    updateGain(eqGainsRef.current.high, volHigh);

  }, [volLow, volMid, volHigh]);

  // Update Playback Rate
  useEffect(() => {
      if (audioRef.current) {
          audioRef.current.playbackRate = playbackRate;
          audioRef.current.preservesPitch = true;
      }
  }, [playbackRate]);

  // Looping Logic & Time Update
  useEffect(() => {
    const loopCheck = () => {
        if (!audioRef.current) return;

        const curr = audioRef.current.currentTime;
        setCurrentTime(curr);

        if (isLooping && loopEnd > loopStart) {
            if (curr >= loopEnd || curr < loopStart) {
                audioRef.current.currentTime = loopStart;
            }
        }
        animationFrameRef.current = requestAnimationFrame(loopCheck);
    };

    if (isPlaying) {
        animationFrameRef.current = requestAnimationFrame(loopCheck);
    } else {
        if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    }

    return () => {
        if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [isPlaying, isLooping, loopStart, loopEnd]);


  // --- VISUALIZER ---

  const drawWaveform = () => {
      if (!canvasRef.current || !waveformBufferRef.current) return;

      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      const width = canvas.width;
      const height = canvas.height;
      const data = waveformBufferRef.current.getChannelData(0); // Left channel
      const step = Math.ceil(data.length / width);
      const amp = height / 2;

      ctx.clearRect(0, 0, width, height);
      ctx.fillStyle = '#1e293b'; // Slate 800 background
      ctx.fillRect(0, 0, width, height);

      ctx.beginPath();
      ctx.moveTo(0, amp);
      ctx.strokeStyle = '#475569'; // Slate 600
      ctx.lineWidth = 1;

      for (let i = 0; i < width; i++) {
          let min = 1.0;
          let max = -1.0;
          for (let j = 0; j < step; j++) {
              const datum = data[(i * step) + j];
              if (datum < min) min = datum;
              if (datum > max) max = datum;
          }
          ctx.lineTo(i, (1 + min) * amp);
          ctx.lineTo(i, (1 + max) * amp);
      }
      ctx.stroke();
  };

  // Draw Overlay (Progress + Loop)
  useEffect(() => {
      if (!canvasRef.current) return;
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      // Redraw base (inefficient but simple for loop overlay updates)
      drawWaveform(); 

      const width = canvas.width;
      const height = canvas.height;

      // Draw Loop Region
      if (duration > 0) {
          const xStart = (loopStart / duration) * width;
          const xEnd = (loopEnd / duration) * width;

          ctx.fillStyle = 'rgba(20, 184, 166, 0.15)'; // Teal tint
          ctx.fillRect(xStart, 0, xEnd - xStart, height);

          // Loop markers
          ctx.strokeStyle = '#14b8a6';
          ctx.beginPath();
          ctx.moveTo(xStart, 0);
          ctx.lineTo(xStart, height);
          ctx.moveTo(xEnd, 0);
          ctx.lineTo(xEnd, height);
          ctx.stroke();

          // Labels
          ctx.fillStyle = '#14b8a6';
          ctx.font = '10px monospace';
          ctx.fillText('A', xStart + 2, 12);
          ctx.fillText('B', xEnd - 8, 12);
      }

      // Draw Playhead
      if (duration > 0) {
          const xPos = (currentTime / duration) * width;
          ctx.strokeStyle = '#ef4444'; // Red
          ctx.lineWidth = 2;
          ctx.beginPath();
          ctx.moveTo(xPos, 0);
          ctx.lineTo(xPos, height);
          ctx.stroke();
      }
  }, [currentTime, loopStart, loopEnd, duration]);


  // --- HANDLERS ---
  const handleSeek = (e: React.MouseEvent<HTMLCanvasElement>) => {
      if (!duration) return;
      const rect = canvasRef.current!.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const perc = x / rect.width;
      const newTime = perc * duration;

      if (audioRef.current) {
          audioRef.current.currentTime = newTime;
          setCurrentTime(newTime);
      }
  };

  const setLoopPoint = (type: 'start' | 'end') => {
      if (type === 'start') setLoopStart(currentTime);
      else setLoopEnd(currentTime);
      setIsLooping(true);
  };

  const formatTime = (t: number) => {
      const min = Math.floor(t / 60);
      const sec = Math.floor(t % 60);
      return `${min}:${sec.toString().padStart(2, '0')}`;
  };

  return (
    <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 h-full flex flex-col">
      <audio 
        ref={audioRef} 
        onEnded={() => setIsPlaying(false)}
        crossOrigin="anonymous"
      />

      {/* HEADER */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
          <div>
            <h2 className="text-xl font-bold text-white flex items-center gap-2">
                <Layers className="text-teal-400" />
                Estúdio de Separação
            </h2>
            <p className="text-xs text-slate-400">Isole frequências, altere velocidade e crie loops.</p>
          </div>

          <label className="cursor-pointer bg-slate-700 hover:bg-slate-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors border border-slate-600">
             {isLoading ? <Loader2 className="animate-spin" size={16} /> : <Upload size={16} />}
             <span className="text-sm font-bold">Carregar Áudio</span>
             <input type="file" accept="audio/*" onChange={handleFileUpload} className="hidden" />
          </label>
      </div>

      {!file ? (
          <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-slate-700 rounded-xl bg-slate-900/30 text-slate-500 gap-4">
              <Upload size={48} className="opacity-50" />
              <p>Carregue um arquivo MP3 ou WAV para começar</p>
          </div>
      ) : (
          <div className="flex-1 flex flex-col gap-6">

              {/* VISUALIZER & TRANSPORT */}
              <div className="bg-slate-900 rounded-xl p-4 border border-slate-700">
                  <div className="relative h-32 w-full bg-slate-800 rounded-lg overflow-hidden cursor-crosshair mb-4 border border-slate-700">
                      <canvas 
                        ref={canvasRef} 
                        width={800} 
                        height={128} 
                        className="w-full h-full"
                        onClick={handleSeek}
                      />
                  </div>

                  <div className="flex flex-wrap items-center justify-between gap-4">
                      <div className="flex items-center gap-2">
                          <button onClick={togglePlay} className="w-12 h-12 rounded-full bg-teal-500 hover:bg-teal-400 text-slate-900 flex items-center justify-center transition-all shadow-lg shadow-teal-900/20">
                              {isPlaying ? <Pause fill="currentColor" /> : <Play fill="currentColor" className="ml-1" />}
                          </button>
                          <button onClick={stopAudio} className="w-12 h-12 rounded-full bg-slate-700 hover:bg-slate-600 text-white flex items-center justify-center transition-all shadow-md">
                              <Square size={20} fill="currentColor" />
                          </button>
                          <div className="text-xs font-mono text-teal-400 bg-slate-800 px-2 py-1 rounded border border-slate-700">
                              {formatTime(currentTime)} / {formatTime(duration)}
                          </div>
                      </div>

                      <div className="flex items-center gap-2 bg-slate-800 p-1.5 rounded-lg border border-slate-700">
                          <button onClick={() => setLoopPoint('start')} className="px-3 py-1 text-xs font-bold hover:bg-slate-700 rounded text-teal-200">Definir A</button>
                          <button onClick={() => setLoopPoint('end')} className="px-3 py-1 text-xs font-bold hover:bg-slate-700 rounded text-teal-200">Definir B</button>
                          <button 
                            onClick={() => setIsLooping(!isLooping)} 
                            className={`p-1.5 rounded transition-colors ${isLooping ? 'bg-teal-500/20 text-teal-400' : 'text-slate-500 hover:text-white'}`}
                          >
                              <Repeat size={16} />
                          </button>
                      </div>

                      <div className="flex items-center gap-3 bg-slate-800 p-2 rounded-lg border border-slate-700 min-w-[200px]">
                          <span className="text-[10px] uppercase font-bold text-slate-500">Velocidade</span>
                          <Rewind size={14} className="text-slate-500 cursor-pointer" onClick={() => setPlaybackRate(Math.max(0.5, playbackRate - 0.1))} />
                          <input 
                            type="range" min="0.5" max="1.5" step="0.05" 
                            value={playbackRate} 
                            onChange={(e) => setPlaybackRate(Number(e.target.value))}
                            className="flex-1 h-1 bg-slate-600 rounded-lg appearance-none accent-teal-500"
                          />
                          <FastForward size={14} className="text-slate-500 cursor-pointer" onClick={() => setPlaybackRate(Math.min(1.5, playbackRate + 0.1))} />
                          <span className="text-xs font-mono w-8 text-right">{playbackRate.toFixed(2)}x</span>
                      </div>
                  </div>
              </div>

              {/* MIXER (STEM SIMULATION) */}
              <div className="flex-1 bg-slate-900/50 rounded-xl p-6 border border-slate-700">
                   <div className="flex items-center gap-2 mb-6">
                       <Layers size={20} className="text-slate-400" />
                       <h3 className="font-bold text-slate-200">Mixer de Frequências (Simulação de Stems)</h3>
                       <div className="ml-auto group relative">
                           <Info size={16} className="text-slate-500 cursor-help" />
                           <div className="absolute right-0 bottom-full mb-2 w-64 p-2 bg-black text-xs text-slate-300 rounded border border-slate-700 hidden group-hover:block z-50">
                               Isola bandas de frequência. Use "Baixo" para ouvir a 7ª corda, ou "Mute Voz" para zerar a harmonia.
                           </div>
                       </div>
                   </div>

                   <div className="grid grid-cols-3 gap-8 h-48">

                       {/* LOW / BASS */}
                       <div className="flex flex-col items-center gap-2 group">
                           <div className="flex-1 bg-slate-800 w-12 rounded-full relative border border-slate-700 flex justify-center p-2 group-hover:border-yellow-500/50 transition-colors">
                               <input 
                                    type="range" min="0" max="2" step="0.1" 
                                    value={volLow}
                                    onChange={(e) => setVolLow(Number(e.target.value))}
                                    className="absolute h-full w-full opacity-0 cursor-pointer z-10"
                               />
                               {/* Custom Visual Slider Bar */}
                               <div className="absolute bottom-2 w-2 bg-yellow-500 rounded-full transition-all duration-75" style={{ height: `${(volLow / 2) * 85}%` }}></div>
                           </div>
                           <div className="text-center">
                               <div className="font-bold text-yellow-500 text-sm">BAIXO</div>
                               <div className="text-[10px] text-slate-500">7 Cordas</div>
                           </div>
                           <button onClick={() => setVolLow(prev => prev === 0 ? 1 : 0)} className="hover:text-yellow-400">
                                {volLow === 0 ? <VolumeX size={16} className="text-red-500" /> : <Volume2 size={16} className="text-yellow-500" />}
                           </button>
                       </div>

                       {/* MID / HARMONY */}
                       <div className="flex flex-col items-center gap-2 group">
                           <div className="flex-1 bg-slate-800 w-12 rounded-full relative border border-slate-700 flex justify-center p-2 group-hover:border-indigo-500/50 transition-colors">
                               <input 
                                    type="range" min="0" max="2" step="0.1" 
                                    value={volMid}
                                    onChange={(e) => setVolMid(Number(e.target.value))}
                                    className="absolute h-full w-full opacity-0 cursor-pointer z-10"
                               />
                               <div className="absolute bottom-2 w-2 bg-indigo-500 rounded-full transition-all duration-75" style={{ height: `${(volMid / 2) * 85}%` }}></div>
                           </div>
                           <div className="text-center">
                               <div className="font-bold text-indigo-500 text-sm">VOZ/HARMONIA</div>
                               <div className="text-[10px] text-slate-500">Mute Voz</div>
                           </div>
                           <button onClick={() => setVolMid(prev => prev === 0 ? 1 : 0)} className="hover:text-indigo-400">
                               {volMid === 0 ? <VolumeX size={16} className="text-red-500" /> : <Volume2 size={16} className="text-indigo-500" />}
                           </button>
                       </div>

                       {/* HIGH / PERCUSSION */}
                       <div className="flex flex-col items-center gap-2 group">
                           <div className="flex-1 bg-slate-800 w-12 rounded-full relative border border-slate-700 flex justify-center p-2 group-hover:border-pink-500/50 transition-colors">
                               <input 
                                    type="range" min="0" max="2" step="0.1" 
                                    value={volHigh}
                                    onChange={(e) => setVolHigh(Number(e.target.value))}
                                    className="absolute h-full w-full opacity-0 cursor-pointer z-10"
                               />
                               <div className="absolute bottom-2 w-2 bg-pink-500 rounded-full transition-all duration-75" style={{ height: `${(volHigh / 2) * 85}%` }}></div>
                           </div>
                           <div className="text-center">
                               <div className="font-bold text-pink-500 text-sm">PERCUSSÃO</div>
                               <div className="text-[10px] text-slate-500">Agudos</div>
                           </div>
                           <button onClick={() => setVolHigh(prev => prev === 0 ? 1 : 0)} className="hover:text-pink-400">
                               {volHigh === 0 ? <VolumeX size={16} className="text-red-500" /> : <Volume2 size={16} className="text-pink-500" />}
                           </button>
                       </div>

                   </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Upload, Play, Pause, Square, Repeat, FastForward, Rewind, Layers, Volume2, Info, Loader2, VolumeX, Plus, Minus, Sliders, Sparkles, Zap } from 'lucide-react';
import { getAudioContext } from '../utils/audio';

// --- TYPES ---

interface ChannelNodes {
  gain: GainNode;
  eqLow: BiquadFilterNode;
  eqMid: BiquadFilterNode;
  eqHigh: BiquadFilterNode;
  reverbSend?: GainNode;
}

interface EqState {
  low: number; // -10 to 10
  mid: number;
  high: number;
}

export const AudioSeparator: React.FC = () => {
  // --- STATE ---
  const [file, setFile] = useState<File | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [duration, setDuration] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isLooping, setIsLooping] = useState(false);
  const [loopStart, setLoopStart] = useState<number>(0);
  const [loopEnd, setLoopEnd] = useState<number>(0);
  const [isLoading, setIsLoading] = useState(false);

  // Volumes (0.0 - 2.0)
  const [volLow, setVolLow] = useState(1.0);
  const [volMid, setVolMid] = useState(1.0);
  const [volHigh, setVolHigh] = useState(1.0);

  // EQ States
  const [eqLowSettings, setEqLowSettings] = useState<EqState>({ low: 0, mid: 0, high: 0 });
  const [eqMidSettings, setEqMidSettings] = useState<EqState>({ low: 0, mid: 2, high: 3 }); // Default boost for guitar
  const [eqHighSettings, setEqHighSettings] = useState<EqState>({ low: 0, mid: 0, high: 0 });

  // Effects
  const [isEnhanced, setIsEnhanced] = useState(true); // "Magic" mode for guitar

  // --- REFS ---
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<MediaElementAudioSourceNode | null>(null);

  // Audio Graph Nodes
  const nodesRef = useRef<{
    low: ChannelNodes | null;
    mid: ChannelNodes | null;
    high: ChannelNodes | null;
    compressor: DynamicsCompressorNode | null;
    reverb: ConvolverNode | null;
  }>({ low: null, mid: null, high: null, compressor: null, reverb: null });

  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const animationFrameRef = useRef<number | null>(null);
  const waveformBufferRef = useRef<AudioBuffer | null>(null);

  // --- AUDIO ENGINE ---

  // Create a simple impulse response for reverb
  const createReverbImpulse = (ctx: AudioContext, duration: number = 2.0, decay: number = 2.0) => {
    const rate = ctx.sampleRate;
    const length = rate * duration;
    const impulse = ctx.createBuffer(2, length, rate);
    const left = impulse.getChannelData(0);
    const right = impulse.getChannelData(1);

    for (let i = 0; i < length; i++) {
        const n = i / length;
        // Simple noise with exponential decay
        left[i] = (Math.random() * 2 - 1) * Math.pow(1 - n, decay);
        right[i] = (Math.random() * 2 - 1) * Math.pow(1 - n, decay);
    }
    return impulse;
  };

  const setupAudioGraph = () => {
    if (!audioRef.current) return;

    const ctx = getAudioContext();
    audioContextRef.current = ctx;

    if (!sourceNodeRef.current) {
        sourceNodeRef.current = ctx.createMediaElementSource(audioRef.current);
    }

    // --- MASTER EFFECTS ---
    // Compressor to glue everything together and prevent clipping when boosting EQ
    const compressor = ctx.createDynamicsCompressor();
    compressor.threshold.value = -24;
    compressor.knee.value = 30;
    compressor.ratio.value = 12;
    compressor.attack.value = 0.003;
    compressor.release.value = 0.25;

    compressor.connect(ctx.destination);
    nodesRef.current.compressor = compressor;

    // Reverb Bus (Simulated Room)
    const reverbNode = ctx.createConvolver();
    reverbNode.buffer = createReverbImpulse(ctx, 1.5, 3.0); // 1.5s reverb
    const reverbGain = ctx.createGain();
    reverbGain.gain.value = 0.15; // 15% wet
    reverbNode.connect(reverbGain);
    reverbGain.connect(compressor);
    nodesRef.current.reverb = reverbNode;

    // --- CROSSOVER DEFINITIONS ---
    // Using 48dB/octave slopes (4 cascaded filters) for clean separation
    const BASS_CROSSOVER = 150; 
    const TREBLE_CROSSOVER = 5000;

    const createFilters = (type: BiquadFilterType, freq: number, count: number) => {
        return Array(count).fill(0).map(() => {
            const f = ctx.createBiquadFilter();
            f.type = type;
            f.frequency.value = freq;
            return f;
        });
    };

    const chainFilters = (source: AudioNode, filters: BiquadFilterNode[], dest: AudioNode) => {
        let curr = source;
        filters.forEach(f => {
            curr.connect(f);
            curr = f;
        });
        curr.connect(dest);
    };

    // --- CHANNEL CREATION HELPER ---
    const createChannel = (initialVol: number): ChannelNodes => {
        // Gain
        const gain = ctx.createGain();
        gain.gain.value = initialVol;

        // 3-Band EQ
        const eqLow = ctx.createBiquadFilter();
        eqLow.type = 'lowshelf';
        eqLow.frequency.value = 300; // Low Shelf

        const eqMid = ctx.createBiquadFilter();
        eqMid.type = 'peaking';
        eqMid.frequency.value = 2500; // Presence/Mid
        eqMid.Q.value = 1.0;

        const eqHigh = ctx.createBiquadFilter();
        eqHigh.type = 'highshelf';
        eqHigh.frequency.value = 8000; // Air

        // Reverb Send
        const reverbSend = ctx.createGain();
        reverbSend.gain.value = 0; // Default off, controlled by "Magic"

        // Internal Chain: Input -> EQ Low -> EQ Mid -> EQ High -> Gain -> Output
        eqLow.connect(eqMid);
        eqMid.connect(eqHigh);
        eqHigh.connect(gain);

        // Output Connects
        gain.connect(compressor);
        gain.connect(reverbSend);
        reverbSend.connect(reverbNode);

        return { gain, eqLow, eqMid, eqHigh, reverbSend };
    };

    // Initialize Channels
    nodesRef.current.low = createChannel(volLow);
    nodesRef.current.mid = createChannel(volMid);
    nodesRef.current.high = createChannel(volHigh);

    // --- ROUTING SOURCE THROUGH CROSSOVERS TO CHANNELS ---

    // Path 1: LOW (Bass)
    // Source -> LowPass Filters -> Low Channel EQ Input
    const lowPasses = createFilters('lowpass', BASS_CROSSOVER, 4);
    chainFilters(sourceNodeRef.current, lowPasses, nodesRef.current.low.eqLow);

    // Path 2: MID (Guitar/Voice)
    // Source -> HighPass (Cut Bass) -> LowPass (Cut Treble) -> Mid Channel EQ Input
    const midHighPasses = createFilters('highpass', BASS_CROSSOVER, 4);
    const midLowPasses = createFilters('lowpass', TREBLE_CROSSOVER, 4);

    let midChainHead: AudioNode = sourceNodeRef.current;
    midHighPasses.forEach(f => { midChainHead.connect(f); midChainHead = f; });
    midLowPasses.forEach(f => { midChainHead.connect(f); midChainHead = f; });
    midChainHead.connect(nodesRef.current.mid.eqLow);

    // Path 3: HIGH (Percussion)
    // Source -> HighPass Filters -> High Channel EQ Input
    const highPasses = createFilters('highpass', TREBLE_CROSSOVER, 4);
    chainFilters(sourceNodeRef.current, highPasses, nodesRef.current.high.eqLow);
  };

  // --- UPDATES & EFFECTS ---

  // Handle EQ Updates
  useEffect(() => {
    const ctx = getAudioContext();
    const t = ctx.currentTime;
    const ramp = 0.1;

    const applyEq = (nodes: ChannelNodes | null, settings: EqState) => {
        if (!nodes) return;
        nodes.eqLow.gain.setTargetAtTime(settings.low, t, ramp);
        nodes.eqMid.gain.setTargetAtTime(settings.mid, t, ramp);
        nodes.eqHigh.gain.setTargetAtTime(settings.high, t, ramp);
    };

    applyEq(nodesRef.current.low, eqLowSettings);
    applyEq(nodesRef.current.mid, eqMidSettings);
    applyEq(nodesRef.current.high, eqHighSettings);

  }, [eqLowSettings, eqMidSettings, eqHighSettings]);

  // Handle "Enhanced" Mode (Reverb Send for Mids)
  useEffect(() => {
      const t = getAudioContext().currentTime;
      if (nodesRef.current.mid?.reverbSend) {
          // If enhanced, send mids (guitar) to reverb
          const val = isEnhanced ? 0.4 : 0; 
          nodesRef.current.mid.reverbSend.gain.setTargetAtTime(val, t, 0.2);
      }
      // Boost presence slightly if enhanced
      if (nodesRef.current.mid) {
           const presence = isEnhanced ? 4 : eqMidSettings.mid; // Force boost or user setting
           nodesRef.current.mid.eqMid.gain.setTargetAtTime(presence, t, 0.2);

           const air = isEnhanced ? 3 : eqHighSettings.high;
           nodesRef.current.mid.eqHigh.gain.setTargetAtTime(air, t, 0.2);
      }
  }, [isEnhanced]);

  // Handle Volume Updates
  useEffect(() => {
    const ctx = getAudioContext();
    const t = ctx.currentTime;

    const updateGain = (nodes: ChannelNodes | null, val: number) => {
        if (!nodes) return;
        nodes.gain.gain.cancelScheduledValues(t);
        if (val === 0) nodes.gain.gain.setValueAtTime(0, t);
        else nodes.gain.gain.setTargetAtTime(val, t, 0.02);
    };

    updateGain(nodesRef.current.low, volLow);
    updateGain(nodesRef.current.mid, volMid);
    updateGain(nodesRef.current.high, volHigh);
  }, [volLow, volMid, volHigh]);


  // --- STANDARD HANDLERS (File, Play, Loop) ---

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      setFile(selectedFile);
      setIsLoading(true);
      setIsPlaying(false);

      const objectUrl = URL.createObjectURL(selectedFile);
      if (audioRef.current) {
          audioRef.current.src = objectUrl;
          audioRef.current.load();
      }
      try {
          const arrayBuffer = await selectedFile.arrayBuffer();
          const ctx = getAudioContext();
          const audioBuffer = await ctx.decodeAudioData(arrayBuffer);
          waveformBufferRef.current = audioBuffer;
          setDuration(audioBuffer.duration);
          setLoopEnd(audioBuffer.duration);
          drawWaveform();
      } catch (err) { console.error(err); } 
      finally { setIsLoading(false); }
    }
  };

  const togglePlay = async () => {
    if (!audioRef.current) return;
    const ctx = getAudioContext();
    if (ctx.state === 'suspended') await ctx.resume();

    if (!nodesRef.current.low) setupAudioGraph();

    if (isPlaying) {
      audioRef.current.pause();
      setIsPlaying(false);
    } else {
      await audioRef.current.play();
      setIsPlaying(true);
    }
  };

  const stopAudio = () => {
      if (!audioRef.current) return;
      audioRef.current.pause();
      audioRef.current.currentTime = isLooping ? loopStart : 0;
      setCurrentTime(audioRef.current.currentTime);
      setIsPlaying(false);
  };

  useEffect(() => {
      if (audioRef.current) {
          audioRef.current.playbackRate = playbackRate;
          audioRef.current.preservesPitch = true;
      }
  }, [playbackRate]);

  // Loop Check
  useEffect(() => {
    const loopCheck = () => {
        if (!audioRef.current) return;
        const curr = audioRef.current.currentTime;
        setCurrentTime(curr);
        if (isLooping && loopEnd > loopStart) {
            if (curr >= loopEnd || curr < loopStart) audioRef.current.currentTime = loopStart;
        }
        animationFrameRef.current = requestAnimationFrame(loopCheck);
    };
    if (isPlaying) animationFrameRef.current = requestAnimationFrame(loopCheck);
    else if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    return () => { if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current); };
  }, [isPlaying, isLooping, loopStart, loopEnd]);


  // --- VISUALS ---
  const drawWaveform = () => {
      if (!canvasRef.current || !waveformBufferRef.current) return;
      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;
      const width = canvasRef.current.width;
      const height = canvasRef.current.height;
      const data = waveformBufferRef.current.getChannelData(0);
      const step = Math.ceil(data.length / width);
      const amp = height / 2;

      ctx.clearRect(0, 0, width, height);
      ctx.fillStyle = '#0f172a';
      ctx.fillRect(0, 0, width, height);
      ctx.beginPath();
      ctx.moveTo(0, amp);
      ctx.strokeStyle = '#334155';
      ctx.lineWidth = 1;

      for (let i = 0; i < width; i++) {
          let min = 1.0, max = -1.0;
          for (let j = 0; j < step; j++) {
              const datum = data[(i * step) + j];
              if (datum < min) min = datum;
              if (datum > max) max = datum;
          }
          ctx.lineTo(i, (1 + min) * amp);
          ctx.lineTo(i, (1 + max) * amp);
      }
      ctx.stroke();
  };

  // Overlay
  useEffect(() => {
      if (!canvasRef.current) return;
      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;
      drawWaveform(); 
      const width = canvasRef.current.width;
      const height = canvasRef.current.height;
      if (duration > 0) {
          const xStart = (loopStart / duration) * width;
          const xEnd = (loopEnd / duration) * width;
          ctx.fillStyle = 'rgba(20, 184, 166, 0.15)';
          ctx.fillRect(xStart, 0, xEnd - xStart, height);
          ctx.strokeStyle = '#14b8a6';
          ctx.beginPath();
          ctx.moveTo(xStart, 0); ctx.lineTo(xStart, height);
          ctx.moveTo(xEnd, 0); ctx.lineTo(xEnd, height);
          ctx.stroke();
      }
      if (duration > 0) {
          const xPos = (currentTime / duration) * width;
          ctx.strokeStyle = '#ef4444';
          ctx.lineWidth = 2;
          ctx.beginPath(); ctx.moveTo(xPos, 0); ctx.lineTo(xPos, height); ctx.stroke();
      }
  }, [currentTime, loopStart, loopEnd, duration]);

  const handleSeek = (e: React.MouseEvent<HTMLCanvasElement>) => {
      if (!duration) return;
      const rect = canvasRef.current!.getBoundingClientRect();
      const perc = (e.clientX - rect.left) / rect.width;
      if (audioRef.current) {
          audioRef.current.currentTime = perc * duration;
          setCurrentTime(perc * duration);
      }
  };
  const setLoopPoint = (type: 'start' | 'end') => {
      if (type === 'start') setLoopStart(currentTime); else setLoopEnd(currentTime);
      setIsLooping(true);
  };
  const formatTime = (t: number) => {
      const min = Math.floor(t / 60);
      const sec = Math.floor(t % 60);
      return `${min}:${sec.toString().padStart(2, '0')}`;
  };

  // --- UI COMPONENTS ---

  const updateVolume = (setter: React.Dispatch<React.SetStateAction<number>>, current: number, delta: number) => {
      const newVal = Math.max(0, Math.min(2, current + delta));
      setter(parseFloat(newVal.toFixed(1)));
  };

  const updateEQ = (
      setter: React.Dispatch<React.SetStateAction<EqState>>, 
      band: keyof EqState, 
      delta: number
  ) => {
      setter(prev => ({ ...prev, [band]: Math.max(-12, Math.min(12, prev[band] + delta)) }));
  };

  const renderChannelControls = (
      title: string, 
      sub: string, 
      color: string, 
      vol: number, 
      setVol: React.Dispatch<React.SetStateAction<number>>,
      eq: EqState,
      setEq: React.Dispatch<React.SetStateAction<EqState>>,
      icon: React.ReactNode,
      isMid: boolean = false
  ) => {
      return (
        <div className="bg-slate-800 rounded-xl p-3 border border-slate-700 flex flex-col gap-3 relative overflow-hidden group">
            {/* Header */}
            <div className={`flex items-center gap-2 border-b border-slate-700 pb-2 ${color}`}>
                {icon}
                <div className="flex-1">
                    <div className="text-xs font-bold uppercase tracking-wider">{title}</div>
                    <div className="text-[9px] text-slate-500">{sub}</div>
                </div>
                {isMid && (
                    <button 
                        onClick={() => setIsEnhanced(!isEnhanced)}
                        className={`p-1.5 rounded-full transition-all ${isEnhanced ? 'bg-indigo-500 text-white shadow-lg shadow-indigo-500/50' : 'bg-slate-700 text-slate-500'}`}
                        title="Magic Enhancer: Abre o som e adiciona ambiência"
                    >
                        <Zap size={14} fill={isEnhanced ? "currentColor" : "none"} />
                    </button>
                )}
            </div>

            {/* Volume Control (Buttons) */}
            <div className="flex items-center justify-between bg-slate-900/50 p-2 rounded-lg">
                <button 
                    onClick={() => updateVolume(setVol, vol, -0.1)}
                    className="w-8 h-8 flex items-center justify-center rounded bg-slate-700 hover:bg-slate-600 active:scale-95 transition-all text-slate-300"
                ><Minus size={14} /></button>

                <div className="flex flex-col items-center w-16">
                    <span className={`text-xl font-bold ${vol === 0 ? 'text-slate-600' : 'text-white'}`}>{(vol * 100).toFixed(0)}%</span>
                    <div className="w-full h-1 bg-slate-700 rounded-full mt-1 overflow-hidden">
                        <div className={`h-full ${color.replace('text-', 'bg-')}`} style={{ width: `${(vol/2)*100}%` }} />
                    </div>
                </div>

                <button 
                    onClick={() => updateVolume(setVol, vol, 0.1)}
                    className="w-8 h-8 flex items-center justify-center rounded bg-slate-700 hover:bg-slate-600 active:scale-95 transition-all text-slate-300"
                ><Plus size={14} /></button>
            </div>

            {/* Mute Button Overlay on Volume */}
            <button 
                onClick={() => setVol(v => v === 0 ? 1 : 0)}
                className={`absolute top-12 right-1/2 translate-x-1/2 -translate-y-1/2 opacity-0 group-hover:opacity-100 transition-opacity bg-slate-900/90 text-red-500 px-2 py-1 rounded text-xs font-bold border border-red-500/30 z-10 pointer-events-none group-hover:pointer-events-auto`}
            >
                {vol === 0 ? 'UNMUTE' : 'MUTE'}
            </button>

            {/* 3-Band EQ */}
            <div className="space-y-2 mt-1">
                <div className="flex items-center gap-1 text-[9px] font-mono text-slate-500 mb-1 uppercase">
                    <Sliders size={10} /> Equalizador
                </div>
                {[
                    { label: 'HIGH', key: 'high', val: eq.high },
                    { label: 'MID', key: 'mid', val: eq.mid },
                    { label: 'LOW', key: 'low', val: eq.low }
                ].map((band) => (
                    <div key={band.label} className="flex items-center gap-2">
                        <span className="w-8 text-[9px] font-bold text-slate-400 text-right">{band.label}</span>
                        <button onClick={() => updateEQ(setEq, band.key as keyof EqState, -1)} className="text-slate-500 hover:text-slate-300"><Minus size={10} /></button>

                        {/* EQ Visual Bar */}
                        <div className="flex-1 h-3 bg-slate-900 rounded relative overflow-hidden flex items-center justify-center">
                            <div className="absolute w-[1px] h-full bg-slate-700 left-1/2" /> {/* Center line */}
                            <div 
                                className={`h-full absolute transition-all ${band.val > 0 ? 'bg-green-500 left-1/2' : 'bg-red-500 right-1/2'}`}
                                style={{ width: `${Math.abs(band.val) * 8}%` }} // Scale factor
                            />
                            <span className="relative text-[8px] z-10 text-white font-mono drop-shadow-md">{band.val > 0 ? `+${band.val}` : band.val}dB</span>
                        </div>

                        <button onClick={() => updateEQ(setEq, band.key as keyof EqState, 1)} className="text-slate-500 hover:text-slate-300"><Plus size={10} /></button>
                    </div>
                ))}
            </div>
        </div>
      );
  };

  return (
    <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 h-full flex flex-col">
      <audio ref={audioRef} onEnded={() => setIsPlaying(false)} crossOrigin="anonymous" />

      {/* HEADER */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
          <div>
            <h2 className="text-xl font-bold text-white flex items-center gap-2">
                <Layers className="text-teal-400" />
                Estúdio Pro
            </h2>
            <p className="text-xs text-slate-400">Separação de canais com EQ, Efeitos e Masterização.</p>
          </div>

          <label className="cursor-pointer bg-slate-700 hover:bg-slate-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors border border-slate-600 shadow-lg">
             {isLoading ? <Loader2 className="animate-spin" size={16} /> : <Upload size={16} />}
             <span className="text-sm font-bold">Carregar MP3/WAV</span>
             <input type="file" accept="audio/*" onChange={handleFileUpload} className="hidden" />
          </label>
      </div>

      {!file ? (
          <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-slate-700 rounded-xl bg-slate-900/30 text-slate-500 gap-4">
              <Upload size={48} className="opacity-50" />
              <p>Carregue um arquivo para entrar no estúdio</p>
          </div>
      ) : (
          <div className="flex-1 flex flex-col gap-4">

              {/* WAVEFORM & TRANSPORT */}
              <div className="bg-slate-900 rounded-xl p-3 border border-slate-700 shadow-inner">
                  <div className="relative h-24 w-full bg-slate-950 rounded-lg overflow-hidden cursor-crosshair mb-3 border border-slate-800">
                      <canvas ref={canvasRef} width={800} height={96} className="w-full h-full" onClick={handleSeek} />
                  </div>

                  <div className="flex flex-wrap items-center justify-between gap-2">
                      <div className="flex items-center gap-2">
                          <button onClick={togglePlay} className="w-10 h-10 rounded-full bg-teal-500 hover:bg-teal-400 text-slate-900 flex items-center justify-center shadow-lg transition-transform hover:scale-105">
                              {isPlaying ? <Pause fill="currentColor" size={18} /> : <Play fill="currentColor" size={18} className="ml-0.5" />}
                          </button>
                          <button onClick={stopAudio} className="w-10 h-10 rounded-full bg-slate-700 hover:bg-slate-600 text-white flex items-center justify-center shadow">
                              <Square size={16} fill="currentColor" />
                          </button>
                          <div className="text-xs font-mono text-teal-400 bg-slate-800 px-3 py-1.5 rounded border border-slate-700 ml-2">
                              {formatTime(currentTime)} / {formatTime(duration)}
                          </div>
                      </div>

                      <div className="flex items-center gap-2 bg-slate-800 p-1 rounded-lg border border-slate-700">
                          <button onClick={() => setLoopPoint('start')} className="px-2 py-1 text-[10px] font-bold hover:bg-slate-700 rounded text-teal-200">IN (A)</button>
                          <button onClick={() => setLoopPoint('end')} className="px-2 py-1 text-[10px] font-bold hover:bg-slate-700 rounded text-teal-200">OUT (B)</button>
                          <button onClick={() => setIsLooping(!isLooping)} className={`p-1 rounded transition-colors ${isLooping ? 'bg-teal-500/20 text-teal-400' : 'text-slate-500'}`}>
                              <Repeat size={14} />
                          </button>
                      </div>

                      <div className="flex items-center gap-2 bg-slate-800 p-1.5 rounded-lg border border-slate-700">
                          <Rewind size={14} className="text-slate-500 cursor-pointer" onClick={() => setPlaybackRate(Math.max(0.5, playbackRate - 0.1))} />
                          <span className="text-xs font-mono w-10 text-center font-bold text-slate-300">{playbackRate.toFixed(2)}x</span>
                          <FastForward size={14} className="text-slate-500 cursor-pointer" onClick={() => setPlaybackRate(Math.min(1.5, playbackRate + 0.1))} />
                      </div>
                  </div>
              </div>

              {/* MIXING CONSOLE */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4 h-full">

                   {/* BASS CHANNEL */}
                   {renderChannelControls(
                       "BAIXO (7 CORDA)", "Frequências Graves", "text-yellow-500", 
                       volLow, setVolLow, eqLowSettings, setEqLowSettings,
                       <Volume2 size={16} className="text-yellow-500" />
                   )}

                   {/* MID CHANNEL (GUITAR) */}
                   {renderChannelControls(
                       "VIOLÃO/HARMONIA", "Frequências Médias", "text-indigo-500", 
                       volMid, setVolMid, eqMidSettings, setEqMidSettings,
                       <Sparkles size={16} className="text-indigo-500" />,
                       true // Is Mid/Guitar channel
                   )}

                   {/* TREBLE CHANNEL */}
                   {renderChannelControls(
                       "PERCUSSÃO/VOZ", "Frequências Agudas", "text-pink-500", 
                       volHigh, setVolHigh, eqHighSettings, setEqHighSettings,
                       <Volume2 size={16} className="text-pink-500" />
                   )}
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Upload, Play, Pause, Square, Repeat, FastForward, Rewind, Layers, Volume2, Info, Loader2, VolumeX, Plus, Minus, Sliders, Sparkles, Zap, Headphones } from 'lucide-react';
import { getAudioContext } from '../utils/audio';

// --- TYPES ---

interface ChannelNodes {
  gain: GainNode;
  eqLow: BiquadFilterNode;
  eqMid: BiquadFilterNode;
  eqHigh: BiquadFilterNode;
  // Specific for Bass Channel to isolate 7-string from Surdo
  bassFocusFilter?: BiquadFilterNode; 
  reverbSend?: GainNode;
}

interface EqState {
  low: number; // -10 to 10
  mid: number;
  high: number;
}

export const AudioSeparator: React.FC = () => {
  // --- STATE ---
  const [file, setFile] = useState<File | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [duration, setDuration] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isLooping, setIsLooping] = useState(false);
  const [loopStart, setLoopStart] = useState<number>(0);
  const [loopEnd, setLoopEnd] = useState<number>(0);
  const [isLoading, setIsLoading] = useState(false);

  // Volumes (0.0 - 2.0)
  const [volLow, setVolLow] = useState(1.0);
  const [volMid, setVolMid] = useState(1.0);
  const [volHigh, setVolHigh] = useState(1.0);

  // EQ States
  const [eqLowSettings, setEqLowSettings] = useState<EqState>({ low: 2, mid: 4, high: 0 }); // Pre-boost bass definition
  const [eqMidSettings, setEqMidSettings] = useState<EqState>({ low: 0, mid: 0, high: 0 });
  const [eqHighSettings, setEqHighSettings] = useState<EqState>({ low: 0, mid: 0, high: 0 });

  // Effects
  const [bassFocusMode, setBassFocusMode] = useState(true); // "Baixaria Clarity" (Cuts mud)
  const [midMagicMode, setMidMagicMode] = useState(false);

  // --- REFS ---
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<MediaElementAudioSourceNode | null>(null);

  // Audio Graph Nodes
  const nodesRef = useRef<{
    low: ChannelNodes | null;
    mid: ChannelNodes | null;
    high: ChannelNodes | null;
    compressor: DynamicsCompressorNode | null;
    bassCompressor: DynamicsCompressorNode | null;
    reverb: ConvolverNode | null;
  }>({ low: null, mid: null, high: null, compressor: null, bassCompressor: null, reverb: null });

  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const animationFrameRef = useRef<number | null>(null);
  const waveformBufferRef = useRef<AudioBuffer | null>(null);

  // --- AUDIO ENGINE ---

  const createReverbImpulse = (ctx: AudioContext, duration: number = 2.0, decay: number = 2.0) => {
    const rate = ctx.sampleRate;
    const length = rate * duration;
    const impulse = ctx.createBuffer(2, length, rate);
    const left = impulse.getChannelData(0);
    const right = impulse.getChannelData(1);
    for (let i = 0; i < length; i++) {
        const n = i / length;
        left[i] = (Math.random() * 2 - 1) * Math.pow(1 - n, decay);
        right[i] = (Math.random() * 2 - 1) * Math.pow(1 - n, decay);
    }
    return impulse;
  };

  const setupAudioGraph = () => {
    if (!audioRef.current) return;

    const ctx = getAudioContext();
    audioContextRef.current = ctx;

    if (!sourceNodeRef.current) {
        sourceNodeRef.current = ctx.createMediaElementSource(audioRef.current);
    }

    // --- DYNAMICS PROCESSING ---

    // Master Compressor (Glue)
    const masterCompressor = ctx.createDynamicsCompressor();
    masterCompressor.threshold.value = -10;
    masterCompressor.ratio.value = 4;
    masterCompressor.connect(ctx.destination);
    nodesRef.current.compressor = masterCompressor;

    // Bass Specific Compressor (To make 7-string lines consistent volume)
    const bassCompressor = ctx.createDynamicsCompressor();
    bassCompressor.threshold.value = -24; // Lower threshold to catch quiet notes
    bassCompressor.knee.value = 10;
    bassCompressor.ratio.value = 8; // High compression for consistency
    bassCompressor.attack.value = 0.01; // Fast attack
    bassCompressor.release.value = 0.1;
    bassCompressor.connect(masterCompressor); // Connects to master
    nodesRef.current.bassCompressor = bassCompressor;

    // Reverb Bus
    const reverbNode = ctx.createConvolver();
    reverbNode.buffer = createReverbImpulse(ctx, 1.5, 3.0);
    const reverbGain = ctx.createGain();
    reverbGain.gain.value = 0.15;
    reverbNode.connect(reverbGain);
    reverbGain.connect(masterCompressor);
    nodesRef.current.reverb = reverbNode;

    // --- CROSSOVER DEFINITIONS (TUNED FOR 7-STRING) ---
    // 7-String fundamental: ~60Hz (B1). 
    // High C on high E string: ~520Hz.
    // Vocal Fundamentals: ~200Hz - 1000Hz.
    // 
    // We set Bass Crossover to 320Hz. 
    // This allows the full body of the guitar but cuts the vocal fundamentals significantly.
    const BASS_CROSSOVER = 320; 
    const TREBLE_CROSSOVER = 3500;

    const createFilters = (type: BiquadFilterType, freq: number, count: number) => {
        return Array(count).fill(0).map(() => {
            const f = ctx.createBiquadFilter();
            f.type = type;
            f.frequency.value = freq;
            return f;
        });
    };

    const chainFilters = (source: AudioNode, filters: BiquadFilterNode[], dest: AudioNode) => {
        let curr = source;
        filters.forEach(f => {
            curr.connect(f);
            curr = f;
        });
        curr.connect(dest);
    };

    // --- CHANNEL CREATION HELPER ---
    const createChannel = (initialVol: number, isBass: boolean = false): ChannelNodes => {
        // Gain
        const gain = ctx.createGain();
        gain.gain.value = initialVol;

        // 3-Band EQ
        const eqLow = ctx.createBiquadFilter();
        eqLow.type = 'lowshelf';
        eqLow.frequency.value = 200;

        const eqMid = ctx.createBiquadFilter();
        eqMid.type = 'peaking';
        eqMid.frequency.value = 1500;
        eqMid.Q.value = 1.0;

        const eqHigh = ctx.createBiquadFilter();
        eqHigh.type = 'highshelf';
        eqHigh.frequency.value = 5000;

        // Special Bass Focus Filter (To cut Surdo rumble and highlight articulation)
        let bassFocusFilter: BiquadFilterNode | undefined;
        if (isBass) {
            bassFocusFilter = ctx.createBiquadFilter();
            bassFocusFilter.type = 'highpass';
            bassFocusFilter.frequency.value = 10; // Default open
            bassFocusFilter.Q.value = 1.0; // Resonance to boost the cut point slightly
        }

        const reverbSend = ctx.createGain();
        reverbSend.gain.value = 0;

        // Chain
        let head: AudioNode = eqLow;
        eqLow.connect(eqMid);
        eqMid.connect(eqHigh);

        let tail: AudioNode = eqHigh;

        if (bassFocusFilter) {
            tail.connect(bassFocusFilter);
            tail = bassFocusFilter;
        }

        tail.connect(gain);

        // Output Routing
        if (isBass) {
            gain.connect(bassCompressor); // Bass goes to dedicated compressor
        } else {
            gain.connect(masterCompressor); // Others go to master
            gain.connect(reverbSend); // Only Mids/Highs go to Reverb usually
            reverbSend.connect(reverbNode);
        }

        return { gain, eqLow, eqMid, eqHigh, reverbSend, bassFocusFilter };
    };

    // Initialize Channels
    nodesRef.current.low = createChannel(volLow, true); // Bass Channel
    nodesRef.current.mid = createChannel(volMid, false);
    nodesRef.current.high = createChannel(volHigh, false);

    // --- ROUTING THROUGH CROSSOVERS ---

    // Path 1: 7-STRING / SURDO (Low)
    // Source -> 4x LowPass (Steep Cut) -> Channel
    const lowPasses = createFilters('lowpass', BASS_CROSSOVER, 4);
    chainFilters(sourceNodeRef.current, lowPasses, nodesRef.current.low.eqLow);

    // Path 2: HARMONY / VOZ (Mid)
    // Source -> 4x HighPass (Cut Bass) -> 4x LowPass (Cut Treble) -> Channel
    const midHighPasses = createFilters('highpass', BASS_CROSSOVER, 4);
    const midLowPasses = createFilters('lowpass', TREBLE_CROSSOVER, 4);

    let midChainHead: AudioNode = sourceNodeRef.current;
    midHighPasses.forEach(f => { midChainHead.connect(f); midChainHead = f; });
    midLowPasses.forEach(f => { midChainHead.connect(f); midChainHead = f; });
    midChainHead.connect(nodesRef.current.mid.eqLow);

    // Path 3: PERCUSSION / AGUDOS (High)
    // Source -> 4x HighPass -> Channel
    const highPasses = createFilters('highpass', TREBLE_CROSSOVER, 4);
    chainFilters(sourceNodeRef.current, highPasses, nodesRef.current.high.eqLow);
  };

  // --- UPDATES & EFFECTS ---

  // Handle EQ Updates
  useEffect(() => {
    const ctx = getAudioContext();
    const t = ctx.currentTime;
    const ramp = 0.1;

    const applyEq = (nodes: ChannelNodes | null, settings: EqState) => {
        if (!nodes) return;
        nodes.eqLow.gain.setTargetAtTime(settings.low * 1.5, t, ramp); // Boost low control effect
        nodes.eqMid.gain.setTargetAtTime(settings.mid, t, ramp);
        nodes.eqHigh.gain.setTargetAtTime(settings.high, t, ramp);
    };

    applyEq(nodesRef.current.low, eqLowSettings);
    applyEq(nodesRef.current.mid, eqMidSettings);
    applyEq(nodesRef.current.high, eqHighSettings);

  }, [eqLowSettings, eqMidSettings, eqHighSettings]);

  // Handle "Bass Focus" (Isolar Baixaria vs Surdo)
  useEffect(() => {
    const t = getAudioContext().currentTime;
    if (nodesRef.current.low?.bassFocusFilter) {
        // If Focus Mode ON: HighPass at 80Hz (Cuts Surdo boom, keeps 7-string) + Q Boost
        // If OFF: HighPass at 10Hz (Lets Surdo boom pass)
        const freq = bassFocusMode ? 85 : 10;
        const q = bassFocusMode ? 2.0 : 0; // Resonance bump to emphasize the 7-string fundamental

        nodesRef.current.low.bassFocusFilter.frequency.setTargetAtTime(freq, t, 0.2);
        nodesRef.current.low.bassFocusFilter.Q.setTargetAtTime(q, t, 0.2);

        // Also boost presence automatically in focus mode
        const midBoost = bassFocusMode ? 5 : eqLowSettings.mid; 
        nodesRef.current.low.eqMid.gain.setTargetAtTime(midBoost, t, 0.2);
    }
  }, [bassFocusMode]);

  // Handle "Enhanced" Mode (Reverb Send for Mids)
  useEffect(() => {
      const t = getAudioContext().currentTime;
      if (nodesRef.current.mid?.reverbSend) {
          const val = midMagicMode ? 0.3 : 0; 
          nodesRef.current.mid.reverbSend.gain.setTargetAtTime(val, t, 0.2);
      }
  }, [midMagicMode]);

  // Handle Volume Updates (Strict Mute)
  useEffect(() => {
    const ctx = getAudioContext();
    const t = ctx.currentTime;

    const updateGain = (nodes: ChannelNodes | null, val: number) => {
        if (!nodes) return;
        nodes.gain.gain.cancelScheduledValues(t);
        if (val <= 0.05) nodes.gain.gain.setTargetAtTime(0, t, 0.01); // Snap to zero
        else nodes.gain.gain.setTargetAtTime(val, t, 0.02);
    };

    updateGain(nodesRef.current.low, volLow);
    updateGain(nodesRef.current.mid, volMid);
    updateGain(nodesRef.current.high, volHigh);
  }, [volLow, volMid, volHigh]);


  // --- STANDARD HANDLERS ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      setFile(selectedFile);
      setIsLoading(true);
      setIsPlaying(false);

      // Default to "Isolation Mode" for Bass
      setVolLow(1.2);
      setVolMid(0);
      setVolHigh(0);
      setBassFocusMode(true);

      const objectUrl = URL.createObjectURL(selectedFile);
      if (audioRef.current) {
          audioRef.current.src = objectUrl;
          audioRef.current.load();
      }
      try {
          const arrayBuffer = await selectedFile.arrayBuffer();
          const ctx = getAudioContext();
          const audioBuffer = await ctx.decodeAudioData(arrayBuffer);
          waveformBufferRef.current = audioBuffer;
          setDuration(audioBuffer.duration);
          setLoopEnd(audioBuffer.duration);
          drawWaveform();
      } catch (err) { console.error(err); } 
      finally { setIsLoading(false); }
    }
  };

  const togglePlay = async () => {
    if (!audioRef.current) return;
    const ctx = getAudioContext();
    if (ctx.state === 'suspended') await ctx.resume();

    if (!nodesRef.current.low) setupAudioGraph();

    if (isPlaying) {
      audioRef.current.pause();
      setIsPlaying(false);
    } else {
      await audioRef.current.play();
      setIsPlaying(true);
    }
  };

  const stopAudio = () => {
      if (!audioRef.current) return;
      audioRef.current.pause();
      audioRef.current.currentTime = isLooping ? loopStart : 0;
      setCurrentTime(audioRef.current.currentTime);
      setIsPlaying(false);
  };

  useEffect(() => {
      if (audioRef.current) {
          audioRef.current.playbackRate = playbackRate;
          audioRef.current.preservesPitch = true;
      }
  }, [playbackRate]);

  // Loop Check
  useEffect(() => {
    const loopCheck = () => {
        if (!audioRef.current) return;
        const curr = audioRef.current.currentTime;
        setCurrentTime(curr);
        if (isLooping && loopEnd > loopStart) {
            if (curr >= loopEnd || curr < loopStart) audioRef.current.currentTime = loopStart;
        }
        animationFrameRef.current = requestAnimationFrame(loopCheck);
    };
    if (isPlaying) animationFrameRef.current = requestAnimationFrame(loopCheck);
    else if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    return () => { if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current); };
  }, [isPlaying, isLooping, loopStart, loopEnd]);


  // --- VISUALS ---
  const drawWaveform = () => {
      if (!canvasRef.current || !waveformBufferRef.current) return;
      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;
      const width = canvasRef.current.width;
      const height = canvasRef.current.height;
      const data = waveformBufferRef.current.getChannelData(0);
      const step = Math.ceil(data.length / width);
      const amp = height / 2;

      ctx.clearRect(0, 0, width, height);
      ctx.fillStyle = '#0f172a';
      ctx.fillRect(0, 0, width, height);
      ctx.beginPath();
      ctx.moveTo(0, amp);
      ctx.strokeStyle = '#334155';
      ctx.lineWidth = 1;

      for (let i = 0; i < width; i++) {
          let min = 1.0, max = -1.0;
          for (let j = 0; j < step; j++) {
              const datum = data[(i * step) + j];
              if (datum < min) min = datum;
              if (datum > max) max = datum;
          }
          ctx.lineTo(i, (1 + min) * amp);
          ctx.lineTo(i, (1 + max) * amp);
      }
      ctx.stroke();
  };

  // Overlay
  useEffect(() => {
      if (!canvasRef.current) return;
      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;
      drawWaveform(); 
      const width = canvasRef.current.width;
      const height = canvasRef.current.height;
      if (duration > 0) {
          const xStart = (loopStart / duration) * width;
          const xEnd = (loopEnd / duration) * width;
          ctx.fillStyle = 'rgba(20, 184, 166, 0.15)';
          ctx.fillRect(xStart, 0, xEnd - xStart, height);
          ctx.strokeStyle = '#14b8a6';
          ctx.beginPath();
          ctx.moveTo(xStart, 0); ctx.lineTo(xStart, height);
          ctx.moveTo(xEnd, 0); ctx.lineTo(xEnd, height);
          ctx.stroke();
      }
      if (duration > 0) {
          const xPos = (currentTime / duration) * width;
          ctx.strokeStyle = '#ef4444';
          ctx.lineWidth = 2;
          ctx.beginPath(); ctx.moveTo(xPos, 0); ctx.lineTo(xPos, height); ctx.stroke();
      }
  }, [currentTime, loopStart, loopEnd, duration]);

  const handleSeek = (e: React.MouseEvent<HTMLCanvasElement>) => {
      if (!duration) return;
      const rect = canvasRef.current!.getBoundingClientRect();
      const perc = (e.clientX - rect.left) / rect.width;
      if (audioRef.current) {
          audioRef.current.currentTime = perc * duration;
          setCurrentTime(perc * duration);
      }
  };
  const setLoopPoint = (type: 'start' | 'end') => {
      if (type === 'start') setLoopStart(currentTime); else setLoopEnd(currentTime);
      setIsLooping(true);
  };
  const formatTime = (t: number) => {
      const min = Math.floor(t / 60);
      const sec = Math.floor(t % 60);
      return `${min}:${sec.toString().padStart(2, '0')}`;
  };

  // --- UI COMPONENTS ---

  const updateVolume = (setter: React.Dispatch<React.SetStateAction<number>>, current: number, delta: number) => {
      const newVal = Math.max(0, Math.min(2, current + delta));
      setter(parseFloat(newVal.toFixed(1)));
  };

  const updateEQ = (
      setter: React.Dispatch<React.SetStateAction<EqState>>, 
      band: keyof EqState, 
      delta: number
  ) => {
      setter(prev => ({ ...prev, [band]: Math.max(-12, Math.min(12, prev[band] + delta)) }));
  };

  const renderChannelControls = (
      title: string, 
      sub: string, 
      color: string, 
      vol: number, 
      setVol: React.Dispatch<React.SetStateAction<number>>,
      eq: EqState,
      setEq: React.Dispatch<React.SetStateAction<EqState>>,
      icon: React.ReactNode,
      modeButton: { isActive: boolean, toggle: () => void, label: string, icon: React.ReactNode }
  ) => {
      return (
        <div className="bg-slate-800 rounded-xl p-3 border border-slate-700 flex flex-col gap-3 relative overflow-hidden group">
            {/* Header */}
            <div className={`flex items-center gap-2 border-b border-slate-700 pb-2 ${color}`}>
                {icon}
                <div className="flex-1">
                    <div className="text-xs font-bold uppercase tracking-wider">{title}</div>
                    <div className="text-[9px] text-slate-500">{sub}</div>
                </div>
                {modeButton && (
                    <button 
                        onClick={modeButton.toggle}
                        className={`p-1.5 rounded-full transition-all flex items-center gap-1 px-2 ${modeButton.isActive ? 'bg-indigo-500 text-white shadow-lg shadow-indigo-500/50' : 'bg-slate-700 text-slate-500'}`}
                        title={modeButton.label}
                    >
                        {modeButton.icon}
                        <span className="text-[9px] font-bold hidden xl:block">{modeButton.isActive ? 'ON' : 'OFF'}</span>
                    </button>
                )}
            </div>

            {/* Volume Control (Buttons) */}
            <div className="flex items-center justify-between bg-slate-900/50 p-2 rounded-lg relative">
                <button 
                    onClick={() => updateVolume(setVol, vol, -0.1)}
                    className="w-8 h-8 flex items-center justify-center rounded bg-slate-700 hover:bg-slate-600 active:scale-95 transition-all text-slate-300 z-20"
                ><Minus size={14} /></button>

                <div className="flex flex-col items-center w-16">
                    <span className={`text-xl font-bold ${vol === 0 ? 'text-slate-600' : 'text-white'}`}>{(vol * 100).toFixed(0)}%</span>
                    <div className="w-full h-1 bg-slate-700 rounded-full mt-1 overflow-hidden">
                        <div className={`h-full ${color.replace('text-', 'bg-')}`} style={{ width: `${(vol/2)*100}%` }} />
                    </div>
                </div>

                <button 
                    onClick={() => updateVolume(setVol, vol, 0.1)}
                    className="w-8 h-8 flex items-center justify-center rounded bg-slate-700 hover:bg-slate-600 active:scale-95 transition-all text-slate-300 z-20"
                ><Plus size={14} /></button>

                {/* Mute Overlay Toggle */}
                {vol === 0 && (
                   <button 
                       onClick={() => setVol(1.0)}
                       className="absolute inset-0 flex items-center justify-center bg-slate-900/80 text-red-500 font-bold tracking-widest text-xs z-10 backdrop-blur-sm rounded-lg border border-red-500/30"
                   >
                       MUTADO
                   </button>
                )}
            </div>

             {/* Mute Button if not 0 */}
            {vol > 0 && (
                <button 
                    onClick={() => setVol(0)}
                    className="w-full py-1 text-[10px] font-bold text-red-400 bg-red-900/10 hover:bg-red-900/30 border border-red-900/30 rounded uppercase tracking-wider transition-colors"
                >
                    Mutar Canal
                </button>
            )}

            {/* 3-Band EQ */}
            <div className="space-y-2 mt-1">
                <div className="flex items-center gap-1 text-[9px] font-mono text-slate-500 mb-1 uppercase">
                    <Sliders size={10} /> Equalizador
                </div>
                {[
                    { label: 'HIGH', key: 'high', val: eq.high },
                    { label: 'MID', key: 'mid', val: eq.mid },
                    { label: 'LOW', key: 'low', val: eq.low }
                ].map((band) => (
                    <div key={band.label} className="flex items-center gap-2">
                        <span className="w-8 text-[9px] font-bold text-slate-400 text-right">{band.label}</span>
                        <button onClick={() => updateEQ(setEq, band.key as keyof EqState, -1)} className="text-slate-500 hover:text-slate-300"><Minus size={10} /></button>

                        {/* EQ Visual Bar */}
                        <div className="flex-1 h-3 bg-slate-900 rounded relative overflow-hidden flex items-center justify-center">
                            <div className="absolute w-[1px] h-full bg-slate-700 left-1/2" /> {/* Center line */}
                            <div 
                                className={`h-full absolute transition-all ${band.val > 0 ? 'bg-green-500 left-1/2' : 'bg-red-500 right-1/2'}`}
                                style={{ width: `${Math.abs(band.val) * 8}%` }} // Scale factor
                            />
                            <span className="relative text-[8px] z-10 text-white font-mono drop-shadow-md">{band.val > 0 ? `+${band.val}` : band.val}dB</span>
                        </div>

                        <button onClick={() => updateEQ(setEq, band.key as keyof EqState, 1)} className="text-slate-500 hover:text-slate-300"><Plus size={10} /></button>
                    </div>
                ))}
            </div>
        </div>
      );
  };

  return (
    <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 h-full flex flex-col">
      <audio ref={audioRef} onEnded={() => setIsPlaying(false)} crossOrigin="anonymous" />

      {/* HEADER */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
          <div>
            <h2 className="text-xl font-bold text-white flex items-center gap-2">
                <Headphones className="text-teal-400" />
                Estúdio de Isolamento (7 Cordas)
            </h2>
            <p className="text-xs text-slate-400">Extraia e estude as baixarias com clareza cristalina.</p>
          </div>

          <label className="cursor-pointer bg-slate-700 hover:bg-slate-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors border border-slate-600 shadow-lg">
             {isLoading ? <Loader2 className="animate-spin" size={16} /> : <Upload size={16} />}
             <span className="text-sm font-bold">Carregar MP3/WAV</span>
             <input type="file" accept="audio/*" onChange={handleFileUpload} className="hidden" />
          </label>
      </div>

      {!file ? (
          <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-slate-700 rounded-xl bg-slate-900/30 text-slate-500 gap-4">
              <Upload size={48} className="opacity-50" />
              <p>Carregue a música para isolar o 7 Cordas</p>
          </div>
      ) : (
          <div className="flex-1 flex flex-col gap-4">

              {/* WAVEFORM & TRANSPORT */}
              <div className="bg-slate-900 rounded-xl p-3 border border-slate-700 shadow-inner">
                  <div className="relative h-24 w-full bg-slate-950 rounded-lg overflow-hidden cursor-crosshair mb-3 border border-slate-800">
                      <canvas ref={canvasRef} width={800} height={96} className="w-full h-full" onClick={handleSeek} />
                  </div>

                  <div className="flex flex-wrap items-center justify-between gap-2">
                      <div className="flex items-center gap-2">
                          <button onClick={togglePlay} className="w-10 h-10 rounded-full bg-teal-500 hover:bg-teal-400 text-slate-900 flex items-center justify-center shadow-lg transition-transform hover:scale-105">
                              {isPlaying ? <Pause fill="currentColor" size={18} /> : <Play fill="currentColor" size={18} className="ml-0.5" />}
                          </button>
                          <button onClick={stopAudio} className="w-10 h-10 rounded-full bg-slate-700 hover:bg-slate-600 text-white flex items-center justify-center shadow">
                              <Square size={16} fill="currentColor" />
                          </button>
                          <div className="text-xs font-mono text-teal-400 bg-slate-800 px-3 py-1.5 rounded border border-slate-700 ml-2">
                              {formatTime(currentTime)} / {formatTime(duration)}
                          </div>
                      </div>

                      <div className="flex items-center gap-2 bg-slate-800 p-1 rounded-lg border border-slate-700">
                          <button onClick={() => setLoopPoint('start')} className="px-2 py-1 text-[10px] font-bold hover:bg-slate-700 rounded text-teal-200">IN (A)</button>
                          <button onClick={() => setLoopPoint('end')} className="px-2 py-1 text-[10px] font-bold hover:bg-slate-700 rounded text-teal-200">OUT (B)</button>
                          <button onClick={() => setIsLooping(!isLooping)} className={`p-1 rounded transition-colors ${isLooping ? 'bg-teal-500/20 text-teal-400' : 'text-slate-500'}`}>
                              <Repeat size={14} />
                          </button>
                      </div>

                      <div className="flex items-center gap-2 bg-slate-800 p-1.5 rounded-lg border border-slate-700">
                          <Rewind size={14} className="text-slate-500 cursor-pointer" onClick={() => setPlaybackRate(Math.max(0.5, playbackRate - 0.1))} />
                          <span className="text-xs font-mono w-10 text-center font-bold text-slate-300">{playbackRate.toFixed(2)}x</span>
                          <FastForward size={14} className="text-slate-500 cursor-pointer" onClick={() => setPlaybackRate(Math.min(1.5, playbackRate + 0.1))} />
                      </div>
                  </div>
              </div>

              {/* MIXING CONSOLE */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4 h-full">

                   {/* BASS CHANNEL (STAR) */}
                   {renderChannelControls(
                       "7 CORDAS / SURDO", "Graves & Baixarias", "text-yellow-500", 
                       volLow, setVolLow, eqLowSettings, setEqLowSettings,
                       <Volume2 size={16} className="text-yellow-500" />,
                       { 
                           isActive: bassFocusMode, 
                           toggle: () => setBassFocusMode(!bassFocusMode), 
                           label: "Modo Foco: Remove Surdo, Realça Frases",
                           icon: <Zap size={12} fill="currentColor" />
                       }
                   )}

                   {/* MID CHANNEL */}
                   {renderChannelControls(
                       "VOZ / HARMONIA", "Corpo da Música", "text-indigo-500", 
                       volMid, setVolMid, eqMidSettings, setEqMidSettings,
                       <Sparkles size={16} className="text-indigo-500" />,
                       {
                           isActive: midMagicMode,
                           toggle: () => setMidMagicMode(!midMagicMode),
                           label: "Ambiência",
                           icon: <Sparkles size={12} fill="currentColor" />
                       }
                   )}

                   {/* TREBLE CHANNEL */}
                   {renderChannelControls(
                       "PERCUSSÃO / AGUDOS", "Brilho & Ataque", "text-pink-500", 
                       volHigh, setVolHigh, eqHighSettings, setEqHighSettings,
                       <Volume2 size={16} className="text-pink-500" />,
                       {
                           isActive: false,
                           toggle: () => {},
                           label: "",
                           icon: <div />
                       }
                   )}
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Upload, Play, Pause, Square, Repeat, FastForward, Rewind, Layers, Volume2, Info, Loader2, VolumeX, Plus, Minus, Sliders, Sparkles, Zap, Headphones, Target, ShieldBan } from 'lucide-react';
import { getAudioContext } from '../utils/audio';

// --- TYPES ---

interface ChannelNodes {
  gain: GainNode;
  eqLow: BiquadFilterNode;
  eqMid: BiquadFilterNode;
  eqHigh: BiquadFilterNode;

  // Specific for 7-String Pro Isolation
  surdoNotch?: BiquadFilterNode; // To surgically remove Surdo boom
  presenceBoost?: BiquadFilterNode; // To highlight string attack

  reverbSend?: GainNode;
}

interface EqState {
  low: number; // -10 to 10
  mid: number;
  high: number;
}

export const AudioSeparator: React.FC = () => {
  // --- STATE ---
  const [file, setFile] = useState<File | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [duration, setDuration] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isLooping, setIsLooping] = useState(false);
  const [loopStart, setLoopStart] = useState<number>(0);
  const [loopEnd, setLoopEnd] = useState<number>(0);
  const [isLoading, setIsLoading] = useState(false);

  // Volumes (0.0 - 2.0)
  const [volLow, setVolLow] = useState(1.0);
  const [volMid, setVolMid] = useState(1.0);
  const [volHigh, setVolHigh] = useState(1.0);

  // EQ States
  const [eqLowSettings, setEqLowSettings] = useState<EqState>({ low: 3, mid: 2, high: 0 }); 
  const [eqMidSettings, setEqMidSettings] = useState<EqState>({ low: 0, mid: 0, high: 0 });
  const [eqHighSettings, setEqHighSettings] = useState<EqState>({ low: 0, mid: 0, high: 0 });

  // Professional Tools State
  const [surdoCutFreq, setSurdoCutFreq] = useState(85); // Hz (Typical Surdo Boom)
  const [definitionAmount, setDefinitionAmount] = useState(5); // dB boost at 1.5kHz for attack
  const [isIsolationMode, setIsIsolationMode] = useState(true);

  // --- REFS ---
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<MediaElementAudioSourceNode | null>(null);

  // Audio Graph Nodes
  const nodesRef = useRef<{
    low: ChannelNodes | null;
    mid: ChannelNodes | null;
    high: ChannelNodes | null;
    compressor: DynamicsCompressorNode | null;
    bassCompressor: DynamicsCompressorNode | null;
    reverb: ConvolverNode | null;
  }>({ low: null, mid: null, high: null, compressor: null, bassCompressor: null, reverb: null });

  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const animationFrameRef = useRef<number | null>(null);
  const waveformBufferRef = useRef<AudioBuffer | null>(null);

  // --- AUDIO ENGINE ---

  const createReverbImpulse = (ctx: AudioContext, duration: number = 2.0, decay: number = 2.0) => {
    const rate = ctx.sampleRate;
    const length = rate * duration;
    const impulse = ctx.createBuffer(2, length, rate);
    const left = impulse.getChannelData(0);
    const right = impulse.getChannelData(1);
    for (let i = 0; i < length; i++) {
        const n = i / length;
        left[i] = (Math.random() * 2 - 1) * Math.pow(1 - n, decay);
        right[i] = (Math.random() * 2 - 1) * Math.pow(1 - n, decay);
    }
    return impulse;
  };

  const setupAudioGraph = () => {
    if (!audioRef.current) return;

    const ctx = getAudioContext();
    audioContextRef.current = ctx;

    if (!sourceNodeRef.current) {
        sourceNodeRef.current = ctx.createMediaElementSource(audioRef.current);
    }

    // --- DYNAMICS PROCESSING ---

    // Master Compressor (Glue)
    const masterCompressor = ctx.createDynamicsCompressor();
    masterCompressor.threshold.value = -10;
    masterCompressor.ratio.value = 4;
    masterCompressor.connect(ctx.destination);
    nodesRef.current.compressor = masterCompressor;

    // Bass Specific Compressor ("Transient Shaper" for 7 String)
    // We want slow attack to let the "pluck" through, fast release to kill the "boom"
    const bassCompressor = ctx.createDynamicsCompressor();
    bassCompressor.threshold.value = -20; 
    bassCompressor.knee.value = 5;
    bassCompressor.ratio.value = 6; 
    bassCompressor.attack.value = 0.03; // 30ms lets the pick attack through
    bassCompressor.release.value = 0.15; // Fast release controls the tail (surdo bloom)
    bassCompressor.connect(masterCompressor); 
    nodesRef.current.bassCompressor = bassCompressor;

    // Reverb Bus
    const reverbNode = ctx.createConvolver();
    reverbNode.buffer = createReverbImpulse(ctx, 1.5, 3.0);
    const reverbGain = ctx.createGain();
    reverbGain.gain.value = 0.15;
    reverbNode.connect(reverbGain);
    reverbGain.connect(masterCompressor);
    nodesRef.current.reverb = reverbNode;

    // --- CROSSOVER DEFINITIONS (PRO TUNING) ---
    // 7-String Range: ~55Hz (A1) to ~600Hz (Upper neck logic). Attack is around 1.2kHz.
    // Vocal Fundamentals: Start around 200Hz (Female) or 100Hz (Male).
    // Surdo: Deep energy at 50-80Hz.

    // Strategy: 
    // Bass Channel gets < 300Hz (Body) AND a bandpass at 1.5kHz (Definition).
    // Mid Channel gets > 300Hz.

    const BASS_CROSSOVER = 280; // Slightly lower to minimize vocal bleed
    const TREBLE_CROSSOVER = 4000;

    const createFilters = (type: BiquadFilterType, freq: number, count: number) => {
        return Array(count).fill(0).map(() => {
            const f = ctx.createBiquadFilter();
            f.type = type;
            f.frequency.value = freq;
            return f;
        });
    };

    const chainFilters = (source: AudioNode, filters: BiquadFilterNode[], dest: AudioNode) => {
        let curr = source;
        filters.forEach(f => {
            curr.connect(f);
            curr = f;
        });
        curr.connect(dest);
    };

    // --- CHANNEL CREATION HELPER ---
    const createChannel = (initialVol: number, isBass: boolean = false): ChannelNodes => {
        // Gain
        const gain = ctx.createGain();
        gain.gain.value = initialVol;

        // 3-Band Standard EQ
        const eqLow = ctx.createBiquadFilter();
        eqLow.type = 'lowshelf';
        eqLow.frequency.value = 200;

        const eqMid = ctx.createBiquadFilter();
        eqMid.type = 'peaking';
        eqMid.frequency.value = 1000;
        eqMid.Q.value = 1.0;

        const eqHigh = ctx.createBiquadFilter();
        eqHigh.type = 'highshelf';
        eqHigh.frequency.value = 5000;

        // --- PRO BASS TOOLS ---
        let surdoNotch: BiquadFilterNode | undefined;
        let presenceBoost: BiquadFilterNode | undefined;
        let hpFilter: BiquadFilterNode | undefined;

        if (isBass) {
            // 1. High Pass (Safety Cut) - Remove absolute rumble/sub-bass that muddies the mix
            hpFilter = ctx.createBiquadFilter();
            hpFilter.type = 'highpass';
            hpFilter.frequency.value = 58; // Just below B1 (61Hz) / A1 (55Hz). Keeps musical notes, kills rumble.
            hpFilter.Q.value = 0.7;

            // 2. Surdo Notch (Surgical Cut) - User adjustable
            surdoNotch = ctx.createBiquadFilter();
            surdoNotch.type = 'notch';
            surdoNotch.frequency.value = surdoCutFreq; 
            surdoNotch.Q.value = 4.0; // Narrow cut to avoid killing the guitar note 'E' or 'A'

            // 3. Presence/Definition (Bring back the attack)
            presenceBoost = ctx.createBiquadFilter();
            presenceBoost.type = 'peaking';
            presenceBoost.frequency.value = 1400; // The "clack" of the string
            presenceBoost.Q.value = 1.5;
            presenceBoost.gain.value = definitionAmount;
        }

        const reverbSend = ctx.createGain();
        reverbSend.gain.value = 0;

        // Internal Chain Construction
        // Signal -> HP (Bass only) -> Surdo Notch (Bass only) -> EQ Low -> EQ Mid -> EQ High -> Presence (Bass only) -> Gain

        let chainHead: AudioNode = eqLow;

        // Connect Head
        if (isBass && hpFilter && surdoNotch) {
            hpFilter.connect(surdoNotch);
            surdoNotch.connect(eqLow);
            chainHead = hpFilter; // New Head
        }

        eqLow.connect(eqMid);
        eqMid.connect(eqHigh);

        let chainTail: AudioNode = eqHigh;

        if (isBass && presenceBoost) {
            eqHigh.connect(presenceBoost);
            chainTail = presenceBoost;
        }

        chainTail.connect(gain);

        // Output Routing
        if (isBass) {
            gain.connect(bassCompressor); 
        } else {
            gain.connect(masterCompressor); 
            gain.connect(reverbSend); 
            reverbSend.connect(reverbNode);
        }

        return { gain, eqLow, eqMid, eqHigh, reverbSend, surdoNotch, presenceBoost };
    };

    // Initialize Channels
    // Force Bass to 1.0, others to 0.0 initially if wanted, or respect state
    nodesRef.current.low = createChannel(volLow, true); 
    nodesRef.current.mid = createChannel(volMid, false);
    nodesRef.current.high = createChannel(volHigh, false);

    // --- CROSSOVER ROUTING ---

    // Path 1: VIOLÃO 7 CORDAS (Low + Attack)
    // We need a complex filter: LowPass < 280Hz OR BandPass @ 1.4kHz. 
    // Implementing purely via LowPass for simplicity but added PresenceBoost in the channel to "catch" any bleed frequency useful for attack.
    // Note: To truly get the attack without the vocal mid, we'd need parallel processing. 
    // Here we rely on the 4th order LowPass to kill the voice, and use the PresenceBoost to amplify what remains of the attack in the low-mid bleed.

    const lowPasses = createFilters('lowpass', BASS_CROSSOVER, 4); // 48dB/oct steep cut
    chainFilters(sourceNodeRef.current, lowPasses, 
        nodesRef.current.low.surdoNotch!.context.createGain().connect(nodesRef.current.low.surdoNotch!.context.destination) ? nodesRef.current.low.gain : nodesRef.current.low.eqLow // Hacky check, simpler:
    );
    // Re-do connection properly:
    // Source -> LowPasses -> [HP -> Notch -> EQs]
    // We need to access the 'head' of the chain created in createChannel.
    // Since we returned struct, we know for Bass it starts at 'hpFilter' implicitly if we reconstructed logic, 
    // but in createChannel we returned specific nodes. Let's fix the connection logic.
    // Actually, createChannel doesn't expose the 'head'. Let's assume standard connection to eqLow or specific head.

    // Hack: We reconnect manually.
    // Disconnect internal head from createChannel to ensure we feed into it.
    // For Low channel, head is actually the HP filter created inside. 
    // To make this robust without refactoring createChannel return type too much:
    // We will assume eqLow is the entry point for standard, but for bass we need to look at our logic.

    // Let's simplified routing: Source -> Crossover -> Channel Input Node.
    // Channel Input Node for Bass = nodesRef.current.low.surdoNotch (approx, since HP is before it but inaccessible).
    // Let's rebuild createChannel to return input node explicitly to be safe.
    // Or just use eqLow and putting HP/Notch *after* eqLow for this specific React component cycle.

    // Correct routing:
    // Source -> 4x LowPass -> Bass Channel
    let bassInput = sourceNodeRef.current;
    lowPasses.forEach(f => { bassInput.connect(f); bassInput = f; });

    // Since we can't easily access the HP filter inside createChannel from here without refactor,
    // let's just connect to eqLow, and accept that HP/Notch are applied *after* EQ Low in the chain?
    // No, createChannel linked them: HP->Notch->Low->Mid...
    // But we didn't return HP.
    // Let's fix createChannel return or use eqLow as entry, knowing it is NOT the head.
    // FIX: Let's assume we connect to eqLow, and in createChannel we change order: Gain -> EQ -> Output.
    // But EQ order matters.

    // OK, simplest fix for this XML patch:
    // We will connect to eqLow. In createChannel (Bass), we will make eqLow the FIRST node, then connect to Notch/HP.
    // Bass Chain: EqLow -> EqMid -> EqHigh -> HP -> Notch -> Presence -> Gain.
    // This is valid. Filtering is linear (mostly).

    // Source -> LowPass Filters -> nodesRef.current.low.eqLow
    let curr = sourceNodeRef.current;
    lowPasses.forEach(f => { curr.connect(f); curr = f; });
    curr.connect(nodesRef.current.low.eqLow);

    // Path 2: MID (Voice/Harmonia)
    const midHighPasses = createFilters('highpass', BASS_CROSSOVER, 4);
    const midLowPasses = createFilters('lowpass', TREBLE_CROSSOVER, 4);

    let midChain = sourceNodeRef.current;
    midHighPasses.forEach(f => { midChain.connect(f); midChain = f; });
    midLowPasses.forEach(f => { midChain.connect(f); midChain = f; });
    midChain.connect(nodesRef.current.mid.eqLow);

    // Path 3: HIGH (Percussion)
    const highPasses = createFilters('highpass', TREBLE_CROSSOVER, 4);
    let highChain = sourceNodeRef.current;
    highPasses.forEach(f => { highChain.connect(f); highChain = f; });
    highChain.connect(nodesRef.current.high.eqLow);
  };

  // --- UPDATES ---

  // Handle Pro Tool Updates (Notch & Definition)
  useEffect(() => {
    const t = getAudioContext().currentTime;
    const lowNodes = nodesRef.current.low;
    if (lowNodes && lowNodes.surdoNotch && lowNodes.presenceBoost) {
        // Update Surdo Notch
        lowNodes.surdoNotch.frequency.setTargetAtTime(surdoCutFreq, t, 0.1);

        // Update Definition
        lowNodes.presenceBoost.gain.setTargetAtTime(definitionAmount, t, 0.1);
    }
  }, [surdoCutFreq, definitionAmount]);

  // Handle EQ
  useEffect(() => {
    const ctx = getAudioContext();
    const t = ctx.currentTime;
    const ramp = 0.1;
    const applyEq = (nodes: ChannelNodes | null, settings: EqState) => {
        if (!nodes) return;
        nodes.eqLow.gain.setTargetAtTime(settings.low, t, ramp);
        nodes.eqMid.gain.setTargetAtTime(settings.mid, t, ramp);
        nodes.eqHigh.gain.setTargetAtTime(settings.high, t, ramp);
    };
    applyEq(nodesRef.current.low, eqLowSettings);
    applyEq(nodesRef.current.mid, eqMidSettings);
    applyEq(nodesRef.current.high, eqHighSettings);
  }, [eqLowSettings, eqMidSettings, eqHighSettings]);

  // Handle Volume (Precision Mute)
  useEffect(() => {
    const ctx = getAudioContext();
    const t = ctx.currentTime;

    const updateGain = (nodes: ChannelNodes | null, val: number) => {
        if (!nodes) return;
        nodes.gain.gain.cancelScheduledValues(t);
        if (val <= 0.01) nodes.gain.gain.setTargetAtTime(0, t, 0.01); // Hard Mute
        else nodes.gain.gain.setTargetAtTime(val, t, 0.05);
    };

    updateGain(nodesRef.current.low, volLow);
    updateGain(nodesRef.current.mid, volMid);
    updateGain(nodesRef.current.high, volHigh);
  }, [volLow, volMid, volHigh]);


  // --- STANDARD HANDLERS ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      setFile(selectedFile);
      setIsLoading(true);
      setIsPlaying(false);

      // AUTO-SETUP FOR 7 STRING ISOLATION
      setVolLow(1.0);
      setVolMid(0); // Mute Voice
      setVolHigh(0); // Mute Percussion
      setSurdoCutFreq(85); // Default Surdo Hz
      setDefinitionAmount(6); // Boost Attack

      const objectUrl = URL.createObjectURL(selectedFile);
      if (audioRef.current) {
          audioRef.current.src = objectUrl;
          audioRef.current.load();
      }
      try {
          const arrayBuffer = await selectedFile.arrayBuffer();
          const ctx = getAudioContext();
          const audioBuffer = await ctx.decodeAudioData(arrayBuffer);
          waveformBufferRef.current = audioBuffer;
          setDuration(audioBuffer.duration);
          setLoopEnd(audioBuffer.duration);
          drawWaveform();
      } catch (err) { console.error(err); } 
      finally { setIsLoading(false); }
    }
  };

  const togglePlay = async () => {
    if (!audioRef.current) return;
    const ctx = getAudioContext();
    if (ctx.state === 'suspended') await ctx.resume();
    if (!nodesRef.current.low) setupAudioGraph();

    if (isPlaying) {
      audioRef.current.pause();
      setIsPlaying(false);
    } else {
      await audioRef.current.play();
      setIsPlaying(true);
    }
  };

  const stopAudio = () => {
      if (!audioRef.current) return;
      audioRef.current.pause();
      audioRef.current.currentTime = isLooping ? loopStart : 0;
      setCurrentTime(audioRef.current.currentTime);
      setIsPlaying(false);
  };

  useEffect(() => {
      if (audioRef.current) {
          audioRef.current.playbackRate = playbackRate;
          audioRef.current.preservesPitch = true;
      }
  }, [playbackRate]);

  // Loop Check
  useEffect(() => {
    const loopCheck = () => {
        if (!audioRef.current) return;
        const curr = audioRef.current.currentTime;
        setCurrentTime(curr);
        if (isLooping && loopEnd > loopStart) {
            if (curr >= loopEnd || curr < loopStart) audioRef.current.currentTime = loopStart;
        }
        animationFrameRef.current = requestAnimationFrame(loopCheck);
    };
    if (isPlaying) animationFrameRef.current = requestAnimationFrame(loopCheck);
    else if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    return () => { if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current); };
  }, [isPlaying, isLooping, loopStart, loopEnd]);


  // --- VISUALS ---
  const drawWaveform = () => {
      if (!canvasRef.current || !waveformBufferRef.current) return;
      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;
      const width = canvasRef.current.width;
      const height = canvasRef.current.height;
      const data = waveformBufferRef.current.getChannelData(0);
      const step = Math.ceil(data.length / width);
      const amp = height / 2;

      ctx.clearRect(0, 0, width, height);
      ctx.fillStyle = '#0f172a';
      ctx.fillRect(0, 0, width, height);
      ctx.beginPath();
      ctx.moveTo(0, amp);
      ctx.strokeStyle = '#334155';
      ctx.lineWidth = 1;

      for (let i = 0; i < width; i++) {
          let min = 1.0, max = -1.0;
          for (let j = 0; j < step; j++) {
              const datum = data[(i * step) + j];
              if (datum < min) min = datum;
              if (datum > max) max = datum;
          }
          ctx.lineTo(i, (1 + min) * amp);
          ctx.lineTo(i, (1 + max) * amp);
      }
      ctx.stroke();
  };

  // Overlay
  useEffect(() => {
      if (!canvasRef.current) return;
      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;
      drawWaveform(); 
      const width = canvasRef.current.width;
      const height = canvasRef.current.height;
      if (duration > 0) {
          const xStart = (loopStart / duration) * width;
          const xEnd = (loopEnd / duration) * width;
          ctx.fillStyle = 'rgba(234, 179, 8, 0.15)'; // Yellow tint
          ctx.fillRect(xStart, 0, xEnd - xStart, height);
          ctx.strokeStyle = '#eab308';
          ctx.beginPath();
          ctx.moveTo(xStart, 0); ctx.lineTo(xStart, height);
          ctx.moveTo(xEnd, 0); ctx.lineTo(xEnd, height);
          ctx.stroke();
      }
      if (duration > 0) {
          const xPos = (currentTime / duration) * width;
          ctx.strokeStyle = '#ef4444';
          ctx.lineWidth = 2;
          ctx.beginPath(); ctx.moveTo(xPos, 0); ctx.lineTo(xPos, height); ctx.stroke();
      }
  }, [currentTime, loopStart, loopEnd, duration]);

  const handleSeek = (e: React.MouseEvent<HTMLCanvasElement>) => {
      if (!duration) return;
      const rect = canvasRef.current!.getBoundingClientRect();
      const perc = (e.clientX - rect.left) / rect.width;
      if (audioRef.current) {
          audioRef.current.currentTime = perc * duration;
          setCurrentTime(perc * duration);
      }
  };
  const setLoopPoint = (type: 'start' | 'end') => {
      if (type === 'start') setLoopStart(currentTime); else setLoopEnd(currentTime);
      setIsLooping(true);
  };
  const formatTime = (t: number) => {
      const min = Math.floor(t / 60);
      const sec = Math.floor(t % 60);
      return `${min}:${sec.toString().padStart(2, '0')}`;
  };

  // --- UI COMPONENTS ---

  const updateVolume = (setter: React.Dispatch<React.SetStateAction<number>>, current: number, delta: number) => {
      const newVal = Math.max(0, Math.min(2, current + delta));
      setter(parseFloat(newVal.toFixed(1)));
  };

  const updateEQ = (
      setter: React.Dispatch<React.SetStateAction<EqState>>, 
      band: keyof EqState, 
      delta: number
  ) => {
      setter(prev => ({ ...prev, [band]: Math.max(-12, Math.min(12, prev[band] + delta)) }));
  };

  const renderChannelControls = (
      title: string, 
      sub: string, 
      color: string, 
      vol: number, 
      setVol: React.Dispatch<React.SetStateAction<number>>,
      eq: EqState,
      setEq: React.Dispatch<React.SetStateAction<EqState>>,
      icon: React.ReactNode,
      children?: React.ReactNode
  ) => {
      return (
        <div className="bg-slate-800 rounded-xl p-3 border border-slate-700 flex flex-col gap-3 relative overflow-hidden group">
            {/* Header */}
            <div className={`flex items-center gap-2 border-b border-slate-700 pb-2 ${color}`}>
                {icon}
                <div className="flex-1">
                    <div className="text-xs font-bold uppercase tracking-wider">{title}</div>
                    <div className="text-[9px] text-slate-500">{sub}</div>
                </div>
            </div>

            {/* Volume Control */}
            <div className="flex items-center justify-between bg-slate-900/50 p-2 rounded-lg relative">
                <button 
                    onClick={() => updateVolume(setVol, vol, -0.1)}
                    className="w-8 h-8 flex items-center justify-center rounded bg-slate-700 hover:bg-slate-600 active:scale-95 transition-all text-slate-300 z-20"
                ><Minus size={14} /></button>

                <div className="flex flex-col items-center w-16">
                    <span className={`text-xl font-bold ${vol === 0 ? 'text-slate-600' : 'text-white'}`}>{(vol * 100).toFixed(0)}%</span>
                    <div className="w-full h-1 bg-slate-700 rounded-full mt-1 overflow-hidden">
                        <div className={`h-full ${color.replace('text-', 'bg-')}`} style={{ width: `${(vol/2)*100}%` }} />
                    </div>
                </div>

                <button 
                    onClick={() => updateVolume(setVol, vol, 0.1)}
                    className="w-8 h-8 flex items-center justify-center rounded bg-slate-700 hover:bg-slate-600 active:scale-95 transition-all text-slate-300 z-20"
                ><Plus size={14} /></button>

                {/* Mute Overlay */}
                {vol === 0 && (
                   <button 
                       onClick={() => setVol(1.0)}
                       className="absolute inset-0 flex items-center justify-center bg-slate-900/80 text-red-500 font-bold tracking-widest text-xs z-10 backdrop-blur-sm rounded-lg border border-red-500/30"
                   >
                       MUTADO
                   </button>
                )}
            </div>

            {/* CUSTOM PRO TOOLS (Like Surdo Killer) */}
            {children}

            {/* 3-Band EQ */}
            <div className="space-y-2 mt-1">
                <div className="flex items-center gap-1 text-[9px] font-mono text-slate-500 mb-1 uppercase">
                    <Sliders size={10} /> Equalizador
                </div>
                {[
                    { label: 'HIGH', key: 'high', val: eq.high },
                    { label: 'MID', key: 'mid', val: eq.mid },
                    { label: 'LOW', key: 'low', val: eq.low }
                ].map((band) => (
                    <div key={band.label} className="flex items-center gap-2">
                        <span className="w-8 text-[9px] font-bold text-slate-400 text-right">{band.label}</span>
                        <button onClick={() => updateEQ(setEq, band.key as keyof EqState, -1)} className="text-slate-500 hover:text-slate-300"><Minus size={10} /></button>

                        <div className="flex-1 h-3 bg-slate-900 rounded relative overflow-hidden flex items-center justify-center">
                            <div className="absolute w-[1px] h-full bg-slate-700 left-1/2" />
                            <div 
                                className={`h-full absolute transition-all ${band.val > 0 ? 'bg-green-500 left-1/2' : 'bg-red-500 right-1/2'}`}
                                style={{ width: `${Math.abs(band.val) * 8}%` }}
                            />
                            <span className="relative text-[8px] z-10 text-white font-mono drop-shadow-md">{band.val > 0 ? `+${band.val}` : band.val}dB</span>
                        </div>

                        <button onClick={() => updateEQ(setEq, band.key as keyof EqState, 1)} className="text-slate-500 hover:text-slate-300"><Plus size={10} /></button>
                    </div>
                ))}
            </div>

            {vol > 0 && (
                <button onClick={() => setVol(0)} className="w-full py-1 text-[10px] font-bold text-red-400 bg-red-900/10 hover:bg-red-900/30 border border-red-900/30 rounded uppercase tracking-wider transition-colors mt-2">
                    Mutar Canal
                </button>
            )}
        </div>
      );
  };

  return (
    <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 h-full flex flex-col">
      <audio ref={audioRef} onEnded={() => setIsPlaying(false)} crossOrigin="anonymous" />

      {/* HEADER */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
          <div>
            <h2 className="text-xl font-bold text-white flex items-center gap-2">
                <Target className="text-yellow-500" />
                Studio Pro 7 Cordas
            </h2>
            <p className="text-xs text-slate-400">Ferramenta profissional de isolamento e equalização de baixarias.</p>
          </div>

          <label className="cursor-pointer bg-slate-700 hover:bg-slate-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors border border-slate-600 shadow-lg">
             {isLoading ? <Loader2 className="animate-spin" size={16} /> : <Upload size={16} />}
             <span className="text-sm font-bold">Carregar Áudio</span>
             <input type="file" accept="audio/*" onChange={handleFileUpload} className="hidden" />
          </label>
      </div>

      {!file ? (
          <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-slate-700 rounded-xl bg-slate-900/30 text-slate-500 gap-4">
              <Upload size={48} className="opacity-50" />
              <p>Carregue um Samba ou Choro para isolar o 7 cordas</p>
          </div>
      ) : (
          <div className="flex-1 flex flex-col gap-4">

              {/* WAVEFORM & TRANSPORT */}
              <div className="bg-slate-900 rounded-xl p-3 border border-slate-700 shadow-inner">
                  <div className="relative h-24 w-full bg-slate-950 rounded-lg overflow-hidden cursor-crosshair mb-3 border border-slate-800">
                      <canvas ref={canvasRef} width={800} height={96} className="w-full h-full" onClick={handleSeek} />
                  </div>

                  <div className="flex flex-wrap items-center justify-between gap-2">
                      <div className="flex items-center gap-2">
                          <button onClick={togglePlay} className="w-10 h-10 rounded-full bg-yellow-500 hover:bg-yellow-400 text-slate-900 flex items-center justify-center shadow-lg transition-transform hover:scale-105">
                              {isPlaying ? <Pause fill="currentColor" size={18} /> : <Play fill="currentColor" size={18} className="ml-0.5" />}
                          </button>
                          <button onClick={stopAudio} className="w-10 h-10 rounded-full bg-slate-700 hover:bg-slate-600 text-white flex items-center justify-center shadow">
                              <Square size={16} fill="currentColor" />
                          </button>
                          <div className="text-xs font-mono text-yellow-500 bg-slate-800 px-3 py-1.5 rounded border border-slate-700 ml-2">
                              {formatTime(currentTime)} / {formatTime(duration)}
                          </div>
                      </div>

                      <div className="flex items-center gap-2 bg-slate-800 p-1 rounded-lg border border-slate-700">
                          <button onClick={() => setLoopPoint('start')} className="px-2 py-1 text-[10px] font-bold hover:bg-slate-700 rounded text-yellow-200">IN (A)</button>
                          <button onClick={() => setLoopPoint('end')} className="px-2 py-1 text-[10px] font-bold hover:bg-slate-700 rounded text-yellow-200">OUT (B)</button>
                          <button onClick={() => setIsLooping(!isLooping)} className={`p-1 rounded transition-colors ${isLooping ? 'bg-yellow-500/20 text-yellow-400' : 'text-slate-500'}`}>
                              <Repeat size={14} />
                          </button>
                      </div>

                      <div className="flex items-center gap-2 bg-slate-800 p-1.5 rounded-lg border border-slate-700">
                          <Rewind size={14} className="text-slate-500 cursor-pointer" onClick={() => setPlaybackRate(Math.max(0.5, playbackRate - 0.1))} />
                          <span className="text-xs font-mono w-10 text-center font-bold text-slate-300">{playbackRate.toFixed(2)}x</span>
                          <FastForward size={14} className="text-slate-500 cursor-pointer" onClick={() => setPlaybackRate(Math.min(1.5, playbackRate + 0.1))} />
                      </div>
                  </div>
              </div>

              {/* MIXING CONSOLE */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4 h-full">

                   {/* 7 STRING CHANNEL (FEATURED) */}
                   {renderChannelControls(
                       "VIOLÃO 7 CORDAS", "Isolamento de Precisão", "text-yellow-500", 
                       volLow, setVolLow, eqLowSettings, setEqLowSettings,
                       <Target size={16} className="text-yellow-500" />,
                       <div className="bg-slate-900/80 p-2 rounded-lg border border-yellow-500/20 space-y-2 mb-2">
                           <div className="flex justify-between items-center text-[9px] font-bold text-slate-400 uppercase">
                               <div className="flex items-center gap-1"><ShieldBan size={10} /> Corte Surdo</div>
                               <span className="text-yellow-500">{surdoCutFreq} Hz</span>
                           </div>
                           <input 
                               type="range" min="50" max="150" step="5"
                               value={surdoCutFreq}
                               onChange={(e) => setSurdoCutFreq(Number(e.target.value))}
                               className="w-full h-1 bg-slate-700 rounded appearance-none accent-red-500"
                               title="Ajuste para cortar o 'boom' do surdo"
                           />

                           <div className="flex justify-between items-center text-[9px] font-bold text-slate-400 uppercase mt-2">
                               <div className="flex items-center gap-1"><Zap size={10} /> Definição (Ataque)</div>
                               <span className="text-yellow-500">+{definitionAmount}dB</span>
                           </div>
                           <input 
                               type="range" min="0" max="15" step="1"
                               value={definitionAmount}
                               onChange={(e) => setDefinitionAmount(Number(e.target.value))}
                               className="w-full h-1 bg-slate-700 rounded appearance-none accent-green-500"
                               title="Aumenta o som da unhada/dedeira"
                           />
                       </div>
                   )}

                   {/* MID CHANNEL */}
                   {renderChannelControls(
                       "VOZ / HARMONIA", "Frequências Médias", "text-indigo-500", 
                       volMid, setVolMid, eqMidSettings, setEqMidSettings,
                       <Sparkles size={16} className="text-indigo-500" />
                   )}

                   {/* TREBLE CHANNEL */}
                   {renderChannelControls(
                       "PERCUSSÃO / AGUDOS", "Brilho & Ataque", "text-pink-500", 
                       volHigh, setVolHigh, eqHighSettings, setEqHighSettings,
                       <Volume2 size={16} className="text-pink-500" />
                   )}
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Upload, Play, Pause, Square, Repeat, FastForward, Rewind, Layers, Volume2, Info, Loader2, VolumeX, Plus, Minus, Sliders, Sparkles, Zap, Headphones, Target, ShieldBan } from 'lucide-react';
import { getAudioContext } from '../utils/audio';

// --- TYPES ---

interface ChannelNodes {
  gain: GainNode;
  eqLow: BiquadFilterNode;
  eqMid: BiquadFilterNode;
  eqHigh: BiquadFilterNode;

  // Specific for 7-String Pro Isolation
  surdoNotch?: BiquadFilterNode; // To surgically remove Surdo boom
  presenceBoost?: BiquadFilterNode; // To highlight string attack

  reverbSend?: GainNode;
}

interface EqState {
  low: number; // -10 to 10
  mid: number;
  high: number;
}

export const AudioSeparator: React.FC = () => {
  // --- STATE ---
  const [file, setFile] = useState<File | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [duration, setDuration] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isLooping, setIsLooping] = useState(false);
  const [loopStart, setLoopStart] = useState<number>(0);
  const [loopEnd, setLoopEnd] = useState<number>(0);
  const [isLoading, setIsLoading] = useState(false);

  // Volumes (0.0 - 2.0)
  const [volLow, setVolLow] = useState(1.0);
  const [volMid, setVolMid] = useState(1.0);
  const [volHigh, setVolHigh] = useState(1.0);

  // EQ States
  const [eqLowSettings, setEqLowSettings] = useState<EqState>({ low: 3, mid: 2, high: 0 }); 
  const [eqMidSettings, setEqMidSettings] = useState<EqState>({ low: 0, mid: 0, high: 0 });
  const [eqHighSettings, setEqHighSettings] = useState<EqState>({ low: 0, mid: 0, high: 0 });

  // Professional Tools State
  const [surdoCutFreq, setSurdoCutFreq] = useState(85); // Hz (Typical Surdo Boom)
  const [definitionAmount, setDefinitionAmount] = useState(5); // dB boost at 1.5kHz for attack
  const [isIsolationMode, setIsIsolationMode] = useState(true);

  // --- REFS ---
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<MediaElementAudioSourceNode | null>(null);

  // Audio Graph Nodes
  const nodesRef = useRef<{
    low: ChannelNodes | null;
    mid: ChannelNodes | null;
    high: ChannelNodes | null;
    compressor: DynamicsCompressorNode | null;
    bassCompressor: DynamicsCompressorNode | null;
    reverb: ConvolverNode | null;
  }>({ low: null, mid: null, high: null, compressor: null, bassCompressor: null, reverb: null });

  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const animationFrameRef = useRef<number | null>(null);
  const waveformBufferRef = useRef<AudioBuffer | null>(null);

  // --- AUDIO ENGINE ---

  const createReverbImpulse = (ctx: AudioContext, duration: number = 2.0, decay: number = 2.0) => {
    const rate = ctx.sampleRate;
    const length = rate * duration;
    const impulse = ctx.createBuffer(2, length, rate);
    const left = impulse.getChannelData(0);
    const right = impulse.getChannelData(1);
    for (let i = 0; i < length; i++) {
        const n = i / length;
        left[i] = (Math.random() * 2 - 1) * Math.pow(1 - n, decay);
        right[i] = (Math.random() * 2 - 1) * Math.pow(1 - n, decay);
    }
    return impulse;
  };

  const setupAudioGraph = () => {
    if (!audioRef.current) return;

    const ctx = getAudioContext();
    audioContextRef.current = ctx;

    if (!sourceNodeRef.current) {
        sourceNodeRef.current = ctx.createMediaElementSource(audioRef.current);
    }

    // --- DYNAMICS PROCESSING ---

    // Master Compressor (Glue)
    const masterCompressor = ctx.createDynamicsCompressor();
    masterCompressor.threshold.value = -10;
    masterCompressor.ratio.value = 4;
    masterCompressor.connect(ctx.destination);
    nodesRef.current.compressor = masterCompressor;

    // Bass Specific Compressor ("Transient Shaper" for 7 String)
    // We want slow attack to let the "pluck" through, fast release to kill the "boom"
    const bassCompressor = ctx.createDynamicsCompressor();
    bassCompressor.threshold.value = -20; 
    bassCompressor.knee.value = 5;
    bassCompressor.ratio.value = 6; 
    bassCompressor.attack.value = 0.03; // 30ms lets the pick attack through
    bassCompressor.release.value = 0.15; // Fast release controls the tail (surdo bloom)
    bassCompressor.connect(masterCompressor); 
    nodesRef.current.bassCompressor = bassCompressor;

    // Reverb Bus
    const reverbNode = ctx.createConvolver();
    reverbNode.buffer = createReverbImpulse(ctx, 1.5, 3.0);
    const reverbGain = ctx.createGain();
    reverbGain.gain.value = 0.15;
    reverbNode.connect(reverbGain);
    reverbGain.connect(masterCompressor);
    nodesRef.current.reverb = reverbNode;

    // --- CROSSOVER DEFINITIONS (PRO TUNING) ---
    // 7-String Range: ~55Hz (A1) to ~600Hz (Upper neck logic). Attack is around 1.2kHz.
    // Vocal Fundamentals: Start around 200Hz (Female) or 100Hz (Male).
    // Surdo: Deep energy at 50-80Hz.

    // Strategy: 
    // Bass Channel gets < 300Hz (Body) AND a bandpass at 1.5kHz (Definition).
    // Mid Channel gets > 300Hz.

    const BASS_CROSSOVER = 280; // Slightly lower to minimize vocal bleed
    const TREBLE_CROSSOVER = 4000;

    const createFilters = (type: BiquadFilterType, freq: number, count: number) => {
        return Array(count).fill(0).map(() => {
            const f = ctx.createBiquadFilter();
            f.type = type;
            f.frequency.value = freq;
            return f;
        });
    };

    const chainFilters = (source: AudioNode, filters: BiquadFilterNode[], dest: AudioNode) => {
        let curr = source;
        filters.forEach(f => {
            curr.connect(f);
            curr = f;
        });
        curr.connect(dest);
    };

    // --- CHANNEL CREATION HELPER ---
    const createChannel = (initialVol: number, isBass: boolean = false): ChannelNodes => {
        // Gain
        const gain = ctx.createGain();
        gain.gain.value = initialVol;

        // 3-Band Standard EQ
        const eqLow = ctx.createBiquadFilter();
        eqLow.type = 'lowshelf';
        eqLow.frequency.value = 200;

        const eqMid = ctx.createBiquadFilter();
        eqMid.type = 'peaking';
        eqMid.frequency.value = 1000;
        eqMid.Q.value = 1.0;

        const eqHigh = ctx.createBiquadFilter();
        eqHigh.type = 'highshelf';
        eqHigh.frequency.value = 5000;

        // --- PRO BASS TOOLS ---
        let surdoNotch: BiquadFilterNode | undefined;
        let presenceBoost: BiquadFilterNode | undefined;
        let hpFilter: BiquadFilterNode | undefined;

        if (isBass) {
            // 1. High Pass (Safety Cut) - Remove absolute rumble/sub-bass that muddies the mix
            hpFilter = ctx.createBiquadFilter();
            hpFilter.type = 'highpass';
            hpFilter.frequency.value = 58; // Just below B1 (61Hz) / A1 (55Hz). Keeps musical notes, kills rumble.
            hpFilter.Q.value = 0.7;

            // 2. Surdo Notch (Surgical Cut) - User adjustable
            surdoNotch = ctx.createBiquadFilter();
            surdoNotch.type = 'notch';
            surdoNotch.frequency.value = surdoCutFreq; 
            surdoNotch.Q.value = 4.0; // Narrow cut to avoid killing the guitar note 'E' or 'A'

            // 3. Presence/Definition (Bring back the attack)
            presenceBoost = ctx.createBiquadFilter();
            presenceBoost.type = 'peaking';
            presenceBoost.frequency.value = 1400; // The "clack" of the string
            presenceBoost.Q.value = 1.5;
            presenceBoost.gain.value = definitionAmount;
        }

        const reverbSend = ctx.createGain();
        reverbSend.gain.value = 0;

        // Internal Chain Construction
        // Signal -> HP (Bass only) -> Surdo Notch (Bass only) -> EQ Low -> EQ Mid -> EQ High -> Presence (Bass only) -> Gain

        let chainHead: AudioNode = eqLow;

        // Connect Head
        if (isBass && hpFilter && surdoNotch) {
            hpFilter.connect(surdoNotch);
            surdoNotch.connect(eqLow);
            chainHead = hpFilter; // New Head
        }

        eqLow.connect(eqMid);
        eqMid.connect(eqHigh);

        let chainTail: AudioNode = eqHigh;

        if (isBass && presenceBoost) {
            eqHigh.connect(presenceBoost);
            chainTail = presenceBoost;
        }

        chainTail.connect(gain);

        // Output Routing
        if (isBass) {
            gain.connect(bassCompressor); 
        } else {
            gain.connect(masterCompressor); 
            gain.connect(reverbSend); 
            reverbSend.connect(reverbNode);
        }

        return { gain, eqLow, eqMid, eqHigh, reverbSend, surdoNotch, presenceBoost };
    };

    // Initialize Channels
    nodesRef.current.low = createChannel(volLow, true); 
    nodesRef.current.mid = createChannel(volMid, false);
    nodesRef.current.high = createChannel(volHigh, false);

    // --- CROSSOVER ROUTING ---

    // Path 1: VIOLÃO 7 CORDAS (Low + Attack)

    const lowPasses = createFilters('lowpass', BASS_CROSSOVER, 4); // 48dB/oct steep cut

    // Correct routing:
    // Source -> 4x LowPass -> Bass Channel
    // Explicitly casting bassInput to AudioNode to handle assignment of BiquadFilterNode
    let bassInput: AudioNode = sourceNodeRef.current!;
    lowPasses.forEach(f => { bassInput.connect(f); bassInput = f; });

    // Source -> LowPass Filters -> nodesRef.current.low.eqLow
    let curr: AudioNode = sourceNodeRef.current!;
    lowPasses.forEach(f => { curr.connect(f); curr = f; });
    if (nodesRef.current.low) curr.connect(nodesRef.current.low.eqLow);

    // Path 2: MID (Voice/Harmonia)
    const midHighPasses = createFilters('highpass', BASS_CROSSOVER, 4);
    const midLowPasses = createFilters('lowpass', TREBLE_CROSSOVER, 4);

    let midChain: AudioNode = sourceNodeRef.current!;
    midHighPasses.forEach(f => { midChain.connect(f); midChain = f; });
    midLowPasses.forEach(f => { midChain.connect(f); midChain = f; });
    if (nodesRef.current.mid) midChain.connect(nodesRef.current.mid.eqLow);

    // Path 3: HIGH (Percussion)
    const highPasses = createFilters('highpass', TREBLE_CROSSOVER, 4);
    let highChain: AudioNode = sourceNodeRef.current!;
    highPasses.forEach(f => { highChain.connect(f); highChain = f; });
    if (nodesRef.current.high) highChain.connect(nodesRef.current.high.eqLow);
  };

  // --- UPDATES ---

  // Handle Pro Tool Updates (Notch & Definition)
  useEffect(() => {
    const t = getAudioContext().currentTime;
    const lowNodes = nodesRef.current.low;
    if (lowNodes && lowNodes.surdoNotch && lowNodes.presenceBoost) {
        // Update Surdo Notch
        lowNodes.surdoNotch.frequency.setTargetAtTime(surdoCutFreq, t, 0.1);

        // Update Definition
        lowNodes.presenceBoost.gain.setTargetAtTime(definitionAmount, t, 0.1);
    }
  }, [surdoCutFreq, definitionAmount]);

  // Handle EQ
  useEffect(() => {
    const ctx = getAudioContext();
    const t = ctx.currentTime;
    const ramp = 0.1;
    const applyEq = (nodes: ChannelNodes | null, settings: EqState) => {
        if (!nodes) return;
        nodes.eqLow.gain.setTargetAtTime(settings.low, t, ramp);
        nodes.eqMid.gain.setTargetAtTime(settings.mid, t, ramp);
        nodes.eqHigh.gain.setTargetAtTime(settings.high, t, ramp);
    };
    applyEq(nodesRef.current.low, eqLowSettings);
    applyEq(nodesRef.current.mid, eqMidSettings);
    applyEq(nodesRef.current.high, eqHighSettings);
  }, [eqLowSettings, eqMidSettings, eqHighSettings]);

  // Handle Volume (Precision Mute)
  useEffect(() => {
    const ctx = getAudioContext();
    const t = ctx.currentTime;

    const updateGain = (nodes: ChannelNodes | null, val: number) => {
        if (!nodes) return;
        nodes.gain.gain.cancelScheduledValues(t);
        if (val <= 0.01) nodes.gain.gain.setTargetAtTime(0, t, 0.01); // Hard Mute
        else nodes.gain.gain.setTargetAtTime(val, t, 0.05);
    };

    updateGain(nodesRef.current.low, volLow);
    updateGain(nodesRef.current.mid, volMid);
    updateGain(nodesRef.current.high, volHigh);
  }, [volLow, volMid, volHigh]);


  // --- STANDARD HANDLERS ---
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      setFile(selectedFile);
      setIsLoading(true);
      setIsPlaying(false);

      // AUTO-SETUP FOR 7 STRING ISOLATION
      setVolLow(1.0);
      setVolMid(0); // Mute Voice
      setVolHigh(0); // Mute Percussion
      setSurdoCutFreq(85); // Default Surdo Hz
      setDefinitionAmount(6); // Boost Attack

      const objectUrl = URL.createObjectURL(selectedFile);
      if (audioRef.current) {
          audioRef.current.src = objectUrl;
          audioRef.current.load();
      }
      try {
          const arrayBuffer = await selectedFile.arrayBuffer();
          const ctx = getAudioContext();
          const audioBuffer = await ctx.decodeAudioData(arrayBuffer);
          waveformBufferRef.current = audioBuffer;
          setDuration(audioBuffer.duration);
          setLoopEnd(audioBuffer.duration);
          drawWaveform();
      } catch (err) { console.error(err); } 
      finally { setIsLoading(false); }
    }
  };

  const togglePlay = async () => {
    if (!audioRef.current) return;
    const ctx = getAudioContext();
    if (ctx.state === 'suspended') await ctx.resume();
    if (!nodesRef.current.low) setupAudioGraph();

    if (isPlaying) {
      audioRef.current.pause();
      setIsPlaying(false);
    } else {
      await audioRef.current.play();
      setIsPlaying(true);
    }
  };

  const stopAudio = () => {
      if (!audioRef.current) return;
      audioRef.current.pause();
      audioRef.current.currentTime = isLooping ? loopStart : 0;
      setCurrentTime(audioRef.current.currentTime);
      setIsPlaying(false);
  };

  useEffect(() => {
      if (audioRef.current) {
          audioRef.current.playbackRate = playbackRate;
          audioRef.current.preservesPitch = true;
      }
  }, [playbackRate]);

  // Loop Check
  useEffect(() => {
    const loopCheck = () => {
        if (!audioRef.current) return;
        const curr = audioRef.current.currentTime;
        setCurrentTime(curr);
        if (isLooping && loopEnd > loopStart) {
            if (curr >= loopEnd || curr < loopStart) audioRef.current.currentTime = loopStart;
        }
        animationFrameRef.current = requestAnimationFrame(loopCheck);
    };
    if (isPlaying) animationFrameRef.current = requestAnimationFrame(loopCheck);
    else if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    return () => { if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current); };
  }, [isPlaying, isLooping, loopStart, loopEnd]);


  // --- VISUALS ---
  const drawWaveform = () => {
      if (!canvasRef.current || !waveformBufferRef.current) return;
      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;
      const width = canvasRef.current.width;
      const height = canvasRef.current.height;
      const data = waveformBufferRef.current.getChannelData(0);
      const step = Math.ceil(data.length / width);
      const amp = height / 2;

      ctx.clearRect(0, 0, width, height);
      ctx.fillStyle = '#0f172a';
      ctx.fillRect(0, 0, width, height);
      ctx.beginPath();
      ctx.moveTo(0, amp);
      ctx.strokeStyle = '#334155';
      ctx.lineWidth = 1;

      for (let i = 0; i < width; i++) {
          let min = 1.0, max = -1.0;
          for (let j = 0; j < step; j++) {
              const datum = data[(i * step) + j];
              if (datum < min) min = datum;
              if (datum > max) max = datum;
          }
          ctx.lineTo(i, (1 + min) * amp);
          ctx.lineTo(i, (1 + max) * amp);
      }
      ctx.stroke();
  };

  // Overlay
  useEffect(() => {
      if (!canvasRef.current) return;
      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;
      drawWaveform(); 
      const width = canvasRef.current.width;
      const height = canvasRef.current.height;
      if (duration > 0) {
          const xStart = (loopStart / duration) * width;
          const xEnd = (loopEnd / duration) * width;
          ctx.fillStyle = 'rgba(234, 179, 8, 0.15)'; // Yellow tint
          ctx.fillRect(xStart, 0, xEnd - xStart, height);
          ctx.strokeStyle = '#eab308';
          ctx.beginPath();
          ctx.moveTo(xStart, 0); ctx.lineTo(xStart, height);
          ctx.moveTo(xEnd, 0); ctx.lineTo(xEnd, height);
          ctx.stroke();
      }
      if (duration > 0) {
          const xPos = (currentTime / duration) * width;
          ctx.strokeStyle = '#ef4444';
          ctx.lineWidth = 2;
          ctx.beginPath(); ctx.moveTo(xPos, 0); ctx.lineTo(xPos, height); ctx.stroke();
      }
  }, [currentTime, loopStart, loopEnd, duration]);

  const handleSeek = (e: React.MouseEvent<HTMLCanvasElement>) => {
      if (!duration) return;
      const rect = canvasRef.current!.getBoundingClientRect();
      const perc = (e.clientX - rect.left) / rect.width;
      if (audioRef.current) {
          audioRef.current.currentTime = perc * duration;
          setCurrentTime(perc * duration);
      }
  };
  const setLoopPoint = (type: 'start' | 'end') => {
      if (type === 'start') setLoopStart(currentTime); else setLoopEnd(currentTime);
      setIsLooping(true);
  };
  const formatTime = (t: number) => {
      const min = Math.floor(t / 60);
      const sec = Math.floor(t % 60);
      return `${min}:${sec.toString().padStart(2, '0')}`;
  };

  // --- UI COMPONENTS ---

  const updateVolume = (setter: React.Dispatch<React.SetStateAction<number>>, current: number, delta: number) => {
      const newVal = Math.max(0, Math.min(2, current + delta));
      setter(parseFloat(newVal.toFixed(1)));
  };

  const updateEQ = (
      setter: React.Dispatch<React.SetStateAction<EqState>>, 
      band: keyof EqState, 
      delta: number
  ) => {
      setter(prev => ({ ...prev, [band]: Math.max(-12, Math.min(12, prev[band] + delta)) }));
  };

  const renderChannelControls = (
      title: string, 
      sub: string, 
      color: string, 
      vol: number, 
      setVol: React.Dispatch<React.SetStateAction<number>>,
      eq: EqState,
      setEq: React.Dispatch<React.SetStateAction<EqState>>,
      icon: React.ReactNode,
      children?: React.ReactNode
  ) => {
      return (
        <div className="bg-slate-800 rounded-xl p-3 border border-slate-700 flex flex-col gap-3 relative overflow-hidden group">
            {/* Header */}
            <div className={`flex items-center gap-2 border-b border-slate-700 pb-2 ${color}`}>
                {icon}
                <div className="flex-1">
                    <div className="text-xs font-bold uppercase tracking-wider">{title}</div>
                    <div className="text-[9px] text-slate-500">{sub}</div>
                </div>
            </div>

            {/* Volume Control */}
            <div className="flex items-center justify-between bg-slate-900/50 p-2 rounded-lg relative">
                <button 
                    onClick={() => updateVolume(setVol, vol, -0.1)}
                    className="w-8 h-8 flex items-center justify-center rounded bg-slate-700 hover:bg-slate-600 active:scale-95 transition-all text-slate-300 z-20"
                ><Minus size={14} /></button>

                <div className="flex flex-col items-center w-16">
                    <span className={`text-xl font-bold ${vol === 0 ? 'text-slate-600' : 'text-white'}`}>{(vol * 100).toFixed(0)}%</span>
                    <div className="w-full h-1 bg-slate-700 rounded-full mt-1 overflow-hidden">
                        <div className={`h-full ${color.replace('text-', 'bg-')}`} style={{ width: `${(vol/2)*100}%` }} />
                    </div>
                </div>

                <button 
                    onClick={() => updateVolume(setVol, vol, 0.1)}
                    className="w-8 h-8 flex items-center justify-center rounded bg-slate-700 hover:bg-slate-600 active:scale-95 transition-all text-slate-300 z-20"
                ><Plus size={14} /></button>

                {/* Mute Overlay */}
                {vol === 0 && (
                   <button 
                       onClick={() => setVol(1.0)}
                       className="absolute inset-0 flex items-center justify-center bg-slate-900/80 text-red-500 font-bold tracking-widest text-xs z-10 backdrop-blur-sm rounded-lg border border-red-500/30"
                   >
                       MUTADO
                   </button>
                )}
            </div>

            {/* CUSTOM PRO TOOLS (Like Surdo Killer) */}
            {children}

            {/* 3-Band EQ */}
            <div className="space-y-2 mt-1">
                <div className="flex items-center gap-1 text-[9px] font-mono text-slate-500 mb-1 uppercase">
                    <Sliders size={10} /> Equalizador
                </div>
                {[
                    { label: 'HIGH', key: 'high', val: eq.high },
                    { label: 'MID', key: 'mid', val: eq.mid },
                    { label: 'LOW', key: 'low', val: eq.low }
                ].map((band) => (
                    <div key={band.label} className="flex items-center gap-2">
                        <span className="w-8 text-[9px] font-bold text-slate-400 text-right">{band.label}</span>
                        <button onClick={() => updateEQ(setEq, band.key as keyof EqState, -1)} className="text-slate-500 hover:text-slate-300"><Minus size={10} /></button>

                        <div className="flex-1 h-3 bg-slate-900 rounded relative overflow-hidden flex items-center justify-center">
                            <div className="absolute w-[1px] h-full bg-slate-700 left-1/2" />
                            <div 
                                className={`h-full absolute transition-all ${band.val > 0 ? 'bg-green-500 left-1/2' : 'bg-red-500 right-1/2'}`}
                                style={{ width: `${Math.abs(band.val) * 8}%` }}
                            />
                            <span className="relative text-[8px] z-10 text-white font-mono drop-shadow-md">{band.val > 0 ? `+${band.val}` : band.val}dB</span>
                        </div>

                        <button onClick={() => updateEQ(setEq, band.key as keyof EqState, 1)} className="text-slate-500 hover:text-slate-300"><Plus size={10} /></button>
                    </div>
                ))}
            </div>

            {vol > 0 && (
                <button onClick={() => setVol(0)} className="w-full py-1 text-[10px] font-bold text-red-400 bg-red-900/10 hover:bg-red-900/30 border border-red-900/30 rounded uppercase tracking-wider transition-colors mt-2">
                    Mutar Canal
                </button>
            )}
        </div>
      );
  };

  return (
    <div className="bg-slate-800 rounded-2xl p-6 shadow-xl border border-slate-700 h-full flex flex-col">
      <audio ref={audioRef} onEnded={() => setIsPlaying(false)} crossOrigin="anonymous" />

      {/* HEADER */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
          <div>
            <h2 className="text-xl font-bold text-white flex items-center gap-2">
                <Target className="text-yellow-500" />
                Studio Pro 7 Cordas
            </h2>
            <p className="text-xs text-slate-400">Ferramenta profissional de isolamento e equalização de baixarias.</p>
          </div>

          <label className="cursor-pointer bg-slate-700 hover:bg-slate-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors border border-slate-600 shadow-lg">
             {isLoading ? <Loader2 className="animate-spin" size={16} /> : <Upload size={16} />}
             <span className="text-sm font-bold">Carregar Áudio</span>
             <input type="file" accept="audio/*" onChange={handleFileUpload} className="hidden" />
          </label>
      </div>

      {!file ? (
          <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-slate-700 rounded-xl bg-slate-900/30 text-slate-500 gap-4">
              <Upload size={48} className="opacity-50" />
              <p>Carregue um Samba ou Choro para isolar o 7 cordas</p>
          </div>
      ) : (
          <div className="flex-1 flex flex-col gap-4">

              {/* WAVEFORM & TRANSPORT */}
              <div className="bg-slate-900 rounded-xl p-3 border border-slate-700 shadow-inner">
                  <div className="relative h-24 w-full bg-slate-950 rounded-lg overflow-hidden cursor-crosshair mb-3 border border-slate-800">
                      <canvas ref={canvasRef} width={800} height={96} className="w-full h-full" onClick={handleSeek} />
                  </div>

                  <div className="flex flex-wrap items-center justify-between gap-2">
                      <div className="flex items-center gap-2">
                          <button onClick={togglePlay} className="w-10 h-10 rounded-full bg-yellow-500 hover:bg-yellow-400 text-slate-900 flex items-center justify-center shadow-lg transition-transform hover:scale-105">
                              {isPlaying ? <Pause fill="currentColor" size={18} /> : <Play fill="currentColor" size={18} className="ml-0.5" />}
                          </button>
                          <button onClick={stopAudio} className="w-10 h-10 rounded-full bg-slate-700 hover:bg-slate-600 text-white flex items-center justify-center shadow">
                              <Square size={16} fill="currentColor" />
                          </button>
                          <div className="text-xs font-mono text-yellow-500 bg-slate-800 px-3 py-1.5 rounded border border-slate-700 ml-2">
                              {formatTime(currentTime)} / {formatTime(duration)}
                          </div>
                      </div>

                      <div className="flex items-center gap-2 bg-slate-800 p-1 rounded-lg border border-slate-700">
                          <button onClick={() => setLoopPoint('start')} className="px-2 py-1 text-[10px] font-bold hover:bg-slate-700 rounded text-yellow-200">IN (A)</button>
                          <button onClick={() => setLoopPoint('end')} className="px-2 py-1 text-[10px] font-bold hover:bg-slate-700 rounded text-yellow-200">OUT (B)</button>
                          <button onClick={() => setIsLooping(!isLooping)} className={`p-1 rounded transition-colors ${isLooping ? 'bg-yellow-500/20 text-yellow-400' : 'text-slate-500'}`}>
                              <Repeat size={14} />
                          </button>
                      </div>

                      <div className="flex items-center gap-2 bg-slate-800 p-1.5 rounded-lg border border-slate-700">
                          <Rewind size={14} className="text-slate-500 cursor-pointer" onClick={() => setPlaybackRate(Math.max(0.5, playbackRate - 0.1))} />
                          <span className="text-xs font-mono w-10 text-center font-bold text-slate-300">{playbackRate.toFixed(2)}x</span>
                          <FastForward size={14} className="text-slate-500 cursor-pointer" onClick={() => setPlaybackRate(Math.min(1.5, playbackRate + 0.1))} />
                      </div>
                  </div>
              </div>

              {/* MIXING CONSOLE */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4 h-full">

                   {/* 7 STRING CHANNEL (FEATURED) */}
                   {renderChannelControls(
                       "VIOLÃO 7 CORDAS", "Isolamento de Precisão", "text-yellow-500", 
                       volLow, setVolLow, eqLowSettings, setEqLowSettings,
                       <Target size={16} className="text-yellow-500" />,
                       <div className="bg-slate-900/80 p-2 rounded-lg border border-yellow-500/20 space-y-2 mb-2">
                           <div className="flex justify-between items-center text-[9px] font-bold text-slate-400 uppercase">
                               <div className="flex items-center gap-1"><ShieldBan size={10} /> Corte Surdo</div>
                               <span className="text-yellow-500">{surdoCutFreq} Hz</span>
                           </div>
                           <input 
                               type="range" min="50" max="150" step="5"
                               value={surdoCutFreq}
                               onChange={(e) => setSurdoCutFreq(Number(e.target.value))}
                               className="w-full h-1 bg-slate-700 rounded appearance-none accent-red-500"
                               title="Ajuste para cortar o 'boom' do surdo"
                           />

                           <div className="flex justify-between items-center text-[9px] font-bold text-slate-400 uppercase mt-2">
                               <div className="flex items-center gap-1"><Zap size={10} /> Definição (Ataque)</div>
                               <span className="text-yellow-500">+{definitionAmount}dB</span>
                           </div>
                           <input 
                               type="range" min="0" max="15" step="1"
                               value={definitionAmount}
                               onChange={(e) => setDefinitionAmount(Number(e.target.value))}
                               className="w-full h-1 bg-slate-700 rounded appearance-none accent-green-500"
                               title="Aumenta o som da unhada/dedeira"
                           />
                       </div>
                   )}

                   {/* MID CHANNEL */}
                   {renderChannelControls(
                       "VOZ / HARMONIA", "Frequências Médias", "text-indigo-500", 
                       volMid, setVolMid, eqMidSettings, setEqMidSettings,
                       <Sparkles size={16} className="text-indigo-500" />
                   )}

                   {/* TREBLE CHANNEL */}
                   {renderChannelControls(
                       "PERCUSSÃO / AGUDOS", "Brilho & Ataque", "text-pink-500", 
                       volHigh, setVolHigh, eqHighSettings, setEqHighSettings,
                       <Volume2 size={16} className="text-pink-500" />
                   )}
              </div>
          </div>
      )}
    </div>
  );
};

export enum SeventhStringTuning {
  B = 'B (Si - Padrão)',
  C = 'C (Dó - Samba/Choro)',
  A = 'A (Lá - Grave)',
}

export enum RhythmStyle {
  SAMBA = 'Samba',
  CHORO = 'Choro',
  BOSSA_NOVA = 'Bossa Nova',
  BAIAO = 'Baião',
  SAMBA_CANCAO = 'Samba-canção',
  PARTIDO_ALTO = 'Partido Alto',
  MAXIXE = 'Maxixe',
}

export interface GuitarString {
  note: string;
  octave: number;
  frequency: number;
  description?: string;
}

export interface RhythmPreset {
  name: RhythmStyle;
  description: string;
  countPattern: string;
  bpmRanges: {
    beginner: number;
    intermediate: number;
    advanced: number;
  };
  accentBeat: number[]; // 1-based index of beats to accent
  subdivision: number; // 2 for 8th notes, 4 for 16th notes
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

export type TimeSignature = '2/4' | '3/4' | '4/4' | '6/8';
export type Subdivision = '1' | '2' | '3' | '4'; // Quarter, 8th, Triplet, 16th

export interface MetronomeState {
  bpm: number;
  isPlaying: boolean;
  timeSignature: TimeSignature;
  subdivision: Subdivision;
  volume: number;
  isGrooveMode: boolean; // 2 & 4 only
  isGhostMode: boolean; // Randomly drops bars
}

// --- NEW TYPES FOR ADVANCED TRAINER ---

export type NoteName = 'C' | 'C#' | 'D' | 'D#' | 'E' | 'F' | 'F#' | 'G' | 'G#' | 'A' | 'A#' | 'B';
export type ChordQuality = 'maj7' | '7' | 'm7' | 'm7b5' | 'dim7' | '6' | 'm6';

// Updated instrument list
export type InstrumentType = 
  | 'nylon' 
  | 'steel' 
  | 'piano' 
  | 'keyboard' 
  | 'bass' 
  | 'sax' 
  | 'clarinet' 
  | 'trombone' 
  | 'trumpet' 
  | 'flute' 
  | 'harmonica' 
  | 'cavaco';

export interface Chord {
  root: NoteName;
  quality: ChordQuality;
  display: string; // e.g., "Am7"
  duration: number; // in beats (usually 2 or 4)
}

export interface BassNote {
  note: NoteName;
  octave: number;
  string: number; // 1-7
  fret: number;
  duration: number; // 0.25 (16th), 0.5 (8th), 1 (quarter)
  startTime: number; // offset in beats from start of progression
  isChordTone?: boolean;
  isChromatic?: boolean;
}

export interface Progression {
  id: string;
  key: NoteName;
  chords: Chord[];
  style: RhythmStyle;
  level: 'Iniciante' | 'Intermediário' | 'Avançado';
}

export interface FretboardNote {
  stringIndex: number; // 0 (High E) to 6 (Low B/C)
  fret: number;
  note: NoteName;
  interval?: string; // e.g., "R", "3M", "5J"
  isActive: boolean;
}

export interface BassLick {
  id: string;
  title: string;
  style: RhythmStyle;
  difficulty: 'Iniciante' | 'Intermediário' | 'Avançado';
  description: string;
  tuningRequired: SeventhStringTuning;
  progression: Chord[]; // The harmonic context
  notes: BassNote[];
}

// --- SMART TRAINER TYPES ---

export interface PracticeHit {
  timestamp: number;
  offsetMs: number; // Negative = Rushing, Positive = Dragging
  accuracy: 'perfect' | 'good' | 'late' | 'early' | 'miss';
  beatNumber: number;
}

export interface PracticeSessionResult {
  date: string;
  bpm: number;
  score: number; // 0-100
  avgOffset: number; // ms
  stability: number; // percentage consistency
  tendency: 'Acelerando' | 'Atrasando' | 'Estável';
  hits: PracticeHit[];
}

export type AppTab = 'tuner' | 'metronome' | 'fretboard' | 'bass-trainer' | 'rhythms' | 'coach' | 'separator' | 'smart-trainer';

import React, { useState, useRef, useEffect } from 'react';
import { Mic, Play, Square, Activity, Target, Clock, TrendingUp, AlertCircle, History, Trophy } from 'lucide-react';
import { getAudioContext, scheduleClick } from '../utils/audio';
import { PracticeSessionResult, PracticeHit } from '../types';

export const SmartTrainer: React.FC = () => {
  // --- STATE ---
  const [bpm, setBpm] = useState(90);
  const [isRecording, setIsRecording] = useState(false);
  const [isCalibrating, setIsCalibrating] = useState(false);
  const [sessionDurationBars, setSessionDurationBars] = useState(8);

  // Real-time Feedback
  const [currentOffset, setCurrentOffset] = useState<number | null>(null);
  const [lastHitQuality, setLastHitQuality] = useState<'perfect' | 'good' | 'bad' | null>(null);
  const [progress, setProgress] = useState(0);

  // Results
  const [lastResult, setLastResult] = useState<PracticeSessionResult | null>(null);
  const [history, setHistory] = useState<PracticeSessionResult[]>([]);

  // --- REFS ---
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const microphoneRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const rafRef = useRef<number | null>(null);

  // Logic Refs
  const nextClickTimeRef = useRef<number>(0);
  const currentBeatRef = useRef<number>(0);
  const sessionHitsRef = useRef<PracticeHit[]>([]);
  const isRunningRef = useRef(false);
  const lastAttackTimeRef = useRef(0);

  // Constants
  const LOOKAHEAD = 25.0; // ms
  const SCHEDULE_AHEAD_TIME = 0.1; // s
  const ATTACK_THRESHOLD = 0.15; // Sensitivity for onset detection
  const DEBOUNCE_TIME = 0.15; // Minimum time between notes (s)

  // --- AUDIO SETUP ---
  const setupAudio = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ctx = getAudioContext();
      audioContextRef.current = ctx;

      const analyser = ctx.createAnalyser();
      analyser.fftSize = 2048; // High res for timing
      analyserRef.current = analyser;

      const mic = ctx.createMediaStreamSource(stream);
      mic.connect(analyser);
      microphoneRef.current = mic;

      return true;
    } catch (err) {
      console.error("Microphone error:", err);
      alert("Erro ao acessar microfone. Verifique as permissões.");
      return false;
    }
  };

  // --- ENGINE ---
  const startSession = async () => {
    if (!audioContextRef.current) {
        const success = await setupAudio();
        if (!success) return;
    }

    const ctx = getAudioContext();
    if (ctx.state === 'suspended') await ctx.resume();

    // Reset
    sessionHitsRef.current = [];
    currentBeatRef.current = -4; // 1 Bar Count-in (assuming 4/4)
    nextClickTimeRef.current = ctx.currentTime + 0.1;
    setLastResult(null);
    setProgress(0);
    isRunningRef.current = true;
    setIsRecording(true);

    scheduler();
    analyzeInput();
  };

  const stopSession = () => {
    isRunningRef.current = false;
    setIsRecording(false);
    if (rafRef.current) cancelAnimationFrame(rafRef.current);

    // Process Results
    if (sessionHitsRef.current.length > 0) {
        processResults();
    }
  };

  // --- METRONOME SCHEDULER ---
  const scheduler = () => {
    if (!isRunningRef.current) return;

    const ctx = getAudioContext();
    while (nextClickTimeRef.current < ctx.currentTime + SCHEDULE_AHEAD_TIME) {
        scheduleNote(currentBeatRef.current, nextClickTimeRef.current);

        // Advance Time
        const secondsPerBeat = 60.0 / bpm;
        nextClickTimeRef.current += secondsPerBeat;
        currentBeatRef.current++;
    }
    setTimeout(scheduler, LOOKAHEAD);
  };

  const scheduleNote = (beat: number, time: number) => {
      // Check for End of Session
      const totalBeats = sessionDurationBars * 4;
      if (beat >= totalBeats) {
          stopSession();
          return;
      }

      // Play Click (Count-in logic)
      if (beat < 0) {
          // Count-in clicks (High pitch)
          scheduleClick(time, 'sub');
      } else {
          // Session clicks
          scheduleClick(time, beat % 4 === 0 ? 'accent' : 'normal');

          // Update Progress Bar
          const percent = (beat / totalBeats) * 100;
          // Defer state update slightly
          setTimeout(() => setProgress(percent), (time - getAudioContext().currentTime) * 1000);
      }
  };

  // --- INPUT ANALYSIS (ONSET DETECTION) ---
  const analyzeInput = () => {
      if (!isRunningRef.current || !analyserRef.current) return;

      const buffer = new Float32Array(analyserRef.current.fftSize);
      analyserRef.current.getFloatTimeDomainData(buffer);

      // Simple RMS calculation
      let sum = 0;
      for (let i = 0; i < buffer.length; i++) {
          sum += buffer[i] * buffer[i];
      }
      const rms = Math.sqrt(sum / buffer.length);
      const ctx = getAudioContext();

      // Detect Transient
      if (rms > ATTACK_THRESHOLD && (ctx.currentTime - lastAttackTimeRef.current) > DEBOUNCE_TIME) {
          // IGNORE hits during count-in
          if (currentBeatRef.current >= 0) {
              registerHit(ctx.currentTime);
              lastAttackTimeRef.current = ctx.currentTime;
          }
      }

      rafRef.current = requestAnimationFrame(analyzeInput);
  };

  const registerHit = (hitTime: number) => {
      // Find the closest expected beat time
      const secondsPerBeat = 60.0 / bpm;
      // We need to find the beat index that this hit likely belongs to.
      // nextClickTimeRef points to the *upcoming* beat.
      // So the previous beat was nextClickTimeRef - secondsPerBeat.

      const nextBeatTime = nextClickTimeRef.current;
      const prevBeatTime = nextClickTimeRef.current - secondsPerBeat;

      const diffNext = Math.abs(hitTime - nextBeatTime);
      const diffPrev = Math.abs(hitTime - prevBeatTime);

      let targetTime = diffNext < diffPrev ? nextBeatTime : prevBeatTime;
      let offset = (hitTime - targetTime) * 1000; // ms

      // Cap crazy offsets (mis-hits)
      if (Math.abs(offset) > (secondsPerBeat * 1000) / 2) return; // Not a relevant hit

      let quality: 'perfect' | 'good' | 'late' | 'early' = 'perfect';
      if (Math.abs(offset) < 25) quality = 'perfect';
      else if (Math.abs(offset) < 60) quality = 'good';
      else if (offset < 0) quality = 'early';
      else quality = 'late';

      const hit: PracticeHit = {
          timestamp: hitTime,
          offsetMs: offset,
          accuracy: quality === 'late' || quality === 'early' ? quality : quality === 'perfect' ? 'perfect' : 'good',
          beatNumber: currentBeatRef.current
      };

      sessionHitsRef.current.push(hit);

      // Update Realtime UI
      setCurrentOffset(offset);
      setLastHitQuality(quality as any);

      // Reset visual feedback after a bit
      setTimeout(() => setCurrentOffset(null), 500);
  };

  const processResults = () => {
      const hits = sessionHitsRef.current;
      if (hits.length === 0) return;

      const avgOffset = hits.reduce((sum, h) => sum + h.offsetMs, 0) / hits.length;
      const absOffsetSum = hits.reduce((sum, h) => sum + Math.abs(h.offsetMs), 0);
      const avgAbsOffset = absOffsetSum / hits.length;

      // Score Calculation (0-100)
      // 0ms error = 100 score. 100ms error = 0 score.
      const rawScore = Math.max(0, 100 - avgAbsOffset);

      // Stability: Standard Deviation-ish
      // How many hits were "Good" or "Perfect"?
      const goodHits = hits.filter(h => Math.abs(h.offsetMs) < 60).length;
      const stability = (goodHits / hits.length) * 100;

      let tendency: 'Acelerando' | 'Atrasando' | 'Estável' = 'Estável';
      if (avgOffset < -15) tendency = 'Acelerando';
      else if (avgOffset > 15) tendency = 'Atrasando';

      const result: PracticeSessionResult = {
          date: new Date().toLocaleTimeString(),
          bpm,
          score: Math.round(rawScore),
          avgOffset: Math.round(avgOffset),
          stability: Math.round(stability),
          tendency,
          hits
      };

      setLastResult(result);
      setHistory(prev => [result, ...prev]);
  };

  // --- RENDER HELPERS ---
  const renderLiveVisualizer = () => {
      // Linear Graph: Center is 0. Left is early (-100ms), Right is late (+100ms)
      const range = 120; // ms range visible
      let pinPosition = 50; // Percent

      if (currentOffset !== null) {
