              <div className="absolute left-3/4 top-0 bottom-0 w-[1px] bg-slate-700 border-dashed border-l border-slate-600" />

              {/* Labels */}
              <div className="absolute top-2 left-2 text-[10px] text-red-400 font-bold">ADIANTADO</div>
