import { BassNote, Chord, NoteName, RhythmStyle, SeventhStringTuning, ChordQuality } from '../types';
import { NOTES, getChordTones, findFretPosition, getNoteIndex, getScaleNotes, getNoteFromInterval, ScaleType } from '../utils/musicTheory';

// --- HELPERS ---
const getRandomInt = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;
const getRandomElement = <T>(arr: T[]): T => arr[Math.floor(Math.random() * arr.length)];

// --- PROGRESSION GENERATOR (Unchanged logic, just keeping structure) ---
const PROGRESSION_POOLS = {
  'Iniciante': {
    'Samba': [
        [{ r: 0, q: '6' }, { r: 7, q: '7' }, { r: 0, q: '6' }, { r: 7, q: '7' }], 
        [{ r: 0, q: '6' }, { r: 5, q: 'maj7' }, { r: 7, q: '7' }, { r: 0, q: '6' }] 
    ],
    'Choro': [
        [{ r: 0, q: 'm6' }, { r: 7, q: '7' }, { r: 0, q: 'm6' }, { r: 7, q: '7' }], 
        [{ r: 0, q: 'm6' }, { r: 5, q: 'm6' }, { r: 7, q: '7' }, { r: 0, q: 'm6' }]
    ],
  },
  'Intermediário': {
    'Samba': [
        [{ r: 0, q: '6' }, { r: 9, q: '7' }, { r: 2, q: 'm7' }, { r: 7, q: '7' }], 
        [{ r: 0, q: 'maj7' }, { r: 4, q: '7' }, { r: 9, q: '7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
    'Choro': [
        [{ r: 0, q: 'm7' }, { r: 0, q: '7' }, { r: 5, q: 'm7' }, { r: 8, q: '7' }, { r: 7, q: '7' }],
        [{ r: 0, q: 'maj7' }, { r: 5, q: 'm6' }, { r: 0, q: 'maj7' }, { r: 7, q: '7' }]
    ],
  },
  'Avançado': {
    'Samba': [
        [{ r: 0, q: 'maj7' }, { r: 3, q: 'dim7' }, { r: 2, q: 'm7' }, { r: 1, q: '7' }, { r: 0, q: '6' }],
        [{ r: 0, q: '6' }, { r: 11, q: 'm7b5' }, { r: 4, q: '7' }, { r: 9, q: 'm7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
    'Choro': [
        [{ r: 0, q: '6' }, { r: 1, q: 'dim7' }, { r: 2, q: 'm7' }, { r: 3, q: 'dim7' }, { r: 4, q: 'm7' }, { r: 7, q: '7' }],
        [{ r: 0, q: 'm6' }, { r: 7, q: '7' }, { r: 4, q: '7' }, { r: 9, q: '7' }, { r: 2, q: '7' }, { r: 7, q: '7' }]
    ],
  }
};

export const generateProgression = (key: NoteName, level: string): Chord[] => {
  const progression: Chord[] = [];
  const keyIdx = getNoteIndex(key);
  const getRelNote = (semitones: number) => NOTES[(keyIdx + semitones) % 12];

  const lvlKey = level as keyof typeof PROGRESSION_POOLS;
  const styles = Object.keys(PROGRESSION_POOLS[lvlKey]);
  const randomStyle = getRandomElement(styles);

  // @ts-ignore
  const pool = PROGRESSION_POOLS[lvlKey][randomStyle] as any[];
  const choice = getRandomElement(pool) as any[];

  choice.forEach((c: any) => {
      progression.push({ 
          root: getRelNote(c.r), 
          quality: c.q as any, 
          display: `${getRelNote(c.r)}${c.q}`, 
          duration: level === 'Iniciante' ? 4 : 2 
      });
  });

  return progression;
};

// --- BASS LINE STRATEGIES ---

type Strategy = 'ROOT_FIFTH' | 'ALTERNATING_RANGE' | 'ASCENDING_RUN' | 'DESCENDING_RESOLUTION';

export const generateBassLine = (
  progression: Chord[],
  style: RhythmStyle,
  level: 'Iniciante' | 'Intermediário' | 'Avançado',
  tuning: SeventhStringTuning,
  key: NoteName
): BassNote[] => {
  const notes: BassNote[] = [];
  let currentBeatOffset = 0;

  // Define MIDI Ranges for "5 Casas" (First 5 Frets)
  // Low limit depends on tuning (7th String Open)
  let LOW_LIMIT = 35; // B1
  if (tuning.includes('C')) LOW_LIMIT = 36; // C2
  if (tuning.includes('A')) LOW_LIMIT = 33; // A1

  // "Bass Zone": Strings 7, 6, 5 (approx B1 to C3/48)
  const BASS_CEILING = 48; 
  // "Treble Zone" (Primas within 5 frets): Strings 4, 3 (approx D3/50 to B3/59)
  // We avoid going too high on string 1/2 to keep it sounding like a bass line
  const TREBLE_CEILING = 60; // Middle C (C4) on 3rd string 5th fret is roughly limit

  progression.forEach((chord, index) => {
    const isLastChord = index === progression.length - 1;
    const nextChord = progression[(index + 1) % progression.length];
    const beatsInChord = chord.duration;

    // Determine Scale Type
    let scaleType: ScaleType = 'Major';
    if (chord.quality.includes('m7b5')) scaleType = 'Locrian';
    else if (chord.quality.includes('dim')) scaleType = 'Harmonic Minor'; // Simplified
    else if (chord.quality === 'm7' || chord.quality === 'm6') scaleType = 'Dorian';
    else if (chord.quality === '7') scaleType = 'Mixolydian';

    const scaleNotes = getScaleNotes(chord.root, scaleType);
    const chordTones = getChordTones(chord);

    // --- STRATEGY SELECTION ---
    let strategy: Strategy = 'ROOT_FIFTH';

    if (level === 'Iniciante') {
        strategy = 'ROOT_FIFTH';
    } else {
        // Advanced logic: Alternate between styles
        const rand = Math.random();
        if (style === RhythmStyle.CHORO) {
            // Choro uses a lot of runs
            if (rand < 0.3) strategy = 'ASCENDING_RUN';
            else if (rand < 0.6) strategy = 'DESCENDING_RESOLUTION';
            else strategy = 'ALTERNATING_RANGE';
        } else {
            // Samba/Bossa
            if (rand < 0.5) strategy = 'ALTERNATING_RANGE'; // Bouncing
            else strategy = 'ROOT_FIFTH';
        }
    }

    // --- BEAT 1: ROOT (Must be in Bass Zone) ---
    // Try to find root on string 7, 6 or 5
    let rootMidi = -1;
    // Search octaves 1 and 2
    [1, 2].forEach(oct => {
        const m = getNoteIndex(chord.root) + (oct + 1) * 12;
        if (m >= LOW_LIMIT && m <= BASS_CEILING) rootMidi = m;
    });
    // Fallback if root is too high/low (rare)
    if (rootMidi === -1) rootMidi = getNoteIndex(chord.root) + (3) * 12; // Octave 3

    const rootPos = findFretPosition(chord.root, Math.floor(rootMidi/12)-1, tuning);

    if (rootPos) {
        notes.push({
            ...rootPos,
            duration: 0.5,
            startTime: currentBeatOffset,
            isChordTone: true
        });
    }

    // --- FILL GENERATION ---
    const totalSubdivisions = beatsInChord * 4; // 16th notes
    let currentMidi = rootMidi;

    // We generate based on patterns per beat
    // 1 bar = 4 beats. We already did Beat 1.0

    if (strategy === 'ROOT_FIFTH') {
        // Simple: Root ... Fifth ...
        const fifthNote = chordTones[2]; // 5th
        let fifthMidi = getNoteIndex(fifthNote) + (Math.floor(rootMidi/12) + 1) * 12; // Try higher octave first
        if (fifthMidi > BASS_CEILING) fifthMidi -= 12; // Drop if too high

        const pos = findFretPosition(fifthNote, Math.floor(fifthMidi/12)-1, tuning);
        if (pos) {
            notes.push({
                ...pos,
                duration: 0.5,
                startTime: currentBeatOffset + (beatsInChord / 2), // Halfway
                isChordTone: true
            });
        }
    }

    else if (strategy === 'ALTERNATING_RANGE') {
        // Pattern: Bass (Root) -> Treble (Chord Tone) -> Chromatic/Scale Run down

        // Beat 2: Jump to Treble Zone (String 3 or 4)
        // Find a chord tone in range 48-60
        const highTarget = chordTones.map(n => {
            const idx = getNoteIndex(n);
            return idx + (3 + 1) * 12; // Octave 3 (Midi 48-59)
        }).find(m => m >= 45 && m <= TREBLE_CEILING);

        if (highTarget) {
            const hNote = midiToNote(highTarget);
            const pos = findFretPosition(hNote.note, hNote.octave, tuning);
            if (pos) {
                notes.push({
                    ...pos,
                    duration: 0.5, // Syncopated feel
                    startTime: currentBeatOffset + 1.5, // e.g., "1... 2 &"
                    isChordTone: true
                });
                currentMidi = highTarget;
            }
        }

        // Beats 3 & 4: Run back down to next chord root
        // Calculate resolution target
        const nextRootIdx = getNoteIndex(nextChord.root);
        let targetMidi = nextRootIdx + (2 + 1) * 12; // Approx Octave 2
        if (targetMidi < LOW_LIMIT) targetMidi += 12;

        const startBeat = beatsInChord - 1.5; // Last 1.5 beats
        const steps = 4; // 4 16th notes

        for (let i = 0; i < steps; i++) {
             // Linear interpolation logic simplified
             const dir = targetMidi < currentMidi ? -1 : 1;

             // Try scale step first
             let attempt = currentMidi + dir;
             // If dist is large, maybe skip a scale note (thirds)
             if (Math.abs(targetMidi - currentMidi) > 5 && i < 2) {
                 // Arpeggio jump
                 attempt = currentMidi + (dir * 3) || currentMidi + (dir * 4);
             } else {
                 // Scale step
                 while (!scaleNotes.includes(midiToNote(attempt).note) && Math.abs(attempt - targetMidi) > 1) {
                    attempt += dir;
                 }
             }

             // Apply Range Constraints
             if (attempt < LOW_LIMIT) attempt = LOW_LIMIT;
             if (attempt > TREBLE_CEILING) attempt = TREBLE_CEILING;

             const n = midiToNote(attempt);
             const p = findFretPosition(n.note, n.octave, tuning);

             if (p) {
                 notes.push({
                     ...p,
                     duration: 0.25,
                     startTime: currentBeatOffset + startBeat + (i * 0.25),
                     isChromatic: !scaleNotes.includes(n.note)
                 });
                 currentMidi = attempt;
             }
        }
    }

    else if (strategy === 'ASCENDING_RUN') {
        // Pattern: Bass -> Mid -> Treble
        // e.g., Root -> 3rd -> 5th -> 7th/Root(Octave)

        // Divide remaining time into equal steps
        const steps = 3; 
        const interval = (beatsInChord - 1) / steps;

        let lastMidi = rootMidi;

        for(let i=0; i<steps; i++) {
            // Find next chord tone upwards
            let nextToneMidi = lastMidi + 1;
            let found = false;

            // Search up to +12 semitones
            for(let offset=1; offset<=12; offset++) {
                const check = lastMidi + offset;
                if (check > TREBLE_CEILING) break;

                const noteName = midiToNote(check).note;
                if (chordTones.includes(noteName)) {
                    // Preference: Don't pick same note name immediately if possible (unless octave)
                    nextToneMidi = check;
                    found = true;
                    // If we found a 3rd or 5th or 7th, take it
                    break;
                }
            }

            if (found) {
                const n = midiToNote(nextToneMidi);
                const p = findFretPosition(n.note, n.octave, tuning);
                if (p) {
                    notes.push({
                        ...p,
                        duration: interval,
                        startTime: currentBeatOffset + 1 + (i * interval),
                        isChordTone: true
                    });
                    lastMidi = nextToneMidi;
                }
            }
        }
    }

    else if (strategy === 'DESCENDING_RESOLUTION') {
        // Pattern: Start High (Treble) -> Scale run down -> Bass
        // This simulates answering a melody on the "primas" and returning to the "bordão"

        // Start note: High chord tone (String 3 or 4)
        const startHigh = chordTones.map(n => getNoteIndex(n) + 48).find(m => m >= 50 && m <= TREBLE_CEILING) || (rootMidi + 12);

        if (startHigh <= TREBLE_CEILING) {
            const n = midiToNote(startHigh);
            const p = findFretPosition(n.note, n.octave, tuning);
            if (p) {
                notes.push({
                    ...p,
                    duration: 0.5,
                    startTime: currentBeatOffset + 1.0, // Beat 2
                    isChordTone: true
                });
                currentMidi = startHigh;
            }
        }

        // Run down to target
        const nextRootIdx = getNoteIndex(nextChord.root);
        let targetMidi = nextRootIdx + (2 + 1) * 12; 
        if (targetMidi < LOW_LIMIT) targetMidi += 12;

        // Create a fast run (16th notes) at the end of the bar
        const startRunBeat = beatsInChord - 1.0; 
        const runSteps = 4;

        for(let i=0; i<runSteps; i++) {
            // Chromatic or Scale approach downwards
            let attempt = currentMidi - 1;
            // Force diatonic unless really close
            if (Math.abs(targetMidi - currentMidi) > 3) {
                while(!scaleNotes.includes(midiToNote(attempt).note)) attempt--;
            }

            if (attempt < LOW_LIMIT) attempt = LOW_LIMIT;

            const n = midiToNote(attempt);
            const p = findFretPosition(n.note, n.octave, tuning);
            if (p) {
                 notes.push({
                     ...p,
                     duration: 0.25,
                     startTime: currentBeatOffset + startRunBeat + (i * 0.25),
                     isChromatic: !scaleNotes.includes(n.note)
                 });
                 currentMidi = attempt;
            }
        }
    }

    currentBeatOffset += beatsInChord;
  });

  return notes.sort((a, b) => a.startTime - b.startTime);
};

// Helper
const midiToNote = (midi: number): { note: NoteName, octave: number } => {
    const idx = midi % 12;
    const oct = Math.floor(midi / 12) - 1;
    return { note: NOTES[idx], octave: oct };
}

import { NoteName, Chord, ChordQuality, SeventhStringTuning } from '../types';

export const NOTES: NoteName[] = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'];

// Map chords to their intervals (semitones from root)
export const CHORD_INTERVALS: Record<ChordQuality, number[]> = {
  'maj7': [0, 4, 7, 11],
  '7': [0, 4, 7, 10],
  'm7': [0, 3, 7, 10],
  'm7b5': [0, 3, 6, 10],
  'dim7': [0, 3, 6, 9],
  '6': [0, 4, 7, 9],
  'm6': [0, 3, 7, 9],
};

// --- SCALES & MODES ---
export type ScaleType = 'Major' | 'Minor' | 'Harmonic Minor' | 'Melodic Minor' | 'Dorian' | 'Phrygian' | 'Lydian' | 'Mixolydian' | 'Locrian';

export const SCALES: Record<ScaleType, number[]> = {
    'Major': [0, 2, 4, 5, 7, 9, 11], // Ionian
    'Minor': [0, 2, 3, 5, 7, 8, 10], // Aeolian
    'Harmonic Minor': [0, 2, 3, 5, 7, 8, 11], // Common in Choro
    'Melodic Minor': [0, 2, 3, 5, 7, 9, 11], // Common in Brazilian Jazz
    'Dorian': [0, 2, 3, 5, 7, 9, 10], // Minor 6 feel
    'Phrygian': [0, 1, 3, 5, 7, 8, 10], // Nordeste/Baião feel sometimes
    'Lydian': [0, 2, 4, 6, 7, 9, 11],
    'Mixolydian': [0, 2, 4, 5, 7, 9, 10], // Dominant/Samba
    'Locrian': [0, 1, 3, 5, 6, 8, 10]
};

export const INTERVAL_NAMES: Record<number, string> = {
    0: 'T', 1: 'b2', 2: '2M', 3: '3m', 4: '3M', 5: '4J', 6: '#4/b5', 7: '5J', 8: 'b6', 9: '6M', 10: '7m', 11: '7M'
};

export const getNoteIndex = (note: NoteName): number => NOTES.indexOf(note);

export const getNoteFromInterval = (root: NoteName, semitones: number): NoteName => {
  const rootIdx = getNoteIndex(root);
  return NOTES[(rootIdx + semitones) % 12];
};

export const getChordTones = (chord: Chord): NoteName[] => {
  const intervals = CHORD_INTERVALS[chord.quality];
  return intervals.map(i => getNoteFromInterval(chord.root, i));
};

export const getScaleNotes = (root: NoteName, scaleType: ScaleType): NoteName[] => {
    return SCALES[scaleType].map(interval => getNoteFromInterval(root, interval));
};

// --- Fretboard Mapping for 7-String ---

interface FretPosition {
  string: number; // 1-7
  fret: number;
  note: NoteName;
  octave: number;
}

// Base frequencies for string calculation
// Standard 7 String: E4, B3, G3, D3, A2, E2, B1
const STRING_OPEN_NOTES: { note: NoteName, octave: number }[] = [
  { note: 'E', octave: 4 }, // 1 (High E)
  { note: 'B', octave: 3 }, // 2
  { note: 'G', octave: 3 }, // 3
  { note: 'D', octave: 3 }, // 4
  { note: 'A', octave: 2 }, // 5
  { note: 'E', octave: 2 }, // 6
  { note: 'B', octave: 1 }, // 7 (Default)
];

export const findFretPosition = (
  targetNote: NoteName, 
  targetOctave: number, 
  tuning: SeventhStringTuning, 
  prevFret?: number,
  prevString?: number
): FretPosition | null => {

  // Adjust 7th string based on tuning
  const currentStringNotes = [...STRING_OPEN_NOTES];
  if (tuning.includes('C')) {
    currentStringNotes[6] = { note: 'C', octave: 2 };
  } else if (tuning.includes('A')) {
    currentStringNotes[6] = { note: 'A', octave: 1 };
  } else {
    currentStringNotes[6] = { note: 'B', octave: 1 };
  }

  const possiblePositions: FretPosition[] = [];

  for (let s = 0; s < 7; s++) { // 0 to 6 (representing strings 1 to 7)
    const open = currentStringNotes[s];
    const openNoteIdx = getNoteIndex(open.note);
    // Base MIDI number approx calculation for comparison
    const openMidi = openNoteIdx + (open.octave + 1) * 12;

    const targetNoteIdx = getNoteIndex(targetNote);
    const targetMidi = targetNoteIdx + (targetOctave + 1) * 12;

    const diff = targetMidi - openMidi;

    // STRICT CONSTRAINT: First 5 frets ONLY.
    if (diff >= 0 && diff <= 5) { 
      possiblePositions.push({
        string: s + 1, // 1-based index
        fret: diff,
        note: targetNote,
        octave: targetOctave
      });
    }
  }

  if (possiblePositions.length === 0) return null;

  // Sorting Logic:
  // 1. Prefer Thicker Strings (Higher index) for Bass Notes (Octave 1 & 2) to maintain warm tone.
  // 2. Prefer position closest to previous note if available, but staying within 5 frets.

  if (prevFret !== undefined && prevString !== undefined) {
      possiblePositions.sort((a, b) => {
          const distA = Math.abs(a.fret - prevFret) + Math.abs(a.string - prevString);
          const distB = Math.abs(b.fret - prevFret) + Math.abs(b.string - prevString);
          return distA - distB;
      });
  } else {
      // Default prioritization
      possiblePositions.sort((a, b) => {
          // If notes are in Octave 1 or 2 (Bass), prefer higher string index (6, 7)
          if (targetOctave <= 2) {
              return b.string - a.string; 
          }
          // Otherwise, just prefer lower fret (open position)
          return a.fret - b.fret;
      });
  }

  return possiblePositions[0];
};

export const getFrequency = (note: NoteName, octave: number): number => {
    const noteIdx = getNoteIndex(note);
    const midi = (octave + 1) * 12 + noteIdx;
    const A4Midi = 69;
    return 440 * Math.pow(2, (midi - A4Midi) / 12);
};

