export const generateProgression = (key: NoteName, level: string): Chord[] => {
  const progression: Chord[] = [];
  const keyIdx = getNoteIndex(key);
  const getRelNote = (semitones: number) => NOTES[(keyIdx + semitones) % 12];

  const lvlKey = level as keyof typeof PROGRESSION_POOLS;
  const styles = Object.keys(PROGRESSION_POOLS[lvlKey]);
  const randomStyle = getRandomElement(styles);

  // @ts-ignore
  const pool = PROGRESSION_POOLS[lvlKey][randomStyle] as any[];
  const choice = getRandomElement(pool) as any[];

  choice.forEach((c: any) => {
      progression.push({ 
          root: getRelNote(c.r), 
          quality: c.q as any, 
          display: `${getRelNote(c.r)}${c.q}`, 
          duration: level === 'Iniciante' ? 4 : 2 
      });
  });

  return progression;
};

// --- BASS LINE STRATEGIES ---

type Strategy = 'ROOT_FIFTH' | 'ALTERNATING_RANGE' | 'ASCENDING_RUN' | 'DESCENDING_RESOLUTION' | 'ARPEGGIO_COUNT';

export const generateBassLine = (
  progression: Chord[],
  style: RhythmStyle,
  level: 'Iniciante' | 'Intermediário' | 'Avançado',
  tuning: SeventhStringTuning,
  key: NoteName,
  density: NoteDensity
): BassNote[] => {
  const notes: BassNote[] = [];
  let currentBeatOffset = 0;

  // Define MIDI Ranges for "5 Casas" (First 5 Frets)
  let LOW_LIMIT = 35; // B1 (String 7)
  if (tuning.includes('C')) LOW_LIMIT = 36; // C2
  if (tuning.includes('A')) LOW_LIMIT = 33; // A1

  const BASS_CEILING = 48; // Upper limit for "Bass function" notes (approx D3)

  // TREBLE CEILING UPDATED: 
  // Middle C is 60. Open High E is 64. A on High E (5th fret) is 69. B is 71.
  // We allow up to 71 to fully utilize the High E string within the first 5-7 frets.
  const TREBLE_CEILING = 71; 

  progression.forEach((chord, index) => {
    const isLastChord = index === progression.length - 1;
    const nextChord = progression[(index + 1) % progression.length];
    const beatsInChord = chord.duration;

    // Determine Scale Type
    let scaleType: ScaleType = 'Major';
    if (chord.quality.includes('m7b5')) scaleType = 'Locrian';
    else if (chord.quality.includes('dim')) scaleType = 'Harmonic Minor';
    else if (chord.quality === 'm7' || chord.quality === 'm6') scaleType = 'Dorian';
    else if (chord.quality === '7') scaleType = 'Mixolydian';

    const scaleNotes = getScaleNotes(chord.root, scaleType);
    const chordTones = getChordTones(chord);

    // --- STRATEGY SELECTION ---
    let strategy: Strategy = 'ROOT_FIFTH';

    if (density !== 'auto') {
        strategy = 'ARPEGGIO_COUNT';
    } else {
        if (level === 'Iniciante') {
            strategy = 'ROOT_FIFTH';
        } else {
            const rand = Math.random();
            if (style === RhythmStyle.CHORO) {
                // Choro loves high register runs
                if (rand < 0.4) strategy = 'ASCENDING_RUN';
                else if (rand < 0.7) strategy = 'DESCENDING_RESOLUTION';
                else strategy = 'ALTERNATING_RANGE';
            } else {
                if (rand < 0.5) strategy = 'ALTERNATING_RANGE';
                else strategy = 'ROOT_FIFTH';
            }
        }
    }

    // --- FIND ROOT (Anchor) ---
    // Start low (Strings 5, 6, 7)
    let rootMidi = -1;
    [1, 2].forEach(oct => {
        const m = getNoteIndex(chord.root) + (oct + 1) * 12;
        if (m >= LOW_LIMIT && m <= BASS_CEILING) rootMidi = m;
    });
    // Fallback
    if (rootMidi === -1) rootMidi = getNoteIndex(chord.root) + (3) * 12;

    // --- EXECUTE STRATEGY ---

    if (strategy === 'ARPEGGIO_COUNT' && typeof density === 'number') {
        const count = density;
        const durationPerNote = beatsInChord / count;
        let currentNoteMidi = rootMidi;

        for (let i = 0; i < count; i++) {
            let targetMidi = currentNoteMidi;

            if (i === 0) {
                targetMidi = rootMidi;
            } else if (i === count - 1) {
                // Resolve to Root of this chord at end
                targetMidi = rootMidi; 
            } else {
                // EXPANDED RANGE: Look up to TREBLE_CEILING (71)
                const validTones: number[] = [];
                // Check Octaves 2, 3, AND 4
                [2, 3, 4].forEach(oct => {
                    chordTones.forEach(t => {
                        const m = getNoteIndex(t) + (oct + 1) * 12;
                        if (m >= LOW_LIMIT && m <= TREBLE_CEILING && m !== currentNoteMidi) {
                            validTones.push(m);
                        }
                    });
                });

                // Prioritize movement towards treble strings for middle notes
                const higher = validTones.filter(n => n > currentNoteMidi).sort((a,b) => a-b);
                const lower = validTones.filter(n => n < currentNoteMidi).sort((a,b) => b-a);

                // Go high in the middle of the phrase
                if (i < count / 2 && higher.length > 0) {
                    targetMidi = higher[Math.min(higher.length - 1, getRandomInt(0, 1))]; // Jump up
                } else if (lower.length > 0) {
                    targetMidi = lower[0];
                } else {
                    targetMidi = getRandomElement(validTones) || rootMidi;
                }
            }

            if (!targetMidi) targetMidi = rootMidi;
            currentNoteMidi = targetMidi;

            const n = midiToNote(targetMidi);
            // findFretPosition now prioritizes open strings and treble strings for high notes
            const p = findFretPosition(n.note, n.octave, tuning);

            if (p) {
                notes.push({
                    ...p,
                    duration: durationPerNote,
                    startTime: currentBeatOffset + (i * durationPerNote),
                    isChordTone: true
                });
            }
        }
    }

    else {
        // --- AUTO STRATEGIES ---

        // Always Start with Root
        const rootPos = findFretPosition(chord.root, Math.floor(rootMidi/12)-1, tuning);
        if (rootPos) {
            notes.push({ ...rootPos, duration: 0.5, startTime: currentBeatOffset, isChordTone: true });
        }

        let currentMidi = rootMidi;

        if (strategy === 'ROOT_FIFTH') {
             // Basic
             const fifthNote = chordTones[2]; 
             let fifthMidi = getNoteIndex(fifthNote) + (Math.floor(rootMidi/12) + 1) * 12;
             if (fifthMidi > 55) fifthMidi -= 12; // Keep it low for basic style
             const pos = findFretPosition(fifthNote, Math.floor(fifthMidi/12)-1, tuning);
             if (pos) notes.push({ ...pos, duration: 0.5, startTime: currentBeatOffset + (beatsInChord/2), isChordTone: true });
        }
        else if (strategy === 'ALTERNATING_RANGE') {
             // TARGET HIGH STRINGS (G, B, E)
             // Look for chord tones in range 55 (Open G) to 71 (High B)
             const highTargets = chordTones.map(n => {
                 // Calculate multiple octaves
                 const oct3 = getNoteIndex(n) + 48;
                 const oct4 = getNoteIndex(n) + 60;
                 return [oct3, oct4];
             }).flat().filter(m => m >= 55 && m <= TREBLE_CEILING);

             // Pick the highest valid target to force "Mizinha" usage
             const highTarget = highTargets.length > 0 ? highTargets[highTargets.length - 1] : rootMidi + 12;

             if (highTarget) {
                const n = midiToNote(highTarget);
                const p = findFretPosition(n.note, n.octave, tuning);
                if (p) {
                    notes.push({ ...p, duration: 0.5, startTime: currentBeatOffset + 1.5, isChordTone: true });
                    currentMidi = highTarget;
                }
             }

             // Run down to next root
             const nextRootIdx = getNoteIndex(nextChord.root);
             let targetMidi = nextRootIdx + 36; 
             if (targetMidi < LOW_LIMIT) targetMidi += 12;

             const startRun = beatsInChord - 1.0;
             for(let i=0; i<4; i++) {
                 if (i===3) {
                     // Resolution to next root anchor
                     // We resolve to THIS chord's root or 5th low just before changing
                     let finishMidi = getNoteIndex(chord.root) + 36; 
                     if (finishMidi < LOW_LIMIT) finishMidi += 12;
                     const n = midiToNote(finishMidi);
                     const p = findFretPosition(n.note, n.octave, tuning);
                     if(p) notes.push({...p, duration: 0.25, startTime: currentBeatOffset + startRun + 0.75, isChordTone: true});
                     continue;
                 }

                 // Chromatic/Scale movement down
                 // If we are super high (e.g. 70), take bigger steps down to reach bass range
                 let step = 1;
                 if (currentMidi > 60) step = 2; // Jump down thirds if very high

                 let attempt = currentMidi - step;
                 // Stay in scale if possible
                 if (!scaleNotes.includes(midiToNote(attempt).note)) attempt--; 

                 currentMidi = attempt;
                 const n = midiToNote(attempt);
                 const p = findFretPosition(n.note, n.octave, tuning);
                 if(p) notes.push({...p, duration: 0.25, startTime: currentBeatOffset + startRun + (i*0.25), isChromatic: true});
             }
        }
        else if (strategy === 'ASCENDING_RUN') {
             // Scale/Arp Up aggressively to reach Mizinha
             const tones = chordTones;
             const step = beatsInChord / 4; 

             let lastMidi = rootMidi;

             for(let i=1; i<4; i++) {
                 // Force final resolution to low root
                 if (i===3) {
                     const n = midiToNote(rootMidi);
                     const p = findFretPosition(n.note, n.octave, tuning);
                     if(p) notes.push({...p, duration: step, startTime: currentBeatOffset + (i*step), isChordTone: true});
                     continue;
                 }

                 // Find next tone UP
                 let nextToneMidi = lastMidi;
                 // Scan up to +16 semitones to encourage string jumping
                 for (let k=1; k<16; k++) {
                     const check = lastMidi + k;
                     if (check > TREBLE_CEILING) break;
                     if (tones.includes(midiToNote(check).note)) {
                         nextToneMidi = check;
                         if (k > 4) break; // If we found a jump > maj3, take it to go high fast
                     }
                 }

                 lastMidi = nextToneMidi;

                 const n = midiToNote(lastMidi);
                 const p = findFretPosition(n.note, n.octave, tuning);
                 if(p) notes.push({...p, duration: step, startTime: currentBeatOffset + (i*step), isChordTone: true});
             }
        }
        else if (strategy === 'DESCENDING_RESOLUTION') {
             // Start on TREBLE strings (Open E, B, G)
             // Try to find a chord tone on high E string (MIDI 64-71)
             const highTargets = chordTones.map(n => getNoteIndex(n) + 60).filter(m => m >= 60 && m <= 71);
             // Fallback to B string (55-64)
             const midTargets = chordTones.map(n => getNoteIndex(n) + 48).filter(m => m >= 55 && m < 64);

             let startNote = getRandomElement(highTargets);
             if (!startNote) startNote = getRandomElement(midTargets);
             if (!startNote) startNote = rootMidi + 12;

             const nStart = midiToNote(startNote);
             const pStart = findFretPosition(nStart.note, nStart.octave, tuning);

             if(pStart) {
                 notes.push({...pStart, duration: 0.5, startTime: currentBeatOffset + 1.0, isChordTone: true});
                 currentMidi = startNote;
             }

             // Run down 4 notes
             const startRun = beatsInChord - 1.0;
             for(let i=0; i<4; i++) {
                 if (i===3) {
                     // Resolve low
                     const n = midiToNote(rootMidi);
                     const p = findFretPosition(n.note, n.octave, tuning);
                     if(p) notes.push({...p, duration: 0.25, startTime: currentBeatOffset + startRun + 0.75, isChordTone: true});
                     continue;
                 }

                 // Diatonic descent
                 let attempt = currentMidi - 1;
                 while(!scaleNotes.includes(midiToNote(attempt).note)) attempt--;
                 currentMidi = attempt;

                 const n = midiToNote(attempt);
                 const p = findFretPosition(n.note, n.octave, tuning);
                 if(p) notes.push({...p, duration: 0.25, startTime: currentBeatOffset + startRun + (i*0.25), isChromatic: true});
             }
        }
    }

    currentBeatOffset += beatsInChord;
  });

  return notes.sort((a, b) => a.startTime - b.startTime);
};

// Helper
const midiToNote = (midi: number): { note: NoteName, octave: number } => {
    const idx = midi % 12;
    const oct = Math.floor(midi / 12) - 1;
    return { note: NOTES[idx], octave: oct };
}

