import { NoteName, Chord, ChordQuality, SeventhStringTuning } from '../types';

export const NOTES: NoteName[] = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'];

// Map chords to their intervals (semitones from root)
export const CHORD_INTERVALS: Record<ChordQuality, number[]> = {
  'maj7': [0, 4, 7, 11],
  '7': [0, 4, 7, 10],
  'm7': [0, 3, 7, 10],
  'm7b5': [0, 3, 6, 10],
  'dim7': [0, 3, 6, 9],
  '6': [0, 4, 7, 9],
  'm6': [0, 3, 7, 9],
  'm': [0, 3, 7],
};

// --- SCALES & MODES ---
export type ScaleType = 'Major' | 'Minor' | 'Harmonic Minor' | 'Melodic Minor' | 'Dorian' | 'Phrygian' | 'Lydian' | 'Mixolydian' | 'Locrian';

export const SCALES: Record<ScaleType, number[]> = {
    'Major': [0, 2, 4, 5, 7, 9, 11], // Ionian
    'Minor': [0, 2, 3, 5, 7, 8, 10], // Aeolian
    'Harmonic Minor': [0, 2, 3, 5, 7, 8, 11], // Common in Choro
    'Melodic Minor': [0, 2, 3, 5, 7, 9, 11], // Common in Brazilian Jazz
    'Dorian': [0, 2, 3, 5, 7, 9, 10], // Minor 6 feel
    'Phrygian': [0, 1, 3, 5, 7, 8, 10], // Nordeste/Baião feel sometimes
    'Lydian': [0, 2, 4, 6, 7, 9, 11],
    'Mixolydian': [0, 2, 4, 5, 7, 9, 10], // Dominant/Samba
    'Locrian': [0, 1, 3, 5, 6, 8, 10]
};

export const INTERVAL_NAMES: Record<number, string> = {
    0: 'T', 1: 'b2', 2: '2M', 3: '3m', 4: '3M', 5: '4J', 6: '#4/b5', 7: '5J', 8: 'b6', 9: '6M', 10: '7m', 11: '7M'
};

export const getNoteIndex = (note: NoteName): number => NOTES.indexOf(note);

export const getNoteFromInterval = (root: NoteName, semitones: number): NoteName => {
  const rootIdx = getNoteIndex(root);
  return NOTES[(rootIdx + semitones) % 12];
};

export const getChordTones = (chord: Chord): NoteName[] => {
  const intervals = CHORD_INTERVALS[chord.quality];
  return intervals.map(i => getNoteFromInterval(chord.root, i));
};

export const getScaleNotes = (root: NoteName, scaleType: ScaleType): NoteName[] => {
    return SCALES[scaleType].map(interval => getNoteFromInterval(root, interval));
};

// --- Fretboard Mapping for 7-String ---

interface FretPosition {
  string: number; // 1-7
  fret: number;
  note: NoteName;
  octave: number;
}

// Base frequencies for string calculation
// Standard 7 String: E4, B3, G3, D3, A2, E2, B1
const STRING_OPEN_NOTES: { note: NoteName, octave: number }[] = [
  { note: 'E', octave: 4 }, // 1 (High E - Mizinha)
  { note: 'B', octave: 3 }, // 2 (Si)
  { note: 'G', octave: 3 }, // 3 (Sol)
  { note: 'D', octave: 3 }, // 4 (Re)
  { note: 'A', octave: 2 }, // 5 (La)
  { note: 'E', octave: 2 }, // 6 (Mi)
  { note: 'B', octave: 1 }, // 7 (Default)
];

export const findFretPosition = (
  targetNote: NoteName, 
  targetOctave: number, 
  tuning: SeventhStringTuning, 
  prevFret?: number,
  prevString?: number
): FretPosition | null => {

  // Adjust 7th string based on tuning
  const currentStringNotes = [...STRING_OPEN_NOTES];
  if (tuning.includes('C')) {
    currentStringNotes[6] = { note: 'C', octave: 2 };
  } else if (tuning.includes('A')) {
    currentStringNotes[6] = { note: 'A', octave: 1 };
  } else {
    currentStringNotes[6] = { note: 'B', octave: 1 };
  }

  const possiblePositions: FretPosition[] = [];

  for (let s = 0; s < 7; s++) { // 0 to 6 (representing strings 1 to 7)
    const open = currentStringNotes[s];
    const openNoteIdx = getNoteIndex(open.note);
    // Base MIDI number approx calculation for comparison
    const openMidi = openNoteIdx + (open.octave + 1) * 12;

    const targetNoteIdx = getNoteIndex(targetNote);
    const targetMidi = targetNoteIdx + (targetOctave + 1) * 12;

    const diff = targetMidi - openMidi;

    // STRICT CONSTRAINT: First 5 frets ONLY.
    if (diff >= 0 && diff <= 5) { 
      possiblePositions.push({
        string: s + 1, // 1-based index
        fret: diff,
        note: targetNote,
        octave: targetOctave
      });
    }
  }

  if (possiblePositions.length === 0) return null;

  // Sorting Logic:
  // 1. **FRETTED NOTES PRIORITY**: User request "Diminuir frases com cordas soltas".
  // If one is fret 0 and other is fretted, prefer fretted.

  possiblePositions.sort((a, b) => {
      // 1. Avoid Open Strings (Reverse Logic)
      if (a.fret === 0 && b.fret !== 0) return 1; // Penalty for A (open)
      if (b.fret === 0 && a.fret !== 0) return -1; // Penalty for B (open)

      // 2. Contextual Positioning (if prev note provided)
      if (prevFret !== undefined && prevString !== undefined) {
          const distA = Math.abs(a.fret - prevFret) + Math.abs(a.string - prevString);
          const distB = Math.abs(b.fret - prevFret) + Math.abs(b.string - prevString);
          return distA - distB;
      }

      // 3. Register Preference
      // If note is high (Octave 3 or 4), we want strings 1, 2, 3.
      if (targetOctave >= 3) {
          return a.string - b.string; // Prefer smaller string index (1, 2, 3)
      } else {
          return b.string - a.string; // Prefer thicker strings for bass
      }
  });

  return possiblePositions[0];
};

export const getFrequency = (note: NoteName, octave: number): number => {
    const noteIdx = getNoteIndex(note);
    const midi = (octave + 1) * 12 + noteIdx;
    const A4Midi = 69;
    return 440 * Math.pow(2, (midi - A4Midi) / 12);
};

import React, { useState, useRef, useEffect } from 'react';
import { Play, Square, Music, Plus, Save, Trash2, Settings2, RefreshCw, Layers, Download, Wand2, Speaker, FileAudio, FileText, Loader2 } from 'lucide-react';
import { RhythmStyle, SeventhStringTuning, BassLick, Chord, BassNote, NoteName, InstrumentType, NoteDensity, Tonality } from '../types';
import { generateProgression, generateBassLine } from '../services/baixariaGenerator';
import { playInstrumentNote, scheduleClick, getAudioContext } from '../utils/audio';
import { getFrequency, NOTES } from '../utils/musicTheory';
import { jsPDF } from "jspdf";

export const BassTrainer: React.FC = () => {
    // --- State ---
    const [style, setStyle] = useState<RhythmStyle>(RhythmStyle.SAMBA);
    const [tuning, setTuning] = useState<SeventhStringTuning>(SeventhStringTuning.C);
    const [level, setLevel] = useState<'Iniciante' | 'Intermediário' | 'Avançado'>('Intermediário');
    const [key, setKey] = useState<NoteName>('C');
    const [tonality, setTonality] = useState<Tonality>('Major');
    const [tempo, setTempo] = useState(90);
    const [instrument, setInstrument] = useState<InstrumentType>('nylon');
    const [density, setDensity] = useState<NoteDensity>('auto');

    // Display State
    const [progression, setProgression] = useState<Chord[]>([]);
    const [bassLine, setBassLine] = useState<BassNote[]>([]);
    const [isPlaying, setIsPlaying] = useState(false);
    const [currentBeat, setCurrentBeat] = useState(0);
    const [isExporting, setIsExporting] = useState(false);

    // --- LIVE AUDIO REFS (For seamless updates without stopping) ---
    const progressionRef = useRef<Chord[]>([]);
    const bassLineRef = useRef<BassNote[]>([]);
    const tempoRef = useRef(tempo);
    const instrumentRef = useRef(instrument);

    // Scheduler Refs
    const timerRef = useRef<number | null>(null);
    const startTimeRef = useRef<number>(0);
    const beatRef = useRef<number>(0);

    // Sync Refs with State
    useEffect(() => { tempoRef.current = tempo; }, [tempo]);
    useEffect(() => { instrumentRef.current = instrument; }, [instrument]);

    // --- GENERATOR (HOT SWAP) ---
    // This effect runs whenever parameters change, updating the music data on the fly
    useEffect(() => {
        const newProg = generateProgression(key, tonality, level);
        const newBass = generateBassLine(newProg, style, level, tuning, key, density);

        // Update State (Visuals)
        setProgression(newProg);
        setBassLine(newBass);

        // Update Refs (Audio Engine - Live)
        progressionRef.current = newProg;
        bassLineRef.current = newBass;

        // If not playing, reset beat visual
        if (!isPlaying) {
            setCurrentBeat(0);
        }
    }, [key, tonality, level, style, tuning, density]); // Dependencies trigger regeneration

    // Force regeneration button (for same parameters, new variation)
    const handleForceGenerate = () => {
        const newProg = generateProgression(key, tonality, level);
        const newBass = generateBassLine(newProg, style, level, tuning, key, density);
        setProgression(newProg);
        setBassLine(newBass);
        progressionRef.current = newProg;
        bassLineRef.current = newBass;
    };

    // --- SEQUENCER / PLAYBACK ---
    const play = () => {
        if (isPlaying) {
            stop();
            return;
        }

        const ctx = getAudioContext();
        if (ctx.state === 'suspended') ctx.resume();

        setIsPlaying(true);
        beatRef.current = 0;
        startTimeRef.current = ctx.currentTime; // Reset start time

        scheduleNext();
    };

    const stop = () => {
        if (timerRef.current) clearTimeout(timerRef.current);
        setIsPlaying(false);
        setCurrentBeat(0);
    };

    const scheduleNext = () => {
        const ctx = getAudioContext();
        // Use Refs for Tempo and Data to allow changing while playing
        const currentTempo = tempoRef.current;
        const currentBassLine = bassLineRef.current;
        const currentProgression = progressionRef.current;
        const currentInstrument = instrumentRef.current;

        const secondsPerBeat = 60.0 / currentTempo;
        const lookahead = 0.1; // 100ms

        // Calculate current time in song
        // We use a modulo based on total duration to handle looping correctly even if length changes
        const playTime = ctx.currentTime - startTimeRef.current;

        // Total Duration in beats
        const totalDuration = currentProgression.reduce((acc, c) => acc + c.duration, 0);
        if (totalDuration === 0) return; // Safety

        // Current Beat Position
        const currentSeqBeat = playTime / secondsPerBeat;

        setCurrentBeat(currentSeqBeat);

        // Schedule Notes
        currentBassLine.forEach(note => {
            // Check if note is in the window relative to the loop
            // Handle Looping Logic for the Note Schedule:
            // We check if the note time is close to (currentSeqBeat % totalDuration)

            // However, simple linear check is safer for short loops:
            // Calculate absolute time of note in this specific loop iteration
            // We might need to handle the wrap around visually, but for audio:

            // Simplification: Just check note.startTime vs currentSeqBeat relative to this loop
            // NOTE: If user changes progression length mid-loop, visual might jump, but audio ref is updated.

            // To support infinite play with changing lengths, we rely on the loop reset logic below
            const noteTime = note.startTime * secondsPerBeat;
            const diff = noteTime - playTime;

            if (diff >= 0 && diff < lookahead) {
                const freq = getFrequency(note.note, note.octave);
                const humanize = Math.random() * 0.02;
                const dur = note.duration * secondsPerBeat;

                setTimeout(() => {
                    playInstrumentNote(freq, currentInstrument, dur);
                }, (diff + humanize) * 1000);
            }
        });

        // Loop Logic
        if (currentSeqBeat >= totalDuration) {
             startTimeRef.current = ctx.currentTime; // Reset loop time anchor
        }

        timerRef.current = window.setTimeout(scheduleNext, 50); // 20Hz refresh
    };

    useEffect(() => {
        return () => stop();
    }, []);

    // --- EXPORT FUNCTIONS ---

    // 1. WAV EXPORT (Audio)
    const exportAudio = async () => {
        setIsExporting(true);
        const ctx = new (window.OfflineAudioContext || (window as any).webkitOfflineAudioContext)(
            1, // Mono
            44100 * (progression.reduce((acc, c) => acc + c.duration, 0) * (60 / tempo) + 2), // Duration + tail
            44100
        );

        const secondsPerBeat = 60.0 / tempo;

        bassLine.forEach(note => {
            const time = note.startTime * secondsPerBeat;
            const duration = note.duration * secondsPerBeat;
            const freq = getFrequency(note.note, note.octave);

            // Simple Synth for Export (Similar to utility but offline)
            const osc = ctx.createOscillator();
            const gain = ctx.createGain();

            // Tone Shaping based on Instrument Selection
            if (instrument === 'bass') {
                osc.type = 'triangle';
                gain.gain.setValueAtTime(0, time);
                gain.gain.linearRampToValueAtTime(0.8, time + 0.05);
                gain.gain.exponentialRampToValueAtTime(0.01, time + duration);
            } else if (instrument === 'trombone') {
                osc.type = 'sawtooth';
                const filter = ctx.createBiquadFilter();
                filter.type = 'lowpass';
                filter.frequency.setValueAtTime(200, time);
                filter.frequency.linearRampToValueAtTime(freq * 3, time + 0.1);
                osc.connect(filter);
                filter.connect(gain);
                gain.gain.setValueAtTime(0, time);
                gain.gain.linearRampToValueAtTime(0.6, time + 0.1);
                gain.gain.setValueAtTime(0.6, time + duration - 0.1);
                gain.gain.linearRampToValueAtTime(0, time + duration);
            } else {
                // Nylon default
                osc.type = 'triangle';
                gain.gain.setValueAtTime(0, time);
                gain.gain.linearRampToValueAtTime(0.5, time + 0.02);
                gain.gain.exponentialRampToValueAtTime(0.01, time + duration * 1.5);
            }

            if (instrument !== 'trombone') osc.connect(gain);
            gain.connect(ctx.destination);

            osc.frequency.value = freq;
            osc.start(time);
            osc.stop(time + duration + 0.5);
        });

        const renderedBuffer = await ctx.startRendering();

        // Convert to WAV
        const wavBlob = audioBufferToWav(renderedBuffer);
        const url = URL.createObjectURL(wavBlob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `baixaria_${style.toLowerCase()}_${key}.wav`;
        a.click();

        setIsExporting(false);
    };

    // Helper: Buffer to WAV
    const audioBufferToWav = (buffer: AudioBuffer) => {
        const length = buffer.length * 2; // 16-bit
        const view = new DataView(new ArrayBuffer(44 + length));

        const writeString = (view: DataView, offset: number, string: string) => {
            for (let i = 0; i < string.length; i++) view.setUint8(offset + i, string.charCodeAt(i));
        };

        // RIFF chunk
        writeString(view, 0, 'RIFF');
        view.setUint32(4, 36 + length, true);
        writeString(view, 8, 'WAVE');
        // fmt chunk
        writeString(view, 12, 'fmt ');
        view.setUint32(16, 16, true);
        view.setUint16(20, 1, true); // PCM
        view.setUint16(22, 1, true); // Mono
        view.setUint32(24, 44100, true);
        view.setUint32(28, 44100 * 2, true);
        view.setUint16(32, 2, true);
        view.setUint16(34, 16, true);
        // data chunk
        writeString(view, 36, 'data');
        view.setUint32(40, length, true);

        // PCM Data
        const data = buffer.getChannelData(0);
        let offset = 44;
        for (let i = 0; i < buffer.length; i++) {
            const s = Math.max(-1, Math.min(1, data[i]));
            view.setInt16(offset, s < 0 ? s * 0x8000 : s * 0x7FFF, true);
            offset += 2;
        }

        return new Blob([view], { type: 'audio/wav' });
    };

    // 2. PDF EXPORT (Sheet Music / Tab)
    const exportPDF = () => {
        setIsExporting(true);
        const doc = new jsPDF();

        // Styling
        doc.setFillColor(15, 23, 42); // Slate 900
